QUESTIONS = [{'id': '45b85e6f-a09d-4120-bb5b-b7983eea15eb', 'chapter_id': 1, 'text': 'Test pytanie zamknięte?', 'type': 'closed', 'created_at': '2026-05-06 18:13:44', 'answers': [{'id': 'cf088415-bbf8-40b3-8763-49baa795e1c4', 'question_id': '45b85e6f-a09d-4120-bb5b-b7983eea15eb', 'text': 'Odpowiedź A', 'is_correct': 1, 'sort_order': 0}, {'id': 'b5847832-4507-4f7e-ae5f-ae59a74dc6dd', 'question_id': '45b85e6f-a09d-4120-bb5b-b7983eea15eb', 'text': 'Odpowiedź B', 'is_correct': 0, 'sort_order': 1}, {'id': '3ca359e2-6b01-491c-97eb-4595008e3e19', 'question_id': '45b85e6f-a09d-4120-bb5b-b7983eea15eb', 'text': 'Odpowiedź C', 'is_correct': 0, 'sort_order': 2}, {'id': 'a073c2a7-79d6-4822-8873-4e7acea7af5d', 'question_id': '45b85e6f-a09d-4120-bb5b-b7983eea15eb', 'text': 'Odpowiedź D', 'is_correct': 0, 'sort_order': 3}]}, {'id': '534e85b5-61ba-4e11-b877-cb53c4e2510c', 'chapter_id': 1, 'text': 'Co to jest kontrastowość i od czego zależy?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'd15315a8-a2e3-486d-9362-ebe80a5c33da', 'question_id': '534e85b5-61ba-4e11-b877-cb53c4e2510c', 'text': 'To różnica w jasności między najjaśniejszymi i najciemniejszymi partiami obrazu; zależy od oświetlenia, tematu i charakterystyki materiału.', 'is_correct': 1, 'sort_order': 0}, {'id': '5b167f10-1640-4912-a8b0-ebddbfc05c8c', 'question_id': '534e85b5-61ba-4e11-b877-cb53c4e2510c', 'text': 'To parametr określający wyłącznie nasycenie barw; zależy od temperatury barwowej światła.', 'is_correct': 0, 'sort_order': 1}, {'id': '9ad92374-1f6e-423b-a3eb-6afa7cd4d193', 'question_id': '534e85b5-61ba-4e11-b877-cb53c4e2510c', 'text': 'To zdolność obiektywu do odwzorowania szczegółów; zależy od liczby soczewek w układzie optycznym.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b96cdc28-8c3d-4ae7-8a43-49977988d31a', 'question_id': '534e85b5-61ba-4e11-b877-cb53c4e2510c', 'text': 'To czas naświetlania materiału światłoczułego; zależy od czułości ISO.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1d097913-d74f-4df2-aabd-57c782a77747', 'chapter_id': 1, 'text': 'Co to jest kontrastowość i od czego zależy?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Kontrastowość to stosunek gęstości optycznej najjaśniejszych i najciemniejszych punktów obrazu. Zależy ona od oświetlenia (kierunku i ostrości światła), właściwości fotografowanego obiektu, rodzaju użytego materiału negatywowego oraz sposobu i czasu wywoływania.'}, {'id': 'f542ca9a-8230-45fe-b3e0-b7bddb491d9f', 'chapter_id': 1, 'text': 'Jakich materiałów i sprzętu użyjesz do fotografowania architektury i jakimi zasadami będziesz się kierować?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'db865849-7fa3-4b1b-8dae-1d9bced48883', 'question_id': 'f542ca9a-8230-45fe-b3e0-b7bddb491d9f', 'text': 'Aparat z teleobiektywem, wysokie ISO, fotografowanie pod słońce.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd8a8e10c-b881-49cb-9c12-f990e24559ac', 'question_id': 'f542ca9a-8230-45fe-b3e0-b7bddb491d9f', 'text': 'Aparat szerokokątny lub z obiektywem Tilt-Shift, statyw, poziomica; zasada zachowania pionów i odpowiedniej pory dnia (np. złota godzina).', 'is_correct': 1, 'sort_order': 1}, {'id': '68de4042-6a1c-40f6-83fc-3ced6c86392c', 'question_id': 'f542ca9a-8230-45fe-b3e0-b7bddb491d9f', 'text': 'Kompaktowy aparat z lampą błyskową, brak statywu, krótkie czasy naświetlania.', 'is_correct': 0, 'sort_order': 2}, {'id': '3e2bd3f3-9feb-42fd-accb-08580300aabb', 'question_id': 'f542ca9a-8230-45fe-b3e0-b7bddb491d9f', 'text': 'Wyłącznie aparat średnioformatowy z filmem czarno-białym, bez użycia filtrów.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd919f59b-468f-40e7-b4ee-393e2cb527ab', 'chapter_id': 1, 'text': 'Jakich materiałów i sprzętu użyjesz do fotografowania architektury i jakimi zasadami będziesz się kierować?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Do architektury używamy aparatów z obiektywami szerokokątnymi lub specjalistycznymi typu Tilt-Shift (do korekcji perspektywy). Niezbędny jest stabilny statyw i poziomica. Kluczową zasadą jest dbałość o zbieżność linii pionowych oraz wybór oświetlenia, które podkreśli bryłę budynku (często rano lub późnym popołudniem).'}, {'id': '81545016-4295-4bfc-9121-b8994a814795', 'chapter_id': 1, 'text': 'Omów w jaki sposób wywołuje się filmy czarno-białe w koreksie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '14850a30-2e8f-4b1b-85b9-f39fef25efb9', 'question_id': '81545016-4295-4bfc-9121-b8994a814795', 'text': 'W pełnym świetle dziennym, używając wyłącznie czystej wody.', 'is_correct': 0, 'sort_order': 0}, {'id': '288ddd99-b814-4fd1-a11e-1bd233a08f89', 'question_id': '81545016-4295-4bfc-9121-b8994a814795', 'text': 'W ciemni lub rękawie ciemniowym nawija się film na szpulę, wkłada do koreksu, a następnie wlewa kolejno: wywoływacz, przerywacz, utrwalacz i płucze.', 'is_correct': 1, 'sort_order': 1}, {'id': '9e47990d-1275-430f-8046-29030268916d', 'question_id': '81545016-4295-4bfc-9121-b8994a814795', 'text': 'Poprzez zanurzenie całego aparatu w chemii fotograficznej.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a1966563-9da8-479c-a9f3-1b0a3dcbfdb2', 'question_id': '81545016-4295-4bfc-9121-b8994a814795', 'text': 'Wyłącznie maszynowo w procesie C-41, nie używając koreksu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '6c55f7b0-cedb-4786-a022-e6735b3b1ed8', 'chapter_id': 1, 'text': 'Omów w jaki sposób wywołuje się filmy czarno-białe w koreksie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Proces zaczynamy od nawinięcia filmu na szpulę koreksu w całkowitej ciemności. Po zamknięciu koreksu dalsze etapy odbywają się przy świetle: wlewamy wywoływacz (z zachowaniem czasu i temperatury), stosujemy kąpiel przerywającą, następnie utrwalacz, a na koniec intensywnie płuczemy film w wodzie i suszymy.'}, {'id': 'a3d8c00b-7d52-4c23-bea1-538a0adb92fc', 'chapter_id': 1, 'text': 'Opisz sposób oświetlenia modela w studio fotograficznym ze względu na kształt twarzy.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'e2462c91-494f-43f8-b0c0-badd6218b77a', 'question_id': 'a3d8c00b-7d52-4c23-bea1-538a0adb92fc', 'text': 'Twarz okrągłą oświetlamy szeroko z przodu, by ją jeszcze bardziej powiększyć.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f494ba32-7fcd-402d-a843-aa1f24fa1c1d', 'question_id': 'a3d8c00b-7d52-4c23-bea1-538a0adb92fc', 'text': 'Twarz wąską oświetlamy bocznie, by stworzyć głębokie cienie na policzkach.', 'is_correct': 0, 'sort_order': 1}, {'id': '3f7b7d53-05e7-4842-88ae-a2f4825565d7', 'question_id': 'a3d8c00b-7d52-4c23-bea1-538a0adb92fc', 'text': 'Oświetlenie dobieramy tak, by korygować rysy: np. przy szerokiej twarzy stosujemy oświetlenie wyszczuplające (short lighting), doświetlając tylko jedną stronę.', 'is_correct': 1, 'sort_order': 2}, {'id': '838f1d3d-79e2-40f2-b707-9cb6698469eb', 'question_id': 'a3d8c00b-7d52-4c23-bea1-538a0adb92fc', 'text': 'Zawsze stosujemy tylko jedno źródło światła skierowane pionowo z góry, niezależnie od kształtu twarzy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f268fb0b-d73e-46af-a4d2-4e4d39d9f16e', 'chapter_id': 1, 'text': 'Opisz sposób oświetlenia modela w studio fotograficznym ze względu na kształt twarzy.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Oświetlenie w studio powinno modelować twarz. Przy twarzy okrągłej stosujemy oświetlenie boczne (wąskie), które pozostawia część twarzy w cieniu, wyszczuplając ją. Przy twarzy pociągłej stosujemy oświetlenie szersze, bardziej frontalne, aby optycznie ją wypełnić.'}, {'id': 'ad200429-61ff-4837-b6bf-cb7fc5cf36ac', 'chapter_id': 1, 'text': 'Opisz najbardziej nowoczesny sposób rejestracji obrazu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '14d55146-5835-49cf-b9a4-96a52f821e50', 'question_id': 'ad200429-61ff-4837-b6bf-cb7fc5cf36ac', 'text': 'Rejestracja na płytach szklanych pokrytych kolodionem.', 'is_correct': 0, 'sort_order': 0}, {'id': '3711928e-412b-40a2-b2b1-79e066c2991a', 'question_id': 'ad200429-61ff-4837-b6bf-cb7fc5cf36ac', 'text': 'Rejestracja cyfrowa za pomocą matryc CMOS lub BSI CMOS o wysokiej rozdzielczości i dynamice tonalnej.', 'is_correct': 1, 'sort_order': 1}, {'id': '37f82478-1a04-474a-abc6-76a951d5b182', 'question_id': 'ad200429-61ff-4837-b6bf-cb7fc5cf36ac', 'text': 'Wykorzystanie wyłącznie błon zwojowych typu 120.', 'is_correct': 0, 'sort_order': 2}, {'id': '04864286-f44f-438b-a4ed-54b09aed8dc1', 'question_id': 'ad200429-61ff-4837-b6bf-cb7fc5cf36ac', 'text': 'Ręczne malowanie na papierze światłoczułym pod powiększalnikiem.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0559e262-19eb-4401-96d0-66b00fd75e0c', 'chapter_id': 1, 'text': 'Opisz najbardziej nowoczesny sposób rejestracji obrazu.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obecnie najnowocześniejszą metodą jest rejestracja obrazu przez matryce światłoczułe (CMOS) w aparatach bezlusterkowych. Obraz przetwarzany jest przez procesory obrazu, co pozwala na zapis surowych danych (RAW) o ogromnej rozpiętości tonalnej oraz szybką obróbkę algorytmiczną (fotografia obliczeniowa).'}, {'id': 'c7239ada-3ea2-4fed-86a4-4204e94e52ae', 'chapter_id': 1, 'text': 'Omów sposób rejestracji obrazu przy wykorzystaniu aparatu cyfrowego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5bbeb27b-4374-4368-8f53-29df2f6ac8e6', 'question_id': 'c7239ada-3ea2-4fed-86a4-4204e94e52ae', 'text': 'Światło przechodzi przez obiektyw i pada na matrycę, gdzie fotony zamieniane są na sygnał elektryczny, a następnie na dane cyfrowe.', 'is_correct': 1, 'sort_order': 0}, {'id': 'ee490486-78bc-4fc9-a4c5-3150232ad458', 'question_id': 'c7239ada-3ea2-4fed-86a4-4204e94e52ae', 'text': 'Światło naświetla emulsję srebrową, która zmienia się pod wpływem energii chemicznej.', 'is_correct': 0, 'sort_order': 1}, {'id': '7dec0ab6-daeb-4e1d-9ced-de76d9a8d3e6', 'question_id': 'c7239ada-3ea2-4fed-86a4-4204e94e52ae', 'text': 'Aparat skanuje obiekt laserem i tworzy mapę punktów w pamięci urządzenia.', 'is_correct': 0, 'sort_order': 2}, {'id': 'cf2eff42-e6d2-4671-84e7-47f2fc60bf32', 'question_id': 'c7239ada-3ea2-4fed-86a4-4204e94e52ae', 'text': 'Obraz jest zapisywany bezpośrednio na karcie pamięci bez udziału soczewek.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '883a4363-1234-41a6-b10d-94700c7454ea', 'chapter_id': 1, 'text': 'Omów sposób rejestracji obrazu przy wykorzystaniu aparatu cyfrowego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W aparacie cyfrowym światło przechodzące przez obiektyw pada na matrycę składającą się z milionów fotodiod. Każda dioda rejestruje natężenie światła, które przetwornik analogowo-cyfrowy zamienia na wartości binarne. Dane te są zapisywane na karcie pamięci w formie plików graficznych.'}, {'id': '4a044c0d-034c-48b7-b3db-8f04001952f6', 'chapter_id': 1, 'text': 'Od czego uzależnione jest prawidłowe wywołanie negatywu?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '09530e61-e8bb-48cf-91c9-bf11d09e9df0', 'question_id': '4a044c0d-034c-48b7-b3db-8f04001952f6', 'text': 'Tylko od marki aparatu, którym zrobiono zdjęcia.', 'is_correct': 0, 'sort_order': 0}, {'id': '4985c927-09a8-4fc8-be4d-e6762a27a7a5', 'question_id': '4a044c0d-034c-48b7-b3db-8f04001952f6', 'text': 'Od temperatury roztworów, czasu kąpieli, stężenia chemii oraz częstotliwości mieszania (mieszania koreksem).', 'is_correct': 1, 'sort_order': 1}, {'id': '73f1579e-65d6-4e81-a39d-316a5a56aef5', 'question_id': '4a044c0d-034c-48b7-b3db-8f04001952f6', 'text': 'Od koloru obudowy koreksu i pory dnia.', 'is_correct': 0, 'sort_order': 2}, {'id': '1a6d3896-b019-4781-b57c-4203b59c97d0', 'question_id': '4a044c0d-034c-48b7-b3db-8f04001952f6', 'text': 'Wyłącznie od czułości ISO ustawionej w aparacie, proces chemiczny jest zawsze taki sam.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd9350611-cc0d-4edd-857a-458b41a4868a', 'chapter_id': 1, 'text': 'Od czego uzależnione jest prawidłowe wywołanie negatywu?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Prawidłowe wywołanie negatywu zależy od rygorystycznego przestrzegania reżimu technologicznego: temperatury wywoływacza (zazwyczaj 20°C dla czarno-białych), czasu trwania procesu, odpowiedniego rozcieńczenia odczynników oraz sposobu agitacji (mieszania), która zapewnia dopływ świeżej chemii do emulsji.'}, {'id': '73007bdc-c51f-4217-9981-cead4f853770', 'chapter_id': 1, 'text': 'Opisz jak wykonasz reprodukcję starego zdjęcia formatu legitymacji.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '46cdb3ac-56cb-4c7f-997e-a0537ae97131', 'question_id': '73007bdc-c51f-4217-9981-cead4f853770', 'text': 'Zrobię zdjęcie telefonem z ręki przy słabym świetle.', 'is_correct': 0, 'sort_order': 0}, {'id': '9a669ae5-b38b-48f3-af69-656a4f4819e7', 'question_id': '73007bdc-c51f-4217-9981-cead4f853770', 'text': 'Użyję skanera płaskiego o wysokiej rozdzielczości lub aparatu z obiektywem makro na statywie, dbając o równomierne oświetlenie i brak odblasków.', 'is_correct': 1, 'sort_order': 1}, {'id': '5718ea67-ca80-4c9d-9a37-da9206ce6325', 'question_id': '73007bdc-c51f-4217-9981-cead4f853770', 'text': 'Położę zdjęcie pod powiększalnik i naświetlę bezpośrednio na papier fotograficzny.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f96d3d68-aad1-4fe8-8768-adf15f09066a', 'question_id': '73007bdc-c51f-4217-9981-cead4f853770', 'text': 'Kseruję zdjęcie na zwykłej drukarce biurowej w trybie czarno-białym.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3b3839d2-2325-47e7-84fd-9d5585327081', 'chapter_id': 1, 'text': 'Opisz jak wykonasz reprodukcję starego zdjęcia formatu legitymacji.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Reprodukcję wykonuje się najlepiej za pomocą skanera (min. 600-1200 dpi) lub metodą fotograficzną. W przypadku fotografowania, zdjęcie umieszcza się na płaskiej powierzchni, oświetla dwiema lampami pod kątem 45 stopni (by uniknąć odblasków) i fotografuje aparatem na statywie ustawionym idealnie równolegle do zdjęcia.'}, {'id': '671b5cd0-5b0f-4905-8aaf-678c8be11f26', 'chapter_id': 1, 'text': 'Opisz metodę wykonania powiększenia dowolnego formatu za pomocą powiększalnika w ciemni fotograficznej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'c24aca5a-7de4-4abe-a792-9664c7ec9d5a', 'question_id': '671b5cd0-5b0f-4905-8aaf-678c8be11f26', 'text': 'Negatyw wkłada się do karetki powiększalnika, ustawia ostrość na maskownicy, naświetla papier światłoczuły i wywołuje go w kuwetach.', 'is_correct': 1, 'sort_order': 0}, {'id': '82e8ba49-fbab-4d8c-8e9a-310cd95a464f', 'question_id': '671b5cd0-5b0f-4905-8aaf-678c8be11f26', 'text': 'Papier kładzie się bezpośrednio na negatyw i włącza światło w pokoju na kilka minut.', 'is_correct': 0, 'sort_order': 1}, {'id': 'c30d6212-8cc6-497f-95b6-79fc8e72f7fc', 'question_id': '671b5cd0-5b0f-4905-8aaf-678c8be11f26', 'text': 'Powiększalnik służy do rzutowania obrazu na ścianę, gdzie odrysowuje się go ołówkiem.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e0ca2fd5-7fe6-494a-9360-ea107b6c4fff', 'question_id': '671b5cd0-5b0f-4905-8aaf-678c8be11f26', 'text': 'Negatyw skanuje się powiększalnikiem, a następnie przesyła do drukarki cyfrowej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2d768087-67e3-4b1a-997d-0c8950b4b5d8', 'chapter_id': 1, 'text': 'Opisz metodę wykonania powiększenia dowolnego formatu za pomocą powiększalnika w ciemni fotograficznej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W ciemni umieszczamy negatyw w głowicy powiększalnika. Rzutujemy obraz na papier umieszczony w maskownicy, dobierając kadr i ostrość. Następnie wykonujemy próbę naświetlania, po czym naświetlamy arkusz papieru. Naświetlony papier poddajemy obróbce chemicznej w kuwetach: wywoływacz, przerywacz, utrwalacz i płukanie.'}, {'id': '957c72f2-c8a9-4457-b66c-5cbf107b338b', 'chapter_id': 1, 'text': 'Wymień przebieg procesu C-41. Kolejne jego etapy.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '919b2503-21d2-4277-b9cf-e62210472fbe', 'question_id': '957c72f2-c8a9-4457-b66c-5cbf107b338b', 'text': 'Wywoływanie, Przerywanie, Utrwalanie, Płukanie, Suszenie.', 'is_correct': 0, 'sort_order': 0}, {'id': '3367cf8a-5249-4a59-8996-bd15850f028f', 'question_id': '957c72f2-c8a9-4457-b66c-5cbf107b338b', 'text': 'Wywoływanie barwne, Wybielanie, Utrwalanie (lub Bleach-Fix), Stabilizowanie.', 'is_correct': 1, 'sort_order': 1}, {'id': 'e891831f-3039-4268-9bef-0a3a200855c3', 'question_id': '957c72f2-c8a9-4457-b66c-5cbf107b338b', 'text': 'Wywoływanie czarno-białe, Odwracanie, Wywoływanie barwne, Wybielanie.', 'is_correct': 0, 'sort_order': 2}, {'id': '68c48db9-13d5-4fef-84fd-50f096a6686e', 'question_id': '957c72f2-c8a9-4457-b66c-5cbf107b338b', 'text': 'Naświetlanie, Skanowanie, Drukowanie cyfrowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'cc72b533-61b6-4dab-94c6-8f4db8bc0faf', 'chapter_id': 1, 'text': 'Wymień przebieg procesu C-41. Kolejne jego etapy.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Standardowy proces C-41 składa się z: wywoływania barwnego (najważniejszy etap, temp. 37.8°C), wybielania (usuwanie srebra metalicznego), utrwalania (usuwanie halogenków srebra), płukania oraz stabilizacji (zapobiega blaknięciu barwników i ułatwia schnięcie).'}, {'id': '7d07b44e-a2de-4514-936e-ba175ee809fb', 'chapter_id': 1, 'text': 'Omów zasadę postępowania przy zdjęciach do paszportu, metodę oświetlenia modela i całego procesu usługi.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ff2ac882-69c0-4cd9-82ea-0ad2037c08cb', 'question_id': '7d07b44e-a2de-4514-936e-ba175ee809fb', 'text': 'Zdjęcie musi być artystyczne, z profilu, z dużym cieniem na połowie twarzy.', 'is_correct': 0, 'sort_order': 0}, {'id': '1a6f2787-ffed-4eb2-a6a0-0f48629e1c6d', 'question_id': '7d07b44e-a2de-4514-936e-ba175ee809fb', 'text': 'Twarz na wprost (en face), równomierne oświetlenie bez cieni, białe/jasne tło, widoczne owale twarzy, oczy otwarte i patrzące w obiektyw.', 'is_correct': 1, 'sort_order': 1}, {'id': '46d9c468-f4d3-4ffc-9e6a-44dbb5321ad6', 'question_id': '7d07b44e-a2de-4514-936e-ba175ee809fb', 'text': 'Można mieć na głowie czapkę i ciemne okulary, oświetlenie kolorowe (neonowe).', 'is_correct': 0, 'sort_order': 2}, {'id': '62321314-c1c0-4c9f-91f7-0ed78f42d5a7', 'question_id': '7d07b44e-a2de-4514-936e-ba175ee809fb', 'text': 'Model powinien stać tyłem i odwracać głowę przez ramię w stronę aparatu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f37c9b5a-0a2c-4802-9822-0a92811341ca', 'chapter_id': 1, 'text': 'Omów zasadę postępowania przy zdjęciach do paszportu, metodę oświetlenia modela i całego procesu usługi.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Zdjęcie paszportowe musi spełniać wymogi biometryczne. Osoba fotografowana musi mieć wzrok skierowany w obiektyw, usta zamknięte, a twarz nieosłoniętą. Stosuje się oświetlenie miękkie, bezcieniowe (np. softboxy z obu stron i doświetlenie tła), aby uniknąć głębokich cieni pod oczami i nosem.'}, {'id': '9996ad0f-fb85-4ba3-a98c-99de77c45649', 'chapter_id': 1, 'text': 'Wymień przebieg procesu negatywowego w minilabie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '45d2281e-375b-4397-bab3-4f95a66b07df', 'question_id': '9996ad0f-fb85-4ba3-a98c-99de77c45649', 'text': 'Ręczne wywoływanie w kuwetach przez laboranta.', 'is_correct': 0, 'sort_order': 0}, {'id': '52dcc020-52ba-4b48-aa1e-9ffd7b88ae5d', 'question_id': '9996ad0f-fb85-4ba3-a98c-99de77c45649', 'text': 'Automatyczne przeciągnięcie filmu przez kolejne tanki z chemią C-41 wewnątrz maszyny wywołującej.', 'is_correct': 1, 'sort_order': 1}, {'id': '6d4d5a25-baa0-4c51-bf14-330f3aa76bea', 'question_id': '9996ad0f-fb85-4ba3-a98c-99de77c45649', 'text': 'Naświetlanie laserem filmu, a potem płukanie w gorącej wodzie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a43ae274-471b-47fa-bede-2bad7e77c990', 'question_id': '9996ad0f-fb85-4ba3-a98c-99de77c45649', 'text': 'Włożenie filmu do gorącego pieca w celu utrwalenia obrazu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd990bd62-c65b-4b70-97f0-b4078760a6c3', 'chapter_id': 1, 'text': 'Wymień przebieg procesu negatywowego w minilabie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W minilabie proces negatywowy jest zautomatyzowany. Film po wpięciu w lidera przechodzi przez sekcję wywoływacza, wybielacza, utrwalacza i stabilizatorów w kontrolowanej temperaturze i czasie, a na końcu trafia do sekcji suszącej.'}, {'id': 'f1817a90-e061-40f5-b9c1-86abb9fb0993', 'chapter_id': 1, 'text': 'Wymień rodzaje wywoływaczy fotograficznych i ich zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5f83b952-2191-468c-8fdb-c2693a3d2a64', 'question_id': 'f1817a90-e061-40f5-b9c1-86abb9fb0993', 'text': 'Wywoływacze do papieru (szybkie) i do negatywów (drobnoziarniste, wyrównawcze, kontrastowe).', 'is_correct': 1, 'sort_order': 0}, {'id': 'e33ffe58-a6b3-4480-a52d-2ef6aa26c022', 'question_id': 'f1817a90-e061-40f5-b9c1-86abb9fb0993', 'text': 'Wywoływacze tylko w proszku do zdjęć czarno-białych i tylko w płynie do kolorowych.', 'is_correct': 0, 'sort_order': 1}, {'id': '34a2f43d-f371-4516-8e0d-6592905c6042', 'question_id': 'f1817a90-e061-40f5-b9c1-86abb9fb0993', 'text': 'Wywoływacze kwaśne do zdjęć nocnych i zasadowe do zdjęć dziennych.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f78b6790-28ef-40f5-93ff-fe9d8b56f200', 'question_id': 'f1817a90-e061-40f5-b9c1-86abb9fb0993', 'text': 'Wywoływacze uniwersalne, które służą także jako utrwalacze.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3d9765f3-394c-4852-954d-0d34a7ee914a', 'chapter_id': 1, 'text': 'Wymień rodzaje wywoływaczy fotograficznych i ich zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wywoływacze dzielimy na negatywowe (np. drobnoziarniste dla zachowania detali, wyrównawcze dla dużych kontrastów) oraz pozytywowe (pracujące szybciej i dające głęboką czerń na papierze). Istnieją też specjalne wywoływacze do procesów barwnych (C-41, E-6).'}, {'id': '4effbdc0-b67c-4a3f-b11c-779f64ed76be', 'chapter_id': 1, 'text': 'Co to jest proces C-41? Gdzie ma zastosowanie? Jakie są temperatury i czas kąpieli?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ca47257c-7a97-4232-962c-44460ab59fd1', 'question_id': '4effbdc0-b67c-4a3f-b11c-779f64ed76be', 'text': 'Standardowy proces do slajdów, temp. 20°C, czas 30 minut.', 'is_correct': 0, 'sort_order': 0}, {'id': 'de001c1f-333b-48b5-89eb-0103ac6de314', 'question_id': '4effbdc0-b67c-4a3f-b11c-779f64ed76be', 'text': 'Standardowy proces obróbki kolorowych negatywów; temp. wywoływacza to 37.8°C (100°F), czas wywoływania 3 minuty 15 sekund.', 'is_correct': 1, 'sort_order': 1}, {'id': 'ca4cd90c-6dc5-490b-9430-3bfb178bdca7', 'question_id': '4effbdc0-b67c-4a3f-b11c-779f64ed76be', 'text': 'Proces do odbitek czarno-białych, temp. 15°C, czas 5 minut.', 'is_correct': 0, 'sort_order': 2}, {'id': '172c493e-dde0-48d5-87c4-f5f115ff71ea', 'question_id': '4effbdc0-b67c-4a3f-b11c-779f64ed76be', 'text': 'System czyszczenia matrycy w aparacie cyfrowym za pomocą ultradźwięków.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '088fb46d-ea49-4d0d-901c-7e5f31ca37e6', 'chapter_id': 1, 'text': 'Co to jest proces C-41? Gdzie ma zastosowanie? Jakie są temperatury i czas kąpieli?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'C-41 to chemiczny proces obróbki kolorowych filmów negatywowych. Ma zastosowanie w większości amatorskich i profesjonalnych filmów kolorowych. Kluczowa jest temperatura wywoływacza (37.8°C +/- 0.1°C) oraz czas 3\'15", co zapewnia powtarzalność barw.'}, {'id': '0e2cbced-87fe-4582-937c-4573a155e5c5', 'chapter_id': 1, 'text': 'Co to retusz?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'bb7fa9c2-41e4-4918-809b-ec86cdc0cfdf', 'question_id': '0e2cbced-87fe-4582-937c-4573a155e5c5', 'text': 'To celowe niszczenie zdjęcia w celu uzyskania efektu postarzenia.', 'is_correct': 0, 'sort_order': 0}, {'id': '316995c2-9b5c-4eed-875b-3c241b9cd3b3', 'question_id': '0e2cbced-87fe-4582-937c-4573a155e5c5', 'text': 'To ogół czynności mających na celu usunięcie wad technicznych obrazu lub poprawę wyglądu fotografowanego obiektu.', 'is_correct': 1, 'sort_order': 1}, {'id': 'ef4a57f1-e82a-45e5-a94f-fb7580ff7f40', 'question_id': '0e2cbced-87fe-4582-937c-4573a155e5c5', 'text': 'To technika polegająca na robieniu zdjęć bez użycia obiektywu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd3835c0d-4bda-45f4-a051-82554fe0b965', 'question_id': '0e2cbced-87fe-4582-937c-4573a155e5c5', 'text': 'To proces nakładania ramki na gotowe zdjęcie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '18760c28-9556-4bcd-8f70-32e73b608394', 'chapter_id': 1, 'text': 'Co to retusz?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Retusz to korygowanie obrazu fotograficznego w celu usunięcia niedoskonałości (np. kurzu, rys na negatywie, skaz cery) lub modyfikacji estetycznej (poprawa sylwetki, zmiana kolorystyki). Może być wykonywany analogowo (pędzelkiem, ołówkiem) lub cyfrowo.'}, {'id': '0655c9d8-8faa-4924-ac6b-389792fed84c', 'chapter_id': 1, 'text': 'Jakie znasz rodzaje retużu stosowane w fotografii studyjnej?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f7775555-a0cf-4aae-847f-0d799f1e2b3f', 'question_id': '0655c9d8-8faa-4924-ac6b-389792fed84c', 'text': 'Retusz techniczny (usuwanie skaz) i retusz estetyczny/portretowy (modelowanie twarzy, poprawa cery).', 'is_correct': 1, 'sort_order': 0}, {'id': '0155fd5d-08a7-49ab-806a-c264f167b4b3', 'question_id': '0655c9d8-8faa-4924-ac6b-389792fed84c', 'text': 'Retusz tylko za pomocą farb olejnych nakładanych na matrycę.', 'is_correct': 0, 'sort_order': 1}, {'id': 'e23bc317-10f6-4af8-bc24-64dce94aa2e3', 'question_id': '0655c9d8-8faa-4924-ac6b-389792fed84c', 'text': 'Retusz polegający na zamazywaniu całego tła czarną farbą.', 'is_correct': 0, 'sort_order': 2}, {'id': '742a3e58-df6f-42db-b18a-711d71b00938', 'question_id': '0655c9d8-8faa-4924-ac6b-389792fed84c', 'text': 'Retusz mechaniczny polegający na wycinaniu fragmentów zdjęcia nożyczkami.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '024937ef-1119-4d3f-9a25-7d7e1869f58f', 'chapter_id': 1, 'text': 'Jakie znasz rodzaje retużu stosowane w fotografii studyjnej?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W fotografii studyjnej stosuje się retusz techniczny (czyszczenie tła, usuwanie zbędnych elementów np. kabli) oraz retusz portretowy (tzw. high-end retouching), obejmujący techniki takie jak Dodge & Burn czy separacja częstotliwości (Frequency Separation) do wygładzania skóry przy zachowaniu jej tekstury.'}, {'id': '8e0c8a27-e396-4684-86a6-48be74bcf6b1', 'chapter_id': 1, 'text': 'Omów sposoby korygowania wad wyglądu osoby portretowej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '0b7aed68-8067-40fa-a656-fe51895d7fb2', 'question_id': '8e0c8a27-e396-4684-86a6-48be74bcf6b1', 'text': 'Zawsze używamy najszerszego obiektywu, aby twarz wydawała się większa.', 'is_correct': 0, 'sort_order': 0}, {'id': '889de53f-85c8-432e-8691-2139fc8261c5', 'question_id': '8e0c8a27-e396-4684-86a6-48be74bcf6b1', 'text': 'Poprzez odpowiednie ustawienie ciała (pozy), dobór oświetlenia, dobór ogniskowej obiektywu oraz retusz postprodukcyjny.', 'is_correct': 1, 'sort_order': 1}, {'id': '4effb7ec-6c89-464f-8eb9-4cb00086777f', 'question_id': '8e0c8a27-e396-4684-86a6-48be74bcf6b1', 'text': 'Nakazujemy osobie portretowanej założenie maski, aby nie było widać twarzy.', 'is_correct': 0, 'sort_order': 2}, {'id': '51aa2a58-5a84-49d4-9776-8938310147ce', 'question_id': '8e0c8a27-e396-4684-86a6-48be74bcf6b1', 'text': 'Silne oświetlenie bezpośrednio z dołu, aby ukryć zmarszczki.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '105955b1-eca0-41e0-991c-87f28798f83c', 'chapter_id': 1, 'text': 'Omów sposoby korygowania wad wyglądu osoby portretowej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wady wyglądu korygujemy na etapie zdjęć poprzez pozowanie (np. wysunięcie brody w celu zniwelowania drugiego podbródka) oraz oświetlenie (cienie mogą wyszczuplać). Dłuższa ogniskowa (np. 85mm lub 135mm) pozwala uniknąć przerysowań twarzy, a finalny retusz cyfrowy usuwa czasowe niedoskonałości cery.'}, {'id': '8b50e1e3-7929-4a75-ab14-0588b9f4c70e', 'chapter_id': 1, 'text': 'Omów 3 techniki retuszu fotograficznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'de26039b-b480-468b-aef2-5d9c37bdf6e6', 'question_id': '8b50e1e3-7929-4a75-ab14-0588b9f4c70e', 'text': 'Rozmycie gausowskie, stemplowanie, dodge & burn (rozjaśnianie i przyciemnianie).', 'is_correct': 1, 'sort_order': 0}, {'id': 'cf58982d-883b-415e-b7e6-0b1cd1576f3d', 'question_id': '8b50e1e3-7929-4a75-ab14-0588b9f4c70e', 'text': 'Prasowanie zdjęcia, moczenie w occie, suszenie suszarką.', 'is_correct': 0, 'sort_order': 1}, {'id': 'bbb0cb66-60d2-4ecb-8959-8577ec612988', 'question_id': '8b50e1e3-7929-4a75-ab14-0588b9f4c70e', 'text': 'Fotografowanie przez brudną szybę, drapanie negatywu gwoździem, naświetlanie lampą błyskową.', 'is_correct': 0, 'sort_order': 2}, {'id': '2d761c91-521e-4da2-9625-1dbca589dfd5', 'question_id': '8b50e1e3-7929-4a75-ab14-0588b9f4c70e', 'text': 'Kserowanie, skanowanie, wysyłanie mailem.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '73903f48-5857-444e-a204-5f6e176c8161', 'chapter_id': 1, 'text': 'Omów 3 techniki retuszu fotograficznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Trzy popularne techniki to: 1. Stemplowanie (Clone Stamp) – kopiowanie fragmentu tekstury w miejsce skazy. 2. Dodge & Burn – lokalne rozjaśnianie i przyciemnianie w celu modelowania światłocienia. 3. Separacja częstotliwości – rozdzielenie detali skóry od kolorystyki, co pozwala na niezależną edycję obu warstw.'}, {'id': '8760b7e5-e606-4e90-b8ac-1327873e2a1d', 'chapter_id': 1, 'text': 'Czy film AGFA można wywoływać w chemii KODAK? Uzasadnij.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'a0075201-ef0c-47f0-9681-66aaa5e9c6fb', 'question_id': '8760b7e5-e606-4e90-b8ac-1327873e2a1d', 'text': 'Nie, każdy producent ma unikalny skład chemiczny, który zniszczy film innej marki.', 'is_correct': 0, 'sort_order': 0}, {'id': '04f71188-63ac-40e7-8dfb-c5561240b499', 'question_id': '8760b7e5-e606-4e90-b8ac-1327873e2a1d', 'text': 'Tak, jeśli oba są przeznaczone do tego samego procesu (np. kolorowe C-41 lub standardowe czarno-białe).', 'is_correct': 1, 'sort_order': 1}, {'id': '40bc7806-940f-4226-9f52-88d2597b6127', 'question_id': '8760b7e5-e606-4e90-b8ac-1327873e2a1d', 'text': 'Tak, ale tylko pod warunkiem, że wywoływanie odbywa się w całkowitej ciemności przez 24 godziny.', 'is_correct': 0, 'sort_order': 2}, {'id': 'cd97d03a-92a0-42ed-913c-afbee347960d', 'question_id': '8760b7e5-e606-4e90-b8ac-1327873e2a1d', 'text': 'Nie, filmy Agfa wymagają specjalnej chemii produkowanej tylko w Niemczech.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e6efe03c-9f85-4098-9993-6a31febfeef2', 'chapter_id': 1, 'text': 'Czy film AGFA można wywoływać w chemii KODAK? Uzasadnij.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Tak, ponieważ procesy barwne takie jak C-41 są zestandaryzowane. Każdy film kolorowy różnych marek (Agfa, Kodak, Fuji) wywołuje się w tych samych kąpielach chemicznych o tych samych parametrach. W przypadku filmów czarno-białych chemia również jest wymienna, choć czasy wywoływania mogą się różnić.'}, {'id': '5843e825-516a-4be2-b24d-38707cc331a8', 'chapter_id': 1, 'text': 'Jaka jest różnica pomiędzy zdjęciami makro i mikro?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ada2f1c9-65d2-4292-882a-d39e6e02f240', 'question_id': '5843e825-516a-4be2-b24d-38707cc331a8', 'text': 'Makro to zdjęcia dużych obiektów (np. budynków), a mikro to zdjęcia małych (np. kwiatów).', 'is_correct': 0, 'sort_order': 0}, {'id': '2635be28-e8a1-4d92-b2bf-4f1243acc72a', 'question_id': '5843e825-516a-4be2-b24d-38707cc331a8', 'text': 'Makro to odwzorowanie w skali od 1:1 do ok. 10:1, mikro (mikrofotografia) to zdjęcia przy użyciu mikroskopu w znacznie większych skalach.', 'is_correct': 1, 'sort_order': 1}, {'id': 'ce4d5054-de34-4c63-bdcd-317dd4cd5dc3', 'question_id': '5843e825-516a-4be2-b24d-38707cc331a8', 'text': 'Nie ma żadnej różnicy, to dwa określenia tego samego procesu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ee0cc8e8-7e1b-42ce-ae11-4fc3b46dc4e1', 'question_id': '5843e825-516a-4be2-b24d-38707cc331a8', 'text': 'Makro wykonuje się tylko w nocy, a mikro tylko w dzień.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '67ea539f-2166-47ed-aed7-1ed71d5fbe1b', 'chapter_id': 1, 'text': 'Jaka jest różnica pomiędzy zdjęciami makro i mikro?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Fotografia makro pozwala na uwiecznienie małych obiektów w powiększeniu, zazwyczaj od skali 1:1. Mikrofotografia (mikro) idzie znacznie dalej – wymaga użycia mikroskopu i służy do rejestracji struktur niewidocznych gołym okiem, często w powiększeniach rzędu kilkuset razy.'}, {'id': '760fcb14-4a47-4eb7-89ba-7a69d26b8b55', 'chapter_id': 1, 'text': 'Omów sposoby zatrzymania ruchu w fotografii.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '194dcf7d-3795-43d5-9d26-4c191ccd9a30', 'question_id': '760fcb14-4a47-4eb7-89ba-7a69d26b8b55', 'text': 'Użycie długiego czasu naświetlania (np. 1 sekunda) i poruszenie aparatem.', 'is_correct': 0, 'sort_order': 0}, {'id': '93399e09-581c-4b53-a273-ee2d800b916a', 'question_id': '760fcb14-4a47-4eb7-89ba-7a69d26b8b55', 'text': 'Zastosowanie krótkiego czasu naświetlania (np. 1/1000s) lub użycie błysku lampy o bardzo krótkim czasie trwania.', 'is_correct': 1, 'sort_order': 1}, {'id': 'fceb8ce9-af2c-47e1-8ce2-3b1ee31521d8', 'question_id': '760fcb14-4a47-4eb7-89ba-7a69d26b8b55', 'text': 'Poproszenie osoby, aby się nie ruszała przez 10 minut.', 'is_correct': 0, 'sort_order': 2}, {'id': '5cbe62e1-676b-4278-83d6-6f9785284679', 'question_id': '760fcb14-4a47-4eb7-89ba-7a69d26b8b55', 'text': 'Zwiększenie wartości przysłony do f/22 bez zmiany innych parametrów.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '69ef2614-8572-4fcd-9a34-e0aabbf4ebcd', 'chapter_id': 1, 'text': 'Omów sposoby zatrzymania ruchu w fotografii.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Ruch można "zamrozić" stosując krótkie czasy otwarcia migawki (np. 1/500s i krótsze). Innym sposobem jest wykorzystanie lampy błyskowej w ciemniejszym otoczeniu – krótki impuls światła błyskowego trwa ułamek sekundy i to on decyduje o ostrości poruszającego się obiektu.'}, {'id': '3bbd19c8-c57d-4cf3-8033-3a00bf39a8c6', 'chapter_id': 1, 'text': 'Co to jest dominata barwna? Jak ją skorygować?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '4b8d49c0-191e-427e-827a-218649db04f8', 'question_id': '3bbd19c8-c57d-4cf3-8033-3a00bf39a8c6', 'text': 'To przewaga jednego koloru na całym zdjęciu; koryguje się ją poprzez ustawienie odpowiedniego balansu bieli (WB) lub w postprodukcji.', 'is_correct': 1, 'sort_order': 0}, {'id': 'd81a2d07-baa8-4b1c-9298-22124939859d', 'question_id': '3bbd19c8-c57d-4cf3-8033-3a00bf39a8c6', 'text': 'To najostrzejszy punkt na zdjęciu; koryguje się ją kręceniem pierścieniem ostrości.', 'is_correct': 0, 'sort_order': 1}, {'id': 'b9684310-c1df-4491-922e-aaf2576efe9a', 'question_id': '3bbd19c8-c57d-4cf3-8033-3a00bf39a8c6', 'text': 'To rodzaj filtra nakładanego na obiektyw, aby zdjęcie było czarno-białe.', 'is_correct': 0, 'sort_order': 2}, {'id': '8ad63711-6d13-454e-8514-c27ec3a1e81d', 'question_id': '3bbd19c8-c57d-4cf3-8033-3a00bf39a8c6', 'text': 'To błąd polegający na niedoświetleniu zdjęcia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1636af16-1551-4bfe-afbd-9c857495afe6', 'chapter_id': 1, 'text': 'Co to jest dominata barwna? Jak ją skorygować?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Dominata barwna to nienaturalne zabarwienie zdjęcia konkretnym kolorem (np. niebieskim w cieniu lub pomarańczowym w świetle żarówek). Koryguje się ją ustawiając balans bieli w aparacie zgodnie z temperaturą światła lub używając filtrów korekcyjnych oraz suwaków temperatury i dominanty w edytorach cyfrowych.'}, {'id': '422a3d17-0248-4f87-aff6-27eec7a05b11', 'chapter_id': 1, 'text': 'Co rozumiemy przez oświetlenie plastyczne, a co przez płaskie?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '7cdfd3df-0d6c-4ad0-a756-5a6beff209a7', 'question_id': '422a3d17-0248-4f87-aff6-27eec7a05b11', 'text': 'Plastyczne podkreśla trójwymiarowość bryły poprzez światłocień; płaskie to oświetlenie frontalne eliminujące cienie i głębię.', 'is_correct': 1, 'sort_order': 0}, {'id': '2200aa18-8836-4725-b578-50b2b8a9ef79', 'question_id': '422a3d17-0248-4f87-aff6-27eec7a05b11', 'text': 'Plastyczne to oświetlenie kolorowe; płaskie to oświetlenie czarno-białe.', 'is_correct': 0, 'sort_order': 1}, {'id': '2648d077-6109-4d0b-ac19-7b7263bf1436', 'question_id': '422a3d17-0248-4f87-aff6-27eec7a05b11', 'text': 'Plastyczne wykonuje się plasteliną, a płaskie na papierze.', 'is_correct': 0, 'sort_order': 2}, {'id': '2409e62f-156b-4f6a-b5d4-859d01629c9a', 'question_id': '422a3d17-0248-4f87-aff6-27eec7a05b11', 'text': 'Plastyczne to światło słoneczne, a płaskie to światło z żarówki.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0dd56c35-db1a-423e-8436-e18fbb3b175a', 'chapter_id': 1, 'text': 'Co rozumiemy przez oświetlenie plastyczne, a co przez płaskie?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Oświetlenie plastyczne (modelujące) ustawione jest zazwyczaj pod kątem, tworząc cienie, które informują widza o kształcie i fakturze obiektu. Oświetlenie płaskie pada z kierunku osi obiektywu (np. lampa błyskowa na aparacie), co "spłaszcza" twarz lub obiekt, ukrywając jego strukturę i objętość.'}, {'id': '988e9775-2dfd-4d1c-b33e-8e08e3875d2f', 'chapter_id': 1, 'text': 'Opisz proces technologiczny procesu pozytywowego w minilabie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '953ca20d-eb93-44a7-a94c-4c6b5e1c2c5f', 'question_id': '988e9775-2dfd-4d1c-b33e-8e08e3875d2f', 'text': 'Naświetlanie papieru światłoczułego laserem/LED, a następnie wywoływanie w chemii RA-4 (wywoływacz, wybielacz-utrwalacz, płukanie, suszenie).', 'is_correct': 1, 'sort_order': 0}, {'id': '6d11c6ef-feed-4277-8236-083afc0ca337', 'question_id': '988e9775-2dfd-4d1c-b33e-8e08e3875d2f', 'text': 'Drukowanie zdjęć atramentem na zwykłym papierze biurowym.', 'is_correct': 0, 'sort_order': 1}, {'id': '00ea3091-b78a-4e1c-a2fc-d7e7fac251fa', 'question_id': '988e9775-2dfd-4d1c-b33e-8e08e3875d2f', 'text': 'Kserowanie negatywu na folię przezroczystą.', 'is_correct': 0, 'sort_order': 2}, {'id': '70a5e315-ae02-4076-942b-039d3a897294', 'question_id': '988e9775-2dfd-4d1c-b33e-8e08e3875d2f', 'text': 'Ręczne nakładanie pędzlem emulsji na karton i naświetlanie lampą biurkową.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c9f30789-ec44-4978-8313-b09f2dd91d2b', 'chapter_id': 1, 'text': 'Opisz proces technologiczny procesu pozytywowego w minilabie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W minilabie cyfrowym obraz z pliku jest rzutowany za pomocą wiązek lasera lub diod LED na papier światłoczuły (proces RA-4). Następnie papier przechodzi przez sekcję chemiczną (wywoływacz barwny, wybielacz utrwalający) oraz kaskadowy system płukania, po czym jest suszony i przycinany do formatu.'}, {'id': '4bedd3c6-67c4-49a3-90f9-cb11869095bd', 'chapter_id': 1, 'text': 'Od czego uzależnione jest prawidłowe wywoływanie negatywu? (powtórzone)', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '2211e7b5-d577-4618-aaa6-64edd99c0095', 'question_id': '4bedd3c6-67c4-49a3-90f9-cb11869095bd', 'text': 'Od fazy księżyca i wilgotności powietrza na zewnątrz.', 'is_correct': 0, 'sort_order': 0}, {'id': 'b2720d0a-b9b3-411b-8ff5-63602a9a8cfb', 'question_id': '4bedd3c6-67c4-49a3-90f9-cb11869095bd', 'text': 'Od parametrów: czas, temperatura, stężenie wywoływacza oraz sposób mieszania.', 'is_correct': 1, 'sort_order': 1}, {'id': '0ed57374-418c-4d61-9640-229c82f966c2', 'question_id': '4bedd3c6-67c4-49a3-90f9-cb11869095bd', 'text': 'Wyłącznie od tego, czy film był wcześniej naświetlony.', 'is_correct': 0, 'sort_order': 2}, {'id': 'df422000-63d4-478e-934f-00f82ceb25ea', 'question_id': '4bedd3c6-67c4-49a3-90f9-cb11869095bd', 'text': 'Od ceny użytego wywoływacza.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '59428f88-4b28-4861-87a2-741150e3df23', 'chapter_id': 1, 'text': 'Od czego uzależnione jest prawidłowe wywoływanie negatywu? (powtórzone)', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Prawidłowe wywoływanie negatywu zależy od precyzyjnego zachowania parametrów czasowo-temperaturowych. Nawet niewielkie odchylenia temperatury (szczególnie w procesie kolorowym) lub błędy w czasie wywoływania i intensywności mieszania wpływają na kontrast, ziarnistość i gęstość negatywu.'}, {'id': '5d1ed7c9-a875-4812-a0e0-cb8eb2019e59', 'chapter_id': 1, 'text': 'Opisz proces pozytywowy w fotografii barwnej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '3fd56da7-c4c9-4d79-b2bb-bc8a63ca110e', 'question_id': '5d1ed7c9-a875-4812-a0e0-cb8eb2019e59', 'text': 'To proces RA-4, w którym naświetlony papier barwny jest wywoływany, wybielany i utrwalany.', 'is_correct': 1, 'sort_order': 0}, {'id': '7d0c4ade-f544-433c-ba9d-0eafa7293b63', 'question_id': '5d1ed7c9-a875-4812-a0e0-cb8eb2019e59', 'text': 'To po prostu robienie zdjęć kolorowych aparatem cyfrowym.', 'is_correct': 0, 'sort_order': 1}, {'id': '4968f622-2903-4dc5-8c27-d4b8b7785bc5', 'question_id': '5d1ed7c9-a875-4812-a0e0-cb8eb2019e59', 'text': 'To wywoływanie filmu czarno-białego w kawie i soli.', 'is_correct': 0, 'sort_order': 2}, {'id': '1438b39e-9f4d-452e-bcd6-012e2922dc04', 'question_id': '5d1ed7c9-a875-4812-a0e0-cb8eb2019e59', 'text': 'To proces polegający na kolorowaniu czarno-białych zdjęć kredkami.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '167ab4f9-ef31-4349-b5a5-0f8f0ea1edba', 'chapter_id': 1, 'text': 'Opisz proces pozytywowy w fotografii barwnej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Proces pozytywowy barwny (najczęściej RA-4) polega na uzyskaniu barwnego obrazu na papierze światłoczułym. Składa się z wywoływania barwnego, podczas którego powstają barwniki w emulsji, oraz z kąpieli wybielająco-utrwalającej, która usuwa srebro, pozostawiając czysty obraz barwny.'}, {'id': '31e7eaf2-b15b-4689-bed4-d1d52ec78b02', 'chapter_id': 1, 'text': 'Opisz metodę przygotowania modela do zdjęć portretowych i na czym polega retusz optyczny?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '91fad277-a0b2-4905-acfb-1d8386080312', 'question_id': '31e7eaf2-b15b-4689-bed4-d1d52ec78b02', 'text': 'Model powinien być nieprzygotowany, aby wyglądać naturalnie.', 'is_correct': 0, 'sort_order': 0}, {'id': '65e9d62f-e239-4e42-b228-56ced6618a3b', 'question_id': '31e7eaf2-b15b-4689-bed4-d1d52ec78b02', 'text': 'Przygotowanie obejmuje makijaż, ubiór i fryzurę; retusz optyczny to korygowanie wyglądu za pomocą światła, cienia i perspektywy.', 'is_correct': 1, 'sort_order': 1}, {'id': '9fece739-3988-4a46-8652-fdd7c076e2e9', 'question_id': '31e7eaf2-b15b-4689-bed4-d1d52ec78b02', 'text': 'Retusz optyczny to użycie okularów przez modela, aby ukryć oczy.', 'is_correct': 0, 'sort_order': 2}, {'id': '4bbff01b-99cd-45c8-9ba3-42cd1495ae0c', 'question_id': '31e7eaf2-b15b-4689-bed4-d1d52ec78b02', 'text': 'Przygotowanie to wyłącznie retuszowanie zdjęcia w Photoshopie przed jego zrobieniem.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '9581ca9f-4afb-4325-acc9-25949cdaedfb', 'chapter_id': 1, 'text': 'Opisz metodę przygotowania modela do zdjęć portretowych i na czym polega retusz optyczny?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Przygotowanie modela obejmuje makijaż fotograficzny (matujący skórę) oraz dobór stroju. Retusz optyczny to technika polegająca na takim operowaniu światłem (np. wyszczuplanie cieniem) i kątem widzenia obiektywu, aby jeszcze przed naciśnięciem migawki ukryć mankamenty urody i podkreślić atuty.'}, {'id': 'e1d8a0b9-3ad9-4a8c-afff-5b2492ff9124', 'chapter_id': 1, 'text': 'Jak fotografujemy przedmioty znajdujące się w ruchu?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '19cf00d3-a756-4b92-8474-27a915587a6d', 'question_id': 'e1d8a0b9-3ad9-4a8c-afff-5b2492ff9124', 'text': 'Zawsze używamy najdłuższego możliwego czasu naświetlania.', 'is_correct': 0, 'sort_order': 0}, {'id': '388a5bac-e53e-49dd-a836-71df7918f404', 'question_id': 'e1d8a0b9-3ad9-4a8c-afff-5b2492ff9124', 'text': 'Stosujemy krótkie czasy naświetlania lub technikę panoramirowania (prowadzenia aparatu za obiektem).', 'is_correct': 1, 'sort_order': 1}, {'id': 'dde7871c-4089-4a9d-a6c7-3583448ac39c', 'question_id': 'e1d8a0b9-3ad9-4a8c-afff-5b2492ff9124', 'text': 'Czekamy, aż przedmiot sam się zatrzyma.', 'is_correct': 0, 'sort_order': 2}, {'id': '9be308b0-fda6-4d2e-9c7e-ba90d25c330c', 'question_id': 'e1d8a0b9-3ad9-4a8c-afff-5b2492ff9124', 'text': 'Fotografujemy tylko w trybie czarno-białym, bo kolor rozmazuje obraz.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '180f0141-bca1-4313-ba5a-cc6f75daa74f', 'chapter_id': 1, 'text': 'Jak fotografujemy przedmioty znajdujące się w ruchu?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Przedmioty w ruchu fotografujemy na dwa sposoby: zamrażając ruch krótkim czasem naświetlania (np. 1/2000s) lub oddając dynamikę poprzez panoramowanie (panning). Panoramowanie polega na śledzeniu aparatem poruszającego się obiektu przy nieco dłuższym czasie (np. 1/60s), co daje ostry obiekt na rozmytym tle.'}, {'id': 'a18eb00d-89b0-4a15-8190-9e21029d18da', 'chapter_id': 1, 'text': 'Jeżeli zastosujemy przysłonę w obiektywie to w jakiej proporcji powstaje głębia ostrości (ile w przód ile w tył) i w jaki sposób to sprawdzić.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '434d817b-8b25-4249-b79c-7930dda6608e', 'question_id': 'a18eb00d-89b0-4a15-8190-9e21029d18da', 'text': '1/2 w przód i 1/2 w tył; sprawdzamy to lupą.', 'is_correct': 0, 'sort_order': 0}, {'id': '024a87e1-095d-403c-b2bc-d32b885bcad8', 'question_id': 'a18eb00d-89b0-4a15-8190-9e21029d18da', 'text': 'Około 1/3 zakresu ostrości przed punktem ostrzenia i 2/3 za nim; można to sprawdzić przyciskiem podglądu głębi ostrości.', 'is_correct': 1, 'sort_order': 1}, {'id': '9b890f09-0b3a-4672-8dd8-2199095cf70f', 'question_id': 'a18eb00d-89b0-4a15-8190-9e21029d18da', 'text': 'Cała ostrość jest zawsze tylko przed obiektem.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e1582cbd-1cb6-44e0-8654-9fa938b6af30', 'question_id': 'a18eb00d-89b0-4a15-8190-9e21029d18da', 'text': '90% w przód i 10% w tył; sprawdzamy to na oko.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e22df124-c720-469b-af1d-3c390a9a1e41', 'chapter_id': 1, 'text': 'Jeżeli zastosujemy przysłonę w obiektywie to w jakiej proporcji powstaje głębia ostrości (ile w przód ile w tył) i w jaki sposób to sprawdzić.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Głębia ostrości rozkłada się asymetrycznie: ok. 1/3 obszaru ostrości znajduje się przed punktem, na który ustawiliśmy ostrość, a ok. 2/3 za nim. Wartość tę można sprawdzić korzystając z przycisku podglądu głębi ostrości w lustrzankach lub na ekranie LCD w bezlusterkowcach.'}, {'id': '53abae0f-2893-4bdd-9686-71ea1d4543d8', 'chapter_id': 1, 'text': 'Co to jest głębia ostrości?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ce6a864b-1a09-47a0-9af6-a4f928840fe8', 'question_id': '53abae0f-2893-4bdd-9686-71ea1d4543d8', 'text': 'To odległość od aparatu do pierwszego planu.', 'is_correct': 0, 'sort_order': 0}, {'id': '42769ddb-6c3f-425f-b533-cbf069ef4288', 'question_id': '53abae0f-2893-4bdd-9686-71ea1d4543d8', 'text': 'To zakres odległości, w którym obiekty na zdjęciu wydają się ostre.', 'is_correct': 1, 'sort_order': 1}, {'id': '88f71822-7b8a-426c-b425-dc18bf81521a', 'question_id': '53abae0f-2893-4bdd-9686-71ea1d4543d8', 'text': 'To parametr określający jasność obiektywu.', 'is_correct': 0, 'sort_order': 2}, {'id': '98459ce8-365a-447f-8fb2-004d9be1f79d', 'question_id': '53abae0f-2893-4bdd-9686-71ea1d4543d8', 'text': 'To głębokość, na jaką można zanurzyć aparat pod wodą.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '72df23dd-12f6-4c81-b8f8-06e443c6d261', 'chapter_id': 1, 'text': 'Co to jest głębia ostrości?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Głębia ostrości to strefa ostrości mierzona wzdłuż osi optycznej obiektywu, w obrębie której elementy obrazu są interpretowane przez ludzkie oko jako ostre. Zależy ona od wartości przysłony, ogniskowej obiektywu oraz odległości od fotografowanego obiektu.'}, {'id': 'ed51de9d-9544-43ac-886c-a930707f0d8b', 'chapter_id': 1, 'text': 'Od czego zależy czas utrwalania negatywów i pozytywów?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'e7201ade-5f50-4566-b598-7c112129675b', 'question_id': 'ed51de9d-9544-43ac-886c-a930707f0d8b', 'text': 'Od rodzaju użytego utrwalacza, jego stężenia, temperatury kąpieli oraz stopnia zużycia roztworu.', 'is_correct': 1, 'sort_order': 0}, {'id': '3456683c-9f07-4d5a-a7b2-66d6edfdf068', 'question_id': 'ed51de9d-9544-43ac-886c-a930707f0d8b', 'text': 'Wyłącznie od tego, czy film był naświetlany w dzień, czy w nocy.', 'is_correct': 0, 'sort_order': 1}, {'id': '69ff9339-4977-4bfa-ae3f-794e98aefa38', 'question_id': 'ed51de9d-9544-43ac-886c-a930707f0d8b', 'text': 'Od koloru obudowy aparatu, którym wykonano zdjęcia.', 'is_correct': 0, 'sort_order': 2}, {'id': '95f05acf-c25b-48cc-b648-8e2b5df6cacd', 'question_id': 'ed51de9d-9544-43ac-886c-a930707f0d8b', 'text': 'Od długości obiektywu użytego podczas fotografowania.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '830e9f63-8ec3-4461-8b85-08b20d4b8ed6', 'chapter_id': 1, 'text': 'Od czego zależy czas utrwalania negatywów i pozytywów?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Czas utrwalania zależy od szybkości usuwania nienaświetlonych halogenków srebra z emulsji. Wpływ na to ma świeżość kąpieli (ilość nagromadzonych soli srebra), temperatura (wyższa przyspiesza proces), rodzaj materiału (negatywy utrwalają się dłużej niż papiery) oraz intensywność mieszania.'}, {'id': 'e525c8be-81fd-4b07-acc7-92770b108510', 'chapter_id': 1, 'text': 'Podaj czas naświetlania negatywu 1/125s przy otworze 5,6. Jaki czas będzie przy przysłonie 11?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'bb37d3c4-7cbb-4d42-b913-d2960961faab', 'question_id': 'e525c8be-81fd-4b07-acc7-92770b108510', 'text': '1/500s.', 'is_correct': 0, 'sort_order': 0}, {'id': 'b9f02f18-9d8a-40d7-8188-6ebaa0575538', 'question_id': 'e525c8be-81fd-4b07-acc7-92770b108510', 'text': '1/250s.', 'is_correct': 0, 'sort_order': 1}, {'id': '6b93970a-ab52-4a45-b4f6-1da88f14932a', 'question_id': 'e525c8be-81fd-4b07-acc7-92770b108510', 'text': '1/30s.', 'is_correct': 1, 'sort_order': 2}, {'id': 'c184cb4e-460b-4fb3-9c2f-fc46f2f4ac7d', 'question_id': 'e525c8be-81fd-4b07-acc7-92770b108510', 'text': '1/15s.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a8cb5624-54ef-4189-9da1-0b7e783660a4', 'chapter_id': 1, 'text': 'Podaj czas naświetlania negatywu 1/125s przy otworze 5,6. Jaki czas będzie przy przysłonie 11?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Przy zmianie przysłony z 5,6 na 11 przymykamy obiektyw o dwie pełne wartości (5,6 -> 8 -> 11). Aby zachować tę samą ekspozycję, musimy czterokrotnie wydłużyć czas naświetlania, zatem z 1/125s przechodzimy na ok. 1/30s.'}, {'id': 'd5a1ba10-870a-4f7e-b9de-d0ddd35558ad', 'chapter_id': 1, 'text': 'Co to jest paralaksa i w jakich aparatach występuje?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '4047b1c0-3e43-4af0-870f-219edc97f91e', 'question_id': 'd5a1ba10-870a-4f7e-b9de-d0ddd35558ad', 'text': 'To błąd ostrości występujący w aparatach bezlusterkowych.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ee55b0ee-80a6-4116-bfe9-c45349b385fd', 'question_id': 'd5a1ba10-870a-4f7e-b9de-d0ddd35558ad', 'text': 'To niezgodność obrazu widzianego w celowniku z obrazem rejestrowanym przez obiektyw; występuje w aparatach dwuobiektywowych i z celownikiem lunetkowym.', 'is_correct': 1, 'sort_order': 1}, {'id': '9b9c3606-847a-4381-8de7-61b5a9f3f28b', 'question_id': 'd5a1ba10-870a-4f7e-b9de-d0ddd35558ad', 'text': 'To specjalny rodzaj filtru polaryzacyjnego stosowany w lustrzankach.', 'is_correct': 0, 'sort_order': 2}, {'id': 'aa624a08-96b7-47ea-9210-97d7270a449e', 'question_id': 'd5a1ba10-870a-4f7e-b9de-d0ddd35558ad', 'text': 'To zjawisko polegające na prześwietleniu krawędzi zdjęcia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '22b76a86-1405-492e-80be-c34442e464be', 'chapter_id': 1, 'text': 'Co to jest paralaksa i w jakich aparatach występuje?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Paralaksa to różnica wynikająca z innego punktu widzenia osi celownika i osi obiektywu. Jest szczególnie uciążliwa przy małych odległościach od obiektu i występuje w aparatach, gdzie celownik nie pokazuje obrazu bezpośrednio przez obiektyw fotografujący (np. w aparatach dalmierzowych lub typu TLR).'}, {'id': 'efbf83e6-f89c-4fe4-93b6-697403e36e4c', 'chapter_id': 1, 'text': 'Omów rodzaje retuszu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '30a6967c-45af-453b-816b-b8b5e82382b0', 'question_id': 'efbf83e6-f89c-4fe4-93b6-697403e36e4c', 'text': 'Tylko retusz ołówkiem na odbitce papierowej.', 'is_correct': 0, 'sort_order': 0}, {'id': '801a1505-dad5-49a2-8168-0089c36dc414', 'question_id': 'efbf83e6-f89c-4fe4-93b6-697403e36e4c', 'text': 'Retusz techniczny (usuwanie wad materiału) i retusz artystyczny (poprawa estetyki obiektu); dzielimy go na analogowy i cyfrowy.', 'is_correct': 1, 'sort_order': 1}, {'id': 'e885078a-3e0f-46ea-a0d7-d916dcfb85c4', 'question_id': 'efbf83e6-f89c-4fe4-93b6-697403e36e4c', 'text': 'Retusz polegający wyłącznie na zmianie formatu zdjęcia z pionowego na poziomy.', 'is_correct': 0, 'sort_order': 2}, {'id': '185330d8-3aa1-41e1-8f5c-d42292def75d', 'question_id': 'efbf83e6-f89c-4fe4-93b6-697403e36e4c', 'text': 'Retusz mechaniczny polegający na zamalowywaniu całego zdjęcia czarną farbą.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f6dc80e3-6953-407b-b9ab-ffe42cee63c9', 'chapter_id': 1, 'text': 'Omów rodzaje retuszu.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Retusz można podzielić na techniczny (usuwanie rys, kurzu, plam) oraz estetyczny (korekta urody, modelowanie sylwetki). Ze względu na technikę wyróżniamy retusz negatywowy (na filmie), pozytywowy (na odbitce) oraz najpowszechniejszy obecnie retusz cyfrowy w programach graficznych.'}, {'id': '428384ad-d53c-4ead-bdf6-a74f7887461d', 'chapter_id': 1, 'text': 'Omów zagadnienie głębi ostrości i od czego ona zależy?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'd69bbe17-7252-4009-ad91-b71b56cf160c', 'question_id': '428384ad-d53c-4ead-bdf6-a74f7887461d', 'text': 'Zależy od długości kabla zasilającego lampy studyjne.', 'is_correct': 0, 'sort_order': 0}, {'id': '32a52653-2953-41d3-a361-62e9908cd724', 'question_id': '428384ad-d53c-4ead-bdf6-a74f7887461d', 'text': 'To zakres ostrości przed i za obiektem; zależy od przysłony, ogniskowej obiektywu i odległości przedmiotowej.', 'is_correct': 1, 'sort_order': 1}, {'id': 'fef7a11e-6ffe-4c63-9c0d-9faf36b9dcf1', 'question_id': '428384ad-d53c-4ead-bdf6-a74f7887461d', 'text': 'To parametr określający tylko głębokość zanurzenia aparatu w wodzie.', 'is_correct': 0, 'sort_order': 2}, {'id': '8cdce3c2-5cd6-4ad9-a300-b46dc13cd44c', 'question_id': '428384ad-d53c-4ead-bdf6-a74f7887461d', 'text': 'Zależy wyłącznie od marki używanej karty pamięci.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e73bc5b0-e28f-4d6d-97ca-c7eb58f1f32a', 'chapter_id': 1, 'text': 'Omów zagadnienie głębi ostrości i od czego ona zależy?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Głębia ostrości to obszar, w którym obiekty wydają się ostre. Zwiększa się ona przy przymykaniu przysłony (większa liczba f), zmniejszaniu ogniskowej (szerszy kąt) oraz przy zwiększaniu odległości od fotografowanego obiektu.'}, {'id': 'd327811c-15eb-4195-a38f-232ac3248e48', 'chapter_id': 1, 'text': 'Omów sposób zamiany obrazu analogowego na obraz cyfrowy.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '0eec07fc-9e01-49b6-acb1-9cba00e9a7fb', 'question_id': 'd327811c-15eb-4195-a38f-232ac3248e48', 'text': 'Poprzez skanowanie negatywu lub odbitki za pomocą skanera albo wykonanie zdjęcia reprodukcyjnego aparatem cyfrowym.', 'is_correct': 1, 'sort_order': 0}, {'id': '8569b33c-fcbf-4bbb-a6fa-dc600685d283', 'question_id': 'd327811c-15eb-4195-a38f-232ac3248e48', 'text': 'Poprzez włożenie negatywu do czytnika kart SD.', 'is_correct': 0, 'sort_order': 1}, {'id': '2a82b50f-18af-4cb3-b890-79ad1276395c', 'question_id': 'd327811c-15eb-4195-a38f-232ac3248e48', 'text': 'Poprzez naświetlanie negatywu światłem lasera w ciemni.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd17424aa-1a42-4335-af87-c9592bf66862', 'question_id': 'd327811c-15eb-4195-a38f-232ac3248e48', 'text': 'Nie da się zamienić obrazu analogowego na cyfrowy bez zniszczenia oryginału.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '79a4d2cc-29d7-433a-953d-340592ac1993', 'chapter_id': 1, 'text': 'Omów sposób zamiany obrazu analogowego na obraz cyfrowy.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Proces ten, zwany dygitalizacją, polega na próbkowaniu obrazu analogowego. Skaner lub matryca aparatu odczytuje natężenie światła i kolor w milionach punktów, zamieniając te informacje na wartości binarne (zera i jedynki), które tworzą plik cyfrowy.'}, {'id': '761bd80f-4b68-4fcf-9abe-d14b1e8423b9', 'chapter_id': 1, 'text': 'Czy aparat analogowy można użyć do fotografii cyfrowej i jak?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ec8f61d9-5c11-4e82-9646-99edfab6eb5a', 'question_id': '761bd80f-4b68-4fcf-9abe-d14b1e8423b9', 'text': 'Nie, jest to technologicznie niemożliwe.', 'is_correct': 0, 'sort_order': 0}, {'id': 'a46d5481-0c7b-4234-b9aa-94dab36a54f3', 'question_id': '761bd80f-4b68-4fcf-9abe-d14b1e8423b9', 'text': 'Tak, poprzez zastosowanie specjalnych przystawek cyfrowych (tzw. plecków) w aparatach średnio- i wielkoformatowych lub skanowanie filmów.', 'is_correct': 1, 'sort_order': 1}, {'id': '17e3fb53-38b6-4188-b73e-01a2b0ac48fb', 'question_id': '761bd80f-4b68-4fcf-9abe-d14b1e8423b9', 'text': 'Tak, wystarczy włożyć kartę pamięci zamiast filmu 35mm.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e1a9833e-79b4-4145-94ae-e86bedd1b2af', 'question_id': '761bd80f-4b68-4fcf-9abe-d14b1e8423b9', 'text': 'Tak, ale tylko jeśli aparat nie ma obiektywu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f35edfad-1384-46e7-8dbf-a3832abfbb19', 'chapter_id': 1, 'text': 'Czy aparat analogowy można użyć do fotografii cyfrowej i jak?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Aparat analogowy może służyć jako podstawa systemu cyfrowego. W profesjonalnych systemach wymienia się ściankę tylną na moduł z matrycą cyfrową. Pośrednią metodą jest naświetlenie tradycyjnego filmu i jego późniejsze zeskanowanie do formatu cyfrowego.'}, {'id': '71b13e73-4aec-4a4c-a29b-ce47a3bc9120', 'chapter_id': 1, 'text': 'Dlaczego stosujemy kąpiel przerywającą w procesie wywoływania - podać przykład takiej kąpieli.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'b5dfcc20-0233-4908-8d0c-668b58c732cc', 'question_id': '71b13e73-4aec-4a4c-a29b-ce47a3bc9120', 'text': 'Aby przyspieszyć działanie wywoływacza; przykładem jest gorąca woda.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e1126327-cf74-42a9-9bb6-fa02b6598d45', 'question_id': '71b13e73-4aec-4a4c-a29b-ce47a3bc9120', 'text': 'Aby natychmiast zatrzymać proces wywoływania i chronić utrwalacz przed zanieczyszczeniem; przykładem jest słaby roztwór kwasu octowego.', 'is_correct': 1, 'sort_order': 1}, {'id': '326f5964-4cf8-453f-a3ff-eef672fea67b', 'question_id': '71b13e73-4aec-4a4c-a29b-ce47a3bc9120', 'text': 'Aby nadać zdjęciom niebieski odcień; przykładem jest atrament.', 'is_correct': 0, 'sort_order': 2}, {'id': '3fd16655-17f0-4675-b248-896203312e71', 'question_id': '71b13e73-4aec-4a4c-a29b-ce47a3bc9120', 'text': 'Aby usunąć warstwę przeciwodblaskową; przykładem jest alkohol.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'cecb2167-c817-4af8-95dc-e5507c806c41', 'chapter_id': 1, 'text': 'Dlaczego stosujemy kąpiel przerywającą w procesie wywoływania - podać przykład takiej kąpieli.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Kąpiel przerywająca ma odczyn kwaśny, który neutralizuje zasadowy wywoływacz. Zatrzymuje to proces chemiczny w dokładnie określonym czasie i zapobiega przenoszeniu wywoływacza do utrwalacza, co przedłuża trwałość tego drugiego. Najczęściej stosuje się 2-3% roztwór kwasu octowego.'}, {'id': 'b4de73c1-76b5-4c9c-a438-db6cc093b16c', 'chapter_id': 1, 'text': 'Co to jest retusz chemiczny?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'd2bb49ae-94fa-4e71-8b88-c6bd7f66daa4', 'question_id': 'b4de73c1-76b5-4c9c-a438-db6cc093b16c', 'text': 'To zmiana kolorów zdjęcia za pomocą kredek akwarelowych.', 'is_correct': 0, 'sort_order': 0}, {'id': '88697955-8bfc-4530-881a-0e86cde7690e', 'question_id': 'b4de73c1-76b5-4c9c-a438-db6cc093b16c', 'text': 'To korygowanie gęstości negatywu lub pozytywu za pomocą kąpieli osłabiających lub wzmacniających.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b126c252-16ed-4d26-8b1f-e680e9982ae7', 'question_id': 'b4de73c1-76b5-4c9c-a438-db6cc093b16c', 'text': 'To czyszczenie obiektywu benzyną ekstrakcyjną.', 'is_correct': 0, 'sort_order': 2}, {'id': 'fd2ff460-1d99-4b7e-ae4e-9158332e044e', 'question_id': 'b4de73c1-76b5-4c9c-a438-db6cc093b16c', 'text': 'To proces wywoływania filmu w bardzo wysokiej temperaturze.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c40ccf3d-fb60-46a7-bdb3-9a88502a541b', 'chapter_id': 1, 'text': 'Co to jest retusz chemiczny?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Retusz chemiczny polega na miejscowym lub całościowym działaniu substancjami chemicznymi na emulsję. Osłabiacze (np. osłabiacz Farmera) służą do rozjaśniania zbyt ciemnych partii obrazu, natomiast wzmacniacze zwiększają gęstość zbyt słabych negatywów.'}, {'id': 'a6ae05b2-1d69-4687-8e5f-2bb8a1fa19bf', 'chapter_id': 1, 'text': 'Wymień podstawowe barwy tworzące obraz fotograficzny.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '9ddca1fb-0d0d-4bbf-aeec-ad215e4e2dda', 'question_id': 'a6ae05b2-1d69-4687-8e5f-2bb8a1fa19bf', 'text': 'Biały i czarny.', 'is_correct': 0, 'sort_order': 0}, {'id': '5368d488-aeef-40ba-b6fc-45a6a6fafc4f', 'question_id': 'a6ae05b2-1d69-4687-8e5f-2bb8a1fa19bf', 'text': 'Czerwony, zielony, niebieski (RGB) lub błękitny, purpurowy, żółty (CMY).', 'is_correct': 1, 'sort_order': 1}, {'id': '84b57542-5a6a-43fc-bece-5470101d54b1', 'question_id': 'a6ae05b2-1d69-4687-8e5f-2bb8a1fa19bf', 'text': 'Brązowy, szary i grafitowy.', 'is_correct': 0, 'sort_order': 2}, {'id': 'cbaf9ec2-fd2f-4cbc-854e-339740752392', 'question_id': 'a6ae05b2-1d69-4687-8e5f-2bb8a1fa19bf', 'text': 'Wyłącznie kolory pastelowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'b4f90b34-0f18-4958-9840-d2068649dd97', 'chapter_id': 1, 'text': 'Wymień podstawowe barwy tworzące obraz fotograficzny.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obraz fotograficzny opiera się na dwóch modelach barwnych: addytywnym (RGB - Red, Green, Blue), stosowanym przy rejestracji przez matryce i wyświetlaniu na ekranach, oraz subtraktywnym (CMY - Cyan, Magenta, Yellow), stosowanym w procesach chemicznych na papierze i w druku.'}, {'id': 'eda1dbad-d0eb-4f5a-b229-1b250d8f229b', 'chapter_id': 1, 'text': 'Wymień podstawowe barwy tworzące obraz fotograficzny i omów jeden z nich.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '95199f3e-98c8-427f-afc3-24050fe52944', 'question_id': 'eda1dbad-d0eb-4f5a-b229-1b250d8f229b', 'text': 'Czerwony, zielony, niebieski; błękitny (cyan) to barwa odejmująca kolor czerwony ze światła białego.', 'is_correct': 1, 'sort_order': 0}, {'id': '1d572d48-15cb-4cb9-a673-6eaab9617c47', 'question_id': 'eda1dbad-d0eb-4f5a-b229-1b250d8f229b', 'text': 'Tylko czarny; służy do wypełniania cieni.', 'is_correct': 0, 'sort_order': 1}, {'id': '9b521ed5-98e3-4e9d-9965-3ec828ea4c1e', 'question_id': 'eda1dbad-d0eb-4f5a-b229-1b250d8f229b', 'text': 'Złoty i srebrny; nadają zdjęciom połysk.', 'is_correct': 0, 'sort_order': 2}, {'id': '8fc6acf2-018d-4028-a187-c2e34ae70920', 'question_id': 'eda1dbad-d0eb-4f5a-b229-1b250d8f229b', 'text': 'Tęcza; składa się z siedmiu kolorów podstawowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a752f20d-ac98-42b0-90bd-98edafa5bf0f', 'chapter_id': 1, 'text': 'Wymień podstawowe barwy tworzące obraz fotograficzny i omów jeden z nich.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Podstawowe barwy to RGB w syntezie światła. Na przykład kolor niebieski (Blue) jest jedną z trzech składowych, która w połączeniu z zielenią i czerwienią daje światło białe. W fotografii barwnej warstwy emulsji są czułe właśnie na te trzy zakresy widma.'}, {'id': 'a29d3cbc-650e-4e7e-9107-364729c663fd', 'chapter_id': 1, 'text': 'Co to jest temperatura barwy światła?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '18d66614-d32f-4822-87f1-e826b67acd1b', 'question_id': 'a29d3cbc-650e-4e7e-9107-364729c663fd', 'text': 'To rzeczywista ciepłota żarówki mierzona w stopniach Celsjusza.', 'is_correct': 0, 'sort_order': 0}, {'id': '81582183-e2aa-434c-a441-a5ebf36bf92a', 'question_id': 'a29d3cbc-650e-4e7e-9107-364729c663fd', 'text': 'To obiektywna miara barwy światła wyrażona w Kelwinach (K); określa czy światło jest "ciepłe" czy "zimne".', 'is_correct': 1, 'sort_order': 1}, {'id': 'ed4ff188-eaa7-4f2a-81ac-869413b21a14', 'question_id': 'a29d3cbc-650e-4e7e-9107-364729c663fd', 'text': 'To prędkość z jaką światło nagrzewa papier fotograficzny.', 'is_correct': 0, 'sort_order': 2}, {'id': '16b00730-e976-4868-a478-513b942d75cc', 'question_id': 'a29d3cbc-650e-4e7e-9107-364729c663fd', 'text': 'To stopień natężenia światła błyskowego.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '66b50764-f3ce-43a6-918c-1e6f096bdd3c', 'chapter_id': 1, 'text': 'Co to jest temperatura barwy światła?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Temperatura barwowa określa spektrum promieniowania źródła światła. Światło świecy ma niską temperaturę (ok. 2000K - barwa ciepła/pomarańczowa), światło dzienne słoneczne to ok. 5500K, natomiast niebo w pochmurny dzień ma wysoką temperaturę barwową (powyżej 7000K - barwa zimna/niebieska).'}, {'id': 'd4117585-2c0e-401b-9a6f-4af8245723a3', 'chapter_id': 1, 'text': 'Omów znaczenie temperatury i czasu przy obróbce materiałów światłoczułych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '159652b2-90e4-44f6-b639-967d5411f787', 'question_id': 'd4117585-2c0e-401b-9a6f-4af8245723a3', 'text': 'Nie mają znaczenia, liczy się tylko rodzaj użytej chemii.', 'is_correct': 0, 'sort_order': 0}, {'id': 'aa19ab48-916e-439b-a1eb-481e747cf861', 'question_id': 'd4117585-2c0e-401b-9a6f-4af8245723a3', 'text': 'Są to kluczowe parametry determinujące stopień wywołania; ich zmiana wpływa na kontrast i gęstość obrazu.', 'is_correct': 1, 'sort_order': 1}, {'id': '1bac1a14-3cfb-48ba-b18b-359fb7db544d', 'question_id': 'd4117585-2c0e-401b-9a6f-4af8245723a3', 'text': 'Czas musi być zawsze taki sam, niezależnie od temperatury.', 'is_correct': 0, 'sort_order': 2}, {'id': '52adb561-755f-44b8-9563-165a8da9c373', 'question_id': 'd4117585-2c0e-401b-9a6f-4af8245723a3', 'text': 'Temperatura powinna być zawsze bliska temperaturze wrzenia wody.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '21de35a5-52dc-4f07-a21e-f666b672428e', 'chapter_id': 1, 'text': 'Omów znaczenie temperatury i czasu przy obróbce materiałów światłoczułych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Proces wywoływania jest reakcją chemiczną, której szybkość zależy od temperatury. Podwyższenie temperatury przyspiesza proces, co wymaga skrócenia czasu wywoływania. Przekroczenie zalecanych norm może prowadzić do nadmiernego zadymienia, wzrostu ziarna lub uszkodzenia emulsji.'}, {'id': 'f754ebd2-ca86-4296-bdd5-80660090b9c9', 'chapter_id': 1, 'text': 'Omów wpływ płukania po utrwaleniu negatywów i pozytywów.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '39a202f8-c05d-4ca8-b2d0-0077dee56f21', 'question_id': 'f754ebd2-ca86-4296-bdd5-80660090b9c9', 'text': 'Płukanie służy tylko do ochłodzenia materiału po gorącej kąpieli.', 'is_correct': 0, 'sort_order': 0}, {'id': 'eb25b20b-c40d-460c-9a7b-b1f304765cef', 'question_id': 'f754ebd2-ca86-4296-bdd5-80660090b9c9', 'text': 'Usuwa resztki utrwalacza i rozpuszczalne związki srebra, co zapewnia trwałość archiwalną zdjęcia.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f6d950b0-3087-496c-b0ee-d5e30185ce37', 'question_id': 'f754ebd2-ca86-4296-bdd5-80660090b9c9', 'text': 'Płukanie nie jest konieczne, jeśli zdjęcie wyschnie na słońcu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ad145979-3ffd-42fb-91ed-c625fb79727c', 'question_id': 'f754ebd2-ca86-4296-bdd5-80660090b9c9', 'text': 'Zbyt długie płukanie zamienia zdjęcie z powrotem w negatyw.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7442dd9d-20e4-48d1-95fa-a1daa45a7df9', 'chapter_id': 1, 'text': 'Omów wpływ płukania po utrwaleniu negatywów i pozytywów.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Niedokładne płukanie pozostawia w emulsji resztki tiosiarczanów (z utrwalacza), które z czasem reagują ze srebrem obrazu, powodując powstawanie brunatnych plam i blaknięcie zdjęcia. Prawidłowe płukanie w bieżącej wodzie jest gwarancją wieloletniej trwałości materiału.'}, {'id': '12b00453-455c-483c-9f50-8344e8a395aa', 'chapter_id': 1, 'text': 'Kiedy stosujemy wywoływacze pracujące kontrastowo?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '48b7d543-12ca-45ce-b70e-cea166ed839a', 'question_id': '12b00453-455c-483c-9f50-8344e8a395aa', 'text': 'Gdy fotografujemy w bardzo słoneczny dzień z dużymi cieniami.', 'is_correct': 0, 'sort_order': 0}, {'id': 'abd24681-ac5f-425d-bf49-80c983eeef58', 'question_id': '12b00453-455c-483c-9f50-8344e8a395aa', 'text': 'Przy reprodukcjach dokumentów, rysunków kreskowych lub gdy chcemy celowo zwiększyć różnice między czernią a bielą.', 'is_correct': 1, 'sort_order': 1}, {'id': 'afbff115-f5d3-4b8e-ad1c-08f23ec3fd3a', 'question_id': '12b00453-455c-483c-9f50-8344e8a395aa', 'text': 'Do miękkich portretów kobiecych.', 'is_correct': 0, 'sort_order': 2}, {'id': '60a9b998-619f-48be-8b53-9f0ee9c5f0fc', 'question_id': '12b00453-455c-483c-9f50-8344e8a395aa', 'text': 'Wyłącznie przy wywoływaniu starych, zniszczonych filmów.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '89ffdd3e-366f-4cc5-9ab6-f829aac28fb8', 'chapter_id': 1, 'text': 'Kiedy stosujemy wywoływacze pracujące kontrastowo?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wywoływacze kontrastowe (twarde) stosuje się wszędzie tam, gdzie zależy nam na eliminacji półtonów i uzyskaniu czystej bieli oraz głębokiej czerni. Są niezbędne w fotografii technicznej, litografii oraz przy kopiowaniu tekstów (reprodukcja kreskowa).'}, {'id': '0d71efef-413b-45b1-964b-077a8f55bb34', 'chapter_id': 1, 'text': 'Dlaczego wywoływany negatyw utrwalamy i jakie znamy rodzaje utrwalaczy?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'c0407da0-8900-4b76-9465-b58a5b36c31b', 'question_id': '0d71efef-413b-45b1-964b-077a8f55bb34', 'text': 'Aby obraz stał się kolorowy; utrwalacze dzielimy na suche i mokre.', 'is_correct': 0, 'sort_order': 0}, {'id': '9d716b4c-e357-4f46-bcf9-e902c2c3aeaf', 'question_id': '0d71efef-413b-45b1-964b-077a8f55bb34', 'text': 'Aby usunąć nienaświetlone halogenki srebra i uczynić obraz odpornym na działanie światła; wyróżniamy utrwalacze zwykłe i szybkie (kwaśne).', 'is_correct': 1, 'sort_order': 1}, {'id': '956e3124-bb4a-4fe7-b972-65367fc1ab4d', 'question_id': '0d71efef-413b-45b1-964b-077a8f55bb34', 'text': 'Aby zmiękczyć warstwę żelatyny; utrwalacze dzielimy na zapachowe i bezzapachowe.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a608bd52-8e41-431b-8eb0-95194c872c3a', 'question_id': '0d71efef-413b-45b1-964b-077a8f55bb34', 'text': 'Utrwalanie nie jest potrzebne w nowoczesnej fotografii.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4c4e3d64-5981-418f-bdd3-7613f9fc3db6', 'chapter_id': 1, 'text': 'Dlaczego wywoływany negatyw utrwalamy i jakie znamy rodzaje utrwalaczy?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Po wywołaniu obraz jest nadal światłoczuły. Utrwalacz rozpuszcza srebro, które nie zostało naświetlone, dzięki czemu zdjęcie nie czernieje po wyjęciu z koreksu. Najpopularniejszymi środkami są tiosiarczan sodu (utrwalacz zwykły) oraz tiosiarczan amonu (utrwalacz szybki).'}, {'id': '4614d20f-6f3b-4c01-b9a8-a7bb7c36b136', 'chapter_id': 1, 'text': 'Dlaczego należy stosować zasadę wywoływania negatywów w stałym czasie i stałej temperaturze i stałym składzie wywoływacza?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '7509cff5-1b1b-4565-b45b-4c71236c0687', 'question_id': '4614d20f-6f3b-4c01-b9a8-a7bb7c36b136', 'text': 'Ponieważ tylko to gwarantuje powtarzalność wyników i pozwala na precyzyjną kontrolę jakości obrazu.', 'is_correct': 1, 'sort_order': 0}, {'id': 'bf947c98-4c23-4514-8d0f-cba6b64d4f94', 'question_id': '4614d20f-6f3b-4c01-b9a8-a7bb7c36b136', 'text': 'Bo inaczej koreks może ulec pęknięciu.', 'is_correct': 0, 'sort_order': 1}, {'id': '17087417-d9cc-4d6d-984f-8df16f816275', 'question_id': '4614d20f-6f3b-4c01-b9a8-a7bb7c36b136', 'text': 'Jest to wymóg prawny nałożony na zakłady fotograficzne.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a18a869e-1dc6-43cc-9c95-377892496755', 'question_id': '4614d20f-6f3b-4c01-b9a8-a7bb7c36b136', 'text': 'Nie ma takiej potrzeby, można wywoływać "na oko".', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4bd08db8-9064-4dec-8191-39aec5815ccd', 'chapter_id': 1, 'text': 'Dlaczego należy stosować zasadę wywoływania negatywów w stałym czasie i stałej temperaturze i stałym składzie wywoływacza?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Standaryzacja procesu pozwala fotografowi przewidzieć efekt końcowy. Stałe parametry gwarantują, że każdy negatyw będzie miał taką samą gęstość i kontrast, co znacznie ułatwia późniejsze wykonywanie odbitek lub skanowanie. Każda zmiana (np. spadek temperatury) zmienia charakterystykę negatywu.'}, {'id': 'b8ad4515-6f24-46d3-8766-8f84d6949215', 'chapter_id': 1, 'text': 'Omów standardowy przebieg procesu C-41.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f4831c37-3e90-4499-9152-7e1eeb879905', 'question_id': 'b8ad4515-6f24-46d3-8766-8f84d6949215', 'text': 'Wywoływanie czarno-białe, płukanie, suszenie.', 'is_correct': 0, 'sort_order': 0}, {'id': '951d401b-d3fa-4f56-a020-980abb941d66', 'question_id': 'b8ad4515-6f24-46d3-8766-8f84d6949215', 'text': 'Wywoływanie barwne, wybielanie, utrwalanie, płukanie, stabilizacja.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f7e3d69d-bcd0-461e-9602-1b2ad8d49c4c', 'question_id': 'b8ad4515-6f24-46d3-8766-8f84d6949215', 'text': 'Naświetlanie papieru, wywoływanie w kawie, prasowanie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'dd1696b7-4868-4029-9b30-6c03226ff9af', 'question_id': 'b8ad4515-6f24-46d3-8766-8f84d6949215', 'text': 'Proces ten polega na cyfrowym wydruku zdjęcia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '88201e15-4245-4ed5-984c-ce685f706581', 'chapter_id': 1, 'text': 'Omów standardowy przebieg procesu C-41.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'C-41 to proces negatywowy barwny. Kluczowym etapem jest wywoływanie barwne (37,8°C), gdzie powstaje obraz srebrowy i barwnikowy. Następnie wybielacz zamienia srebro metaliczne z powrotem w sole, które utrwalacz usuwa, pozostawiając w emulsji jedynie barwniki tworzące obraz.'}, {'id': 'b969197d-3fd7-4b2e-8f52-a74e26248e11', 'chapter_id': 1, 'text': 'Omów zasady fotografowania architektury.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'c645d6e8-bca8-4da4-8c5a-56a53b2e8add', 'question_id': 'b969197d-3fd7-4b2e-8f52-a74e26248e11', 'text': 'Należy zawsze używać lampy błyskowej wbudowanej w aparat.', 'is_correct': 0, 'sort_order': 0}, {'id': 'db5cb75e-fd4b-40e0-ae4a-f6787c745de8', 'question_id': 'b969197d-3fd7-4b2e-8f52-a74e26248e11', 'text': 'Zachowanie pionowych linii (unikanie "walących się" budynków), dbałość o perspektywę, wykorzystanie bocznego światła dla podkreślenia bryły.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b04e753d-0ebe-4993-baee-02e5ab2ab2e8', 'question_id': 'b969197d-3fd7-4b2e-8f52-a74e26248e11', 'text': 'Fotografowanie wyłącznie z bardzo bliska szerokim kątem skierowanym w górę.', 'is_correct': 0, 'sort_order': 2}, {'id': '20685857-0461-4686-9960-217fc4ab665c', 'question_id': 'b969197d-3fd7-4b2e-8f52-a74e26248e11', 'text': 'Zdjęcia architektury powinny być zawsze robione z jadącego samochodu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0f60f832-1f27-49dd-8b5d-928fddaade04', 'chapter_id': 1, 'text': 'Omów zasady fotografowania architektury.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W fotografii architektury kluczowe jest unikanie dystorsji i zbieżności linii pionowych (stosuje się statyw, poziomicę lub obiektywy typu PC/Shift). Ważne jest też oświetlenie – słońce świecące pod kątem najlepiej wydobywa detale elewacji i fakturę materiałów budowlanych.'}, {'id': '6b13d54b-ddf6-4055-8721-bba79aa01dc5', 'chapter_id': 1, 'text': 'Jakie wymagania powinno spełniać przepisowe zdjęcie do paszportu?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5e83474f-035b-4898-967e-e169e1ddffbd', 'question_id': '6b13d54b-ddf6-4055-8721-bba79aa01dc5', 'text': 'Dowolne zdjęcie z wakacji, na którym widać twarz.', 'is_correct': 0, 'sort_order': 0}, {'id': '5974a5a7-5aa1-4528-9453-7bdf8d175eb3', 'question_id': '6b13d54b-ddf6-4055-8721-bba79aa01dc5', 'text': 'Twarz biometryczna: na wprost, otwate oczy, zamknięte usta, naturalny wyraz twarzy, jasne tło, brak nakryć głowy i okularów przeciwsłonecznych.', 'is_correct': 1, 'sort_order': 1}, {'id': '52082ac6-6e7c-448f-a680-37443c42e983', 'question_id': '6b13d54b-ddf6-4055-8721-bba79aa01dc5', 'text': 'Zdjęcie profilowe z artystycznym cieniem.', 'is_correct': 0, 'sort_order': 2}, {'id': '331a02fb-1f2b-462d-a201-b483299a0f9d', 'question_id': '6b13d54b-ddf6-4055-8721-bba79aa01dc5', 'text': 'Fotografia całej sylwetki na tle przyrody.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2678d89f-9eee-4a90-a214-1cd473226651', 'chapter_id': 1, 'text': 'Jakie wymagania powinno spełniać przepisowe zdjęcie do paszportu?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Zdjęcie paszportowe musi być biometryczne, co umożliwia automatyczne rozpoznawanie twarzy. Oznacza to, że owal twarzy musi być w pełni widoczny, oczy muszą znajdować się na określonej wysokości, a oświetlenie musi być równomierne, bez głębokich cieni i refleksów w okularach.'}, {'id': '746a80ee-0e37-4eb3-a8f9-844fd7aefc63', 'chapter_id': 1, 'text': 'Czym różni się rozdzielczość obrazu analogowego od cyfrowego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'df19b2c5-d3bd-4c8a-a95a-aa599093ff3f', 'question_id': '746a80ee-0e37-4eb3-a8f9-844fd7aefc63', 'text': 'Nie różnią się niczym.', 'is_correct': 0, 'sort_order': 0}, {'id': '5ba8d781-14bc-4129-b2d8-e75a1a91b04e', 'question_id': '746a80ee-0e37-4eb3-a8f9-844fd7aefc63', 'text': 'Analogowa zależy od wielkości ziarna srebra i jakości optyki; cyfrowa od liczby pikseli na matrycy.', 'is_correct': 1, 'sort_order': 1}, {'id': '0ba85e76-c4ac-4919-a496-088a697911d5', 'question_id': '746a80ee-0e37-4eb3-a8f9-844fd7aefc63', 'text': 'Rozdzielczość cyfrowa jest zawsze gorsza od analogowej.', 'is_correct': 0, 'sort_order': 2}, {'id': '9e87ed88-61f4-4414-81d6-ed4adc5b6f16', 'question_id': '746a80ee-0e37-4eb3-a8f9-844fd7aefc63', 'text': 'Rozdzielczość analogową mierzy się w kilogramach, a cyfrową w litrach.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'df38a618-b63c-4654-a6fa-6ecc19aeb276', 'chapter_id': 1, 'text': 'Czym różni się rozdzielczość obrazu analogowego od cyfrowego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W fotografii analogowej rozdzielczość jest determinowana przez strukturę molekularną emulsji (ziarno) oraz zdolność rozdzielczą obiektywu. W fotografii cyfrowej limituje ją siatka fotodiod na matrycy (liczba megapikseli) oraz gęstość ich rozmieszczenia (PPI/DPI).'}, {'id': '2cde9eaa-2e59-49aa-bbc7-b279ece03da6', 'chapter_id': 1, 'text': 'Omów oświetlenie w fotografii portretowej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '99f6e2e9-d665-4347-9c40-2bca84abbb70', 'question_id': '2cde9eaa-2e59-49aa-bbc7-b279ece03da6', 'text': 'Najlepiej używać tylko ostrego słońca w samo południe.', 'is_correct': 0, 'sort_order': 0}, {'id': '1f5a1d5d-6a44-4380-80f4-eeada9d03a37', 'question_id': '2cde9eaa-2e59-49aa-bbc7-b279ece03da6', 'text': 'Stosuje się podział na światło główne (rysujące), dopełniające (rozjaśniające cienie), konturowe i tła.', 'is_correct': 1, 'sort_order': 1}, {'id': '876f487d-b270-4998-86ad-62e0b11ebbb9', 'question_id': '2cde9eaa-2e59-49aa-bbc7-b279ece03da6', 'text': 'Portret oświetla się zawsze od tyłu, by twarz była czarna.', 'is_correct': 0, 'sort_order': 2}, {'id': '664d9add-dd13-429c-b600-2fb7885901e1', 'question_id': '2cde9eaa-2e59-49aa-bbc7-b279ece03da6', 'text': 'W portrecie nie stosuje się lamp, tylko światło świec.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '56d4ca4b-4eb5-43a9-8a66-9f4922f165c7', 'chapter_id': 1, 'text': 'Omów oświetlenie w fotografii portretowej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Oświetlenie portretowe ma na celu wymodelowanie twarzy. Światło rysujące nadaje charakter i tworzy światłocień, dopełniające (często z softboxa lub blendy) łagodzi kontrasty, a światło konturowe oddziela postać od tła, nadając zdjęciu głębię przestrzenną.'}, {'id': '2e9cdf94-4e57-4877-91a9-0920ecc01d0c', 'chapter_id': 1, 'text': 'Omów podstawowe sposoby powstawania reprodukcji.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '112b045e-535c-40c6-942b-876039fdd3b2', 'question_id': '2e9cdf94-4e57-4877-91a9-0920ecc01d0c', 'text': 'Skanowanie, fotografowanie na stole reprodukcyjnym lub kopiowanie stykowe.', 'is_correct': 1, 'sort_order': 0}, {'id': '1dfec449-7e47-46ac-9494-4ea66077d6b8', 'question_id': '2e9cdf94-4e57-4877-91a9-0920ecc01d0c', 'text': 'Kserowanie zdjęcia na zwykłym papierze i kolorowanie go.', 'is_correct': 0, 'sort_order': 1}, {'id': '81f63c12-a3e2-4855-a8d4-59d2325fa703', 'question_id': '2e9cdf94-4e57-4877-91a9-0920ecc01d0c', 'text': 'Przebijanie konturów igłą na nową kartkę.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e97c0b5a-6219-4ac3-96b9-cdabbb145387', 'question_id': '2e9cdf94-4e57-4877-91a9-0920ecc01d0c', 'text': 'Wyłącznie poprzez ręczne przerysowywanie obrazu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0bd643e4-d1f3-4eab-9aa2-a53acd4973d3', 'chapter_id': 1, 'text': 'Omów podstawowe sposoby powstawania reprodukcji.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Reprodukcja to wierne odtworzenie oryginału. Metoda fotograficzna polega na umieszczeniu obiektu płaskiego równolegle do płaszczyzny matrycy/filmu i oświetleniu go pod kątem 45 stopni światłem spolaryzowanym, aby wyeliminować odblaski. Skanowanie jest metodą cyfrową o najwyższej precyzji geometrycznej.'}, {'id': '7d330f1d-90ec-4c4f-9828-1e171a10186f', 'chapter_id': 1, 'text': 'Porównaj reprodukcję kreskową z reprodukcją półtonową.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'd56ac07b-09d5-49e1-8934-d887cd350a54', 'question_id': '7d330f1d-90ec-4c4f-9828-1e171a10186f', 'text': 'Kreskowa to tylko czarne linie na białym tle; półtonowa oddaje przejścia tonalne i szarości.', 'is_correct': 1, 'sort_order': 0}, {'id': '97cbc306-abf0-4469-8e1d-77260ab501d0', 'question_id': '7d330f1d-90ec-4c4f-9828-1e171a10186f', 'text': 'Kreskowa służy do zdjęć krajobrazu, a półtonowa do architektury.', 'is_correct': 0, 'sort_order': 1}, {'id': '2287507b-44e7-4cf7-8b25-20c195c26667', 'question_id': '7d330f1d-90ec-4c4f-9828-1e171a10186f', 'text': 'Nie ma między nimi żadnej różnicy.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b133fdd8-000e-4909-9a57-7cc803020d96', 'question_id': '7d330f1d-90ec-4c4f-9828-1e171a10186f', 'text': 'Reprodukcja kreskowa jest zawsze kolorowa, a półtonowa czarno-biała.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '8055b24e-c24d-4b80-be9b-849b7d15067c', 'chapter_id': 1, 'text': 'Porównaj reprodukcję kreskową z reprodukcją półtonową.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Reprodukcja kreskowa (np. tekstu, rysunku technicznego) operuje tylko dwiema wartościami: czernią i bielą. Reprodukcja półtonowa (np. zdjęcia, obrazu olejnego) wymaga oddania całej skali szarości lub bogactwa barw, co w poligrafii uzyskuje się poprzez raster.'}, {'id': 'bb547f42-06e9-421f-8b09-fa0d026e9ee4', 'chapter_id': 1, 'text': 'Co to jest odległość hiperfokalna?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'a515e271-5fa3-4746-9c77-69ab1c648a28', 'question_id': 'bb547f42-06e9-421f-8b09-fa0d026e9ee4', 'text': 'Odległość, poniżej której obiektyw nie może ustawić ostrości.', 'is_correct': 0, 'sort_order': 0}, {'id': '8fc9555d-85f3-4a14-a069-02c12ae92a3e', 'question_id': 'bb547f42-06e9-421f-8b09-fa0d026e9ee4', 'text': 'Odległość, po ustawieniu której ostrość rozciąga się od połowy tej odległości aż do nieskończoności.', 'is_correct': 1, 'sort_order': 1}, {'id': '6199f91d-2e4d-40de-be9c-fb5e9dd6e4b2', 'question_id': 'bb547f42-06e9-421f-8b09-fa0d026e9ee4', 'text': 'Największa odległość, na jaką sięga błysk lampy.', 'is_correct': 0, 'sort_order': 2}, {'id': '313348d7-9e06-44db-b817-9797067bd8dd', 'question_id': 'bb547f42-06e9-421f-8b09-fa0d026e9ee4', 'text': 'Długość obiektywu mierzona w milimetrach.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '6d767226-f0d1-42c4-af77-3967bb5a2ffc', 'chapter_id': 1, 'text': 'Co to jest odległość hiperfokalna?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Ustawienie obiektywu na odległość hiperfokalną pozwala uzyskać maksymalną możliwą głębię ostrości dla danej przysłony. Jest to technika często stosowana w fotografii krajobrazowej i reportażowej, by mieć pewność, że wszystko od planu bliskiego po horyzont będzie akceptowalnie ostre.'}, {'id': 'd3e7cbdf-1c21-4dab-9ea6-47c422ea83f1', 'chapter_id': 1, 'text': 'Jaka powinna być ogniskowa w aparacie o formacie 6x9, aby nie było przerysowania perspektywicznego (portret)?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '006505c4-4ce1-4492-a09a-3746326fe099', 'question_id': 'd3e7cbdf-1c21-4dab-9ea6-47c422ea83f1', 'text': '50 mm.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c77fedcc-e8eb-40f4-aa13-02e1727596fd', 'question_id': 'd3e7cbdf-1c21-4dab-9ea6-47c422ea83f1', 'text': 'Około 150-180 mm.', 'is_correct': 1, 'sort_order': 1}, {'id': '914bf952-c338-4a01-af60-a61289656fb3', 'question_id': 'd3e7cbdf-1c21-4dab-9ea6-47c422ea83f1', 'text': '28 mm.', 'is_correct': 0, 'sort_order': 2}, {'id': '9feb424d-147e-4996-aeb2-08e7f48e6a57', 'question_id': 'd3e7cbdf-1c21-4dab-9ea6-47c422ea83f1', 'text': 'Taka sama jak szerokość filmu, czyli 60 mm.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'b6e1f402-e590-46fb-8c74-fe467aa71828', 'chapter_id': 1, 'text': 'Jaka powinna być ogniskowa w aparacie o formacie 6x9, aby nie było przerysowania perspektywicznego (portret)?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W formacie 6x9 standardowym obiektywem jest ok. 100-105 mm. Do portretu, aby uniknąć zniekształceń twarzy (np. nienaturalnie dużego nosa) wynikających ze zbyt bliskiego podchodzenia, stosuje się obiektywy o ogniskowej ok. 1,5-2 razy dłuższej niż standard, czyli ok. 150-180 mm.'}, {'id': 'c9e997db-a8ed-4397-acad-7051bceee1b5', 'chapter_id': 1, 'text': 'Kiedy i dlaczego należy stosować wywoływacz drobnoziarnisty?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ebe275e9-5243-4342-a000-091aaa05e1c9', 'question_id': 'c9e997db-a8ed-4397-acad-7051bceee1b5', 'text': 'Gdy chcemy uzyskać bardzo duży kontrast.', 'is_correct': 0, 'sort_order': 0}, {'id': '304c1614-9686-460a-ab0c-f932186e9d56', 'question_id': 'c9e997db-a8ed-4397-acad-7051bceee1b5', 'text': 'Gdy z małego negatywu (np. 35mm) chcemy wykonać duże powiększenia przy zachowaniu maksymalnej ilości detali i minimalnym ziarnie.', 'is_correct': 1, 'sort_order': 1}, {'id': 'c5062c76-500f-455d-9c7e-8f2dd49a6ecd', 'question_id': 'c9e997db-a8ed-4397-acad-7051bceee1b5', 'text': 'Tylko przy wywoływaniu zdjęć robionych w nocy.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c9d6918c-1c49-4d70-9ba8-4167abbb5372', 'question_id': 'c9e997db-a8ed-4397-acad-7051bceee1b5', 'text': 'Nigdy, wywoływacze drobnoziarniste psują obraz.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1d57f6ea-34d2-4459-8ce4-145c1557c90c', 'chapter_id': 1, 'text': 'Kiedy i dlaczego należy stosować wywoływacz drobnoziarnisty?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wywoływacze drobnoziarniste zawierają substancje (np. siarczyn sodu w dużym stężeniu), które częściowo rozpuszczają krawędzie kryształków srebra podczas wywoływania. Dzięki temu struktura obrazu jest bardziej jednolita, co pozwala na robienie wielkoformatowych odbitek bez efektu "piasku" na zdjęciu.'}, {'id': '37b8c280-725c-4400-aa37-ceaef1fec04b', 'chapter_id': 1, 'text': 'Od czego zależy perspektywa obrazu fotograficznego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'cd71f885-178a-463b-bf92-0b5cf6a5588b', 'question_id': '37b8c280-725c-4400-aa37-ceaef1fec04b', 'text': 'Wyłącznie od ceny obiektywu.', 'is_correct': 0, 'sort_order': 0}, {'id': '83eec7d5-16d6-4c8b-a7d5-b4ab80068851', 'question_id': '37b8c280-725c-4400-aa37-ceaef1fec04b', 'text': 'Od punktu widzenia (odległości aparatu od fotografowanego obiektu).', 'is_correct': 1, 'sort_order': 1}, {'id': 'bcdaa840-42fb-44b8-884c-b731d31f3c5f', 'question_id': '37b8c280-725c-4400-aa37-ceaef1fec04b', 'text': 'Tylko od czasu naświetlania.', 'is_correct': 0, 'sort_order': 2}, {'id': 'aecd9ddf-93ec-4f94-9226-6c77614cbec1', 'question_id': '37b8c280-725c-4400-aa37-ceaef1fec04b', 'text': 'Perspektywa jest stała i nie można jej zmienić.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1df128d7-a715-47d3-bd1c-44e3e2113aa1', 'chapter_id': 1, 'text': 'Od czego zależy perspektywa obrazu fotograficznego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wbrew powszechnemu przekonaniu, to nie ogniskowa obiektywu zmienia perspektywę, ale zmiana pozycji fotografa. Zbliżanie się lub oddalanie od obiektu zmienia wzajemne relacje wielkości między planem pierwszym a tłem. Obiektyw szerokokątny po prostu wymusza podejście bliżej, co potęguje wrażenie głębi.'}, {'id': '7dc71132-b1ea-4f71-9e4a-ef898bad17aa', 'chapter_id': 1, 'text': 'Co to są barwy podstawowe i barwy dopełniające?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '99340171-12c7-4ab5-9d7a-db15502dbac1', 'question_id': '7dc71132-b1ea-4f71-9e4a-ef898bad17aa', 'text': 'Podstawowe to RGB; dopełniające to te, które po zmieszaniu z podstawowymi w odpowiedniej proporcji dają barwę białą lub czarną (np. dla Red to Cyan).', 'is_correct': 1, 'sort_order': 0}, {'id': '38a16932-78d4-4df5-af06-4ed8ff2d2e76', 'question_id': '7dc71132-b1ea-4f71-9e4a-ef898bad17aa', 'text': 'Podstawowe to tylko biały i czarny; dopełniające to wszystkie inne.', 'is_correct': 0, 'sort_order': 1}, {'id': '681e3ef4-ef0a-4ef8-8f46-e05f1bd5978b', 'question_id': '7dc71132-b1ea-4f71-9e4a-ef898bad17aa', 'text': 'To nazwy handlowe farb drukarskich.', 'is_correct': 0, 'sort_order': 2}, {'id': '6c57db16-77b5-4ee2-9dd9-896cc7d701eb', 'question_id': '7dc71132-b1ea-4f71-9e4a-ef898bad17aa', 'text': 'Barwy podstawowe to te, które widzimy w dzień, a dopełniające to te z nocy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '6861a88a-6ce4-4d76-8c06-66b989dd3be8', 'chapter_id': 1, 'text': 'Co to są barwy podstawowe i barwy dopełniające?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Barwy podstawowe (addytywne: R, G, B) to te, z których można złożyć każde inne światło. Barwa dopełniająca to taka, która leży po przeciwnej stronie koła barw. Dla czerwonego jest to błękitny (cyan), dla zielonego purpurowy (magenta), a dla niebieskiego żółty (yellow).'}, {'id': '76b850c8-9ed0-46d8-80bb-0d97152333d6', 'chapter_id': 1, 'text': 'Od czego zależy właściwe naświetlenie materiału negatywowego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '3b9bb39d-9788-4ca8-8677-df4ed6e5d1b0', 'question_id': '76b850c8-9ed0-46d8-80bb-0d97152333d6', 'text': 'Od czułości filmu (ISO), natężenia światła, czasu naświetlania i wartości przysłony.', 'is_correct': 1, 'sort_order': 0}, {'id': '22d5b955-70b6-442d-b9ca-91f05c5aeec9', 'question_id': '76b850c8-9ed0-46d8-80bb-0d97152333d6', 'text': 'Tylko od tego, jak długo trzymamy przycisk migawki.', 'is_correct': 0, 'sort_order': 1}, {'id': '7ccc2d31-3317-4582-a924-de0e2dc0c524', 'question_id': '76b850c8-9ed0-46d8-80bb-0d97152333d6', 'text': 'Od marki aparatu i wielkości obiektywu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd73bfd35-affa-43f3-ba00-12078135288c', 'question_id': '76b850c8-9ed0-46d8-80bb-0d97152333d6', 'text': 'Właściwe naświetlenie zależy wyłącznie od późniejszego wywoływania.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '83dca624-27e9-4c6a-a0aa-eb54cd723228', 'chapter_id': 1, 'text': 'Od czego zależy właściwe naświetlenie materiału negatywowego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Prawidłowe naświetlenie to dostarczenie do emulsji takiej ilości energii świetlnej, aby po wywołaniu uzyskać czytelne szczegóły zarówno w cieniach, jak i w światłach. Odpowiada za to tzw. trójkąt ekspozycji: czas naświetlania, przysłona oraz czułość materiału.'}, {'id': '045b7fe1-8e59-4411-a209-3140f77e8049', 'chapter_id': 1, 'text': 'Omów sposoby suszenia papierów fotograficznych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '8a76cf33-5c0b-402c-8e04-01e1b2f257fd', 'question_id': '045b7fe1-8e59-4411-a209-3140f77e8049', 'text': 'Przez prasowanie gorącym żelazkiem domowym bezpośrednio po wyjęciu z wody.', 'is_correct': 0, 'sort_order': 0}, {'id': '21e3da46-6f8a-4119-b876-00442201ac63', 'question_id': '045b7fe1-8e59-4411-a209-3140f77e8049', 'text': 'Na powietrzu (emulsją do góry), w suszarkach bębnowych lub na nabłyszczarkach (dla papierów barytowych).', 'is_correct': 1, 'sort_order': 1}, {'id': '25fe0e2b-8666-4f64-b3e4-938f29e7ea2f', 'question_id': '045b7fe1-8e59-4411-a209-3140f77e8049', 'text': 'Wyłącznie za pomocą silnego strumienia gorącego powietrza z suszarki do włosów.', 'is_correct': 0, 'sort_order': 2}, {'id': '1e83ec49-eb5d-46d1-b27f-3bf0cd17fe70', 'question_id': '045b7fe1-8e59-4411-a209-3140f77e8049', 'text': 'Przez zanurzenie w czystym alkoholu, który błyskawicznie odparowuje.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd2bd0935-0026-4396-be6d-a70e93bf5bb7', 'chapter_id': 1, 'text': 'Omów sposoby suszenia papierów fotograficznych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Papiery fotograficzne można suszyć metodą naturalną, rozkładając je na siatkach lub czystym podłożu. Papiery na podłożu plastikowym (RC) schną szybko na powietrzu, natomiast papiery barytowe wymagają suszenia w suszarkach bębnowych lub na nabłyszczarkach, aby uniknąć zwijania się.'}, {'id': '715b8c5c-b97d-47dd-90f8-1031b67a411e', 'chapter_id': 1, 'text': 'Jakie znasz programy komputerowe do obróbki fotografii i omów ich zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '453e0040-f05e-49a0-87fb-a9ecbf28cd1c', 'question_id': '715b8c5c-b97d-47dd-90f8-1031b67a411e', 'text': 'Microsoft Word i Excel do tworzenia tabel kolorystycznych.', 'is_correct': 0, 'sort_order': 0}, {'id': '92035dcc-cd57-4bb5-8a58-fc736cdba792', 'question_id': '715b8c5c-b97d-47dd-90f8-1031b67a411e', 'text': 'Adobe Photoshop (edycja rastrowa), Adobe Lightroom (wywoływanie RAW) oraz Capture One.', 'is_correct': 1, 'sort_order': 1}, {'id': 'e8aec5ff-46a5-4015-9ce0-be1174d5df81', 'question_id': '715b8c5c-b97d-47dd-90f8-1031b67a411e', 'text': 'Wyłącznie Paint i Notatnik do edycji kodów kolorów.', 'is_correct': 0, 'sort_order': 2}, {'id': '077c07ca-f506-4e95-b26c-45cdef484a4a', 'question_id': '715b8c5c-b97d-47dd-90f8-1031b67a411e', 'text': 'Programy antywirusowe, które czyszczą szumy na zdjęciach.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'db001a46-a124-4676-8a78-0ccca3107dad', 'chapter_id': 1, 'text': 'Jakie znasz programy komputerowe do obróbki fotografii i omów ich zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Do profesjonalnej obróbki stosuje się Adobe Lightroom lub Capture One, które służą do selekcji i bezstratnej edycji plików RAW. Adobe Photoshop jest używany do zaawansowanego retuszu, fotomontażu i pracy na warstwach.'}, {'id': '61972022-3c2d-4441-b57d-09fac09e57ff', 'chapter_id': 1, 'text': 'Omów zasady fotografowania wyrobów ze szkła i metalu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'e81049f7-55e3-49f6-816d-1450d0f637eb', 'question_id': '61972022-3c2d-4441-b57d-09fac09e57ff', 'text': 'Należy używać bezpośredniego błysku z lampy na aparacie, aby uzyskać mocne odbicia.', 'is_correct': 0, 'sort_order': 0}, {'id': '495a1278-c891-4fd8-a6a0-bd30a314d321', 'question_id': '61972022-3c2d-4441-b57d-09fac09e57ff', 'text': 'Kluczowe jest operowanie odbiciami w dużych płaszczyznach (softboxy, ekrany), stosowanie oświetlenia konturowego i dbałość o czystość powierzchni.', 'is_correct': 1, 'sort_order': 1}, {'id': 'dedf8e7e-21fd-49df-bc54-a155b19d0ec1', 'question_id': '61972022-3c2d-4441-b57d-09fac09e57ff', 'text': 'Szkło i metal fotografuje się zawsze w pełnym słońcu bez żadnych ekranów.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c8a89f3d-9b8b-42f0-8c89-5c0b6913044d', 'question_id': '61972022-3c2d-4441-b57d-09fac09e57ff', 'text': 'Takie przedmioty należy przed zdjęciem pomalować matową farbą, aby nie odbijały światła.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7bb7ee7c-5d2b-4dbe-ae28-886ccee98e69', 'chapter_id': 1, 'text': 'Omów zasady fotografowania wyrobów ze szkła i metalu.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Przy fotografowaniu szkła najważniejsze jest oświetlenie tła lub stosowanie dużych płaszczyzn świecących, które tworzą estetyczne bliki na krawędziach. W przypadku metalu fotografujemy nie sam przedmiot, lecz to, co się w nim odbija, dlatego niezbędne są białe i czarne ekrany modelujące kształt obiektu.'}, {'id': 'a31ea958-da4b-4885-b72e-a0d0ab41c3e2', 'chapter_id': 1, 'text': 'Co to jest kontrastowość materiału fotograficznego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '62ac9da1-2035-4b51-8a73-c8e5ed6d88dc', 'question_id': 'a31ea958-da4b-4885-b72e-a0d0ab41c3e2', 'text': 'Zdolność materiału do oddania różnic w jasności (gęstości optycznej) fotografowanego obiektu.', 'is_correct': 1, 'sort_order': 0}, {'id': 'a576ffc5-23b2-43a8-9973-011c83c08bae', 'question_id': 'a31ea958-da4b-4885-b72e-a0d0ab41c3e2', 'text': 'Grubość podłoża, na którym znajduje się emulsja światłoczuła.', 'is_correct': 0, 'sort_order': 1}, {'id': '821119b6-7b5e-4daa-ace1-8add2d3c94cb', 'question_id': 'a31ea958-da4b-4885-b72e-a0d0ab41c3e2', 'text': 'Czas, po którym film ulega przeterminowaniu.', 'is_correct': 0, 'sort_order': 2}, {'id': '43eee6ec-c02a-447e-bdd7-dec0c0026dff', 'question_id': 'a31ea958-da4b-4885-b72e-a0d0ab41c3e2', 'text': 'Ilość barwników w negatywie kolorowym.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1b7d5758-bbdb-48fc-a724-d83168d664a0', 'chapter_id': 1, 'text': 'Co to jest kontrastowość materiału fotograficznego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Kontrastowość to cecha materiału określająca nachylenie krzywej charakterystycznej. Materiały twarde (wysokokontrastowe) oddają subtelne różnice jasności jako duże różnice gęstości, natomiast materiały miękkie spłaszczają te różnice.'}, {'id': '47ead2f4-4672-4a4d-b7d1-b5715acdb46d', 'chapter_id': 1, 'text': 'Co wiesz na temat kompozycji obrazu fotograficznego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '48c33934-b482-4a3a-a8e0-655714cf00cb', 'question_id': '47ead2f4-4672-4a4d-b7d1-b5715acdb46d', 'text': 'Polega na umieszczaniu wszystkich ważnych elementów dokładnie w geometrycznym środku kadru.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c19ff53a-ff74-4889-8f45-8310c4ef0c53', 'question_id': '47ead2f4-4672-4a4d-b7d1-b5715acdb46d', 'text': 'To świadome rozmieszczenie elementów w kadrze (np. zasada trójpodziału, złoty podział, linie prowadzące), by nadać zdjęciu ład i przekaz.', 'is_correct': 1, 'sort_order': 1}, {'id': 'd42bbeb3-ccdd-4712-9176-1997ff20ac58', 'question_id': '47ead2f4-4672-4a4d-b7d1-b5715acdb46d', 'text': 'Kompozycja to proces wywoływania filmu w różnych temperaturach.', 'is_correct': 0, 'sort_order': 2}, {'id': '6653eeb5-6142-465b-93dc-a30b1a7733ec', 'question_id': '47ead2f4-4672-4a4d-b7d1-b5715acdb46d', 'text': 'To technika polegająca na robieniu jak największej liczby zdjęć w krótkim czasie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1a118f7e-d104-40df-a5e3-b4bbb32014b0', 'chapter_id': 1, 'text': 'Co wiesz na temat kompozycji obrazu fotograficznego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Kompozycja służy prowadzeniu oka widza przez obraz. Najpopularniejszą metodą jest zasada trójpodziału, polegająca na umieszczaniu kluczowych motywów w punktach przecięcia linii dzielących kadr.'}, {'id': 'b77e1b33-cc92-484a-99a4-5886209fdc03', 'chapter_id': 1, 'text': 'Sposoby na „czerwone oczy” w fotografii barwnej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '97374827-5ecb-4845-87e1-b619c2bcb179', 'question_id': 'b77e1b33-cc92-484a-99a4-5886209fdc03', 'text': 'Zawsze używamy czarno-białego filmu, by uniknąć koloru czerwonego.', 'is_correct': 0, 'sort_order': 0}, {'id': '18209a91-700f-4213-b782-e1851ec336d0', 'question_id': 'b77e1b33-cc92-484a-99a4-5886209fdc03', 'text': 'Odsunięcie lampy od osi obiektywu, zwiększenie oświetlenia w pomieszczeniu lub użycie przedbłysków redukujących.', 'is_correct': 1, 'sort_order': 1}, {'id': '87f7870b-3497-42d4-a7e1-42e00fb3c967', 'question_id': 'b77e1b33-cc92-484a-99a4-5886209fdc03', 'text': 'Kazanie modelowi zamknąć oczy podczas błysku.', 'is_correct': 0, 'sort_order': 2}, {'id': '0cc83f4d-174e-4e75-b64a-be837c52bc4c', 'question_id': 'b77e1b33-cc92-484a-99a4-5886209fdc03', 'text': 'Zaklejenie lampy błyskowej czerwoną taśmą.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '072c35d2-0068-406c-bd1d-bfd7900d0930', 'chapter_id': 1, 'text': 'Sposoby na „czerwone oczy” w fotografii barwnej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Efekt powstaje przez odbicie światła lampy od unaczynionego dna oka, gdy źrenica jest szeroko otwarta. Można go uniknąć, stosując światło odbite (np. od sufitu) lub funkcję redukcji czerwonych oczu w aparacie, która powoduje zwężenie źrenic modela przed głównym błyskiem.'}, {'id': '8f60e4b0-c024-4bca-987e-805b5a9cd117', 'chapter_id': 1, 'text': 'Co wiesz na temat kadrowania obrazu fotograficznego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1ca36436-3550-4b81-8e2f-d8d9f64a39b6', 'question_id': '8f60e4b0-c024-4bca-987e-805b5a9cd117', 'text': 'To proces wycinania zbędnych fragmentów obrazu w celu poprawy kompozycji i skupienia uwagi na temacie.', 'is_correct': 1, 'sort_order': 0}, {'id': '4b73b0ea-032c-45c1-aff1-50bbf2d1a079', 'question_id': '8f60e4b0-c024-4bca-987e-805b5a9cd117', 'text': 'To ustawianie ostrości za pomocą pierścienia na obiektywie.', 'is_correct': 0, 'sort_order': 1}, {'id': 'a32ca164-3c3c-4f46-b9a1-7ea653f02ed6', 'question_id': '8f60e4b0-c024-4bca-987e-805b5a9cd117', 'text': 'To rodzaj chemicznego utrwalania papieru pod powiększalnikiem.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd2741848-6b32-4918-9eb4-b985ca7c3708', 'question_id': '8f60e4b0-c024-4bca-987e-805b5a9cd117', 'text': 'Polega na wkładaniu gotowego zdjęcia w ozdobną ramkę.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0b72b623-d4c7-4b10-8c65-3325452875a9', 'chapter_id': 1, 'text': 'Co wiesz na temat kadrowania obrazu fotograficznego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Kadrowanie zaczyna się w momencie robienia zdjęcia poprzez wybór granic obrazu w celowniku. Może być też realizowane w postprodukcji (kadrowanie wtórne), co pozwala na zmianę proporcji zdjęcia lub eliminację niepożądanych elementów z brzegów kadru.'}, {'id': 'a8ef3615-48c0-429b-801a-e0a9dd75c75e', 'chapter_id': 1, 'text': 'Omów źródła światła stosowane w fotografii.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '32cb1ef8-bef4-432a-a148-988c84166774', 'question_id': 'a8ef3615-48c0-429b-801a-e0a9dd75c75e', 'text': 'Dzielimy je na naturalne (słońce, księżyc) oraz sztuczne (ciągłe np. żarowe i błyskowe).', 'is_correct': 1, 'sort_order': 0}, {'id': 'd25d3102-031d-424f-84a7-bed227fd70b5', 'question_id': 'a8ef3615-48c0-429b-801a-e0a9dd75c75e', 'text': 'Stosuje się wyłącznie światło lasera i podczerwień.', 'is_correct': 0, 'sort_order': 1}, {'id': 'c29cf48b-0929-4910-a3f3-d36aa7c26069', 'question_id': 'a8ef3615-48c0-429b-801a-e0a9dd75c75e', 'text': 'Jedynym źródłem światła w fotografii jest lampa błyskowa wbudowana w aparat.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c852d5f5-20a7-442f-8392-472935cd2a54', 'question_id': 'a8ef3615-48c0-429b-801a-e0a9dd75c75e', 'text': 'Źródła światła dzielimy na mokre i suche.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '709875c2-918b-465e-a9bd-471d0c008c3a', 'chapter_id': 1, 'text': 'Omów źródła światła stosowane w fotografii.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Światło naturalne zmienia swój charakter zależnie od pory dnia i pogody. Światło sztuczne ciągłe pozwala na stały podgląd światłocienia, natomiast światło błyskowe oferuje dużą moc i możliwość "zamrożenia" ruchu przy niskim poborze energii.'}, {'id': '80ae4a75-393a-4e59-8e62-717d7e2e0313', 'chapter_id': 1, 'text': 'Omów zastosowanie obiektywu o ogniskowej 28-90mm i 90-200mm.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f8842a42-0724-4ee5-971a-117d21599183', 'question_id': '80ae4a75-393a-4e59-8e62-717d7e2e0313', 'text': '28-90mm to uniwersalny zoom (od szerokiego kąta do portretu); 90-200mm to teleobiektyw do zbliżeń i sportu.', 'is_correct': 1, 'sort_order': 0}, {'id': '738422fe-2c3f-4a0e-a42e-28a96b704d45', 'question_id': '80ae4a75-393a-4e59-8e62-717d7e2e0313', 'text': 'Oba obiektywy służą wyłącznie do fotografii makro w bardzo małych odległościach.', 'is_correct': 0, 'sort_order': 1}, {'id': 'ff77f98e-7d21-485b-828c-05f7e9c65f12', 'question_id': '80ae4a75-393a-4e59-8e62-717d7e2e0313', 'text': '28-90mm używamy tylko w nocy, a 90-200mm tylko w słoneczne dni.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c2e5f1ed-ad13-4598-9a75-57c6bde6a6ec', 'question_id': '80ae4a75-393a-4e59-8e62-717d7e2e0313', 'text': 'Pierwszy służy do aparatów cyfrowych, a drugi tylko do analogowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3dbce3b8-ba8f-487a-ac0b-dd97a80aa19b', 'chapter_id': 1, 'text': 'Omów zastosowanie obiektywu o ogniskowej 28-90mm i 90-200mm.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Zakres 28-90mm pokrywa większość codziennych sytuacji, od krajobrazu po reportaż i portret. Obiektywy 90-200mm pozwalają na fotografowanie odległych obiektów, oferując duże powiększenie i charakterystyczne spłaszczenie perspektywy.'}, {'id': '92f7a1c9-210f-45e7-ae74-3fafe14a6d24', 'chapter_id': 1, 'text': 'Omów, jak powstaje obraz na kliszy fotograficznej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '92c7c710-ed97-4f4d-be70-023a7b030289', 'question_id': '92f7a1c9-210f-45e7-ae74-3fafe14a6d24', 'text': 'Pod wpływem światła w emulsji powstaje obraz utajony, który staje się widoczny dopiero po wywołaniu chemicznym.', 'is_correct': 1, 'sort_order': 0}, {'id': '59aac182-7058-4b63-ba89-df7eb475d9b7', 'question_id': '92f7a1c9-210f-45e7-ae74-3fafe14a6d24', 'text': 'Światło wypala dziury w filmie, tworząc wzór obrazu.', 'is_correct': 0, 'sort_order': 1}, {'id': '3ba05c99-4d0c-4873-8094-f62b6ca32bd7', 'question_id': '92f7a1c9-210f-45e7-ae74-3fafe14a6d24', 'text': 'Klisza jest skanowana przez aparat i zapisywana magnetycznie na taśmie.', 'is_correct': 0, 'sort_order': 2}, {'id': '08c1a75a-83fb-4c64-a593-eb9753b2e3a6', 'question_id': '92f7a1c9-210f-45e7-ae74-3fafe14a6d24', 'text': 'Obraz powstaje natychmiastowo w momencie uderzenia migawki o film.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0d6536fc-8cfa-4e94-b515-f4b047770b2c', 'chapter_id': 1, 'text': 'Omów, jak powstaje obraz na kliszy fotograficznej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Fotony padające na kryształki halogenków srebra powodują ich częściową redukcję do atomów srebra metalicznego, tworząc obraz utajony. Podczas wywoływania te naświetlone kryształki są w całości redukowane do czarnego srebra, tworząc widoczny obraz negatywowy.'}, {'id': '2492be8d-19ab-4207-bda5-bc0f38e54bed', 'chapter_id': 1, 'text': 'Jak zapisany jest obraz w pamięci aparatu cyfrowego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '565dfa1d-2748-4084-a1e3-e40c88e343e5', 'question_id': '2492be8d-19ab-4207-bda5-bc0f38e54bed', 'text': 'W postaci rzędów malutkich magnesów ułożonych w kształt zdjęcia.', 'is_correct': 0, 'sort_order': 0}, {'id': '1ad1ccfb-24b6-40d4-a59c-1c01cde43ceb', 'question_id': '2492be8d-19ab-4207-bda5-bc0f38e54bed', 'text': 'Jako dane binarne (pliki RAW, JPEG, TIFF) na karcie pamięci.', 'is_correct': 1, 'sort_order': 1}, {'id': '2ecb3e2b-fdda-43a6-aed6-7732cb75f9cc', 'question_id': '2492be8d-19ab-4207-bda5-bc0f38e54bed', 'text': 'Jako mikrofilm ukryty wewnątrz karty SD.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a4778642-7129-465a-afe8-fbe85e734115', 'question_id': '2492be8d-19ab-4207-bda5-bc0f38e54bed', 'text': 'Jako ładunek elektrostatyczny, który znika po wyjęciu baterii.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '08ce03e3-ec03-45c9-abde-12cb32d93d31', 'chapter_id': 1, 'text': 'Jak zapisany jest obraz w pamięci aparatu cyfrowego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Sygnał z matrycy jest przetwarzany przez procesor obrazu i zapisywany w formie cyfrowej na nośniku flash. Plik RAW zawiera surowe dane z matrycy, natomiast JPEG jest obrazem skompresowanym i przetworzonym zgodnie z ustawieniami aparatu.'}, {'id': '3a39fc0c-168f-4550-b51f-dfa27fc3a8f2', 'chapter_id': 1, 'text': 'Omów sposoby pomiaru światła w aparatach fotograficznych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '20ba5a13-84bc-4239-a713-51df22d691a2', 'question_id': '3a39fc0c-168f-4550-b51f-dfa27fc3a8f2', 'text': 'Pomiar punktowy, matrycowy (wielopolowy) i centralnie ważony.', 'is_correct': 1, 'sort_order': 0}, {'id': 'fc1fcfa7-f11e-411a-b4aa-21d3c3ccd56d', 'question_id': '3a39fc0c-168f-4550-b51f-dfa27fc3a8f2', 'text': 'Pomiar temperatury otoczenia i wilgotności powietrza.', 'is_correct': 0, 'sort_order': 1}, {'id': '19ee4dcb-d898-406f-9ebf-f8b5a94519f4', 'question_id': '3a39fc0c-168f-4550-b51f-dfa27fc3a8f2', 'text': 'Wyłącznie za pomocą zewnętrznego światłomierza trzymanego w dłoni.', 'is_correct': 0, 'sort_order': 2}, {'id': 'fd16429f-72fb-4d07-b310-c9206941d05a', 'question_id': '3a39fc0c-168f-4550-b51f-dfa27fc3a8f2', 'text': 'Przez patrzenie prosto w słońce i ocenę jego jasności.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '15e229c6-f6d5-4f11-bf5e-0541a64f9283', 'chapter_id': 1, 'text': 'Omów sposoby pomiaru światła w aparatach fotograficznych?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Pomiar matrycowy analizuje całą scenę i dobiera parametry tak, by uniknąć błędów w trudnych warunkach. Pomiar punktowy mierzy światło tylko w niewielkim fragmencie kadru (ok. 1-3%), co jest przydatne przy scenach o bardzo dużym kontraście.'}, {'id': '39de443a-384f-4610-803d-ba009f334207', 'chapter_id': 1, 'text': 'Wyjaśnij na czym polega retusz techniczny?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '285b7867-2663-4553-8fff-0ad7cffcf8da', 'question_id': '39de443a-384f-4610-803d-ba009f334207', 'text': 'Na usuwaniu skaz powstałych w procesie produkcji lub eksploatacji zdjęcia (kurz, rysy, plamy).', 'is_correct': 1, 'sort_order': 0}, {'id': 'fb272433-228e-4a0c-a8fc-95508a70bd38', 'question_id': '39de443a-384f-4610-803d-ba009f334207', 'text': 'Na wymianie obiektywu na nowszy model.', 'is_correct': 0, 'sort_order': 1}, {'id': 'c43bb89a-4835-4953-9d58-9e60157ae98b', 'question_id': '39de443a-384f-4610-803d-ba009f334207', 'text': 'Na smarowaniu aparatu olejem technicznym.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ec09cd76-680c-4780-9f20-7e74e81f9def', 'question_id': '39de443a-384f-4610-803d-ba009f334207', 'text': 'Na zmianie parametrów ekspozycji podczas robienia zdjęcia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a903296c-3d27-4d3d-b890-fc04fdb2e1f1', 'chapter_id': 1, 'text': 'Wyjaśnij na czym polega retusz techniczny?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Retusz techniczny ma na celu przywrócenie jakości wizualnej oryginału poprzez eliminację artefaktów niedotyczących samej treści zdjęcia. W fotografii cyfrowej używa się do tego narzędzi takich jak "Pędzel korygujący" czy "Stempel".'}, {'id': 'c0f8680a-ac03-4a3f-a87f-5d78fa10b055', 'chapter_id': 1, 'text': 'Omów pojęcie światła i cienia w obrazie negatywowym.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'edaddeeb-d14d-4de4-8ca4-38bffba4541d', 'question_id': 'c0f8680a-ac03-4a3f-a87f-5d78fa10b055', 'text': 'Wyglądają tak samo jak w rzeczywistości.', 'is_correct': 0, 'sort_order': 0}, {'id': '43c3616a-b9e0-4d89-a8d4-ba7fcc26e4e7', 'question_id': 'c0f8680a-ac03-4a3f-a87f-5d78fa10b055', 'text': 'Są odwrócone: miejsca jasne w rzeczywistości są ciemne (gęste) na negatywie, a cienie są jasne (przezroczyste).', 'is_correct': 1, 'sort_order': 1}, {'id': '2568f595-832d-4bcc-916a-bfbebc8ffa4c', 'question_id': 'c0f8680a-ac03-4a3f-a87f-5d78fa10b055', 'text': 'Na negatywie nie ma cieni, są tylko kolory.', 'is_correct': 0, 'sort_order': 2}, {'id': '6df3f751-b8c6-448b-8786-c6c8504923af', 'question_id': 'c0f8680a-ac03-4a3f-a87f-5d78fa10b055', 'text': 'Światło jest czerwone, a cień niebieski.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'ea1a5ee8-8cc0-4d95-a54b-6063995ad121', 'chapter_id': 1, 'text': 'Omów pojęcie światła i cienia w obrazie negatywowym.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W procesie negatywowym stopień zaczernienia srebra jest proporcjonalny do ilości światła, która padła na dany fragment filmu. Dlatego najjaśniejsze partie obrazu (np. niebo) na negatywie mają największą gęstość optyczną.'}, {'id': '924c9e57-05ec-4da0-a7d4-cd24201ee2a4', 'chapter_id': 1, 'text': 'Co to jest Dagerotypia?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'b7470ee1-8a1f-4d57-9107-2880e68049ac', 'question_id': '924c9e57-05ec-4da0-a7d4-cd24201ee2a4', 'text': 'Nowoczesna metoda druku wielkoformatowego.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd2426f0a-d607-427f-a69e-46a9df30bc74', 'question_id': '924c9e57-05ec-4da0-a7d4-cd24201ee2a4', 'text': 'Pierwszy praktyczny proces fotograficzny, w którym obraz powstawał na posrebrzanej płytce miedzianej.', 'is_correct': 1, 'sort_order': 1}, {'id': '5a021645-1262-4864-9b3f-50b8105bf3f6', 'question_id': '924c9e57-05ec-4da0-a7d4-cd24201ee2a4', 'text': 'Rodzaj aparatu cyfrowego marki Dagero.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd42ed8e6-00b9-47dd-bae2-996698c0f779', 'question_id': '924c9e57-05ec-4da0-a7d4-cd24201ee2a4', 'text': 'Technika wywoływania slajdów kolorowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2c504948-c6f8-4f6d-a7b9-edeb35cadcf9', 'chapter_id': 1, 'text': 'Co to jest Dagerotypia?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': "Wynaleziona przez Louisa Daguerre'a w 1839 roku, pozwalała na otrzymanie unikatowego (bez możliwości powielania) obrazu o bardzo wysokiej rozdzielczości. Obraz wywoływany był w oparach rtęci i utrwalany w roztworze soli kuchennej, a później tiosiarczanu sodu."}, {'id': '6ff59d68-2635-4299-9262-9dfe72dbe87f', 'chapter_id': 1, 'text': 'Na czym polega retusz optyczny?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'c27fcd4f-7b5c-4210-b7e8-12831a43e99f', 'question_id': '6ff59d68-2635-4299-9262-9dfe72dbe87f', 'text': 'Na poprawianiu wyglądu osoby poprzez dobór oświetlenia, ogniskowej i kąta widzenia przed zrobieniem zdjęcia.', 'is_correct': 1, 'sort_order': 0}, {'id': 'c50cfbac-b172-480d-9c04-1adaea2f575e', 'question_id': '6ff59d68-2635-4299-9262-9dfe72dbe87f', 'text': 'Na polerowaniu soczewek obiektywu w celu usunięcia zmarszczek modela.', 'is_correct': 0, 'sort_order': 1}, {'id': '1188b281-aba0-4515-aeb8-b413698c9fe9', 'question_id': '6ff59d68-2635-4299-9262-9dfe72dbe87f', 'text': 'Na noszeniu okularów korekcyjnych przez fotografa.', 'is_correct': 0, 'sort_order': 2}, {'id': '6f8a8970-92a6-439a-92b7-eb10ef66e1ad', 'question_id': '6ff59d68-2635-4299-9262-9dfe72dbe87f', 'text': 'Na naklejaniu filtrów bezpośrednio na twarz modela.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '56c32236-e9fd-4949-8fdf-fb6a770ce7f9', 'chapter_id': 1, 'text': 'Na czym polega retusz optyczny?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Retusz optyczny wykorzystuje właściwości światła i optyki do maskowania niedoskonałości. Przykładowo, miękkie oświetlenie frontalne (flat lighting) spłaszcza teksturę skóry, czyniąc zmarszczki mniej widocznymi.'}, {'id': '8d05c603-5beb-4fe2-a998-a482a80a4f74', 'chapter_id': 1, 'text': 'Jakie barwy nazywamy ciepłymi a jakie zimnymi?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '8be0af61-6e2c-41f9-bdef-dd79e8e505a8', 'question_id': '8d05c603-5beb-4fe2-a998-a482a80a4f74', 'text': 'Ciepłe to odcienie czerwieni, pomarańczu i żółci; zimne to odcienie niebieskiego, zieleni i fioletu.', 'is_correct': 1, 'sort_order': 0}, {'id': 'f8dc05f4-e10d-4964-a3b7-7e9f85908c35', 'question_id': '8d05c603-5beb-4fe2-a998-a482a80a4f74', 'text': 'Ciepłe to barwy jasne, a zimne to barwy ciemne.', 'is_correct': 0, 'sort_order': 1}, {'id': '23163f0b-0073-4452-a299-6f85a17fd057', 'question_id': '8d05c603-5beb-4fe2-a998-a482a80a4f74', 'text': 'Ciepłe to barwy matowe, a zimne to barwy błyszczące.', 'is_correct': 0, 'sort_order': 2}, {'id': '3e7aca92-079a-4735-a096-1a63620faf6b', 'question_id': '8d05c603-5beb-4fe2-a998-a482a80a4f74', 'text': 'Podział ten zależy tylko od temperatury powietrza w studio.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '984ae475-bde3-49cb-98b0-fa1b055e5cc5', 'chapter_id': 1, 'text': 'Jakie barwy nazywamy ciepłymi a jakie zimnymi?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Podział ten wynika z psychologicznego oddziaływania kolorów i skojarzeń z naturą (ogień vs woda). W fotografii balans bieli pozwala na celowe przesuwanie kolorystyki zdjęcia w stronę barw ciepłych lub zimnych w celu uzyskania określonego nastroju.'}, {'id': 'beec39d8-00c2-4647-80c0-f9cd09b81271', 'chapter_id': 1, 'text': 'Co to jest dominata barwna i jak ją usunąć?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '44206fca-bd99-4cfb-8899-67127e80adee', 'question_id': 'beec39d8-00c2-4647-80c0-f9cd09b81271', 'text': 'To zabarwienie całego zdjęcia obcym kolorem; usuwamy ją przez korekcję balansu bieli.', 'is_correct': 1, 'sort_order': 0}, {'id': '8ebb5073-e18c-4109-836c-9f4ae46420da', 'question_id': 'beec39d8-00c2-4647-80c0-f9cd09b81271', 'text': 'To najważniejsza osoba na zdjęciu; usuwamy ją retuszem.', 'is_correct': 0, 'sort_order': 1}, {'id': '6424e792-e450-48ad-a914-fe05e9ee6891', 'question_id': 'beec39d8-00c2-4647-80c0-f9cd09b81271', 'text': 'To czarna ramka wokół zdjęcia; usuwamy ją nożyczkami.', 'is_correct': 0, 'sort_order': 2}, {'id': '83d02130-2976-47cb-97ce-63f671ef4720', 'question_id': 'beec39d8-00c2-4647-80c0-f9cd09b81271', 'text': 'To efekt zbyt długiego naświetlania papieru pod powiększalnikiem.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4bf8f8d5-2838-43ec-8a7a-77425a5cfe62', 'chapter_id': 1, 'text': 'Co to jest dominata barwna i jak ją usunąć?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Dominata pojawia się, gdy temperatura barwowa źródła światła nie odpowiada ustawieniom materiału lub matrycy. Można ją usunąć w postprodukcji, wskazując na zdjęciu punkt, który powinien być neutralnie szary lub biały.'}, {'id': 'af2701cc-7e95-4873-a4f5-a314740ca44a', 'chapter_id': 1, 'text': 'Co to jest dystorsja i na czym polega?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '17ba6ae6-57c9-41ad-8e9f-9757c5139445', 'question_id': 'af2701cc-7e95-4873-a4f5-a314740ca44a', 'text': 'To wada optyczna obiektywu objawiająca się zakrzywieniem linii prostych (beczkowata lub poduszkowata).', 'is_correct': 1, 'sort_order': 0}, {'id': 'a554018b-3d0e-4eeb-bf6b-7232a106097e', 'question_id': 'af2701cc-7e95-4873-a4f5-a314740ca44a', 'text': 'To celowe poruszenie aparatem w celu rozmycia tła.', 'is_correct': 0, 'sort_order': 1}, {'id': '7e6768a1-a767-4da6-9fee-c33ddbccb9c5', 'question_id': 'af2701cc-7e95-4873-a4f5-a314740ca44a', 'text': 'To błąd w wywoływaniu polegający na spłynięciu emulsji.', 'is_correct': 0, 'sort_order': 2}, {'id': 'bc6ed778-c5de-4788-b856-8cd9d17d0c06', 'question_id': 'af2701cc-7e95-4873-a4f5-a314740ca44a', 'text': 'To zjawisko powstawania tęczy na krawędziach soczewek.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '562d5b8f-4d99-4a50-8815-c58080a030a6', 'chapter_id': 1, 'text': 'Co to jest dystorsja i na czym polega?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Dystorsja wynika ze zmiennego powiększenia obrazu wraz z oddalaniem się od osi optycznej obiektywu. Dystorsja beczkowata jest typowa dla obiektywów szerokokątnych, natomiast poduszkowata często występuje w teleobiektywach.'}, {'id': '0fc4d8af-0584-45a1-a177-6097420b994b', 'chapter_id': 1, 'text': 'Wymień procesy wysokotemperaturowe i omów jeden z nich.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '8a4a655a-131d-4169-a382-82566242cc0f', 'question_id': '0fc4d8af-0584-45a1-a177-6097420b994b', 'text': 'Pranie ubrań fotograficznych w 90 stopniach.', 'is_correct': 0, 'sort_order': 0}, {'id': '84a39dc7-6d7a-4da6-a826-d963ed994280', 'question_id': '0fc4d8af-0584-45a1-a177-6097420b994b', 'text': 'Procesy C-41 (negatyw kolor), E-6 (slajd) i RA-4 (papier kolor).', 'is_correct': 1, 'sort_order': 1}, {'id': 'c4096dd6-964c-4809-a47a-9691c7c07f8b', 'question_id': '0fc4d8af-0584-45a1-a177-6097420b994b', 'text': 'Wyłącznie wywoływanie w gorącej kawie (caffenol).', 'is_correct': 0, 'sort_order': 2}, {'id': 'e466cb5b-1706-48f6-b922-cc019645ea83', 'question_id': '0fc4d8af-0584-45a1-a177-6097420b994b', 'text': 'Suszenie zdjęć nad otwartym ogniem.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '9a1ed70f-09f1-45f1-aeb6-1afb4611d221', 'chapter_id': 1, 'text': 'Wymień procesy wysokotemperaturowe i omów jeden z nich.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Procesy te wymagają precyzyjnie utrzymywanej temperatury (zazwyczaj ok. 38°C) w celu zapewnienia prawidłowej reakcji barwników. Na przykład w procesie C-41 odchylenie temperatury o 0,1°C może już wpłynąć na balans kolorystyczny negatywu.'}, {'id': 'f88a7871-9a5c-4296-b454-3e54e4fd1616', 'chapter_id': 1, 'text': 'Omów jakie znaczenie praktyczne ma temperatura barwowa źródła światła w fotografii barwnej?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ffe816d8-0563-4780-b9c3-97bfbc001365', 'question_id': 'f88a7871-9a5c-4296-b454-3e54e4fd1616', 'text': 'Nie ma znaczenia, aparat sam zawsze widzi kolory poprawnie.', 'is_correct': 0, 'sort_order': 0}, {'id': '12623454-6cad-43ef-9cef-4705a8648e73', 'question_id': 'f88a7871-9a5c-4296-b454-3e54e4fd1616', 'text': 'Decyduje o oddaniu barw na zdjęciu; pozwala uniknąć nienaturalnych zafarbów (np. żółtych zdjęć w domu).', 'is_correct': 1, 'sort_order': 1}, {'id': 'ad050d5e-eec9-472f-ba8c-659919f2e537', 'question_id': 'f88a7871-9a5c-4296-b454-3e54e4fd1616', 'text': 'Wpływa tylko na to, jak szybko nagrzewa się matryca aparatu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a0a86b48-c1de-41cb-85ec-38898e06d375', 'question_id': 'f88a7871-9a5c-4296-b454-3e54e4fd1616', 'text': 'Ma znaczenie tylko przy fotografowaniu ognia i lodu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '5fb5bfe6-72ed-426f-bb00-e840a5a3f747', 'chapter_id': 1, 'text': 'Omów jakie znaczenie praktyczne ma temperatura barwowa źródła światła w fotografii barwnej?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Znajomość temperatury barwowej (wyrażonej w Kelwinach) pozwala fotografowi dobrać odpowiednie filtry korekcyjne lub ustawić balans bieli. Dzięki temu biały przedmiot na zdjęciu pozostanie biały, niezależnie od tego, czy oświetla go świeca, czy błękitne niebo.'}, {'id': '3a9e3aaf-c121-4466-bb2c-bba31a225aaf', 'chapter_id': 1, 'text': 'Scharakteryzuj oświetlenie słoneczne, od czego ono zależy?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'a01815f5-0222-4c69-96e3-2a102f2a9d0c', 'question_id': '3a9e3aaf-c121-4466-bb2c-bba31a225aaf', 'text': 'Jest zawsze stałe i nie zmienia się w ciągu dnia.', 'is_correct': 0, 'sort_order': 0}, {'id': '112a346a-cc3d-4d82-a2fc-0fb04749906f', 'question_id': '3a9e3aaf-c121-4466-bb2c-bba31a225aaf', 'text': 'Zależy od pory dnia, pory roku, zachmurzenia i wysokości słońca nad horyzontem.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f94bd413-ab9d-49c7-8789-7d20c74357f0', 'question_id': '3a9e3aaf-c121-4466-bb2c-bba31a225aaf', 'text': 'Zależy tylko od tego, jak mocno fotograf zmruży oczy.', 'is_correct': 0, 'sort_order': 2}, {'id': '368085c3-5bfd-44ae-a6a4-1180ac5ed37f', 'question_id': '3a9e3aaf-c121-4466-bb2c-bba31a225aaf', 'text': 'Jest to światło o temperaturze barwowej zawsze równej 1000K.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2037976c-41c2-4cbe-9005-c1c7988590f4', 'chapter_id': 1, 'text': 'Scharakteryzuj oświetlenie słoneczne, od czego ono zależy?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Słońce w zenicie daje ostre, kontrastowe światło o temperaturze ok. 5500K. Tuż przed zachodem (złota godzina) światło staje się bardzo miękkie, ma ciepłą barwę i długie cienie, co jest cenione w fotografii krajobrazowej i portretowej.'}, {'id': '031081f0-6f29-4813-853a-3a9e1ad65d09', 'chapter_id': 1, 'text': 'Omów standardowy przebieg procesu RA-4.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '0da4a033-5323-4c09-a019-1589238bfcc3', 'question_id': '031081f0-6f29-4813-853a-3a9e1ad65d09', 'text': 'Wywoływanie barwne, kąpiel wybielająco-utrwalająca (blix), płukanie i suszenie.', 'is_correct': 1, 'sort_order': 0}, {'id': 'ec487e80-55e3-43ef-a377-9c7afce76be8', 'question_id': '031081f0-6f29-4813-853a-3a9e1ad65d09', 'text': 'Wywoływanie czarno-białe, utrwalanie, malowanie farbami.', 'is_correct': 0, 'sort_order': 1}, {'id': 'b076d45a-9c6a-42a8-9110-3e3254b9721a', 'question_id': '031081f0-6f29-4813-853a-3a9e1ad65d09', 'text': 'Skanowanie, drukowanie, laminowanie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e5bac2ae-4dde-4baf-924b-47338e9c418f', 'question_id': '031081f0-6f29-4813-853a-3a9e1ad65d09', 'text': 'Naświetlanie papieru przez 10 minut i płukanie w gorącej wodzie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3f30b74d-e418-42df-b408-c63e7477f369', 'chapter_id': 1, 'text': 'Omów standardowy przebieg procesu RA-4.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Proces RA-4 służy do obróbki barwnych papierów światłoczułych. Charakterystyczne dla niego jest połączenie etapów wybielania i utrwalania w jedną kąpiel (blix), co skraca czas obróbki i upraszcza proces w maszynach automatycznych.'}, {'id': '78b4250f-908f-4676-9079-73f691addf5d', 'chapter_id': 1, 'text': 'Omów technikę wykonywania katalogowych zdjęć przedmiotów drewnianych i tkanin.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '86d49496-311b-422e-aedc-1301ce03ec55', 'question_id': '78b4250f-908f-4676-9079-73f691addf5d', 'text': 'Używamy ostrego światła punktowego, by powstały jak największe cienie.', 'is_correct': 0, 'sort_order': 0}, {'id': '47bf273e-223e-4465-bff2-53abfb0779bb', 'question_id': '78b4250f-908f-4676-9079-73f691addf5d', 'text': 'Stosujemy światło miękkie, boczne (pod kątem), aby podkreślić fakturę (strukturę) materiału.', 'is_correct': 1, 'sort_order': 1}, {'id': 'e023ad12-380c-459f-b559-0c0f71aee9fb', 'question_id': '78b4250f-908f-4676-9079-73f691addf5d', 'text': 'Przedmioty te fotografujemy pod wodą, aby nasycić ich kolory.', 'is_correct': 0, 'sort_order': 2}, {'id': 'aebbdce3-f56f-4c61-a47b-2b6afc688020', 'question_id': '78b4250f-908f-4676-9079-73f691addf5d', 'text': 'Fotografujemy je zawsze z bardzo dużej odległości, by nie było widać detali.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e61d979f-595a-4558-bad1-4dac0554fb12', 'chapter_id': 1, 'text': 'Omów technikę wykonywania katalogowych zdjęć przedmiotów drewnianych i tkanin.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W fotografii katalogowej kluczowe jest wierne oddanie faktury. Użycie światła kierunkowego padającego pod małym kątem do powierzchni drewna czy tkaniny pozwala wydobyć rysunek słojów lub splot nici dzięki powstawaniu mikrocieni.'}, {'id': '5b858c97-740e-49d8-9003-6956fd86b10d', 'chapter_id': 1, 'text': 'Jakie wymagania powinno spełniać zdjęcie paszportowe według przepisów?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'df89db26-2c8f-40a6-bd59-9049addb7c69', 'question_id': '5b858c97-740e-49d8-9003-6956fd86b10d', 'text': 'Białe tło, twarz en face, oczy otwarte, uszy muszą być widoczne, brak uśmiechu.', 'is_correct': 1, 'sort_order': 0}, {'id': '508fad9f-1c25-4304-966e-0af9326864bd', 'question_id': '5b858c97-740e-49d8-9003-6956fd86b10d', 'text': 'Dowolny kolor tła, okulary przeciwsłoneczne, szeroki uśmiech.', 'is_correct': 0, 'sort_order': 1}, {'id': 'd0f1cf49-f08c-4220-a0fc-78a5ead2c057', 'question_id': '5b858c97-740e-49d8-9003-6956fd86b10d', 'text': 'Zdjęcie całej sylwetki na tle gór.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f73ac957-fef8-410e-810c-6510ef288510', 'question_id': '5b858c97-740e-49d8-9003-6956fd86b10d', 'text': 'Zdjęcie musi być wykonane wyłącznie aparatem analogowym na czarno-białym filmie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e45092f2-8c9f-4def-b963-df9c4032ed28', 'chapter_id': 1, 'text': 'Jakie wymagania powinno spełniać zdjęcie paszportowe według przepisów?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Zdjęcie paszportowe musi być biometryczne, co oznacza określone proporcje twarzy względem kadru (twarz zajmuje 70-80% zdjęcia). Oświetlenie musi być równomierne, a wzrok skierowany prosto w obiektyw.'}, {'id': '2e950534-23e1-431c-b4c8-722399e339a3', 'chapter_id': 1, 'text': 'Wyjaśnij pojęcie „synchronizacji błysku”.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '773df36a-384e-43a4-8aec-620d1de0dfe1', 'question_id': '2e950534-23e1-431c-b4c8-722399e339a3', 'text': 'To czas, w którym migawka aparatu jest całkowicie otwarta, umożliwiając naświetlenie klatki przez błysk lampy.', 'is_correct': 1, 'sort_order': 0}, {'id': '23e2a134-b474-428a-98e6-4d24f3952ed3', 'question_id': '2e950534-23e1-431c-b4c8-722399e339a3', 'text': 'To ustawienie zegarków wszystkich osób w studio na tę samą godzinę.', 'is_correct': 0, 'sort_order': 1}, {'id': '396d84cf-27b4-42cc-924c-716e837050dd', 'question_id': '2e950534-23e1-431c-b4c8-722399e339a3', 'text': 'To jednoczesne naciśnięcie migawki w dwóch różnych aparatach.', 'is_correct': 0, 'sort_order': 2}, {'id': '95a36d76-b802-4ce5-af90-232b6bf6c1d0', 'question_id': '2e950534-23e1-431c-b4c8-722399e339a3', 'text': 'To proces ładowania baterii w lampie błyskowej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f1db7492-585a-4c96-86b0-4a4e62846e56', 'chapter_id': 1, 'text': 'Wyjaśnij pojęcie „synchronizacji błysku”.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Większość aparatów posiada migawkę szczelinową, która przy krótkich czasach naświetlania nie odsłania całej matrycy naraz. Czas synchronizacji (np. 1/200s) to najkrótszy czas, przy którym cała matryca jest widoczna dla błysku lampy.'}, {'id': '531e9d96-633f-4ac0-9822-8471a0468d42', 'chapter_id': 1, 'text': 'Na czym polega addytywna metoda korekcji barw?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'a335d389-9b6d-4b9e-981f-ae7482bbb835', 'question_id': '531e9d96-633f-4ac0-9822-8471a0468d42', 'text': 'Na mieszaniu trzech barw podstawowych światła: czerwonej, zielonej i niebieskiej (RGB).', 'is_correct': 1, 'sort_order': 0}, {'id': '24b0fed1-5274-4a3c-a4cd-ed1603c972c7', 'question_id': '531e9d96-633f-4ac0-9822-8471a0468d42', 'text': 'Na dodawaniu kolejnych warstw farby olejnej na gotowe zdjęcie.', 'is_correct': 0, 'sort_order': 1}, {'id': '594148ca-1e78-45d9-84c5-4c4bac55741c', 'question_id': '531e9d96-633f-4ac0-9822-8471a0468d42', 'text': 'Na zwiększaniu czasu wywoływania o każdą kolejną minutę.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ff86af3a-8a4c-487a-8eea-76d9c3eea83b', 'question_id': '531e9d96-633f-4ac0-9822-8471a0468d42', 'text': 'Na doklejaniu kolorowych filtrów na odbitkę.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1b0600b3-7f97-439b-9e67-5ff68c79e657', 'chapter_id': 1, 'text': 'Na czym polega addytywna metoda korekcji barw?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Metoda addytywna polega na nakładaniu na siebie strumieni światła o trzech barwach podstawowych. Suma wszystkich trzech barw w maksymalnym natężeniu daje światło białe.'}, {'id': 'a6803224-bbe0-4b14-a651-46c5c05ed3a7', 'chapter_id': 1, 'text': 'Co rozumiemy przez proces utrwalania obrazu?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f4227b06-20d3-4678-8451-3e8fea87324e', 'question_id': 'a6803224-bbe0-4b14-a651-46c5c05ed3a7', 'text': 'Usuwanie nienaświetlonych halogenków srebra z emulsji, aby obraz stał się odporny na światło.', 'is_correct': 1, 'sort_order': 0}, {'id': 'a3c445fc-6e2b-4972-8c04-e4672465147a', 'question_id': 'a6803224-bbe0-4b14-a651-46c5c05ed3a7', 'text': 'Proces robienia zdjęcia, które zostaje "utrwalone" na karcie pamięci.', 'is_correct': 0, 'sort_order': 1}, {'id': '599b50e9-3ffa-4817-a48f-5c28730896ea', 'question_id': 'a6803224-bbe0-4b14-a651-46c5c05ed3a7', 'text': 'Przyklejanie zdjęcia do sztywnej podkładki, aby się nie pogniotło.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b446d977-6022-4f03-9e9f-d4ad66da802f', 'question_id': 'a6803224-bbe0-4b14-a651-46c5c05ed3a7', 'text': 'Spryskiwanie odbitki lakierem do włosów dla połysku.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '5e2f57ad-09bb-4a79-abbc-9db4d720b093', 'chapter_id': 1, 'text': 'Co rozumiemy przez proces utrwalania obrazu?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Utrwalanie to niezbędny etap obróbki chemicznej, bez którego negatyw lub odbitka sczerniałyby po kontakcie ze światłem dziennym. Substancją utrwalającą jest zazwyczaj tiosiarczan sodu lub amonu.'}, {'id': '6c864be4-59b2-47b4-a101-d272bd97c5ed', 'chapter_id': 1, 'text': 'Wywoływanie jako proces wzmacniania obrazu utajonego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '8a574860-70c2-4cb6-9935-a48e867cebe9', 'question_id': '6c864be4-59b2-47b4-a101-d272bd97c5ed', 'text': 'To reakcja chemiczna zamieniająca niewidoczne jądra srebra w widoczne ziarna srebra metalicznego.', 'is_correct': 1, 'sort_order': 0}, {'id': '5a15566e-a083-43e8-be66-9d2f40c24c00', 'question_id': '6c864be4-59b2-47b4-a101-d272bd97c5ed', 'text': 'To proces polegający na silnym oświetleniu filmu lampą biurkową.', 'is_correct': 0, 'sort_order': 1}, {'id': 'f1a3f283-97a8-4ab6-91ee-de8971dc518f', 'question_id': '6c864be4-59b2-47b4-a101-d272bd97c5ed', 'text': 'To mechaniczne zdrapywanie warstwy ochronnej z filmu.', 'is_correct': 0, 'sort_order': 2}, {'id': '37bae0b4-baca-47b6-89be-75c97cc25533', 'question_id': '6c864be4-59b2-47b4-a101-d272bd97c5ed', 'text': 'To wyłącznie czynność cyfrowa polegająca na otwarciu pliku w programie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '435f9494-f9ab-42ce-8ca3-f4890318ed9d', 'chapter_id': 1, 'text': 'Wywoływanie jako proces wzmacniania obrazu utajonego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wywoływacz dostarcza elektrony do naświetlonych kryształów, powodując ich redukcję miliony razy szybciej niż kryształów nienaświetlonych. W ten sposób mikroskopijny obraz utajony zostaje "wzmocniony" do postaci widocznego obrazu negatywowego.'}, {'id': '13734215-9a19-4064-a181-641dc7ac4d4b', 'chapter_id': 1, 'text': 'W jakim celu ustala się balans bieli?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '43554047-e624-4e73-9ee5-d7e00ac09cd6', 'question_id': '13734215-9a19-4064-a181-641dc7ac4d4b', 'text': 'Aby barwy na zdjęciu wyglądały naturalnie, niezależnie od rodzaju światła oświetlającego scenę.', 'is_correct': 1, 'sort_order': 0}, {'id': 'f84e9374-ab7d-43e4-aad4-1196deb66b29', 'question_id': '13734215-9a19-4064-a181-641dc7ac4d4b', 'text': 'Aby zdjęcie było jak najbardziej jasne i białe.', 'is_correct': 0, 'sort_order': 1}, {'id': '44ba50a6-4288-4f48-876b-9c90360fcbfe', 'question_id': '13734215-9a19-4064-a181-641dc7ac4d4b', 'text': 'Aby zaoszczędzić energię w baterii aparatu.', 'is_correct': 0, 'sort_order': 2}, {'id': '037e451a-d511-4737-851f-1ec2b7658e36', 'question_id': '13734215-9a19-4064-a181-641dc7ac4d4b', 'text': 'Aby usunąć czarne elementy z kadru.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a437d75b-1c09-47d5-a70d-077b823fb9ea', 'chapter_id': 1, 'text': 'W jakim celu ustala się balans bieli?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Balans bieli informuje aparat, jaka temperatura barwowa odpowiada czystej bieli w danych warunkach. Dzięki temu eliminujemy zjawisko, w którym białe obiekty wydają się niebieskie (w cieniu) lub pomarańczowe (w świetle żarówek).'}, {'id': '3d6bc2ac-2272-4f87-b2a6-19c3f3c18f3c', 'chapter_id': 1, 'text': 'Od jakich parametrów aparatu cyfrowego zależy jakość zdjęcia?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '91c89f91-1fd4-4ae5-9198-b29e5eb65b24', 'question_id': '3d6bc2ac-2272-4f87-b2a6-19c3f3c18f3c', 'text': 'Wyłącznie od liczby megapikseli; im wyższa wartość, tym zawsze lepsze zdjęcie.', 'is_correct': 0, 'sort_order': 0}, {'id': '307137e9-3de5-4298-a00b-cc14d60acc25', 'question_id': '3d6bc2ac-2272-4f87-b2a6-19c3f3c18f3c', 'text': 'Od wielkości fizycznej matrycy, jakości optyki obiektywu, wydajności procesora obrazu oraz poziomu szumów.', 'is_correct': 1, 'sort_order': 1}, {'id': '3a4147c3-9e3b-42e1-ad67-bf378f90e8d0', 'question_id': '3d6bc2ac-2272-4f87-b2a6-19c3f3c18f3c', 'text': 'Od pojemności karty pamięci i koloru obudowy aparatu.', 'is_correct': 0, 'sort_order': 2}, {'id': '848abfdc-79d3-4074-be12-e37e5f56a749', 'question_id': '3d6bc2ac-2272-4f87-b2a6-19c3f3c18f3c', 'text': 'Od tego, jak głośno pracuje migawka podczas robienia zdjęcia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '96bda5cb-5011-45c2-b663-919940fac4ef', 'chapter_id': 1, 'text': 'Od jakich parametrów aparatu cyfrowego zależy jakość zdjęcia?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Jakość zdjęcia cyfrowego jest wypadkową kilku czynników: rozmiaru matrycy (większa zapewnia lepszą dynamikę i mniejsze szumy), klasy obiektywu (rozdzielczość optyczna i brak wad), sprawności procesora (obróbka sygnału) oraz zakresu czułości ISO.'}, {'id': '4e86f773-a3f6-4281-a049-44d5211d2c77', 'chapter_id': 1, 'text': 'Czym różni się rozdzielczość obrazu analogowego od cyfrowego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'a1cc67fe-4b0b-4377-b54a-6925ecba329f', 'question_id': '4e86f773-a3f6-4281-a049-44d5211d2c77', 'text': 'Nie różnią się niczym, w obu przypadkach mierzona jest w megapikselach.', 'is_correct': 0, 'sort_order': 0}, {'id': '620bfca2-57be-40cf-95d4-31641d0b81fe', 'question_id': '4e86f773-a3f6-4281-a049-44d5211d2c77', 'text': 'Analogowa zależy od wielkości ziarna emulsji i optyki; cyfrowa od liczby i gęstości pikseli na matrycy.', 'is_correct': 1, 'sort_order': 1}, {'id': '4954c39e-86dd-4e0a-8709-43b3800ba322', 'question_id': '4e86f773-a3f6-4281-a049-44d5211d2c77', 'text': 'Rozdzielczość analogowa jest zawsze mniejsza niż cyfrowa, niezależnie od formatu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e22d5c30-18fd-46b7-95d4-22ec43ef7323', 'question_id': '4e86f773-a3f6-4281-a049-44d5211d2c77', 'text': 'Cyfrowa rozdzielczość zależy od szybkości internetu, a analogowa od temperatury wywoływacza.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd3fd9990-8a64-47e6-8b0c-8d6a6553fe6f', 'chapter_id': 1, 'text': 'Czym różni się rozdzielczość obrazu analogowego od cyfrowego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W fotografii analogowej o szczegółowości decyduje struktura srebra w emulsji (ziarno) oraz jakość obiektywu. W fotografii cyfrowej rozdzielczość definiuje siatka fotodiod na matrycy (piksele) – im jest ich więcej na danej powierzchni, tym obraz jest bardziej szczegółowy.'}, {'id': '15675fad-2f35-40cb-b0b6-7195c3088f68', 'chapter_id': 1, 'text': 'Podaj różnicę między czułością filmu analogowego a czułością matrycy.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '9a84e373-4fcc-4771-89d7-2323f7e25352', 'question_id': '15675fad-2f35-40cb-b0b6-7195c3088f68', 'text': 'Film ma stałą czułość chemiczną; w matrycy ISO zmienia się poprzez elektroniczne wzmocnienie sygnału.', 'is_correct': 1, 'sort_order': 0}, {'id': '90890ad5-281b-45a0-95c6-4c2d75375e2e', 'question_id': '15675fad-2f35-40cb-b0b6-7195c3088f68', 'text': 'Matryca zmienia swoją fizyczną strukturę przy zmianie ISO, a film nie.', 'is_correct': 0, 'sort_order': 1}, {'id': '24696fe5-3b73-4a07-907d-1aef8a903dc4', 'question_id': '15675fad-2f35-40cb-b0b6-7195c3088f68', 'text': 'Czułość filmu zależy od baterii, a matrycy od rodzaju obiektywu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a7d2eec2-117d-41b1-8ab0-eb9ed7b2a7a1', 'question_id': '15675fad-2f35-40cb-b0b6-7195c3088f68', 'text': 'Nie ma żadnej różnicy, oba materiały reagują identycznie na światło.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '25e3d330-5466-4e25-9d7f-06ddf5750677', 'chapter_id': 1, 'text': 'Podaj różnicę między czułością filmu analogowego a czułością matrycy.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Czułość filmu (ISO) jest cechą stałą wynikającą z rozmiaru kryształów halogenków srebra w emulsji. W aparacie cyfrowym matryca ma jedną natywną czułość, a wyższe wartości ISO uzyskuje się poprzez wzmocnienie prądu sygnału, co generuje szum cyfrowy.'}, {'id': '2dc94314-dde9-4a4d-9113-4f9e62a0092d', 'chapter_id': 1, 'text': 'Fotografowanie „pod światło” – niebezpieczeństwa i sposoby ich uniknięcia.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '67d4fa4d-5539-4938-8000-606f1b822642', 'question_id': '2dc94314-dde9-4a4d-9113-4f9e62a0092d', 'text': 'Ryzyko uszkodzenia wzroku i matrycy; jedynym sposobem jest fotografowanie tyłem do słońca.', 'is_correct': 0, 'sort_order': 0}, {'id': 'df3fc4ea-94c1-47a1-a8f8-8e788847ac5e', 'question_id': '2dc94314-dde9-4a4d-9113-4f9e62a0092d', 'text': 'Ryzyko flar, utraty kontrastu i niedoświetlenia obiektu; sposoby to osłona przeciwsłoneczna, blenda lub błysk wypełniający.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b3664e33-dd21-45f1-9362-144330c3d4ab', 'question_id': '2dc94314-dde9-4a4d-9113-4f9e62a0092d', 'text': 'Zdjęcia pod światło są zawsze idealne i nie wymagają żadnych dodatkowych zabiegów.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e6c7f317-5d85-4907-b0ca-2bca84a339c7', 'question_id': '2dc94314-dde9-4a4d-9113-4f9e62a0092d', 'text': 'Należy użyć najdłuższego czasu naświetlania, aby "wypalić" słońce z kadru.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '5e8995fb-f68a-4268-bbb1-4204330e10e4', 'chapter_id': 1, 'text': 'Fotografowanie „pod światło” – niebezpieczeństwa i sposoby ich uniknięcia.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Głównym problemem jest spadek kontrastu przez odblaski wewnątrz obiektywu oraz powstanie sylwetki (niedoświetlenie tematu). Można temu zaradzić, używając osłony obiektywu, stosując pomiar punktowy światła na modela lub doświetlając go lampą/blendą.'}, {'id': 'b482729e-cb49-4491-aafe-7b6e0ec8f8f9', 'chapter_id': 1, 'text': 'Jakie aplikacje i w jakim zakresie pozwalają na modyfikację obrazu zapisanego cyfrowo?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '86049b6d-9f2a-4326-a874-021adf4751dc', 'question_id': 'b482729e-cb49-4491-aafe-7b6e0ec8f8f9', 'text': 'Adobe Photoshop, Lightroom czy Capture One; pozwalają na korektę ekspozycji, retusz, edycję barw i fotomontaż.', 'is_correct': 1, 'sort_order': 0}, {'id': 'b4e5f998-5f30-4f38-a74c-a104ddf09465', 'question_id': 'b482729e-cb49-4491-aafe-7b6e0ec8f8f9', 'text': 'Tylko systemowe kalkulatory i notatniki do zmiany nazwy pliku.', 'is_correct': 0, 'sort_order': 1}, {'id': '3a1b0235-c305-4c77-8ad3-2b8ab96308da', 'question_id': 'b482729e-cb49-4491-aafe-7b6e0ec8f8f9', 'text': 'Wyłącznie programy do odtwarzania wideo, które zmieniają klatki w zdjęcia.', 'is_correct': 0, 'sort_order': 2}, {'id': 'cad4707d-ce67-4409-982f-2e6fbc4653d8', 'question_id': 'b482729e-cb49-4491-aafe-7b6e0ec8f8f9', 'text': 'Przeglądarki internetowe, które automatycznie naprawiają nieostre zdjęcia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2d3bee65-d23e-401d-a4e9-4cd861700226', 'chapter_id': 1, 'text': 'Jakie aplikacje i w jakim zakresie pozwalają na modyfikację obrazu zapisanego cyfrowo?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Profesjonalne aplikacje (np. Lightroom) służą do wywoływania plików RAW (korekta ekspozycji, balansu bieli), natomiast programy rastrowe (np. Photoshop) pozwalają na zaawansowany retusz pikselowy, pracę na warstwach i tworzenie złożonych kompozycji.'}, {'id': 'a208feaf-c09a-4c0c-82cf-0720c164932b', 'chapter_id': 1, 'text': 'Omów prawa rozchodzenia się światła.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '43b861bf-ade0-4c94-b2fe-eee6803b7a57', 'question_id': 'a208feaf-c09a-4c0c-82cf-0720c164932b', 'text': 'Światło rozchodzi się w ośrodku jednorodnym po liniach prostych jako fala elektromagnetyczna.', 'is_correct': 1, 'sort_order': 0}, {'id': '550a7a0e-dbdd-4585-8824-c99fdfca8851', 'question_id': 'a208feaf-c09a-4c0c-82cf-0720c164932b', 'text': 'Światło zawsze zakręca wokół dużych obiektów, tworząc spiralne cienie.', 'is_correct': 0, 'sort_order': 1}, {'id': '2e97de44-a3a1-414a-8319-0e2f17674eb3', 'question_id': 'a208feaf-c09a-4c0c-82cf-0720c164932b', 'text': 'Prędkość światła zależy od koloru ściany, od której się odbija.', 'is_correct': 0, 'sort_order': 2}, {'id': '5c5e6321-9217-4529-ab01-24af2b0eada8', 'question_id': 'a208feaf-c09a-4c0c-82cf-0720c164932b', 'text': 'Światło rozchodzi się tylko w kierunku północnym ze względu na pole magnetyczne Ziemi.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2636c65b-9b56-459d-b478-b60f3e6330c8', 'chapter_id': 1, 'text': 'Omów prawa rozchodzenia się światła.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Podstawowym prawem jest prostoliniowe rozchodzenie się światła w ośrodkach optycznie jednorodnych. Promienie świetlne rozchodzą się od źródła we wszystkich kierunkach, a ich zachowanie na granicy ośrodków opisują prawa odbicia i załamania.'}, {'id': '738aece4-78e4-40d4-8876-798f78da5337', 'chapter_id': 1, 'text': 'Co to są mocne punkty w obrazie?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '9a783b76-520a-43b9-a124-b0119d622086', 'question_id': '738aece4-78e4-40d4-8876-798f78da5337', 'text': 'Miejsca na matrycy, które są najbardziej odporne na silne światło.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd34f111b-8461-4699-a973-d16ac8998a29', 'question_id': '738aece4-78e4-40d4-8876-798f78da5337', 'text': 'Punkty przecięcia linii dzielących kadr na trzy równe części w pionie i poziomie (reguła trójpodziału).', 'is_correct': 1, 'sort_order': 1}, {'id': '99f7751c-c1b5-4015-9bf4-700f7fe27eb6', 'question_id': '738aece4-78e4-40d4-8876-798f78da5337', 'text': 'Najjaśniejsze punkty na zdjęciu, które zawsze muszą być w centrum.', 'is_correct': 0, 'sort_order': 2}, {'id': '27fbe753-92a0-47e5-ab77-b94dd2b9f742', 'question_id': '738aece4-78e4-40d4-8876-798f78da5337', 'text': 'Punkty, w których mocujemy statyw do aparatu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '50eb2513-069b-4141-803d-9fb154f348eb', 'chapter_id': 1, 'text': 'Co to są mocne punkty w obrazie?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Mocne punkty to miejsca, w których naturalnie skupia się wzrok widza. Według zasady trójpodziału, umieszczenie głównego motywu w jednym z tych czterech punktów przecięcia sprawia, że kompozycja staje się bardziej wyważona i interesująca.'}, {'id': 'db7520bd-363e-46f4-86e3-e8b86cc3d5ff', 'chapter_id': 1, 'text': 'Omów prawo załamania i odbicia światła.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5c1088b4-91f6-4490-836a-56905edaaa1b', 'question_id': 'db7520bd-363e-46f4-86e3-e8b86cc3d5ff', 'text': 'Kąt padania jest równy kątowi odbicia; załamanie to zmiana kierunku promienia na granicy dwóch ośrodków.', 'is_correct': 1, 'sort_order': 0}, {'id': '4777784f-eeb4-45e9-92a0-62a6b7e2a4fe', 'question_id': 'db7520bd-363e-46f4-86e3-e8b86cc3d5ff', 'text': 'Światło zawsze odbija się pod kątem 45 stopni, niezależnie od kąta padania.', 'is_correct': 0, 'sort_order': 1}, {'id': '1c8caae0-cdff-48fd-9280-2ba3cae10b7c', 'question_id': 'db7520bd-363e-46f4-86e3-e8b86cc3d5ff', 'text': 'Załamanie światła występuje tylko w nocy, gdy powietrze jest zimne.', 'is_correct': 0, 'sort_order': 2}, {'id': 'fbaea8f7-4662-4bf6-97b2-5b847986582e', 'question_id': 'db7520bd-363e-46f4-86e3-e8b86cc3d5ff', 'text': 'Odbicie światła powoduje, że obraz staje się czarno-biały.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0ee409da-ce96-42b1-8ed0-9ff6c4ffc511', 'chapter_id': 1, 'text': 'Omów prawo załamania i odbicia światła.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Prawo odbicia mówi, że promień odbity leży w tej samej płaszczyźnie co padający, a kąty padania i odbicia są równe. Załamanie (refrakcja) polega na zmianie prędkości i kierunku fali przy przejściu do ośrodka o innej gęstości, co jest podstawą działania soczewek.'}, {'id': '4ef6e056-ef9c-4212-b7f5-25471d705980', 'chapter_id': 1, 'text': 'Wytłumacz zjawisko polaryzacji światła.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1525c022-36af-4c61-ad8e-458782b781f6', 'question_id': '4ef6e056-ef9c-4212-b7f5-25471d705980', 'text': 'To uporządkowanie drgań fali świetlnej w jednej płaszczyźnie; wykorzystywane do usuwania odblasków.', 'is_correct': 1, 'sort_order': 0}, {'id': 'a7df6b86-a25c-45c1-a678-f75e8256e804', 'question_id': '4ef6e056-ef9c-4212-b7f5-25471d705980', 'text': 'To proces zamiany światła słonecznego na energię cieplną w obiektywie.', 'is_correct': 0, 'sort_order': 1}, {'id': '1e62431e-006b-4ad2-9c84-954387863216', 'question_id': '4ef6e056-ef9c-4212-b7f5-25471d705980', 'text': 'To zjawisko powstawania tęczy przy użyciu lampy błyskowej.', 'is_correct': 0, 'sort_order': 2}, {'id': '298b4b0a-87b0-4918-acc7-9c6f3d534416', 'question_id': '4ef6e056-ef9c-4212-b7f5-25471d705980', 'text': 'Polega na przyciąganiu promieni światła przez naładowane elektrody.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '04b501c4-5567-4c23-b830-e788dedcd213', 'chapter_id': 1, 'text': 'Wytłumacz zjawisko polaryzacji światła.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Światło naturalne drga w wielu płaszczyznach. Po odbiciu od powierzchni niemetalicznych (woda, szkło) zostaje spolaryzowane. Filtr polaryzacyjny pozwala odciąć te uporządkowane drgania, co eliminuje odblaski i nasyca kolory (np. błękit nieba).'}, {'id': 'fa75f3f8-d321-42c5-ae38-efe52697b7ab', 'chapter_id': 1, 'text': 'Omów zależność między ogniskową obiektywu a przekątną formatu zdjęcia.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'dabd89e7-e189-4806-b87b-e11be3aee7c0', 'question_id': 'fa75f3f8-d321-42c5-ae38-efe52697b7ab', 'text': 'Ogniskowa obiektywu standardowego jest w przybliżeniu równa długości przekątnej materiału światłoczułego.', 'is_correct': 1, 'sort_order': 0}, {'id': '90ad75e9-d66d-487a-86a8-fef5ae83d0e2', 'question_id': 'fa75f3f8-d321-42c5-ae38-efe52697b7ab', 'text': 'Im większa przekątna formatu, tym mniejsza musi być ogniskowa każdego obiektywu.', 'is_correct': 0, 'sort_order': 1}, {'id': 'd1759788-40e0-48a8-8809-aab79453891f', 'question_id': 'fa75f3f8-d321-42c5-ae38-efe52697b7ab', 'text': 'Nie ma żadnej zależności; ogniskowa jest parametrem stałym dla każdego aparatu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f7f8865a-5d8a-49eb-b024-d21f642944ac', 'question_id': 'fa75f3f8-d321-42c5-ae38-efe52697b7ab', 'text': 'Przekątna formatu zdjęcia zawsze musi być dwa razy większa niż ogniskowa.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'be4b210b-8312-42db-957a-eb70253d4791', 'chapter_id': 1, 'text': 'Omów zależność między ogniskową obiektywu a przekątną formatu zdjęcia.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Ogniskowa uznawana za "standardową" odpowiada przekątnej klatki (np. ok. 43mm dla formatu 35mm). Jeśli ogniskowa jest krótsza od przekątnej, mamy do czynienia z obiektywem szerokokątnym, jeśli dłuższa – z teleobiektywem.'}, {'id': 'e7cdd4ff-4601-4cfa-b3a6-8f14b5b79bc2', 'chapter_id': 1, 'text': 'Co oznacza termin zdolność rozdzielcza?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'bff1be30-922e-413b-a007-add542e26634', 'question_id': 'e7cdd4ff-4601-4cfa-b3a6-8f14b5b79bc2', 'text': 'Umiejętność obiektywu lub matrycy do odwzorowania blisko położonych detali jako oddzielnych punktów/linii.', 'is_correct': 1, 'sort_order': 0}, {'id': '72b8fc7b-2aaa-4e66-8973-76835b6d29aa', 'question_id': 'e7cdd4ff-4601-4cfa-b3a6-8f14b5b79bc2', 'text': 'Prędkość, z jaką aparat potrafi rozdzielić sygnał na kolory RGB.', 'is_correct': 0, 'sort_order': 1}, {'id': '8c5bd312-78ba-4e31-bd68-bbc53a22d51f', 'question_id': 'e7cdd4ff-4601-4cfa-b3a6-8f14b5b79bc2', 'text': 'Maksymalna rozdzielczość monitora, na którym oglądamy zdjęcia.', 'is_correct': 0, 'sort_order': 2}, {'id': '7ba45d4c-3028-42d9-b2e1-5b45ddf44c28', 'question_id': 'e7cdd4ff-4601-4cfa-b3a6-8f14b5b79bc2', 'text': 'Zdolność fotografa do poprawnego wykadrowania zdjęcia w trudnych warunkach.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7d6465e0-acf1-4f2a-9c5a-95ca52e78408', 'chapter_id': 1, 'text': 'Co oznacza termin zdolność rozdzielcza?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Zdolność rozdzielcza określa stopień szczegółowości obrazu. Mierzy się ją zazwyczaj w liczbie par linii na milimetr (l/mm), które dany układ optyczny jest w stanie zarejestrować, zanim zleją się one w jedną szarą plamę.'}, {'id': '938b261c-daab-4853-935d-2164f65389b7', 'chapter_id': 1, 'text': 'Metody ustalania warunków oświetlenia.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'd1822631-1ea2-498d-9618-529d2d0e73ea', 'question_id': '938b261c-daab-4853-935d-2164f65389b7', 'text': 'Pomiar światła padającego (na przedmiot) oraz pomiar światła odbitego (od przedmiotu).', 'is_correct': 1, 'sort_order': 0}, {'id': '45e6870f-8967-40a1-8ba8-b2bde94c1ccb', 'question_id': '938b261c-daab-4853-935d-2164f65389b7', 'text': 'Wyłącznie ocena jasności na oko przez wizjer aparatu.', 'is_correct': 0, 'sort_order': 1}, {'id': 'b2975c67-b281-4738-8669-1b165e2b4ca8', 'question_id': '938b261c-daab-4853-935d-2164f65389b7', 'text': 'Sprawdzanie aktualnej godziny i pory roku w kalendarzu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd66ae242-dcf9-4bc6-83b5-b67e1e6c35c8', 'question_id': '938b261c-daab-4853-935d-2164f65389b7', 'text': 'Pomiar temperatury powietrza w miejscu fotografowania.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '39571350-b578-4f64-99ee-317ba2e282e0', 'chapter_id': 1, 'text': 'Metody ustalania warunków oświetlenia.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wyróżniamy pomiar światła odbitego (dokonywany przez aparat), który zależy od jasności fotografowanego obiektu, oraz pomiar światła padającego (zewnętrznym światłomierzem), który jest niezależny od koloru obiektu i daje najbardziej obiektywny wynik ekspozycji.'}, {'id': '7355b7bd-22ad-43c2-b922-88674794bf5a', 'chapter_id': 2, 'text': 'Podaj typy oraz omów budowę kamer zakładowych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f3b25537-834f-444e-9f91-450f2f389313', 'question_id': '7355b7bd-22ad-43c2-b922-88674794bf5a', 'text': 'Małoformatowe lustrzanki cyfrowe z wbudowaną lampą.', 'is_correct': 0, 'sort_order': 0}, {'id': '065d0b29-d6d2-4730-913f-f06833af8ac2', 'question_id': '7355b7bd-22ad-43c2-b922-88674794bf5a', 'text': 'Kamery wielkoformatowe (studyjne), składające się z przedniego standardu (z obiektywem), tylnego standardu (z matówką/kasetą) i łączącego je miecha.', 'is_correct': 1, 'sort_order': 1}, {'id': '257b596d-8b8e-420a-88fa-62804be79fba', 'question_id': '7355b7bd-22ad-43c2-b922-88674794bf5a', 'text': 'Wyłącznie kieszonkowe aparaty kompaktowe do szybkich zdjęć.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a0e71e40-d7ce-4461-a9fa-79fdbc95fd60', 'question_id': '7355b7bd-22ad-43c2-b922-88674794bf5a', 'text': 'Kamery monitoringu montowane na ścianach zakładów fotograficznych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '28a42557-a984-49f4-9d4e-3efc2c1b30bd', 'chapter_id': 2, 'text': 'Podaj typy oraz omów budowę kamer zakładowych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Kamery zakładowe (wielkoformatowe) dzielą się na ławowe (na sztywnej szynie) oraz polowe (składane do skrzynki). Ich budowa opiera się na modułowości, co pozwala na pokłony i przesunięcia standardów względem siebie, umożliwiając precyzyjną kontrolę perspektywy i płaszczyzny ostrości.'}, {'id': '6b6a5bf6-1be0-4368-b24a-3aa9ec3f3064', 'chapter_id': 2, 'text': 'Pracownia fotograficzna – jej funkcjonalność i wyposażenie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '96807555-1282-47a3-b87c-e6217f2ab438', 'question_id': '6b6a5bf6-1be0-4368-b24a-3aa9ec3f3064', 'text': 'To puste pomieszczenie z oknem wychodzącym na północ.', 'is_correct': 0, 'sort_order': 0}, {'id': '86e7fde4-9e8d-4813-a43e-add9886b3d7c', 'question_id': '6b6a5bf6-1be0-4368-b24a-3aa9ec3f3064', 'text': 'To przestrzeń podzielona na strefę zdjęciową (studio z lampami i tłem), ciemnię (jeśli analogowa) oraz stanowisko do obróbki cyfrowej i wykańczania zdjęć.', 'is_correct': 1, 'sort_order': 1}, {'id': 'a537afc1-d22c-4ed6-97e3-4d4487312c30', 'question_id': '6b6a5bf6-1be0-4368-b24a-3aa9ec3f3064', 'text': 'Wyłącznie biurko z komputerem i dostępem do Internetu.', 'is_correct': 0, 'sort_order': 2}, {'id': '4a57e223-5093-4da7-b58c-a4d363f3bb87', 'question_id': '6b6a5bf6-1be0-4368-b24a-3aa9ec3f3064', 'text': 'Miejsce, gdzie przechowuje się tylko stare chemikalia fotograficzne.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '59995aca-b9fb-4381-b669-560d59f582ca', 'chapter_id': 2, 'text': 'Pracownia fotograficzna – jej funkcjonalność i wyposażenie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Funkcjonalna pracownia musi zapewniać kontrolę nad światłem (zaciemnienie) oraz posiadać odpowiednie zasilanie dla lamp studyjnych. Wyposażenie obejmuje systemy zawieszania teł, statywy, modyfikatory światła, a w nowoczesnym wydaniu – profesjonalne monitory graficzne i drukarki.'}, {'id': '4e9a1db7-eca0-4ac5-a40a-647857469893', 'chapter_id': 2, 'text': 'Omów sprzęt dodatkowy do aparatów fotograficznych i jego zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5a32b85c-7e5e-494d-ab25-379f1477068c', 'question_id': '4e9a1db7-eca0-4ac5-a40a-647857469893', 'text': 'Statywy (stabilizacja), wężyki spustowe (brak drgań), filtry (efekty/ochrona), blendy (odbijanie światła) i światłomierze.', 'is_correct': 1, 'sort_order': 0}, {'id': '542d3483-4e7f-4d9c-86a7-5ef91a7dd81d', 'question_id': '4e9a1db7-eca0-4ac5-a40a-647857469893', 'text': 'Tylko dodatkowe ozdobne paski do zawieszenia aparatu na szyi.', 'is_correct': 0, 'sort_order': 1}, {'id': '8ca8910b-0fcd-43d3-bb2e-0a5504a8bdf5', 'question_id': '4e9a1db7-eca0-4ac5-a40a-647857469893', 'text': 'Wyłącznie torby i plecaki do transportu sprzętu.', 'is_correct': 0, 'sort_order': 2}, {'id': '439cc40f-f633-4ab6-9deb-70b2be6756d6', 'question_id': '4e9a1db7-eca0-4ac5-a40a-647857469893', 'text': 'Sprzęt dodatkowy to tylko zapasowe obiektywy o tej samej ogniskowej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '42e9adf8-2cd1-4827-8e0f-b4bfe33a793f', 'chapter_id': 2, 'text': 'Omów sprzęt dodatkowy do aparatów fotograficznych i jego zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Akcesoria rozszerzają możliwości aparatu. Statyw jest niezbędny przy długich czasach naświetlania i reprodukcji, filtry polaryzacyjne usuwają odblaski, a światłomierze pozwalają na precyzyjny pomiar światła padającego, szczególnie w studio.'}, {'id': '590fd2ea-03dd-4eb3-8874-6142ee4505f8', 'chapter_id': 2, 'text': 'Wymień podstawowe lampy i ich funkcję w oświetleniu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '2869f292-30a5-41f4-aa5a-0d02616812d7', 'question_id': '590fd2ea-03dd-4eb3-8874-6142ee4505f8', 'text': 'Lampy rysujące (główne), dopełniające (cienie), konturowe (oddzielenie od tła) i lampy oświetlające tło.', 'is_correct': 1, 'sort_order': 0}, {'id': '7df77005-c05a-4811-99d1-d53b4b781ff2', 'question_id': '590fd2ea-03dd-4eb3-8874-6142ee4505f8', 'text': 'Wyłącznie zwykłe żarówki domowe o dużej mocy.', 'is_correct': 0, 'sort_order': 1}, {'id': '73f988bd-e227-4625-b9ea-ee77d88a47fc', 'question_id': '590fd2ea-03dd-4eb3-8874-6142ee4505f8', 'text': 'Tylko lampy błyskowe zamontowane na stałe w sufitach.', 'is_correct': 0, 'sort_order': 2}, {'id': '9854a901-d698-46c4-92c4-3e637cc39d79', 'question_id': '590fd2ea-03dd-4eb3-8874-6142ee4505f8', 'text': 'Lampy dzielimy na czerwone, zielone i niebieskie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7e9f5c71-416d-4ea1-818e-1eb1ebe49b1e', 'chapter_id': 2, 'text': 'Wymień podstawowe lampy i ich funkcję w oświetleniu.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Lampa rysująca nadaje formę i charakter, dopełniająca zmniejsza kontrast (rozjaśnia cienie), a konturowa wydobywa krawędzie i nadaje zdjęciu trójwymiarowość. Lampy tła służą do eliminacji cieni rzucanych przez modela lub nadania tłu konkretnego koloru i jasności.'}, {'id': '144a7ace-94d9-4308-8a6b-22e7bb6e5ad5', 'chapter_id': 2, 'text': 'Omów różnice między aparatem analogowym a cyfrowym.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ea226c40-4b07-4197-87ca-a2e026d0aa41', 'question_id': '144a7ace-94d9-4308-8a6b-22e7bb6e5ad5', 'text': 'Nie ma żadnych różnic poza nazwą.', 'is_correct': 0, 'sort_order': 0}, {'id': '93b63c68-d9d4-4d34-a5f5-c9bc948de5b5', 'question_id': '144a7ace-94d9-4308-8a6b-22e7bb6e5ad5', 'text': 'Różnią się medium zapisu (film vs matryca) oraz sposobem powstawania obrazu (chemiczny vs elektroniczny).', 'is_correct': 1, 'sort_order': 1}, {'id': 'dcb1cc4d-3d74-42d5-97e9-edb396dbf176', 'question_id': '144a7ace-94d9-4308-8a6b-22e7bb6e5ad5', 'text': 'Aparat analogowy nie potrzebuje obiektywu, a cyfrowy tak.', 'is_correct': 0, 'sort_order': 2}, {'id': 'caf35a56-cdb4-43c7-941a-bc4694d8fdc4', 'question_id': '144a7ace-94d9-4308-8a6b-22e7bb6e5ad5', 'text': 'Cyfrowy zapisuje zdjęcia na kliszy, którą potem skanuje komputer.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '8720211d-ae7c-4e3e-b24a-542d843fa2a8', 'chapter_id': 2, 'text': 'Omów różnice między aparatem analogowym a cyfrowym.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W aparacie analogowym obraz powstaje w wyniku reakcji fotochemicznej na filmie i wymaga obróbki mokrej. W aparacie cyfrowym matryca zamienia światło na sygnały elektryczne, które są przetwarzane przez procesor i zapisywane jako plik binarny na karcie pamięci.'}, {'id': 'e190544b-f60f-4f79-8136-75bc7110a3a5', 'chapter_id': 2, 'text': 'Podać typy aparatów na błony zwojowe, wymienić zalety aparatów lustrzanych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'aa740df5-5743-4a10-80dc-8ea00620bc28', 'question_id': 'e190544b-f60f-4f79-8136-75bc7110a3a5', 'text': 'Typy: 6x4.5, 6x6, 6x7, 6x9. Zalety lustrzanek: brak błędu paralaksy i pełna kontrola głębi ostrości przez obiektyw.', 'is_correct': 1, 'sort_order': 0}, {'id': '52b902af-4154-406c-aab2-ff5aef80ef5b', 'question_id': 'e190544b-f60f-4f79-8136-75bc7110a3a5', 'text': 'Typy: tylko 35mm. Zaleta: są bardzo ciężkie, co zapobiega kradzieży.', 'is_correct': 0, 'sort_order': 1}, {'id': '619bfcba-ad42-4c32-a12b-b3361755dc9e', 'question_id': 'e190544b-f60f-4f79-8136-75bc7110a3a5', 'text': 'Typy: tylko aparaty natychmiastowe. Zaleta: nie potrzebują baterii.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ba1e2ed9-7409-4d46-a7ef-01f10daf16dd', 'question_id': 'e190544b-f60f-4f79-8136-75bc7110a3a5', 'text': 'Lustrzanki nie mają żadnych zalet względem aparatów celownikowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e9f7bd9c-931f-4fdc-a06f-147fa3687f4d', 'chapter_id': 2, 'text': 'Podać typy aparatów na błony zwojowe, wymienić zalety aparatów lustrzanych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Aparaty na błony zwojowe (średnioformatowe) oferują znacznie większą powierzchnię negatywu niż małoformatowe, co przekłada się na lepszą jakość i mniejsze ziarno. Lustrzanki (SLR/TLR) pozwalają widzieć dokładnie to, co zarejestruje obiektyw, co eliminuje błędy kadrowania przy małych odległościach.'}, {'id': '412b4ab1-2bf5-46ca-826b-8db90acacb52', 'chapter_id': 2, 'text': 'Omów budowę powiększalnika.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5c05ffcc-5736-477e-8da8-543443ac71c7', 'question_id': '412b4ab1-2bf5-46ca-826b-8db90acacb52', 'text': 'Obiektyw, monitor, klawiatura i drukarka.', 'is_correct': 0, 'sort_order': 0}, {'id': '83e568a1-afe2-4e1d-a058-0941e2c98628', 'question_id': '412b4ab1-2bf5-46ca-826b-8db90acacb52', 'text': 'Głowica (ze źródłem światła i kondensorem), kolumna, karetka na negatyw, obiektyw i podstawa.', 'is_correct': 1, 'sort_order': 1}, {'id': 'fa11b810-cd40-4a38-9e91-5375447d84c0', 'question_id': '412b4ab1-2bf5-46ca-826b-8db90acacb52', 'text': 'Jest to prosta skrzynka z dziurką, przez którą wpada światło słoneczne.', 'is_correct': 0, 'sort_order': 2}, {'id': '130693fe-1ae1-48c6-bf76-ca8a9c080a6e', 'question_id': '412b4ab1-2bf5-46ca-826b-8db90acacb52', 'text': 'Powiększalnik składa się tylko z żarówki i białego papieru.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'eda7b6b5-d79c-4bfe-94e1-eeec8eae71cf', 'chapter_id': 2, 'text': 'Omów budowę powiększalnika.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Powiększalnik służy do rzutowania obrazu z negatywu na papier światłoczuły. Głowica zawiera układ optyczny skupiający światło, a ruchoma kolumna pozwala na zmianę skali powiększenia poprzez oddalanie lub przybliżanie głowicy do podstawy, na której leży papier.'}, {'id': '71bf6630-0d52-4d37-9100-8b25c10e4ec0', 'chapter_id': 2, 'text': 'Omów zasadę działania aparatu do fotografii natychmiastowej (Polaroid).', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '8728ea73-9bf6-4730-83ca-b30ac24af93b', 'question_id': '71bf6630-0d52-4d37-9100-8b25c10e4ec0', 'text': 'Zdjęcie jest przesyłane przez Wi-Fi do pobliskiego punktu ksero.', 'is_correct': 0, 'sort_order': 0}, {'id': 'fc869c60-99b1-4375-bbc5-80b2836f9ce4', 'question_id': '71bf6630-0d52-4d37-9100-8b25c10e4ec0', 'text': 'Po naświetleniu materiał przechodzi przez rolki, które rozgniatają kapsułkę z chemią, inicjując wywoływanie bezpośrednio w odbitce.', 'is_correct': 1, 'sort_order': 1}, {'id': '37d24a66-2549-495a-947c-758cfb338db3', 'question_id': '71bf6630-0d52-4d37-9100-8b25c10e4ec0', 'text': 'Aparat posiada wbudowaną małą drukarkę atramentową.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f698d59c-2c92-46b6-a223-2ac1687ada6d', 'question_id': '71bf6630-0d52-4d37-9100-8b25c10e4ec0', 'text': 'Film z aparatu należy wyjąć i wywołać w tradycyjnej ciemni.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e286badf-a190-40a1-9b41-aff99dcbb418', 'chapter_id': 2, 'text': 'Omów zasadę działania aparatu do fotografii natychmiastowej (Polaroid).', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'System ten (np. Polaroid lub Instax) łączy w sobie negatyw i pozytyw. Proces wywoływania i utrwalania zachodzi wewnątrz "kanapki" materiałów pod wpływem odczynników rozprowadzonych przez rolki aparatu w momencie wysuwania zdjęcia.'}, {'id': 'bf21ca75-6ce8-4d4f-bbb5-bd5229b9dd9e', 'chapter_id': 2, 'text': 'Omów wady i zalety aparatu kompaktowego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '6b50264d-0619-4218-af2e-1e13882edd77', 'question_id': 'bf21ca75-6ce8-4d4f-bbb5-bd5229b9dd9e', 'text': 'Zaleta: mały rozmiar i prostota obsługi. Wada: mała matryca i brak możliwości wymiany obiektywów.', 'is_correct': 1, 'sort_order': 0}, {'id': '190476b2-2739-4c05-9997-d1612db4c088', 'question_id': 'bf21ca75-6ce8-4d4f-bbb5-bd5229b9dd9e', 'text': 'Zaleta: ogromne rozmiary. Wada: robi tylko czarno-białe zdjęcia.', 'is_correct': 0, 'sort_order': 1}, {'id': '02c0acd4-91da-4603-bd03-6b14cdcaa7e1', 'question_id': 'bf21ca75-6ce8-4d4f-bbb5-bd5229b9dd9e', 'text': 'Zaleta: najwyższa na rynku jakość obrazu. Wada: brak przycisku migawki.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c99dcb85-8267-418c-b756-5bd6ebc5d2db', 'question_id': 'bf21ca75-6ce8-4d4f-bbb5-bd5229b9dd9e', 'text': 'Aparaty kompaktowe nie mają wad.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2ac34501-d452-4287-8595-b63746386a20', 'chapter_id': 2, 'text': 'Omów wady i zalety aparatu kompaktowego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Kompakty są idealne do codziennego użytku ze względu na mobilność. Ich głównym ograniczeniem jest jednak mniejsza plastyka obrazu i gorsza praca przy słabym świetle w porównaniu do lustrzanek czy bezlusterkowców z większymi matrycami.'}, {'id': '6a031c11-4a1d-4ca1-ae06-29552718b56c', 'chapter_id': 2, 'text': 'Rodzaje reflektorów używanych w studiach fotograficznych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '21924c9c-c6e7-4b02-8882-14680c809f44', 'question_id': '6a031c11-4a1d-4ca1-ae06-29552718b56c', 'text': 'Wyłącznie światła drogowe z samochodów.', 'is_correct': 0, 'sort_order': 0}, {'id': 'eea3c48c-12f1-499f-9fae-ca61046dd6f9', 'question_id': '6a031c11-4a1d-4ca1-ae06-29552718b56c', 'text': 'Czasze (beauty dish, standardowe), softboxy, parasolki, strumienice (snoot) i wrota.', 'is_correct': 1, 'sort_order': 1}, {'id': '66a415fa-d5bb-407c-9cf3-15ba3974febc', 'question_id': '6a031c11-4a1d-4ca1-ae06-29552718b56c', 'text': 'Lampy neonowe i diody choinkowe.', 'is_correct': 0, 'sort_order': 2}, {'id': '7baf0382-299d-4f41-bab5-cface3213933', 'question_id': '6a031c11-4a1d-4ca1-ae06-29552718b56c', 'text': 'Reflektory dzielimy na okrągłe i kwadratowe, bez innych różnic.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'ee64f1d2-9bd4-4efe-87eb-9cf9820400fc', 'chapter_id': 2, 'text': 'Rodzaje reflektorów używanych w studiach fotograficznych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Każdy modyfikator inaczej kształtuje światło: softboxy dają miękkie, rozproszone oświetlenie idealne do portretu, podczas gdy strumienice dają wąski, punktowy snop światła do oświetlania detali.'}, {'id': 'ce74a841-e87c-4c6e-bf45-a8835a5c1e5d', 'chapter_id': 2, 'text': 'Jakim cechom powinien odpowiadać aparat do zdjęć reportażowych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '0b54247d-371f-4f25-979f-1c1169bc8c7d', 'question_id': 'ce74a841-e87c-4c6e-bf45-a8835a5c1e5d', 'text': 'Musi być jak największy i najcięższy.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f9e59085-c823-4fee-86a3-1a8c75d9db3e', 'question_id': 'ce74a841-e87c-4c6e-bf45-a8835a5c1e5d', 'text': 'Szybki autofocus, wysoka czułość ISO bez szumów, wytrzymała obudowa i duża szybkość zdjęć seryjnych.', 'is_correct': 1, 'sort_order': 1}, {'id': 'c82a46f6-bb24-4155-9ca2-9a6251e89933', 'question_id': 'ce74a841-e87c-4c6e-bf45-a8835a5c1e5d', 'text': 'Powinien mieć tylko jeden przycisk i brak ekranu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b03b9fb1-cd7a-46b4-b1d5-deb358fdf67b', 'question_id': 'ce74a841-e87c-4c6e-bf45-a8835a5c1e5d', 'text': 'Musi mieć wbudowany głośnik do odtwarzania muzyki.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '058a1e98-f446-4385-a1d7-c197c15c0115', 'chapter_id': 2, 'text': 'Jakim cechom powinien odpowiadać aparat do zdjęć reportażowych?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W reportażu liczy się niezawodność i szybkość reakcji. Aparat musi radzić sobie w zmiennych warunkach oświetleniowych i pozwalać na błyskawiczną zmianę parametrów bez odrywania oka od wizjera.'}, {'id': '5daa8673-ca56-49c7-8596-6f774dc083a5', 'chapter_id': 2, 'text': 'Co to jest soczewka? Wymień rodzaje soczewek.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '46f6662a-898d-4a53-99e3-c52c02df4f64', 'question_id': '5daa8673-ca56-49c7-8596-6f774dc083a5', 'text': 'Kawałek plastiku służący do ochrony obiektywu przed kurzem.', 'is_correct': 0, 'sort_order': 0}, {'id': '4f0ae4e0-1b7e-47d9-8c22-4b8a718a9c17', 'question_id': '5daa8673-ca56-49c7-8596-6f774dc083a5', 'text': 'Przezroczyste ciało ograniczone dwiema powierzchniami krzywymi; dzielimy je na skupiające (wypukłe) i rozpraszające (wklęsłe).', 'is_correct': 1, 'sort_order': 1}, {'id': '25a18c66-a72b-41c8-a1b6-bb6927f931a8', 'question_id': '5daa8673-ca56-49c7-8596-6f774dc083a5', 'text': 'Elektroniczny element matrycy zbierający prąd.', 'is_correct': 0, 'sort_order': 2}, {'id': '331682ba-9126-4119-a47e-83228240ebb0', 'question_id': '5daa8673-ca56-49c7-8596-6f774dc083a5', 'text': 'Rodzaj okularów, które fotograf musi nosić w ciemni.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1250fceb-faad-4fa7-8445-21addf40aa3e', 'chapter_id': 2, 'text': 'Co to jest soczewka? Wymień rodzaje soczewek.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Soczewka załamuje promienie świetlne, tworząc obraz optyczny. W obiektywach fotograficznych stosuje się układy wielu soczewek o różnych kształtach i z różnych gatunków szkła, aby korygować wady optyczne.'}, {'id': '97bf1971-3c64-4c5a-989b-6c92f43171a0', 'chapter_id': 2, 'text': 'Wymień obiektywy fotograficzne i omów ich zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'bf74156a-ba3e-407c-98db-66f8ff0693f5', 'question_id': '97bf1971-3c64-4c5a-989b-6c92f43171a0', 'text': 'Szerokokątne (krajobraz), standardowe (naturalna perspektywa), teleobiektywy (zbliżenia) i makro (detale).', 'is_correct': 1, 'sort_order': 0}, {'id': '027958e4-7c40-4901-81e9-e16f5ff97ed9', 'question_id': '97bf1971-3c64-4c5a-989b-6c92f43171a0', 'text': 'Obiektywy dzielimy na szklane i plastikowe.', 'is_correct': 0, 'sort_order': 1}, {'id': '5d44d825-5c96-484f-acc6-fc898f7630d0', 'question_id': '97bf1971-3c64-4c5a-989b-6c92f43171a0', 'text': 'Wyłącznie obiektywy z zoomem, stałoogniskowe nie istnieją.', 'is_correct': 0, 'sort_order': 2}, {'id': '21c87d0a-dbaa-48e9-a77e-733445e04ed5', 'question_id': '97bf1971-3c64-4c5a-989b-6c92f43171a0', 'text': 'Wszystkie obiektywy służą do tego samego.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7bf66814-3f4e-40b1-9735-590f11445a10', 'chapter_id': 2, 'text': 'Wymień obiektywy fotograficzne i omów ich zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wybór obiektywu zależy od tematu zdjęcia. Szeroki kąt pozwala objąć dużą przestrzeń, teleobiektyw skraca perspektywę i pozwala fotografować z dystansu, a obiektyw makro umożliwia odwzorowanie przedmiotów w skali 1:1 lub większej.'}, {'id': 'd3e16d36-293d-444c-ab99-cf6de94f0121', 'chapter_id': 2, 'text': 'Omów wpływ rozdzielczości matrycy aparatu cyfrowego na jakość obrazu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'd98227b0-81f9-448e-8cbe-1b4eb64e5f75', 'question_id': 'd3e16d36-293d-444c-ab99-cf6de94f0121', 'text': 'Im więcej megapikseli, tym zawsze ładniejsze kolory na zdjęciu.', 'is_correct': 0, 'sort_order': 0}, {'id': '247f4523-2fd6-4673-86d9-2ae4342f7059', 'question_id': 'd3e16d36-293d-444c-ab99-cf6de94f0121', 'text': 'Wyższa rozdzielczość pozwala na większe powiększenia i lepsze odwzorowanie detali, ale może zwiększać szum przy małych matrycach.', 'is_correct': 1, 'sort_order': 1}, {'id': 'a5b698d4-d72e-4a27-bbd7-f3c230fb7071', 'question_id': 'd3e16d36-293d-444c-ab99-cf6de94f0121', 'text': 'Rozdzielczość matrycy wpływa tylko na wagę aparatu.', 'is_correct': 0, 'sort_order': 2}, {'id': '3fdb6dcd-3266-4961-9d46-b458d236a5b3', 'question_id': 'd3e16d36-293d-444c-ab99-cf6de94f0121', 'text': 'Matryca nie ma wpływu na jakość obrazu, liczy się tylko karta pamięci.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f748e034-aea6-4689-8e23-8cc542820d40', 'chapter_id': 2, 'text': 'Omów wpływ rozdzielczości matrycy aparatu cyfrowego na jakość obrazu.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Gęstość upakowania pikseli ma kluczowe znaczenie. Duża liczba megapikseli na małej matrycy może powodować spadek jakości obrazu przy wysokich czułościach ISO, dlatego profesjonalne aparaty łączą wysoką rozdzielczość z fizycznie dużym rozmiarem matrycy (np. Full Frame).'}, {'id': '3ade742e-91b8-4c8c-8185-3dafd0731e68', 'chapter_id': 2, 'text': 'Podaj jakie znasz typy aparatów w zależności od formatu materiału fotograficznego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f98edd92-643b-4026-b618-09acbfe3df31', 'question_id': '3ade742e-91b8-4c8c-8185-3dafd0731e68', 'text': 'Małoformatowe (35mm), średnioformatowe (6x6, 6x7 itp.) i wielkoformatowe (płyty).', 'is_correct': 1, 'sort_order': 0}, {'id': '2d5a9893-6916-467c-a113-934305520ca2', 'question_id': '3ade742e-91b8-4c8c-8185-3dafd0731e68', 'text': 'Aparaty pionowe i poziome.', 'is_correct': 0, 'sort_order': 1}, {'id': 'ea3745e9-1529-48b8-939d-166fb14bedcc', 'question_id': '3ade742e-91b8-4c8c-8185-3dafd0731e68', 'text': 'Aparaty papierowe i metalowe.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f18dec32-7527-4cec-bd98-7bc4277c307d', 'question_id': '3ade742e-91b8-4c8c-8185-3dafd0731e68', 'text': 'Format aparatu zależy tylko od wielkości ekranu LCD.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'ab8b8e4c-292c-4de5-b998-9b490bedf90a', 'chapter_id': 2, 'text': 'Podaj jakie znasz typy aparatów w zależności od formatu materiału fotograficznego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Format materiału determinuje jakość końcową i wielkość sprzętu. Mały obrazek to najpopularniejszy standard reportażowy, średni format jest ceniony w modzie i portrecie, a wielki format w fotografii reklamowej i architekturze ze względu na nieprawdopodobną szczegółowość.'}, {'id': 'f9111f5d-6fbb-4540-82d2-8593e5c3d763', 'chapter_id': 2, 'text': 'Omów wady soczewek.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '6a7f6d20-5ad8-4364-83e5-f229047e0e54', 'question_id': 'f9111f5d-6fbb-4540-82d2-8593e5c3d763', 'text': 'Soczewki nie posiadają żadnych wad.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd402cc2a-86b6-482a-be31-76868659926b', 'question_id': 'f9111f5d-6fbb-4540-82d2-8593e5c3d763', 'text': 'Aberracja chromatyczna (kolorowe obwódki), sferyczna (nieostrość), dystorsja i winietowanie.', 'is_correct': 1, 'sort_order': 1}, {'id': '8eb82846-339a-4b50-863c-d738822d1f9a', 'question_id': 'f9111f5d-6fbb-4540-82d2-8593e5c3d763', 'text': 'Główną wadą jest to, że są przezroczyste.', 'is_correct': 0, 'sort_order': 2}, {'id': '2b057c1b-123e-4774-b28b-24d0cf7744ce', 'question_id': 'f9111f5d-6fbb-4540-82d2-8593e5c3d763', 'text': 'Wada soczewki polega na tym, że trzeba ją czyścić co 5 minut.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '9a3dbd58-ba82-40b8-8483-553ae9ab4d8d', 'chapter_id': 2, 'text': 'Omów wady soczewek.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wady (aberracje) wynikają z praw fizyki. Przykładowo aberracja chromatyczna powstaje, bo światło o różnych kolorach załamuje się pod różnymi kątami, co skutkuje tęczowymi obwódkami na kontrastowych krawędziach obrazu.'}, {'id': '5180d214-a3bf-48d4-837a-874b08ffa3eb', 'chapter_id': 2, 'text': 'Omów obiektyw szerokokątny i jego zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1f0bdbee-f301-40cc-adc3-e493a85cd8d2', 'question_id': '5180d214-a3bf-48d4-837a-874b08ffa3eb', 'text': 'Służy tylko do robienia zdjęć bardzo małym mrówkom.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e42ca7d4-a512-4172-94b9-cbc6b741c034', 'question_id': '5180d214-a3bf-48d4-837a-874b08ffa3eb', 'text': 'Posiada krótką ogniskową i szeroki kąt widzenia; stosowany w fotografii architektury, wnętrz i krajobrazu.', 'is_correct': 1, 'sort_order': 1}, {'id': '11a103b1-d976-4ee3-9f4a-c958beeeffc5', 'question_id': '5180d214-a3bf-48d4-837a-874b08ffa3eb', 'text': 'Powoduje, że wszystkie obiekty na zdjęciu wydają się bardzo bliskie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd624b4b4-d158-4ae8-9c38-e1bb22d93f53', 'question_id': '5180d214-a3bf-48d4-837a-874b08ffa3eb', 'text': 'Obiektyw szerokokątny nie nadaje się do robienia zdjęć w kolorze.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'ff8dfed0-eaad-46f1-8695-36528584a149', 'chapter_id': 2, 'text': 'Omów obiektyw szerokokątny i jego zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obiektywy te (poniżej 35mm dla pełnej klatki) pozwalają na ujęcie szerokiej sceny z niewielkiej odległości. Charakteryzują się dużą głębią ostrości, ale mogą powodować przerysowania perspektywiczne przy brzegach kadru.'}, {'id': '9cb1d121-60cf-4343-80cf-32d3ead67a7c', 'chapter_id': 2, 'text': 'Co to jest obiektyw standardowy, szerokokątny i długoogniskowy?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '9e131a73-d071-469f-a0ae-4c2ffecae476', 'question_id': '9cb1d121-60cf-4343-80cf-32d3ead67a7c', 'text': 'Standard (kąt zbliżony do ludzkiego oka), szeroki (szeroki kąt), długoogniskowy (wąski kąt, duże przybliżenie).', 'is_correct': 1, 'sort_order': 0}, {'id': '943452e6-2136-41f3-ab25-f15c1855a4bd', 'question_id': '9cb1d121-60cf-4343-80cf-32d3ead67a7c', 'text': 'To nazwy marek produkujących obiektywy.', 'is_correct': 0, 'sort_order': 1}, {'id': '4290994f-4e1e-4ea0-b016-162ccfebfecf', 'question_id': '9cb1d121-60cf-4343-80cf-32d3ead67a7c', 'text': 'Każdy z nich służy do tego samego, różnią się tylko ceną.', 'is_correct': 0, 'sort_order': 2}, {'id': 'aa21d2fd-d20e-4645-b6c7-ff17707cbb35', 'question_id': '9cb1d121-60cf-4343-80cf-32d3ead67a7c', 'text': 'Standardowy to taki, który jest zawsze brudny.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '6ce2d8b5-a39f-4c67-832e-65844c3b8a3a', 'chapter_id': 2, 'text': 'Co to jest obiektyw standardowy, szerokokątny i długoogniskowy?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Dla formatu 35mm obiektyw 50mm jest uznawany za standard. Obiektywy o krótszej ogniskowej to szerokokątne, a o dłuższej (powyżej 80-100mm) to teleobiektywy (długoogniskowe), które służą do wyławiania detali z oddali.'}, {'id': '05f07e5f-f1e8-4f90-81a0-aa1cd504c384', 'chapter_id': 2, 'text': 'Omów budowę powiększalnika i rolę zegara ciemniowego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'fb20863b-fb9c-4860-ae6c-918f4df93aef', 'question_id': '05f07e5f-f1e8-4f90-81a0-aa1cd504c384', 'text': 'Budowa: głowica, kolumna, podstawa. Zegar precyzyjnie odmierza czas naświetlania papieru.', 'is_correct': 1, 'sort_order': 0}, {'id': '72c6a245-c05d-417f-8650-06791768a9f1', 'question_id': '05f07e5f-f1e8-4f90-81a0-aa1cd504c384', 'text': 'Budowa: tylko żarówka. Zegar służy do sprawdzania, która jest godzina w nocy.', 'is_correct': 0, 'sort_order': 1}, {'id': '754a57de-8dc8-469b-8873-76a079e58085', 'question_id': '05f07e5f-f1e8-4f90-81a0-aa1cd504c384', 'text': 'Powiększalnik nie ma budowy, to jednolity blok szkła.', 'is_correct': 0, 'sort_order': 2}, {'id': 'fe3bec55-f1fd-47d7-bb52-998bf17a0b2e', 'question_id': '05f07e5f-f1e8-4f90-81a0-aa1cd504c384', 'text': 'Zegar ciemniowy służy do gotowania wywoływacza.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '57da0c4a-e5f6-4c7f-90df-9291188583ca', 'chapter_id': 2, 'text': 'Omów budowę powiększalnika i rolę zegara ciemniowego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Zegar ciemniowy jest kluczowy dla powtarzalności wyników. Steruje on włączaniem i wyłączaniem lampy powiększalnika z dokładnością do ułamka sekundy, co pozwala na precyzyjne dawkowanie światła na papier.'}, {'id': '7ff5cea0-98d4-456a-873f-da0da77baf1e', 'chapter_id': 2, 'text': 'Z jakich elementów składa się aparat fotograficzny?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '230f3f23-b90f-431e-b2cb-209a96e65e12', 'question_id': '7ff5cea0-98d4-456a-873f-da0da77baf1e', 'text': 'Obiektyw, korpus (body), układ celowniczy, migawka, przysłona i element światłoczuły.', 'is_correct': 1, 'sort_order': 0}, {'id': '9bf4dd1a-2392-47aa-8400-47207feeb8ce', 'question_id': '7ff5cea0-98d4-456a-873f-da0da77baf1e', 'text': 'Tylko z guzika i baterii.', 'is_correct': 0, 'sort_order': 1}, {'id': 'c52bebd0-ab5a-416e-b495-dcca218cb506', 'question_id': '7ff5cea0-98d4-456a-873f-da0da77baf1e', 'text': 'Z rzutnika i ekranu.', 'is_correct': 0, 'sort_order': 2}, {'id': '5f5186c4-f8bc-49fa-87b0-7815cd110882', 'question_id': '7ff5cea0-98d4-456a-873f-da0da77baf1e', 'text': 'Aparat składa się wyłącznie z obiektywu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '9af5d425-972b-439a-aab1-8eade37c732d', 'chapter_id': 2, 'text': 'Z jakich elementów składa się aparat fotograficzny?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Korpus jest światłoszczelną komorą chroniącą medium rejestrujące. Obiektyw zbiera światło, przysłona reguluje jego ilość, a migawka kontroluje czas, w jakim to światło pada na matrycę lub film.'}, {'id': '7cde3562-b648-414d-a4e8-629fa479c06a', 'chapter_id': 2, 'text': 'Omów pracę minilaba fotograficznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '8ae8a897-15c8-469a-b8f0-57c828e103e5', 'question_id': '7cde3562-b648-414d-a4e8-629fa479c06a', 'text': 'To urządzenie do automatycznego wywoływania filmów i wykonywania odbitek w dużych ilościach.', 'is_correct': 1, 'sort_order': 0}, {'id': '28face18-5a08-436a-b7b5-40777c90c952', 'question_id': '7cde3562-b648-414d-a4e8-629fa479c06a', 'text': 'To mały pokój (laboratorium), w którym pracuje tylko jeden karzeł.', 'is_correct': 0, 'sort_order': 1}, {'id': 'e54e3584-113f-4670-8046-9a272d4ed963', 'question_id': '7cde3562-b648-414d-a4e8-629fa479c06a', 'text': 'Urządzenie służące wyłącznie do robienia zdjęć legitymacyjnych.', 'is_correct': 0, 'sort_order': 2}, {'id': '93469a20-69e4-4fe7-894d-e356db06b168', 'question_id': '7cde3562-b648-414d-a4e8-629fa479c06a', 'text': 'Maszyna do niszczenia starych negatywów.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'af17d7a3-d1d7-417c-9610-ae8479497b65', 'chapter_id': 2, 'text': 'Omów pracę minilaba fotograficznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Współczesne minilaby pracują w systemie hybrydowym: wywołują negatyw w procesie C-41, skanują go do postaci cyfrowej, a następnie naświetlają laserem papier fotograficzny, który przechodzi przez proces chemiczny RA-4.'}, {'id': '6c21dfb6-e810-424e-90d8-954626638867', 'chapter_id': 2, 'text': 'Co to jest filtr polaryzacyjny? Omów jego zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'b4b1b2a4-6742-4f20-86cf-1f6eb90634cf', 'question_id': '6c21dfb6-e810-424e-90d8-954626638867', 'text': 'Służy do zmiany koloru zdjęcia na całkowicie niebieski.', 'is_correct': 0, 'sort_order': 0}, {'id': 'be53004c-d68f-4a4a-b837-83c465ac06eb', 'question_id': '6c21dfb6-e810-424e-90d8-954626638867', 'text': 'Filtr, który wygasza odblaski od powierzchni niemetalicznych i nasyca błękit nieba.', 'is_correct': 1, 'sort_order': 1}, {'id': '8b78e516-101d-4219-9d03-f3b107bc6570', 'question_id': '6c21dfb6-e810-424e-90d8-954626638867', 'text': 'To kawałek papieru ściernego do czyszczenia soczewek.', 'is_correct': 0, 'sort_order': 2}, {'id': 'db8166e1-2db2-4558-b6a2-b0142f11f5e0', 'question_id': '6c21dfb6-e810-424e-90d8-954626638867', 'text': 'Filtr ten sprawia, że aparat widzi przez ściany.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f3c8e6e0-d01c-4422-9c70-330078a43027', 'chapter_id': 2, 'text': 'Co to jest filtr polaryzacyjny? Omów jego zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W praktyce filtr ten jest niezastąpiony przy fotografowaniu przez szyby lub wodę, ponieważ pozwala "zajrzeć" pod powierzchnię refleksu. Najsilniej działa pod kątem 90 stopni względem padających promieni słonecznych.'}, {'id': '51240b1b-32fc-4772-83b2-d941e4874a60', 'chapter_id': 2, 'text': 'Opisz budowę lustrzanki dwuobiektywowej (TLR).', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '9ddddae2-09f8-4ab1-bd81-37b98c685da3', 'question_id': '51240b1b-32fc-4772-83b2-d941e4874a60', 'text': 'Posiada dwa obiektywy: górny do celowania i dolny do robienia zdjęcia, oraz matówkę na górze korpusu.', 'is_correct': 1, 'sort_order': 0}, {'id': '6c16c616-4f48-48d3-ad55-6496a2a670a3', 'question_id': '51240b1b-32fc-4772-83b2-d941e4874a60', 'text': 'Posiada dwa obiektywy obok siebie do robienia zdjęć 3D.', 'is_correct': 0, 'sort_order': 1}, {'id': 'ab490396-72f5-4967-a42e-6bc238534a2f', 'question_id': '51240b1b-32fc-4772-83b2-d941e4874a60', 'text': 'Jeden obiektyw służy do koloru, a drugi do czarno-białego.', 'is_correct': 0, 'sort_order': 2}, {'id': 'bb16d495-0d57-45f7-9a79-6bb1b9e84ae5', 'question_id': '51240b1b-32fc-4772-83b2-d941e4874a60', 'text': 'To aparat, w którym jeden obiektyw jest zapasowy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd5f1e6be-6229-4878-ae7a-1aece47fb9bb', 'chapter_id': 2, 'text': 'Opisz budowę lustrzanki dwuobiektywowej (TLR).', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Klasycznym przykładem jest aparat Rolleiflex. Obiektyw celowniczy rzutuje obraz przez stałe lustro na matówkę, co pozwala na kadrowanie z poziomu pasa, podczas gdy obiektyw fotografujący posiada migawkę centralną i naświetla film umieszczony z tyłu.'}, {'id': '08c1ef13-8754-4d62-98cb-2fff62abadef', 'chapter_id': 2, 'text': 'Co wpływa na ziarnistość negatywu?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'db2f65d3-e009-4e90-a60c-17bfe1c1bc7a', 'question_id': '08c1ef13-8754-4d62-98cb-2fff62abadef', 'text': 'Czułość filmu (ISO), rodzaj wywoływacza, temperatura obróbki i stopień powiększenia.', 'is_correct': 1, 'sort_order': 0}, {'id': 'a3e1ee1f-78a4-40a3-9baa-556a057a20d1', 'question_id': '08c1ef13-8754-4d62-98cb-2fff62abadef', 'text': 'Wyłącznie to, czy zdjęcie robiono w dzień, czy w nocy.', 'is_correct': 0, 'sort_order': 1}, {'id': '2d23d673-3f22-451d-a39f-92b49bb8ad83', 'question_id': '08c1ef13-8754-4d62-98cb-2fff62abadef', 'text': 'Kolor puszki, w której znajdował się film.', 'is_correct': 0, 'sort_order': 2}, {'id': '0411ae6b-242c-4b6e-bd54-21cbc60b2ffa', 'question_id': '08c1ef13-8754-4d62-98cb-2fff62abadef', 'text': 'Ziarnistość zależy tylko od jakości statywu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '890fed31-d4d2-41f6-b0c7-76b8b6052ae4', 'chapter_id': 2, 'text': 'Co wpływa na ziarnistość negatywu?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Im wyższa czułość filmu, tym większe kryształy srebra i bardziej widoczne ziarno. Przewołanie filmu (zbyt wysoka temperatura lub zbyt długi czas) również potęguje efekt ziarnistości, co pogarsza ostrość konturową obrazu.'}, {'id': '4cd89340-c6c5-4ce9-9050-6d11474ffbb8', 'chapter_id': 2, 'text': 'Jakie znamy rodzaje soczewek? (powtórzenie)', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '567f8b10-e091-40f0-a0ae-07c757c3e7c3', 'question_id': '4cd89340-c6c5-4ce9-9050-6d11474ffbb8', 'text': 'Skupiające, rozpraszające, płaskie, sferyczne i asferyczne.', 'is_correct': 1, 'sort_order': 0}, {'id': '3d15f51e-ad63-4d4a-89d1-ed29a2524809', 'question_id': '4cd89340-c6c5-4ce9-9050-6d11474ffbb8', 'text': 'Tylko soczewki kontaktowe do oczu.', 'is_correct': 0, 'sort_order': 1}, {'id': '7a2e8629-e5dc-4ca5-9df4-2f9cde850b9f', 'question_id': '4cd89340-c6c5-4ce9-9050-6d11474ffbb8', 'text': 'Soczewki dzielimy na letnie i zimowe.', 'is_correct': 0, 'sort_order': 2}, {'id': '03838cea-981b-4779-a6c2-ade891029ab4', 'question_id': '4cd89340-c6c5-4ce9-9050-6d11474ffbb8', 'text': 'Wszystkie soczewki są takie same.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4b53ed4f-5148-42ee-bd0e-6bc29ebc3e80', 'chapter_id': 2, 'text': 'Jakie znamy rodzaje soczewek? (powtórzenie)', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W zaawansowanych obiektywach stosuje się soczewki asferyczne, które mają bardziej skomplikowany kształt niż wycinek kuli, co pozwala na skuteczniejszą korekcję wad obrazu przy mniejszej liczbie elementów szklanych.'}, {'id': '309a5553-5ef9-4aeb-b3f8-974b3efc0874', 'chapter_id': 2, 'text': 'Wymień rodzaje aparatów cyfrowych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '14e27b5d-9445-4d2e-b99d-3fd747c41350', 'question_id': '309a5553-5ef9-4aeb-b3f8-974b3efc0874', 'text': 'Kompaktowe, bezlusterkowce, lustrzanki (DSLR) oraz aparaty w smartfonach.', 'is_correct': 1, 'sort_order': 0}, {'id': '73a8f4fb-7517-442f-b7a1-6c94cb1c8aab', 'question_id': '309a5553-5ef9-4aeb-b3f8-974b3efc0874', 'text': 'Aparaty cyfrowe dzielimy na te z kablem i bez kabla.', 'is_correct': 0, 'sort_order': 1}, {'id': '7eee82d9-2874-44e8-a231-d4e4917f81be', 'question_id': '309a5553-5ef9-4aeb-b3f8-974b3efc0874', 'text': 'Wyłącznie aparaty, które drukują zdjęcia od razu.', 'is_correct': 0, 'sort_order': 2}, {'id': '5ade5b96-b499-4ad6-b24c-e6e5adbb844f', 'question_id': '309a5553-5ef9-4aeb-b3f8-974b3efc0874', 'text': 'Są tylko dwa rodzaje: czarne i srebrne.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'baffa5bc-f9a3-49bc-8231-41976f9b275b', 'chapter_id': 2, 'text': 'Wymień rodzaje aparatów cyfrowych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Podstawowy podział dotyczy wielkości matrycy oraz możliwości wymiany optyki. Lustrzanki posiadają ruchome lustro i wizjer optyczny, podczas gdy bezlusterkowce oferują podgląd bezpośrednio z matrycy na ekranie lub w wizjerze elektronicznym.'}, {'id': '4d59af8b-2602-4397-895b-017dcebb2953', 'chapter_id': 2, 'text': 'Omów funkcję i znaczenie przesłony w obiektywie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f58c8591-8101-4da7-ae89-f06542c74cb0', 'question_id': '4d59af8b-2602-4397-895b-017dcebb2953', 'text': 'Reguluje ilość światła wpadającego do aparatu oraz wpływa na głębię ostrości.', 'is_correct': 1, 'sort_order': 0}, {'id': 'b248ac38-4d94-45e1-91d2-1ffb7aeef8b5', 'question_id': '4d59af8b-2602-4397-895b-017dcebb2953', 'text': 'Służy do zasłaniania obiektywu po zakończeniu pracy.', 'is_correct': 0, 'sort_order': 1}, {'id': 'b3883f77-b266-4691-9142-c1a9c2f93227', 'question_id': '4d59af8b-2602-4397-895b-017dcebb2953', 'text': 'Przesłona decyduje tylko o tym, jak głośne jest zdjęcie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd53aa3bf-e780-4116-b9fd-1a46a716527f', 'question_id': '4d59af8b-2602-4397-895b-017dcebb2953', 'text': 'Odpowiada za kolorystykę zdjęcia (balans bieli).', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f3f9a203-5e0b-473a-bedd-cbfd7e9173a8', 'chapter_id': 2, 'text': 'Omów funkcję i znaczenie przesłony w obiektywie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Przymykanie przysłony (zwiększanie liczby f) skutkuje mniejszą ilością światła, ale większą głębią ostrości. Otwieranie przysłony pozwala na fotografowanie w ciemności i uzyskanie efektu rozmytego tła (bokeh).'}, {'id': '8a71e75b-1fb5-46d1-9aa7-d697717e5040', 'chapter_id': 2, 'text': 'Scharakteryzuj przysłonę i jej funkcję w praktyce.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'd3c46276-1dc7-405d-9c77-23f576234642', 'question_id': '8a71e75b-1fb5-46d1-9aa7-d697717e5040', 'text': 'To mechanizm z listków, który zmienia średnicę otworu względnego obiektywu.', 'is_correct': 1, 'sort_order': 0}, {'id': 'c7702235-94a5-4d7e-892a-710439d12265', 'question_id': '8a71e75b-1fb5-46d1-9aa7-d697717e5040', 'text': 'To elektroniczny filtr nakładany na matrycę.', 'is_correct': 0, 'sort_order': 1}, {'id': '4b58592e-348e-41ef-96e6-b3cc6f8dbfff', 'question_id': '8a71e75b-1fb5-46d1-9aa7-d697717e5040', 'text': 'Przysłona służy do powiększania zdjęcia wewnątrz aparatu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'dec35575-d43b-4aee-b25e-716904af634c', 'question_id': '8a71e75b-1fb5-46d1-9aa7-d697717e5040', 'text': 'Jest to rodzaj lampy błyskowej wbudowanej w szkło.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '87bc3552-1c63-4a1f-8db1-613a4bd45902', 'chapter_id': 2, 'text': 'Scharakteryzuj przysłonę i jej funkcję w praktyce.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W praktyce wybór przysłony to kompromis między czasem naświetlania a pożądaną głębią ostrości. Każdy obiektyw ma też swoją "optymalną" przysłonę (zazwyczaj w środku skali), przy której generuje najbardziej ostry obraz.'}, {'id': '6685b7be-3e4f-4f87-879d-1071dcb3f4af', 'chapter_id': 2, 'text': 'Jakie zadanie spełnia przysłona i co oznaczają liczby?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ccac0a25-0cab-49db-867b-ed0396af3e05', 'question_id': '6685b7be-3e4f-4f87-879d-1071dcb3f4af', 'text': 'Liczby f określają stosunek ogniskowej do średnicy otworu; im mniejsza liczba, tym większy otwór.', 'is_correct': 1, 'sort_order': 0}, {'id': '3985f672-53aa-4219-8140-1c1e125f6062', 'question_id': '6685b7be-3e4f-4f87-879d-1071dcb3f4af', 'text': 'Liczby oznaczają wagę obiektywu w gramach.', 'is_correct': 0, 'sort_order': 1}, {'id': 'db6a9271-58df-4ef2-9690-85fa5efbf5f8', 'question_id': '6685b7be-3e4f-4f87-879d-1071dcb3f4af', 'text': 'Liczby f oznaczają liczbę soczewek wewnątrz obiektywu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b910efa3-19e2-48ef-8138-50dc82efc2a2', 'question_id': '6685b7be-3e4f-4f87-879d-1071dcb3f4af', 'text': 'Są to numery seryjne części zamiennych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '23d2bc6a-7606-4cdd-beeb-82071a32f6ef', 'chapter_id': 2, 'text': 'Jakie zadanie spełnia przysłona i co oznaczają liczby?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Przysłona kontroluje natężenie światła. Skala liczb f jest logarytmiczna – każda kolejna pełna wartość (np. z 4 na 5,6) oznacza dwukrotne zmniejszenie ilości światła docierającego do medium.'}, {'id': '9ef68f29-2b18-41db-9cf6-20fad1b0442c', 'chapter_id': 2, 'text': 'Współzależność liczb: 2, 2.8, 4, 5.6, 8, 11, 16, 22.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '2fac9172-07f4-43d1-9ebe-db650a45f076', 'question_id': '9ef68f29-2b18-41db-9cf6-20fad1b0442c', 'text': 'Każda kolejna liczba oznacza dwukrotne zmniejszenie (lub przy otwieraniu – zwiększenie) powierzchni otworu przysłony.', 'is_correct': 1, 'sort_order': 0}, {'id': '248113da-ad88-4d2d-9e46-3532ce33466e', 'question_id': '9ef68f29-2b18-41db-9cf6-20fad1b0442c', 'text': 'Są to numery kanałów w radiu fotograficznym.', 'is_correct': 0, 'sort_order': 1}, {'id': '8adbcb08-de04-4a50-834d-5ec0957e9b5d', 'question_id': '9ef68f29-2b18-41db-9cf6-20fad1b0442c', 'text': 'Liczby te oznaczają maksymalną odległość w metrach, na jaką można zrobić zdjęcie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'dfab05d6-c1c8-4bd5-8017-dc5280bbda23', 'question_id': '9ef68f29-2b18-41db-9cf6-20fad1b0442c', 'text': 'Nie ma między nimi żadnej stałej współzależności.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1e36a15f-3a91-4c89-a22a-75a28647826d', 'chapter_id': 2, 'text': 'Współzależność liczb: 2, 2.8, 4, 5.6, 8, 11, 16, 22.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Jest to znormalizowany ciąg geometryczny o ilorazie pierwiastek z 2. Zmiana o jeden "stop" na tej skali wymaga dwukrotnej zmiany czasu naświetlania, aby zachować tę samą ekspozycję zdjęcia.'}, {'id': '3a0243b7-3dc9-4b94-8014-e1e2995eb247', 'chapter_id': 2, 'text': 'Gdzie występuje migawka centralna i omów jej zalety.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '38d7336e-23a7-411d-8ad4-6a2108ea4ed8', 'question_id': '3a0243b7-3dc9-4b94-8014-e1e2995eb247', 'text': 'W aparatach kompaktowych cyfrowych; zaletą jest niska cena i cicha praca.', 'is_correct': 0, 'sort_order': 0}, {'id': '469cbeeb-ff7b-4998-bedd-1f22007fcc1d', 'question_id': '3a0243b7-3dc9-4b94-8014-e1e2995eb247', 'text': 'W aparatach średnioformatowych i dużego formatu; zalety to synchronizacja z lampą błyskową na wszystkich czasach oraz brak zniekształceń obrazu przy szybkich ruchach.', 'is_correct': 1, 'sort_order': 1}, {'id': 'c98014e7-7722-428f-bb61-b18e5d0cbaed', 'question_id': '3a0243b7-3dc9-4b94-8014-e1e2995eb247', 'text': 'Wyłącznie w aparatach jednorazowych; zaletą jest wodoodporność.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a6fef6b7-3da9-4fe5-abdb-7a66bc96c28c', 'question_id': '3a0243b7-3dc9-4b94-8014-e1e2995eb247', 'text': 'W telefonach komórkowych; zaletą jest możliwość pracy z czasem do 1/16000 s.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'dc53e94f-ee1d-4f72-8632-bda13be7ee28', 'chapter_id': 2, 'text': 'Gdzie występuje migawka centralna i omów jej zalety.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Migawka centralna występuje najczęściej w aparatach średnioformatowych (np. 6×6 cm) oraz wielkoformatowych. Jej główne zalety to możliwość synchronizacji z lampą błyskową przy każdym dostępnym czasie naświetlania oraz brak zniekształceń kadłubowych (rolling shutter), ponieważ cała powierzchnia kliszy jest naświetlana jednocześnie, a nie przesuwającą się szczeliną.'}, {'id': '9ece6c63-500d-4ed5-b903-a56ed40d7719', 'chapter_id': 2, 'text': 'Omów filtry zdjęciowe do fotografii czarno-białej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'fe6e4c24-67ae-4945-ae99-c7484d3461ac', 'question_id': '9ece6c63-500d-4ed5-b903-a56ed40d7719', 'text': 'Filtry UV, polaryzacyjne i szare; służą do ochrony obiektywu i redukcji ilości światła.', 'is_correct': 0, 'sort_order': 0}, {'id': '6057cbe8-aca0-4c62-a02c-403b719990fc', 'question_id': '9ece6c63-500d-4ed5-b903-a56ed40d7719', 'text': 'Filtry barwne (żółty, pomarańczowy, czerwony, zielony), które zmieniają tonalność szarości obiektów kolorowych na zdjęciach czarno-białych.', 'is_correct': 1, 'sort_order': 1}, {'id': 'cbdbf5c8-e8dd-4b57-b46c-3727bad6835a', 'question_id': '9ece6c63-500d-4ed5-b903-a56ed40d7719', 'text': 'Wyłącznie filtry rozmywające i gwieździste; służą do efektów specjalnych.', 'is_correct': 0, 'sort_order': 2}, {'id': '58052420-b373-49fc-9b4c-ed7007816664', 'question_id': '9ece6c63-500d-4ed5-b903-a56ed40d7719', 'text': 'Filtry ciepłe i zimne; służą do korekcji temperatury barwowej światła.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f7b4dd0c-cdd8-4160-adbf-45686d08cc3c', 'chapter_id': 2, 'text': 'Omów filtry zdjęciowe do fotografii czarno-białej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W fotografii czarno-białej stosuje się filtry barwne, które przepuszczają własny kolor i blokują barwy dopełniające. Filtr żółty rozjaśnia niebo i ciemnieje liście, pomarańczowy i czerwony wzmacniają ten efekt, dramatycznie kontrastując chmury z niebem, a filtr zielony rozjaśnia roślinność, co jest przydatne w zdjęciach krajobrazowych i ogrodowych.'}, {'id': '08a85ca8-12f2-44de-99d4-dc155730a21c', 'chapter_id': 2, 'text': 'Jaki jest cel stosowania filtrów w fotografii?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1aa70d95-ce3f-4230-987b-df1981f109f7', 'question_id': '08a85ca8-12f2-44de-99d4-dc155730a21c', 'text': 'Wyłącznie do zmiany kształtu obiektywu i zmniejszenia jego wagi.', 'is_correct': 0, 'sort_order': 0}, {'id': '55849392-869e-4cf0-ad83-702c68a88b2b', 'question_id': '08a85ca8-12f2-44de-99d4-dc155730a21c', 'text': 'Korekcja ekspozycji, korekcja barw, eliminacja odblasków, tworzenie efektów specjalnych oraz ochrona przedniej soczewki.', 'is_correct': 1, 'sort_order': 1}, {'id': 'a0699ee4-ff74-4903-990b-b87942562f59', 'question_id': '08a85ca8-12f2-44de-99d4-dc155730a21c', 'text': 'Tylko do zwiększenia rozdzielczości matrycy cyfrowej.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b0244a2a-eb50-4f4b-b4da-30861d9f848c', 'question_id': '08a85ca8-12f2-44de-99d4-dc155730a21c', 'text': 'Wyłącznie do dezynfekcji obiektywu przed użyciem.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '92033bfb-cb0d-4fa8-9735-e51f02fb84e6', 'chapter_id': 2, 'text': 'Jaki jest cel stosowania filtrów w fotografii?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Filtry fotograficzne pełnią wiele funkcji: filtry szare (ND) pozwalają na dłuższe czasy naświetlania lub większe przysłony, filtry polaryzacyjne usuwają niepożądane refleksy i nasycają barwy, filtry korekcyjne dostosowują temperaturę barwową do rodzaju filmu lub źródła światła, a filtry efektowe (rozmywające, gwieździste) pozwalają na kreatywną ingerencję w obraz. Filtr UV lub ochronny zabezpiecza też przedni element obiektywu przed zarysowaniami.'}, {'id': 'de690717-a7b9-49c6-851b-acb54df2d2ea', 'chapter_id': 2, 'text': 'Uzasadnij, czy obiektyw o ogniskowej 50mm jest standardowym dla filmu 24×36mm i do jakich tematów fotograficznych go użyjesz?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f79adbc2-a12f-4306-b84c-75d5d6d09571', 'question_id': 'de690717-a7b9-49c6-851b-acb54df2d2ea', 'text': 'Nie, to obiektyw szerokokątny; używa się go wyłącznie do zdjęć krajobrazowych.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c9144f2d-555b-4d7a-987e-80ac66ceac08', 'question_id': 'de690717-a7b9-49c6-851b-acb54df2d2ea', 'text': 'Tak, 50mm to klasyczny obiektyw standardowy dla formatu 24×36mm, ponieważ jego kąt widzenia jest zbliżony do ludzkiego oka; używa się go do portretów, reportażu i fotografii ulicznej.', 'is_correct': 1, 'sort_order': 1}, {'id': '299d7a18-ef91-493a-9e9c-f9f2889c165f', 'question_id': 'de690717-a7b9-49c6-851b-acb54df2d2ea', 'text': 'Nie, to obiektyw tele; stosuje się go tylko do sportu i dzikiej przyrody.', 'is_correct': 0, 'sort_order': 2}, {'id': '583ef2e9-5bb0-42fe-908c-832f40801b76', 'question_id': 'de690717-a7b9-49c6-851b-acb54df2d2ea', 'text': 'Tak, ale tylko do fotografii makro i mikro.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4757eb09-cd6f-490b-8846-d86abd97a92d', 'chapter_id': 2, 'text': 'Uzasadnij, czy obiektyw o ogniskowej 50mm jest standardowym dla filmu 24×36mm i do jakich tematów fotograficznych go użyjesz?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obiektyw 50mm dla formatu 24×36mm uznawany jest za standardowy, ponieważ jego przekątna kąta widzenia (ok. 46°) jest zbliżona do naturalnego pola widzenia ludzkiego oka. Jest to uniwersalna ogniskowa, którą wykorzystuje się w fotografii portretowej, reporterskiej, ulicznej oraz do ogólnych zastosowań codziennych ze względu na niewielkie zniekształcenia perspektywiczne i dużą jasność.'}, {'id': '2f3503dc-eaad-4bbb-95fa-664cbfcebf60', 'chapter_id': 2, 'text': 'Omów budowę aparatu fotograficznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '7ed5c756-e095-4fc7-b3de-6f2afa00ad72', 'question_id': '2f3503dc-eaad-4bbb-95fa-664cbfcebf60', 'text': 'Korpus, obiektyw, przysłona, migawka, materiał światłoczuły lub matryca, wizjer, układ pomiaru światła.', 'is_correct': 1, 'sort_order': 0}, {'id': '08cbdf01-3fa9-4ef0-b7a0-38cc7de2affa', 'question_id': '2f3503dc-eaad-4bbb-95fa-664cbfcebf60', 'text': 'Tylko obiektyw i karta pamięci.', 'is_correct': 0, 'sort_order': 1}, {'id': 'eb42675e-026f-40fa-9f98-92e83b2db196', 'question_id': '2f3503dc-eaad-4bbb-95fa-664cbfcebf60', 'text': 'Tylko matryca i wyświetlacz LCD.', 'is_correct': 0, 'sort_order': 2}, {'id': '0beaa6e8-cfd6-4d17-8007-cfd40200408b', 'question_id': '2f3503dc-eaad-4bbb-95fa-664cbfcebf60', 'text': 'Korpus, lampa błyskowa i pasek na ramię.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'fb1805f7-562c-44a3-aed6-75860982d72a', 'chapter_id': 2, 'text': 'Omów budowę aparatu fotograficznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Aparat fotograficzny składa się z korpusu stanowiącego szkielet urządzenia, obiektywu zawierającego układ optyczny skupiający światło, przysłony regulującej ilość przepuszczanego światła, migawki kontrolującej czas ekspozycji, materiału światłoczułego lub matrycy cyfrowej rejestrującej obraz, wizjera służącego do kadrowania oraz układu pomiaru światła (światłomierza) pozwalającego na prawidłowe naświetlenie.'}, {'id': '555d2e38-8b49-4dce-9453-8b1c3d7b9976', 'chapter_id': 2, 'text': 'Jakie znasz urządzenia do otrzymywania obrazów fotograficznych na podłożu papierowym z plików cyfrowych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '0074c108-e016-46aa-883a-d6105758111f', 'question_id': '555d2e38-8b49-4dce-9453-8b1c3d7b9976', 'text': 'Wyłącznie kserokopiarki i skanery.', 'is_correct': 0, 'sort_order': 0}, {'id': '3477ac97-011d-44e4-a842-bab5709b7844', 'question_id': '555d2e38-8b49-4dce-9453-8b1c3d7b9976', 'text': 'Drukarki atramentowe, sublimacyjne, minilaby cyfrowe oraz ekspozytory LED na papier światłoczuły.', 'is_correct': 1, 'sort_order': 1}, {'id': '9556f102-12d6-41fa-8e68-1dc2c650fd81', 'question_id': '555d2e38-8b49-4dce-9453-8b1c3d7b9976', 'text': 'Tylko projektory multimedialne.', 'is_correct': 0, 'sort_order': 2}, {'id': '516a4c7a-6b0d-4041-a383-47042af1da5a', 'question_id': '555d2e38-8b49-4dce-9453-8b1c3d7b9976', 'text': 'Wyłącznie drukarki laserowe biurowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '59b5afcb-114b-49ea-a5fe-8c04889bd419', 'chapter_id': 2, 'text': 'Jakie znasz urządzenia do otrzymywania obrazów fotograficznych na podłożu papierowym z plików cyfrowych?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Do wywoływania plików cyfrowych na papierze fotograficznym wykorzystuje się drukarki atramentowe (plotery) o wysokiej rozdzielczości, drukarki sublimacyjne zapewniające płynne przejścia tonalne, minilaby cyfrowe rzutujące obraz laserem lub diodami LED na papier światłoczuły wywoływany chemicznie (proces RA-4), a także nowoczesne ekspozytory LED naświetlające tradycyjny papier kolorowy.'}, {'id': '98c43b56-e311-4eae-a5ea-6b1fcbff5408', 'chapter_id': 2, 'text': 'Co to są filtry konwersyjne – do czego służą?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'b009d50b-d556-4f5c-b8d3-36d32fecfea4', 'question_id': '98c43b56-e311-4eae-a5ea-6b1fcbff5408', 'text': 'Filtry do konwersji zdjęć czarno-białych na kolorowe.', 'is_correct': 0, 'sort_order': 0}, {'id': '76552429-3d73-4480-b071-934d25e29cb3', 'question_id': '98c43b56-e311-4eae-a5ea-6b1fcbff5408', 'text': 'Filtry korekcyjne barwne (np. 80A, 85B) służące do dostosowania temperatury barwowej filmu do rodzaju oświetlenia (dziennego lub sztucznego).', 'is_correct': 1, 'sort_order': 1}, {'id': '129f14ba-452c-4426-a988-f09e55d7be46', 'question_id': '98c43b56-e311-4eae-a5ea-6b1fcbff5408', 'text': 'Filtry do zmiany formatu negatywu z małego na średni.', 'is_correct': 0, 'sort_order': 2}, {'id': '7c2b8511-0125-48d6-93dd-a21cc2311a2b', 'question_id': '98c43b56-e311-4eae-a5ea-6b1fcbff5408', 'text': 'Filtry chroniące obiektyw przed kurzem i zarysowaniami.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'bfccb496-d66a-4609-a1a4-92b0549f7550', 'chapter_id': 2, 'text': 'Co to są filtry konwersyjne – do czego służą?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Filtry konwersyjne to filtry korekcyjne barwne, które pozwalają dostosować temperaturę barwową światła do danego typu filmu. Filtr 85B (pomarańczowy) stosuje się przy filmie do światła żarowego (3200K) fotografowanym w świetle dziennym (5500K), natomiast filtr 80A (niebieski) pozwala użyć filmu dziennego przy oświetleniu żarowym. Dzięki nim uzyskuje się prawidłowe odwzorowanie barw bez dominaty.'}, {'id': '0c473b34-64c1-43d0-a409-a73dd198911d', 'chapter_id': 2, 'text': 'Kiedy obiektyw nazywamy długoogniskowym?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '16925fdb-e368-4d3c-a5fd-94afda156338', 'question_id': '0c473b34-64c1-43d0-a409-a73dd198911d', 'text': 'Gdy ogniskowa jest krótsza od przekątnej formatu.', 'is_correct': 0, 'sort_order': 0}, {'id': '6bebd24e-1ab9-410e-be74-7cdf34723191', 'question_id': '0c473b34-64c1-43d0-a409-a73dd198911d', 'text': 'Gdy ogniskowa jest znacznie dłuższa od przekątnej formatu (np. dla małego obrazka 24×36 mm są to ogniskowe powyżej 70–85 mm).', 'is_correct': 1, 'sort_order': 1}, {'id': 'c485a2ec-2f52-4c90-8877-935144762a72', 'question_id': '0c473b34-64c1-43d0-a409-a73dd198911d', 'text': 'Gdy obiektyw składa się z więcej niż dziesięciu soczewek.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e85ec997-8145-4d4a-bfcc-3058d4b2b41c', 'question_id': '0c473b34-64c1-43d0-a409-a73dd198911d', 'text': 'Gdy średnica gwintu filtra wynosi więcej niż 77 mm.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c9fd6813-3285-40f9-88d9-aa1db04906a6', 'chapter_id': 2, 'text': 'Kiedy obiektyw nazywamy długoogniskowym?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obiektyw uznajemy za długoogniskowy (teleobiektyw), gdy jego ogniskowa jest znacznie dłuższa od przekątnej używanego formatu. Dla filmu małoobrazkowego (przekątna ok. 43 mm) obiektywy powyżej 70–85 mm zaczynają wykazywać właściwości tele, a im dłuższa ogniskowa, tym większe powiększenie obrazu i węższe pole widzenia, co jest wykorzystywane w fotografii portretowej, sportowej i przyrodniczej.'}, {'id': 'd3b775ac-26d7-4384-a62b-744e0df794de', 'chapter_id': 2, 'text': 'Omów rodzaje reflektorów używanych w studio.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '7d288236-49fc-49ed-bbe7-7825cd01952f', 'question_id': 'd3b775ac-26d7-4384-a62b-744e0df794de', 'text': 'Tylko lampy biurkowe i latarki.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f8a845d0-a035-4581-9108-0dfb44a67e40', 'question_id': 'd3b775ac-26d7-4384-a62b-744e0df794de', 'text': 'Parasolki (rozpraszające i odblaskowe), softboxy, beauty dish, reflektory z gridem i snootem, płyty odbijające.', 'is_correct': 1, 'sort_order': 1}, {'id': '2f6f845e-1411-42c4-88a3-fc8a5206f35c', 'question_id': 'd3b775ac-26d7-4384-a62b-744e0df794de', 'text': 'Tylko filtry UV i polaryzacyjne.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f1115949-173d-4a6f-89a3-59aacdf66f3b', 'question_id': 'd3b775ac-26d7-4384-a62b-744e0df794de', 'text': 'Wyłącznie odbłyśniki wbudowane w korpus aparatu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '783568ef-da31-4c91-8545-a0cab0c65863', 'chapter_id': 2, 'text': 'Omów rodzaje reflektorów używanych w studio.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W studio fotograficznym używa się różnych rodzajów reflektorów: parasolek rozpraszających (białe, przezroczyste) dających miękkie światło, parasolek odblaskowych (srebrnych, złotych) wzmacniających i ciepłych, softboxów tworzących duże, równomierne źródło światła, beauty dish do portretów, reflektorów z gridem kierujących światło w wąski strumień, snootów punktowych oraz płaskich płyt styropianowych służących jako odbłyśniki doświetlające cienie.'}, {'id': '9ddd3dfc-939f-4752-9559-1bf675059963', 'chapter_id': 2, 'text': 'W jakim miejscu zamontowana jest w aparacie migawka szczelinowa?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f5d50687-1d33-4be6-b874-733af7268780', 'question_id': '9ddd3dfc-939f-4752-9559-1bf675059963', 'text': 'W obiektywie, tuż za przysłoną.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ca73f146-3398-4899-840e-28edb20960bf', 'question_id': '9ddd3dfc-939f-4752-9559-1bf675059963', 'text': 'W płaszczyźnie ogniskowej obrazu, tuż przed materiałem światłoczułym lub matrycą cyfrową.', 'is_correct': 1, 'sort_order': 1}, {'id': '63e7b640-17b3-497f-b274-4479d934078f', 'question_id': '9ddd3dfc-939f-4752-9559-1bf675059963', 'text': 'Na górze aparatu, obok wizjera optycznego.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a0d90114-eb58-4f72-80fa-16fe5239fe9e', 'question_id': '9ddd3dfc-939f-4752-9559-1bf675059963', 'text': 'Wewnątrz lampy błyskowej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '8582c34e-da5c-429b-8f4d-5f96b38b2a2c', 'chapter_id': 2, 'text': 'W jakim miejscu zamontowana jest w aparacie migawka szczelinowa?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Migawka szczelinowa (płaszczyznowa) montowana jest w płaszczyźnie ogniskowej obrazu, bezpośrednio przed materiałem światłoczułym lub matrycą cyfrową. Taka lokalizacja pozwala na osiągnięcie bardzo krótkich czasów naświetlania (nawet do 1/8000 s), ponieważ szczelina przesuwa się tuż nad powierzchnią rejestrującą, jednak ogranicza synchronizację z lampą błyskową do maksymalnego czasu synchronizacji (zazwyczaj 1/200–1/250 s).'}, {'id': '3443796e-258f-443f-854e-1b00d7af4b86', 'chapter_id': 2, 'text': 'Jakie znamy rodzaje migawek – omów zalety i wady?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1e5d95bf-f1e2-4398-86f5-0c0c5769151e', 'question_id': '3443796e-258f-443f-854e-1b00d7af4b86', 'text': 'Tylko migawka mechaniczna i elektroniczna.', 'is_correct': 0, 'sort_order': 0}, {'id': '15e56c13-6832-4f67-a608-c417cbccb099', 'question_id': '3443796e-258f-443f-854e-1b00d7af4b86', 'text': 'Migawka szczelinowa (zalety: bardzo krótkie czasy, wady: zniekształcenia kadłubowe i ograniczenia synchronizacji z lampą) oraz centralna (zalety: synchronizacja z lampą na wszystkich czasach i brak zniekształceń, wady: ograniczona prędkość maksymalna).', 'is_correct': 1, 'sort_order': 1}, {'id': '9702a26f-4986-4288-a839-b309f16734bb', 'question_id': '3443796e-258f-443f-854e-1b00d7af4b86', 'text': 'Tylko migawka czasowa i przestrzenna.', 'is_correct': 0, 'sort_order': 2}, {'id': '0ec811f0-4221-4615-a05b-9cc755d64785', 'question_id': '3443796e-258f-443f-854e-1b00d7af4b86', 'text': 'Migawka ręczna i migawka automatyczna.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f01b30d9-9d37-4155-b7d5-869ed87eade2', 'chapter_id': 2, 'text': 'Jakie znamy rodzaje migawek – omów zalety i wady?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W fotografii spotykamy migawkę szczelinową, której zaletą jest możliwość uzyskania ekstremalnie krótkich czasów nawet do 1/8000 s, ale wadą są zniekształczenia kadłubowe przy szybkich ruchach oraz ograniczona synchronizacja z lampą błyskową. Migawka centralna pozwala na synchronizację z lampą przy każdym czasie i nie wprowadza zniekształceń, lecz jej maksymalna prędkość jest ograniczona (zazwyczaj do ok. 1/500 s). W aparatach cyfrowych występuje też migawka elektroniczna (global i rolling shutter).'}, {'id': '69177e5b-3089-4e1e-85b0-8ab7dad144a4', 'chapter_id': 2, 'text': 'Co oznacza liczba przewodnia lamp błyskowych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '8ed1e343-28bb-485c-8a15-fb50b17cc294', 'question_id': '69177e5b-3089-4e1e-85b0-8ab7dad144a4', 'text': 'Liczba określająca wagę lampy w gramach.', 'is_correct': 0, 'sort_order': 0}, {'id': '48066875-3d2b-43d8-b9d3-73a67cd483ef', 'question_id': '69177e5b-3089-4e1e-85b0-8ab7dad144a4', 'text': 'Wskaźnik mocy lampy, określający iloczyn odległości od obiektu i wartości przysłony przy określonej czułości (standardowo ISO 100).', 'is_correct': 1, 'sort_order': 1}, {'id': '7ad3f5a2-621e-4d2c-b3e7-e0d26785051e', 'question_id': '69177e5b-3089-4e1e-85b0-8ab7dad144a4', 'text': 'Liczba zdjęć, które można wykonać na jednym zestawie baterii.', 'is_correct': 0, 'sort_order': 2}, {'id': '6579a07d-eb2b-40a3-9ce9-771d5910a355', 'question_id': '69177e5b-3089-4e1e-85b0-8ab7dad144a4', 'text': 'Temperatura barwowa światła błyskowego wyrażona w kelwinach.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'af993d81-fa4b-4c6e-ae57-627fddd19285', 'chapter_id': 2, 'text': 'Co oznacza liczba przewodnia lamp błyskowych?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Liczba przewodnia (Guide Number, GN) to parametr określający moc lampy błyskowej. Jest to iloczyn odległości od fotografowanego obiektu (w metrach) i wartości przysłony, przy której uzyskamy prawidłową ekspozycję przy określonej czułości (najczęściej ISO 100). Im wyższa liczba przewodnia, tym mocniejsza lampa i tym dalej można efektywnie doświetlić scenę.'}, {'id': 'bd8401d5-850d-4627-8e10-77bd06428133', 'chapter_id': 2, 'text': 'Podaj wady i zalety migawki szczelinowej i centralnej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'e2a5479e-0222-4854-8696-f399e00959dc', 'question_id': 'bd8401d5-850d-4627-8e10-77bd06428133', 'text': 'Szczelinowa: zalety – krótsze czasy (do 1/8000 s), wady – zniekształcenia kadłubowe i ograniczona synchronizacja z lampą. Centralna: zalety – synchronizacja z lampą na wszystkich czasach i brak zniekształceń, wady – ograniczona prędkość maksymalna.', 'is_correct': 1, 'sort_order': 0}, {'id': '28d77817-4101-4d67-bb5b-225b91a33f8e', 'question_id': 'bd8401d5-850d-4627-8e10-77bd06428133', 'text': 'Szczelinowa jest zawsze lepsza we wszystkich aspektach od centralnej.', 'is_correct': 0, 'sort_order': 1}, {'id': '6755e1e5-c907-41cb-84d2-fe002816c19d', 'question_id': 'bd8401d5-850d-4627-8e10-77bd06428133', 'text': 'Centralna pozwala na czasy naświetlania do 1/16000 s.', 'is_correct': 0, 'sort_order': 2}, {'id': 'eff85936-f295-42fe-bd2f-a030cf948904', 'question_id': 'bd8401d5-850d-4627-8e10-77bd06428133', 'text': 'Szczelinowa nie występuje w nowoczesnych aparatach cyfrowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '96a7ee8b-c5e8-4518-a956-2c4f18c233ac', 'chapter_id': 2, 'text': 'Podaj wady i zalety migawki szczelinowej i centralnej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Migawka szczelinowa pozwala na uzyskanie bardzo krótkich czasów ekspozycji, co jest kluczowe przy zamrażaniu szybkiego ruchu, jednak wprowadza efekt rolling shutter oraz ogranicza synchronizację z lampą błyskową. Migawka centralna eliminuje te problemy, umożliwiając pracę z lampą przy każdym czasie i zachowując geometryczną poprawność obrazu, ale jej konstrukcja mechaniczna ogranicza maksymalną prędkość do około 1/500 s.'}, {'id': 'f3c36d67-42ca-4e16-94aa-e1ea8075e8da', 'chapter_id': 2, 'text': 'Omów budowę i zastosowanie koreksu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '760b1a02-23e8-4a3d-bbe7-2951c7620455', 'question_id': 'f3c36d67-42ca-4e16-94aa-e1ea8075e8da', 'text': 'Urządzenie do skanowania negatywów; budowa to podstawa, kamera i lampa.', 'is_correct': 0, 'sort_order': 0}, {'id': '741a1c08-d014-4fe1-bc40-872e7171709d', 'question_id': 'f3c36d67-42ca-4e16-94aa-e1ea8075e8da', 'text': 'Pojemnik szczelny ze szpulą wewnętrzną służący do wywoływania filmów w świetle, wyposażony w wlewy na chemię i wylewy na odpływ.', 'is_correct': 1, 'sort_order': 1}, {'id': '60b5eeb2-37c1-4255-9d92-57610d12e8d8', 'question_id': 'f3c36d67-42ca-4e16-94aa-e1ea8075e8da', 'text': 'Rodzaj statywu do aparatów średnioformatowych.', 'is_correct': 0, 'sort_order': 2}, {'id': '86a5ff85-cfab-442b-8588-2a965330640a', 'question_id': 'f3c36d67-42ca-4e16-94aa-e1ea8075e8da', 'text': 'Program komputerowy do obróbki zdjęć cyfrowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '70317aae-9033-4b20-a95f-855cf5592950', 'chapter_id': 2, 'text': 'Omów budowę i zastosowanie koreksu.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Koreks to lekki, szczelny pojemnik z tworzywa sztucznego służący do samodzielnego wywoływania filmów fotograficznych. Wewnątrz znajduje się szpula, na którą w ciemni (lub rękawie ciemniowym) nawija się film. Po zamknięciu koreksu kolejne czynności (wlewanie wywoływacza, przerywacza, utrwalacza i płukanie) można wykonywać przy świetle dziennym, ponieważ światło nie przenika do środka. Jest niezbędny w domowej obróbce filmów.'}, {'id': 'a0d4d29e-2ef8-4ed8-9f91-5f2bd7056543', 'chapter_id': 2, 'text': 'Camera obscura – jej historia, budowa i zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '0fd69a6f-f2af-4188-992b-7aa4052ebcab', 'question_id': 'a0d4d29e-2ef8-4ed8-9f91-5f2bd7056543', 'text': 'Pierwszy aparat cyfrowy wynaleziony w 1990 roku.', 'is_correct': 0, 'sort_order': 0}, {'id': '2e7133c9-b8c4-47fb-9819-050dc6db9a16', 'question_id': 'a0d4d29e-2ef8-4ed8-9f91-5f2bd7056543', 'text': 'Ciemna komora z małym otworem, przez który światło projektuje odwrócony obraz na przeciwległej ścianie; zastosowanie w malarstwie i jako przodek aparatu fotograficznego.', 'is_correct': 1, 'sort_order': 1}, {'id': '162b30c9-8cd9-469f-bc03-e9158cffc85c', 'question_id': 'a0d4d29e-2ef8-4ed8-9f91-5f2bd7056543', 'text': 'Rodzaj nowoczesnego obiektywu szerokokątnego.', 'is_correct': 0, 'sort_order': 2}, {'id': '5473c859-8b9d-4d7c-9bff-ef8b6606bf56', 'question_id': 'a0d4d29e-2ef8-4ed8-9f91-5f2bd7056543', 'text': 'Technika wywoływania filmów w całkowitej ciemności.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '425c7f68-9a5e-4e5c-8f63-67e389e9b5a2', 'chapter_id': 2, 'text': 'Camera obscura – jej historia, budowa i zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Camera obscura (łac. ciemna komora) to zjawisko optyczne i proste urządzenie znane od starożytności, składające się z zamkniętej, ciemnej przestrzeni z malutkim otworem w ścianie. Przechodzące przez nie światło rzutuje na przeciwległą ścianę odwrócony i pomniejszony obraz otoczenia. W XVI–XVIII wieku malarze (np. Canaletto) używali jej do kopiowania perspektywy, a w XIX wieku stała się bezpośrednim prototypem pierwszego aparatu fotograficznego.'}, {'id': '5ad256e2-d40a-40f2-8a97-76c75dc587cc', 'chapter_id': 2, 'text': 'Scharakteryzuj rodzaje i zastosowanie filtrów w aparacie fotograficznym.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '925651b5-26aa-4753-be02-13a624ac83bc', 'question_id': '5ad256e2-d40a-40f2-8a97-76c75dc587cc', 'text': 'Tylko filtry UV i polaryzacyjne.', 'is_correct': 0, 'sort_order': 0}, {'id': 'bbbbeef6-84d7-47a4-bb1a-927a45b4cc8c', 'question_id': '5ad256e2-d40a-40f2-8a97-76c75dc587cc', 'text': 'Filtry polaryzacyjne, szare (ND), korekcyjne barwne, UV, efektowe (rozmywające, gwieździste) oraz barwne do fotografii czarno-białej.', 'is_correct': 1, 'sort_order': 1}, {'id': 'd8f77421-8f8d-425e-ae05-978ab5b30378', 'question_id': '5ad256e2-d40a-40f2-8a97-76c75dc587cc', 'text': 'Wyłącznie filtry przeciwsłoneczne nakładane na obiektyw.', 'is_correct': 0, 'sort_order': 2}, {'id': '580018ea-6ae3-491a-911c-858dff75cd1d', 'question_id': '5ad256e2-d40a-40f2-8a97-76c75dc587cc', 'text': 'Tylko filtry cyfrowe dostępne w aplikacjach na telefon.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '953a6535-21b8-4063-856f-a724fd59a03f', 'chapter_id': 2, 'text': 'Scharakteryzuj rodzaje i zastosowanie filtrów w aparacie fotograficznym.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W aparacie fotograficznym stosuje się filtry polaryzacyjne (eliminacja połysków i wzmocnienie nasycenia barw), filtry szare ND (redukcja ilości światła pozwalająca na dłuższe czasy lub większe przysłony), filtry korekcyjne barwne (konwersyjne do korekty temperatury barwowej), filtry UV i ochronne (zabezpieczenie przedniej soczewki), filtry efektowe (rozmywające, gwieździste, makro) oraz filtry barwne do fotografii czarno-białej (żółty, czerwony, zielony), które kontrolują tonalność szarości.'}, {'id': '9337c34f-d0bf-4967-b2de-7c5f2cc6bc0a', 'chapter_id': 2, 'text': 'Omów budowę i zasadę działania lustrzanki jednoobiektywowej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '96d0347b-c70a-4156-868b-5133ddb5bb30', 'question_id': '9337c34f-d0bf-4967-b2de-7c5f2cc6bc0a', 'text': 'Aparat bez lustra z elektronicznym wizjerem.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e1fbf379-9179-4134-a663-86ed8c8442f7', 'question_id': '9337c34f-d0bf-4967-b2de-7c5f2cc6bc0a', 'text': 'Aparat z jednym obiektywem, lustrem ustawionym pod kątem 45°, pryzmatem pentagonalnym i matówką; lustro odbija obraz do wizjera, a podczas wykonywania zdjęcia podnosi się, kierując światło na matrycę lub film.', 'is_correct': 1, 'sort_order': 1}, {'id': '051c73ef-b0d2-4360-ae7a-e17512333811', 'question_id': '9337c34f-d0bf-4967-b2de-7c5f2cc6bc0a', 'text': 'Aparat z dwoma obiektywami i dwoma lustrami.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e8cd71ad-8fd1-4356-b818-cd005baab420', 'question_id': '9337c34f-d0bf-4967-b2de-7c5f2cc6bc0a', 'text': 'Aparat z taśmą filmową i wbudowanym skanerem.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '463e4376-486d-467e-a163-d60f9572f606', 'chapter_id': 2, 'text': 'Omów budowę i zasadę działania lustrzanki jednoobiektywowej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Lustrzanka jednoobiektywowa (SLR) składa się z korpusu, jednego obiektywu, lustra umieszczonego pod kątem 45 stopni, matówki, pryzmatu pentagonalnego oraz wizjera optycznego. Światło przechodzące przez obiektyw odbija się od lustra na matówkę i przez pryzmat trafia do wizjera, co pozwala fotografowi widzieć dokładnie to, co rejestruje obiektyw. W momencie naciśnięcia spustu migawki lustro podnosi się, odsłaniając film lub matrycę, a po ekspozycji wraca do pozycji wyjściowej.'}, {'id': '6bbfc9d7-561d-4595-be6c-ec2f06ca95b1', 'chapter_id': 2, 'text': 'Minilab – omów budowę i zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '965a348b-b228-4d38-b913-9442662713dc', 'question_id': '6bbfc9d7-561d-4595-be6c-ec2f06ca95b1', 'text': 'Ręczny zestaw kuwet do wywoływania filmów w ciemni.', 'is_correct': 0, 'sort_order': 0}, {'id': 'fc73e731-4401-43bf-b546-331c8611fa8c', 'question_id': '6bbfc9d7-561d-4595-be6c-ec2f06ca95b1', 'text': 'Automatyczna maszyna do wywoływania filmów i wykonywania odbitek, składająca się z sekcji chemicznej (C-41/RA-4), suszącej i drukującej.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f401e948-08fb-42e0-a763-3757d151fec5', 'question_id': '6bbfc9d7-561d-4595-be6c-ec2f06ca95b1', 'text': 'Mały aparat kieszonkowy do zdjęć natychmiastowych.', 'is_correct': 0, 'sort_order': 2}, {'id': '39c060a9-43bf-49dd-8d3b-5bb7f322e4c4', 'question_id': '6bbfc9d7-561d-4595-be6c-ec2f06ca95b1', 'text': 'Program do edycji zdjęć na komputerze.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '00ad3f7c-83fa-4af3-bc58-aeaa96e1cdb3', 'chapter_id': 2, 'text': 'Minilab – omów budowę i zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Minilab to zautomatyzowane urządzenie do przemysłowej obróbki fotograficznej. Składa się z modułu ładowania filmu, sekcji wywoływania chemicznego (kąpiele C-41 dla negatywów kolorowych lub RA-4 dla odbitek), kaskadowego systemu płukania, suszarni oraz modułu skanująco-drukującego, który naświetla papier światłoczuły laserem lub diodami LED. Stosuje się go w zakładach fotograficznych do szybkiej i powtarzalnej produkcji odbitek.'}, {'id': '5af63157-ddee-4336-aeeb-b6e869d14471', 'chapter_id': 2, 'text': 'Co to jest auto-fokus? Podaj jego wady i zalety.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1c12a5f9-7da8-419b-8764-f1ef948404d4', 'question_id': '5af63157-ddee-4336-aeeb-b6e869d14471', 'text': 'Ręczne ustawianie ostrości za pomocą pierścienia na obiektywie.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ab23712f-0738-4aeb-bce4-7069218d3d13', 'question_id': '5af63157-ddee-4336-aeeb-b6e869d14471', 'text': 'Automatyczny system ustawiania ostrości (detekcja fazy lub kontrastu); zalety to szybkość i wygoda, wady to błędy w słabym świetle i przy fotografowaniu przezroczystych obiektów.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b596c3ed-067c-4ab0-8575-43a98983db26', 'question_id': '5af63157-ddee-4336-aeeb-b6e869d14471', 'text': 'System do automatycznego zmieniania temperatury barwowej zdjęcia.', 'is_correct': 0, 'sort_order': 2}, {'id': '7dc05aa3-c5ca-4f8e-bd5e-d90fcc46c666', 'question_id': '5af63157-ddee-4336-aeeb-b6e869d14471', 'text': 'Funkcja automatycznego kadrowania i kadrowania twarzy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '67958647-5896-43be-8d29-2da2ca232817', 'chapter_id': 2, 'text': 'Co to jest auto-fokus? Podaj jego wady i zalety.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Auto-fokus (AF) to system automatycznego ustawiania ostrości w aparacie fotograficznym. W lustrzankach najczęściej wykorzystuje się detekcję fazy (szybka, sprawdza się przy ruchomych obiektach), a w bezlusterkowcach i kompaktach detekcję kontrastu (dokładniejsza, ale wolniejsza). Zaletami AF są szybkość, wygoda i skuteczność w typowych warunkach; wadami natomiast są problemy w słabym świetle, przy niskim kontraście, przez szyby lub siatki oraz przy fotografowaniu przezroczystych lub lustrzanych powierzchni.'}, {'id': '6c7d5bc4-f74b-4544-9cd1-49b17337da97', 'chapter_id': 2, 'text': 'Porównaj lustrzankę jednoobiektywową z dwuobiektywową.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1c8285ea-7521-497d-a252-5d2c932de53d', 'question_id': '6c7d5bc4-f74b-4544-9cd1-49b17337da97', 'text': 'SLR ma dwa obiektywy, a TLR ma jeden.', 'is_correct': 0, 'sort_order': 0}, {'id': '95c5341d-d691-4d7c-97e0-cdea6c98839c', 'question_id': '6c7d5bc4-f74b-4544-9cd1-49b17337da97', 'text': 'SLR: jeden obiektyw, precyzyjny wizjer przez obiektyw, wymienna optyka. TLR: dwa obiektywy (wizjerowy i zdjęciowy), format średni, mniejsza paralaksa przy dalekich obiektach, cichsza praca bez podnoszenia lustra.', 'is_correct': 1, 'sort_order': 1}, {'id': '3bc4f6ad-9c28-4712-8bf6-7c7fd92d9a1c', 'question_id': '6c7d5bc4-f74b-4544-9cd1-49b17337da97', 'text': 'Nie ma między nimi żadnej różnicy technicznej.', 'is_correct': 0, 'sort_order': 2}, {'id': '112c0236-ac75-40ca-9b47-8bb186998b2e', 'question_id': '6c7d5bc4-f74b-4544-9cd1-49b17337da97', 'text': 'TLR to nowoczesny aparat cyfrowy, a SLR wyłącznie analogowy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c67acec8-962e-4912-8e3c-b3911c5193bd', 'chapter_id': 2, 'text': 'Porównaj lustrzankę jednoobiektywową z dwuobiektywową.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Lustrzanka jednoobiektywowa (SLR) wykorzystuje jeden obiektyw zarówno do obserwacji, jak i do ekspozycji; dzięki lustru i pryzmatowi fotograf widzi dokładnie ten sam obraz, który zostanie zarejestrowany, a wymienna optyka daje dużą elastyczność. Lustrzanka dwuobiektywowa (TLR) posiada dwa identyczne obiektywy – górny służy do obserwacji przez matówkę, dolny do ekspozycji. TLR jest cichsza (brak podnoszenia lustra), zazwyczaj pracuje w formacie średnim (6×6 cm), ale przy fotografowaniu z bliska występuje paralaksa, a optyka najczęściej jest stała.'}, {'id': '2df47e40-50f8-45f4-be84-a424425886fc', 'chapter_id': 2, 'text': 'Omów budowę i zastosowanie światłomierza.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '7e4ca5d5-91a2-428d-84b1-f656a8117e02', 'question_id': '2df47e40-50f8-45f4-be84-a424425886fc', 'text': 'Urządzenie do mierzenia odległości od fotografowanego obiektu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e122785b-c16f-4654-aa72-1848a085722b', 'question_id': '2df47e40-50f8-45f4-be84-a424425886fc', 'text': 'Przyrząd z fotokomórką i wskaźnikiem do pomiaru natężenia światła; stosowany do określenia prawidłowych parametrów ekspozycji (czas, przysłona).', 'is_correct': 1, 'sort_order': 1}, {'id': '52ae595b-a9aa-447d-82f5-02b893c2bb8a', 'question_id': '2df47e40-50f8-45f4-be84-a424425886fc', 'text': 'Narzędzie do czyszczenia obiektywu z kurzu.', 'is_correct': 0, 'sort_order': 2}, {'id': '616fb88b-62e6-4691-9fbe-ef4f57b15931', 'question_id': '2df47e40-50f8-45f4-be84-a424425886fc', 'text': 'Uchwyt do mocowania lampy błyskowej na statywie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3388ba86-a93b-44cf-8259-e3f98adf4f89', 'chapter_id': 2, 'text': 'Omów budowę i zastosowanie światłomierza.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Światłomierz to przyrząd służący do pomiaru natężenia oświetlenia. Składa się z fotokomórki (światłoczułego elementu) oraz układu wskazującego (igły lub wyświetlacza cyfrowego), który na podstawie wskazań proponuje parametry ekspozycji (przysłonę i czas). Wyróżniamy światłomierze zewnętrzne (mierzące światło padające lub odbite od obiektu, często typu „spot") oraz wbudowane w aparat (TTL), które mierzą światło przechodzące przez obiektyw.'}, {'id': 'da8eefcd-3bd2-429c-b220-7928b2833e35', 'chapter_id': 2, 'text': 'Scharakteryzuj budowę i zastosowanie powiększalnika.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'ac9b4471-b1b6-4849-93e9-1b2f9325cd03', 'question_id': 'da8eefcd-3bd2-429c-b220-7928b2833e35', 'text': 'Urządzenie do skanowania dokumentów biurowych.', 'is_correct': 0, 'sort_order': 0}, {'id': '7aa52b4c-389f-4a2c-b706-d60d4c57fcb9', 'question_id': 'da8eefcd-3bd2-429c-b220-7928b2833e35', 'text': 'Aparat optyczny składający się z podstawy, kolumny, głowicy z obiektywem, źródła światła i karetki na negatyw; służy do rzutowania i powiększania obrazu negatywu na papier światłoczuły.', 'is_correct': 1, 'sort_order': 1}, {'id': 'db3c95b6-33f5-49b2-9648-83fdfc687cc8', 'question_id': 'da8eefcd-3bd2-429c-b220-7928b2833e35', 'text': 'Rodzaj statywu do aparatu fotograficznego.', 'is_correct': 0, 'sort_order': 2}, {'id': '46ae391f-ef4e-41ac-9e43-b9dd4baedcf9', 'question_id': 'da8eefcd-3bd2-429c-b220-7928b2833e35', 'text': 'Program komputerowy do powiększania zdjęć cyfrowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a98f429a-0734-4fba-ac5c-e650060038cf', 'chapter_id': 2, 'text': 'Scharakteryzuj budowę i zastosowanie powiększalnika.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Powiększalnik to urządzenie ciemniowe służące do optycznego powiększania negatywu na papier fotograficzny. Jego budowa obejmuje stabilną podstawę z miejscem na kuwety, pionową kolumnę z głowicą zawierającą źródło światła, kondensor, karetę na negatyw z maskownicą oraz obiektyw powiększalnikowy. W powiększalnikach kolorowych znajdują się też filtry do korekcji barwnej (tzw. głowica filtrów). Umożliwia precyzyjne kadrowanie, regulację ostrości i wielkości odbitki.'}, {'id': 'e395b0a0-7de2-4008-a9a8-9564b6179185', 'chapter_id': 2, 'text': 'Wymień i omów rodzaje migawek w aparatach fotograficznych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5f5b9652-791f-4d71-9ade-13b91b7d9a2e', 'question_id': 'e395b0a0-7de2-4008-a9a8-9564b6179185', 'text': 'Tylko migawka ręczna i automatyczna.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e0ddacf2-dbe9-48b9-9854-ea4d330886c2', 'question_id': 'e395b0a0-7de2-4008-a9a8-9564b6179185', 'text': 'Migawka centralna (w obiektywie), szczelinowa (w płaszczyźnie ogniskowej) oraz elektronowa (w matrycach cyfrowych); każda ma inne zalety dotyczące synchronizacji z lampą i maksymalnych czasów.', 'is_correct': 1, 'sort_order': 1}, {'id': '75e386f4-be55-42b8-a291-8e228ce496d9', 'question_id': 'e395b0a0-7de2-4008-a9a8-9564b6179185', 'text': 'Migawka wodna i powietrzna.', 'is_correct': 0, 'sort_order': 2}, {'id': '70963a9e-366e-4805-a184-79c90b25fdc2', 'question_id': 'e395b0a0-7de2-4008-a9a8-9564b6179185', 'text': 'Tylko migawka czasowa i migawka przestrzenna.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '07b387ae-46af-4a8c-907e-4a917c12956e', 'chapter_id': 2, 'text': 'Wymień i omów rodzaje migawek w aparatach fotograficznych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W aparatach fotograficznych występują trzy główne rodzaje migawek: centralna (migawka obiektywowa) – umieszczona w obiektywie, cicha, umożliwia synchronizację z lampą na wszystkich czasach, ale ma ograniczoną prędkość; szczelinowa (płaszczyznowa) – znajdująca się przed filmem lub matrycą, pozwala na bardzo krótkie czasy, ale wprowadza zniekształcenia i ogranicza synchronizację z błyskiem; oraz migawka elektroniczna – wykorzystywana w aparatach cyfrowych, gdzie matryca jest włączana i wyłączana elektronicznie (global lub rolling shutter).'}, {'id': 'b18dfe49-4370-4c63-ae2c-2143cc8be939', 'chapter_id': 2, 'text': 'Dokonaj podziału aparatów ze względu na rodzaj negatywu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1ca3534d-c8ed-4f2e-8917-a594daac2359', 'question_id': 'b18dfe49-4370-4c63-ae2c-2143cc8be939', 'text': 'Aparaty cyfrowe i analogowe.', 'is_correct': 0, 'sort_order': 0}, {'id': '6a305791-78e9-41e8-a55a-256cdfb44376', 'question_id': 'b18dfe49-4370-4c63-ae2c-2143cc8be939', 'text': 'Małoobrazkowe (24×36 mm), średnioformatowe (np. 6×6 cm), wielkoformatowe (klisze płaskie, np. 4×5") oraz formaty instancyjne.', 'is_correct': 1, 'sort_order': 1}, {'id': '125add45-e4bc-4b81-8ce1-3e3eecd2e30a', 'question_id': 'b18dfe49-4370-4c63-ae2c-2143cc8be939', 'text': 'Tylko czarno-białe i kolorowe.', 'is_correct': 0, 'sort_order': 2}, {'id': '7e9c0a3b-9255-43e7-97cc-d79aaf185a56', 'question_id': 'b18dfe49-4370-4c63-ae2c-2143cc8be939', 'text': 'Profesjonalne i amatorskie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '5bb9ce96-f080-441f-8d50-d28c28e04ca2', 'chapter_id': 2, 'text': 'Dokonaj podziału aparatów ze względu na rodzaj negatywu.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Ze względu na rodzaj używanego materiału światłoczułego aparaty dzielimy na: małoobrazkowe (format 24×36 mm, film zwojowy 135), średnioformatowe (film typ 120/220, formaty 6×4,5; 6×6; 6×7; 6×9 cm), wielkoformatowe (klisze płaskie – 4×5", 8×10" i większe, ładowane kasetami), aparaty półformatowe (18×24 mm) oraz aparaty instancyjne (np. Polaroid wykorzystujący odbitkę samoczynnie wywołującą się po naświetleniu).'}, {'id': '8ddb3446-23a3-416f-bae9-798573c20d0f', 'chapter_id': 2, 'text': 'Omów działanie i zastosowanie lampy błyskowej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '41254f1b-b934-4de7-bbaf-0515bdc328bb', 'question_id': '8ddb3446-23a3-416f-bae9-798573c20d0f', 'text': 'Urządzenie grzewcze do suszenia zdjęć fotograficznych.', 'is_correct': 0, 'sort_order': 0}, {'id': 'a826e1f9-6457-4ebb-af77-fb218261ddc0', 'question_id': '8ddb3446-23a3-416f-bae9-798573c20d0f', 'text': 'Źródło światła powstałe przez rozładowanie kondensatora w rurce ksenonowej; służy do doświetlania zdjęć w nocy, zamrażania ruchu i oświetlenia studyjnego.', 'is_correct': 1, 'sort_order': 1}, {'id': 'd777701a-aec5-4941-a83b-8a1017069af6', 'question_id': '8ddb3446-23a3-416f-bae9-798573c20d0f', 'text': 'Narzędzie do czyszczenia matrycy aparatu cyfrowego.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd7d41763-4959-40ca-aa9e-6d3346bc0ce9', 'question_id': '8ddb3446-23a3-416f-bae9-798573c20d0f', 'text': 'Urządzenie do nagrywania dźwięku podczas sesji zdjęciowej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '20f811e5-b1be-4d8e-a881-7a4d85c738fd', 'chapter_id': 2, 'text': 'Omów działanie i zastosowanie lampy błyskowej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Lampa błyskowa to źródło sztucznego światła o bardzo krótkim czasie trwania (ułamki do tysięcznych sekundy). Działa na zasadzie rozładowania nagromadzonego w kondensatorze ładunku elektrycznego przez rurkę wypełnioną gazem ksenonowym, który wytwarza jasny błysk. Stosuje się ją do doświetlania zdjęć w warunkach słabego oświetlenia, do zamrażania szybkiego ruchu oraz jako główne lub wypełniające źródło światła w studiu fotograficznym.'}, {'id': 'ac9bc1e8-01e1-464d-a8e1-bf2d8000fbc2', 'chapter_id': 2, 'text': 'Omów zasadę działania aparatu fotograficznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'fc25b56c-f4a8-4e25-a85d-9f8822e1637a', 'question_id': 'ac9bc1e8-01e1-464d-a8e1-bf2d8000fbc2', 'text': 'Aparat rysuje obraz za pomocą wiązki laserowej.', 'is_correct': 0, 'sort_order': 0}, {'id': '19dbf7b7-27ce-4f47-8683-d9d7589c9a1f', 'question_id': 'ac9bc1e8-01e1-464d-a8e1-bf2d8000fbc2', 'text': 'Światło przechodzi przez układ optyczny obiektywu, przysłona reguluje jego ilość, a migawka czas ekspozycji; obraz rejestrowany jest na materiale światłoczułym lub matrycy cyfrowej.', 'is_correct': 1, 'sort_order': 1}, {'id': '1ac63ced-0cc1-48b8-b8c9-84c67a6d8f0c', 'question_id': 'ac9bc1e8-01e1-464d-a8e1-bf2d8000fbc2', 'text': 'Aparat skanuje otoczenie za pomocą radarów ultradźwiękowych.', 'is_correct': 0, 'sort_order': 2}, {'id': '9350eca9-5110-4c11-a77e-d03f79fa8cc0', 'question_id': 'ac9bc1e8-01e1-464d-a8e1-bf2d8000fbc2', 'text': 'Obraz tworzony jest przez komputer wewnątrz aparatu bez udziału światła.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'bae98d88-5d68-48a5-abd6-c52bf41d6ca0', 'chapter_id': 2, 'text': 'Omów zasadę działania aparatu fotograficznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Zasada działania aparatu fotograficznego opiera się na rejestracji światła przechodzącego przez obiektyw, który skupia promienie i tworzy obraz na materiale światłoczułym lub matrycy cyfrowej. Przysłona kontroluje ilość docierającego światła, a migawka określa czas, przez jaki materiał jest naświetlany. Połączenie tych parametrów z czułością medium (ISO) decyduje o prawidłowej ekspozycji i jasności końcowego obrazu.'}, {'id': '48896a5a-78ec-4c1f-b3ff-0d79fa6ab81f', 'chapter_id': 2, 'text': 'Omów działanie, znaczenie i zastosowanie urządzenia wyzwalającego migawkę.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'eaff3a35-0b07-47a8-944a-c59fd668a967', 'question_id': '48896a5a-78ec-4c1f-b3ff-0d79fa6ab81f', 'text': 'Tylko przycisk spustu znajdujący się na górze aparatu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd2832424-77a7-4853-8537-2cc8265000b6', 'question_id': '48896a5a-78ec-4c1f-b3ff-0d79fa6ab81f', 'text': 'Spust migawki, wężyk spustowy, pilot radiowy lub podczerwieni, samowyzwalacz; służą do wykonywania zdjęć bez drgań, z ukrycia lub zsynchronizowanych z zdarzeniem.', 'is_correct': 1, 'sort_order': 1}, {'id': 'ed9c1467-d0d4-4f4f-adf9-2a2eec5b70a5', 'question_id': '48896a5a-78ec-4c1f-b3ff-0d79fa6ab81f', 'text': 'Tylko głosowe komendy słowne wydawane w stronę aparatu.', 'is_correct': 0, 'sort_order': 2}, {'id': '99a0071a-685c-43ae-9340-2a51536dfc61', 'question_id': '48896a5a-78ec-4c1f-b3ff-0d79fa6ab81f', 'text': 'Wyłącznie aplikacja na smartfonie połączona z aparatem przez Bluetooth.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'b21a5b11-59f8-41aa-b6f3-718f89da7511', 'chapter_id': 2, 'text': 'Omów działanie, znaczenie i zastosowanie urządzenia wyzwalającego migawkę.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Urządzenia wyzwalające migawkę pozwalają na zdalne lub opóźnione wykonanie zdjęcia. Podstawowym jest spust migawki na korpusie aparatu, ale stosuje się też wężyki spustowe eliminujące drgania przy długich czasach, piloty radiowe i podczerwieni do zdjęć z ukrycia lub autoportretów, wyzwalacze dźwiękowe (reagujące na hałas) oraz wyzwalacze optyczne synchronizujące lampy. Samowyzwalacz pozwala fotografowi wejść w kadr lub ustabilizować aparat przed ekspozycją.'}, {'id': 'a394ffba-d037-40d1-bb08-8807db846965', 'chapter_id': 2, 'text': 'Omów system TTL w pomiarze światła.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '2d523eff-4f96-4655-a364-9f5c1e01ec90', 'question_id': 'a394ffba-d037-40d1-bb08-8807db846965', 'text': 'System do automatycznego czyszczenia obiektywu z kurzu.', 'is_correct': 0, 'sort_order': 0}, {'id': '55297648-b7c5-42e1-a696-24e7da0098c4', 'question_id': 'a394ffba-d037-40d1-bb08-8807db846965', 'text': 'Pomiar światła dokonywany przez obiektyw aparatu; fotokomórka mierzy światło docierające do matrycy lub filmu, co zapewnia precyzyjny pomiar ekspozycji z uwzględnieniem używanej optyki i filtrów.', 'is_correct': 1, 'sort_order': 1}, {'id': '1905a021-f812-45ce-97b9-ac38b17a40b8', 'question_id': 'a394ffba-d037-40d1-bb08-8807db846965', 'text': 'System transmisji zdjęć przez internet do chmury.', 'is_correct': 0, 'sort_order': 2}, {'id': '60dfed20-f224-43cb-bc77-9fbff94d4df3', 'question_id': 'a394ffba-d037-40d1-bb08-8807db846965', 'text': 'Rodzaj obiektywu szerokokątnego z wbudowanym światłomierzem.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '99dd8a8e-bb5a-4d0d-9ac8-ba6921296ba9', 'chapter_id': 2, 'text': 'Omów system TTL w pomiarze światła.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'TTL (Through The Lens) to system pomiaru światła realizowany przez sam obiektyw aparatu. Fotokomórka lub sensory umieszczone wewnątrz korpusu mierzą światło przechodzące przez układ optyczny, co pozwala uwzględnić wpływ używanej ogniskowej, przysłony oraz ewentualnych filtrów na ekspozycję. W przypadku pomiaru błyskowego TTL system może analizować światło odbite od filmu lub matrycy w czasie rzeczywistym, precyzyjnie kończąc błysk w momencie uzyskania prawidłowej ekspozycji.'}, {'id': '004122f1-5a5a-490e-8c1c-c180d1254e15', 'chapter_id': 2, 'text': 'Omów budowę, działanie i zastosowanie samowyzwalacza.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '745a639c-1a7d-4197-80fb-35a91bc0f044', 'question_id': '004122f1-5a5a-490e-8c1c-c180d1254e15', 'text': 'Urządzenie do automatycznej wymiany obiektywu w aparacie.', 'is_correct': 0, 'sort_order': 0}, {'id': '144efea9-57c1-4ba2-a01d-44e787a0eaed', 'question_id': '004122f1-5a5a-490e-8c1c-c180d1254e15', 'text': 'Mechanizm opóźniający wyzwolenie migawki o określony czas (np. 2 lub 10 s); służy do autoportretów, zdjęć grupowych i eliminacji drgań przy ekspozycjach na statywie.', 'is_correct': 1, 'sort_order': 1}, {'id': 'd906027e-2f29-435b-b90b-a195250b8555', 'question_id': '004122f1-5a5a-490e-8c1c-c180d1254e15', 'text': 'System do samoczynnego wywoływania filmów w koreksie.', 'is_correct': 0, 'sort_order': 2}, {'id': '19be77f7-9a4a-459f-9223-2f3691fca3e9', 'question_id': '004122f1-5a5a-490e-8c1c-c180d1254e15', 'text': 'Funkcja automatycznego kadrowania twarzy w aparacie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '9d3ab265-beea-4c31-b47d-1b894fc2dc05', 'chapter_id': 2, 'text': 'Omów budowę, działanie i zastosowanie samowyzwalacza.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Samowyzwalacz to mechanizm (sprężynowy w aparatach analogowych lub elektroniczny w cyfrowych) opóźniający wyzwolenie migawki o zadany czas, najczęściej 2 lub 10 sekund. Po naciśnięciu przycisku aparat wykonuje odliczanie (często sygnalizowane dźwiękiem lub lampką), a następnie otwiera migawkę. Stosuje się go przy fotografowaniu z długimi czasami na statywie, aby wyeliminować drgania własne, przy autoportretach oraz zdjęciach grupowych, gdy fotograf chce znaleźć się w kadrze.'}, {'id': 'ca80203b-f99f-4ddb-bcf2-b37c8fb34d58', 'chapter_id': 2, 'text': 'Omów znaczenie czasu „B".', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '53d07d2b-0f3a-40e4-af4d-d261923ee8aa', 'question_id': 'ca80203b-f99f-4ddb-bcf2-b37c8fb34d58', 'text': 'Automatyczny tryb balansu bieli w aparacie.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd4c3864c-3694-4956-9995-c6c4b712fcf6', 'question_id': 'ca80203b-f99f-4ddb-bcf2-b37c8fb34d58', 'text': 'Tryb ręcznego kontrolowania czasu otwarcia migawki, w którym migawka pozostaje otwarta tak długo, jak długo wciśnięty jest spust; stosowany przy ekspozycjach dłuższych niż 30 sekund.', 'is_correct': 1, 'sort_order': 1}, {'id': '008f77dc-9603-41e6-84dc-ab025a2039b5', 'question_id': 'ca80203b-f99f-4ddb-bcf2-b37c8fb34d58', 'text': 'Szybki czas synchronizacji z lampą błyskową.', 'is_correct': 0, 'sort_order': 2}, {'id': '02047b06-4daa-4711-b463-30adc2264ff0', 'question_id': 'ca80203b-f99f-4ddb-bcf2-b37c8fb34d58', 'text': 'Format zapisu zdjęć o niskiej jakości kompresji.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '432f2fac-2848-4688-a7b4-c4b12742104f', 'chapter_id': 2, 'text': 'Omów znaczenie czasu „B".', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Czas „B" (od ang. bulb) to tryb pracy migawki, w której pozostaje ona otwarta tak długo, jak długo fotograf przytrzymuje wciśnięty spust migawki lub zablokowany wężyk spustowy. Jest to niezbędne przy bardzo długich ekspozycjach przekraczających zakres automatyczny aparatu (np. powyżej 30 sekund), stosowany w fotografii nocnej, astrofotografii, przy fotografowaniu sztucznych ogni oraz w technice „painting with light" (malowania światłem).'}, {'id': 'f0eb9017-d833-47da-a20c-8c9f9cdf08e4', 'chapter_id': 2, 'text': 'Wymień rodzaje statywów oraz omów ich budowę i zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '34c4c69e-bfe2-46d9-838f-058e0a0a272a', 'question_id': 'f0eb9017-d833-47da-a20c-8c9f9cdf08e4', 'text': 'Tylko statywy biurkowe przeznaczone do mocowania skanerów.', 'is_correct': 0, 'sort_order': 0}, {'id': '0030f79c-28aa-4b47-b852-c2cb54bc459d', 'question_id': 'f0eb9017-d833-47da-a20c-8c9f9cdf08e4', 'text': 'Statywy fotograficzne składające się z głowicy, nóg i kolumny centralnej: studyjne (ciężkie, maksymalnie stabilne), turystyczne (lekkie, składane), monopody (jednonogowe), miniaturowe (stołowe); zastosowanie zależy od wagi sprzętu i warunków pracy.', 'is_correct': 1, 'sort_order': 1}, {'id': '7c0a9c79-6ae2-49f2-8087-f0d1df31bba0', 'question_id': 'f0eb9017-d833-47da-a20c-8c9f9cdf08e4', 'text': 'Wyłącznie statywy do telewizorów i monitorów komputerowych.', 'is_correct': 0, 'sort_order': 2}, {'id': '80421f09-ee9b-4454-a6cf-2b968aef9fc2', 'question_id': 'f0eb9017-d833-47da-a20c-8c9f9cdf08e4', 'text': 'Statywy wykonane wyłącznie z drewna i służące do mocowania anten radiowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c8464dcf-c421-482b-b873-7b0c2f817134', 'chapter_id': 2, 'text': 'Wymień rodzaje statywów oraz omów ich budowę i zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Statywy dzielimy na studyjne – ciężkie, stabilne, z głowicami hydraulicznymi lub kulowymi, służące do pracy w studio z dużym obciążeniem; turystyczne – lekkie, składane z trzech segmentów, przeznaczone do pracy w terenie; monopody – jednonogowe, mobilne, używane przy reportażu i teleobiektywach; oraz miniaturowe (stołowe) – niskie, do makrofotografii i fotografii produktowej. Budowa każdego obejmuje nogi z blokadami, głowicę z płytką mocującą oraz często kolumnę centralną do precyzyjnej regulacji wysokości.'}, {'id': '25968ba5-a381-4a21-9dec-5564972828e3', 'chapter_id': 2, 'text': 'Historia aparatu fotograficznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'e4b819ef-f259-439b-9a10-aab5ba39f855', 'question_id': '25968ba5-a381-4a21-9dec-5564972828e3', 'text': "Aparat fotograficzny został wynaleziony w 2000 roku przez Steve'a Jobsa.", 'is_correct': 0, 'sort_order': 0}, {'id': '28629a3c-cc92-4d2c-b52f-9cc678bda91e', 'question_id': '25968ba5-a381-4a21-9dec-5564972828e3', 'text': "Od camera obscury przez heliografię Niepce'a (1826), dagerotypy Daguerre'a, negatyw na papierze Talbota, film celuloidowy Eastmana, małoobrazkową Leicę, kolor (Autochrome, Kodachrome), aż po matryce CCD/CMOS i współczesne aparaty cyfrowe oraz bezlusterkowe.", 'is_correct': 1, 'sort_order': 1}, {'id': 'c6c607bc-3fd0-4977-8523-cb00c81a2d93', 'question_id': '25968ba5-a381-4a21-9dec-5564972828e3', 'text': 'Historia aparatu zaczyna się od wynalezienia komputera w 1945 roku.', 'is_correct': 0, 'sort_order': 2}, {'id': 'db18b3b4-4615-4bc4-9e11-bbba8f3b515c', 'question_id': '25968ba5-a381-4a21-9dec-5564972828e3', 'text': 'Pierwszy aparat powstał w starożytnym Rzymie wyłącznie do robienia selfie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '6cbaca90-866e-4367-8e19-3afa5f3e10ad', 'chapter_id': 2, 'text': 'Historia aparatu fotograficznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': "Historia fotografii rozpoczyna się od camera obscury znanej od starożytności. Przełomem była heliografia Nicéphore'a Niepce'a (1826), pierwszy trwały obraz. Louis Daguerre w 1839 roku zaprezentował dagerotypię, a William Henry Fox Talbot wynalazł proces negatywowy na papierze. George Eastman spopularyzował film zwojowy w aparacie Kodak (1888), a Oskar Barnack stworzył małoobrazkową Leikę. Rozwój koloru to Autochrome Lumière (1907) i Kodachrome (1935). Rewolucja cyfrowa nastąpiła w latach 70. i 90. dzięki matrycom CCD/CMOS, prowadząc do współczesnych aparatów bezlusterkowych z fotografią obliczeniową."}, {'id': 'abb9ba0d-23e8-48fc-b4a0-7415f9366540', 'chapter_id': 2, 'text': 'Omów powiększalnik do kopiowania fotografii barwnej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '7abc8484-8a7e-4a37-95e4-2b69c09a8060', 'question_id': 'abb9ba0d-23e8-48fc-b4a0-7415f9366540', 'text': 'Urządzenie biurowe do skanowania dokumentów i kserokopiowania.', 'is_correct': 0, 'sort_order': 0}, {'id': '13a979d5-8825-465a-a555-a9b37816bb54', 'question_id': 'abb9ba0d-23e8-48fc-b4a0-7415f9366540', 'text': 'Powiększalnik wyposażony w głowicę filtrów barwnych (subtraktywnych lub addytywnych) pozwalających korygować kolorystykę podczas kopiowania odbitek lub diapozytywów na papier barwny.', 'is_correct': 1, 'sort_order': 1}, {'id': '55d0707b-ae5c-4705-97a3-9a91b6951e90', 'question_id': 'abb9ba0d-23e8-48fc-b4a0-7415f9366540', 'text': 'Wyłącznie czarno-biały powiększalnik bez możliwości jakiejkolwiek korekcji barw.', 'is_correct': 0, 'sort_order': 2}, {'id': '3ef1169b-175d-4576-a054-d32251266c75', 'question_id': 'abb9ba0d-23e8-48fc-b4a0-7415f9366540', 'text': 'Rodzaj drukarki atramentowej przeznaczonej do wydruku zdjęć.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'ea83bdc1-2387-4e38-914d-0350ac3dcee4', 'chapter_id': 2, 'text': 'Omów powiększalnik do kopiowania fotografii barwnej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Powiększalnik do kopiowania fotografii barwnej (tzw. kopiarka) wyposażony jest w głowicę z zestawem filtrów barwnych (żółty, purpurowy, błękitny w systemie subtraktywnym lub czerwony, zielony, niebieski w addytywnym). Pozwala to na precyzyjną korekcję balansu bieli i nasycenia poszczególnych barw podczas rzutowania obrazu z odbitki lub slajdu na papier światłoczuły, co jest niezbędne przy wykonywaniu duplikatów fotografii kolorowych.'}, {'id': '546a5dbf-a8fe-45ed-97eb-02e0aa15a627', 'chapter_id': 2, 'text': 'Wymień, z jakich części składa się printer do robienia zdjęć.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'dc5d1a82-9115-424c-ba62-50c22a295418', 'question_id': '546a5dbf-a8fe-45ed-97eb-02e0aa15a627', 'text': 'Wyłącznie tusz i papier fotograficzny.', 'is_correct': 0, 'sort_order': 0}, {'id': '513cf072-c78c-409a-bb2e-b43178e544a5', 'question_id': '546a5dbf-a8fe-45ed-97eb-02e0aa15a627', 'text': 'Mechanizm podawania papieru, głowica drukująca (atramentowa, sublimacyjna lub laserowa/LED naświetlająca), kasety z barwnikiem bądź tonerem, układ sterujący i wyświetlacz.', 'is_correct': 1, 'sort_order': 1}, {'id': 'e14f7c05-979a-4ead-9c5d-97192ae237fd', 'question_id': '546a5dbf-a8fe-45ed-97eb-02e0aa15a627', 'text': 'Wyłącznie obiektyw i matryca światłoczuła.', 'is_correct': 0, 'sort_order': 2}, {'id': 'cb3cd739-6125-4f61-af22-9a43e1419e42', 'question_id': '546a5dbf-a8fe-45ed-97eb-02e0aa15a627', 'text': 'Klawiatura, myszka komputerowa i monitor LCD.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '16935d32-67cb-4bb3-866a-78771e6232b3', 'chapter_id': 2, 'text': 'Wymień, z jakich części składa się printer do robienia zdjęć.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Printer fotograficzny składa się z mechanizmu podawania papieru fotograficznego, głowicy drukującej (w drukarkach atramentowych są to dysze rozpylające mikrokrople pigmentu, w sublimacyjnych – głowica termiczna transferująca barwnik z folii na papier), kaset z tuszem lub folią barwną, układu sterującego z procesorem, wyświetlacza do podglądu i złącz komunikacyjnych (USB, Wi-Fi, sloty kart pamięci).'}, {'id': 'ad700418-203e-468c-9078-8e6a18ddf38e', 'chapter_id': 2, 'text': 'Podaj różnicę w budowie aparatu analogowego i cyfrowego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1cbb1f1f-71d4-438f-ada1-60405af8037f', 'question_id': 'ad700418-203e-468c-9078-8e6a18ddf38e', 'text': 'Analogowy posiada tylko obiektyw, a cyfrowy wyłącznie ekran dotykowy.', 'is_correct': 0, 'sort_order': 0}, {'id': '80b99f1d-3844-41b7-8d07-ecdf85cd90f2', 'question_id': 'ad700418-203e-468c-9078-8e6a18ddf38e', 'text': 'Analogowy: film światłoczuły, chemiczna rejestracja obrazu, brak natychmiastowego podglądu. Cyfrowy: matryca CMOS/CCD, przetwornik analogowo-cyfrowy, procesor obrazu, karta pamięci, wyświetlacz LCD, natychmiastowy podgląd i możliwość kasowania zdjęć.', 'is_correct': 1, 'sort_order': 1}, {'id': 'a8439580-95fd-4836-af9b-58899b8320f2', 'question_id': 'ad700418-203e-468c-9078-8e6a18ddf38e', 'text': 'Nie ma między nimi żadnych różnic technicznych, to to samo urządzenie.', 'is_correct': 0, 'sort_order': 2}, {'id': '259c4d37-af97-42a9-9ea7-7ac6cb728aa8', 'question_id': 'ad700418-203e-468c-9078-8e6a18ddf38e', 'text': 'Aparat analogowy jest zawsze fizycznie mniejszy od cyfrowego.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '257b4315-0ce4-4612-99da-bfc0a0f5becd', 'chapter_id': 2, 'text': 'Podaj różnicę w budowie aparatu analogowego i cyfrowego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Aparat analogowy rejestruje obraz chemicznie na emulsji srebrowej filmu, który wymaga późniejszego wywołania. Jego budowa opiera się na mechanizmie przewijania filmu, szpulach i kasetce na wkład. Aparat cyfrowy zastępuje film matrycą półprzewodnikową (CMOS/CCD), która zamienia fotony na sygnał elektryczny, przetwarzany przez procesor na dane cyfrowe zapisywane na karcie pamięci. Posiada wyświetlacz LCD umożliwiający natychmiastowy podgląd, usuwanie zdjęć i regulację parametrów w menu.'}, {'id': '09a8e323-45f3-496a-91c8-5bb35f662414', 'chapter_id': 2, 'text': 'Omów budowę wywoływarki do filmu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'b7a9bfb9-ba7d-457b-8f8e-bbf14e24dc0f', 'question_id': '09a8e323-45f3-496a-91c8-5bb35f662414', 'text': 'Wyłącznie plastikowe wiaderko i zwykła woda kranowa.', 'is_correct': 0, 'sort_order': 0}, {'id': '2a058fc4-c0eb-47a1-9342-2eb4d197ec39', 'question_id': '09a8e323-45f3-496a-91c8-5bb35f662414', 'text': 'Koreks (pojemnik szczelny ze szpulą, wlewy i wylewy), wywoływarka rotacyjna (bębny obrotowe pracujące w świetle), wywoływarka ciemniowa (kuwety z termostatem); każda zapewnia kontrolę temperatury i dostęp chemii do emulsji.', 'is_correct': 1, 'sort_order': 1}, {'id': '38989a8d-918b-4c98-9953-a1aeb3921ff5', 'question_id': '09a8e323-45f3-496a-91c8-5bb35f662414', 'text': 'Wyłącznie komputer z programem do obróbki zdjęć cyfrowych.', 'is_correct': 0, 'sort_order': 2}, {'id': 'cd99b476-c315-482b-8f39-a5332b37e9bf', 'question_id': '09a8e323-45f3-496a-91c8-5bb35f662414', 'text': 'Suszarka do włosów i żelazko parowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '87e082ce-a5ae-4d9e-8f35-a0c4b6f32ce7', 'chapter_id': 2, 'text': 'Omów budowę wywoływarki do filmu.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Wywoływarki do filmów dzielą się na koreksy – szczelne pojemniki z wewnętrzną szpulą, w których film nawija się w ciemności, a późniejsze etapy chemiczne wykonuje się przy świetle; wywoływarki rotacyjne – bębny obracające się w wannie wodnej z termostatem, zapewniające równomierną agitację; oraz wywoływarki ciemniowe – zestawy kuwet umieszczonych w wannie termostatycznej, używane przy wywoływaniu na szpulach lub w arkuszach. Wszystkie te konstrukcje mają na celu precyzyjną kontrolę temperatury, czasu i dostępu odczynników do emulsji.'}, {'id': '1fee40d9-1499-4b25-a480-4f03fbe3e372', 'chapter_id': 2, 'text': 'Sklasyfikuj i omów lampy błyskowe stosowane w fotografii.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'fd5dded4-0c21-481f-9516-c37d0c315760', 'question_id': '1fee40d9-1499-4b25-a480-4f03fbe3e372', 'text': 'Wyłącznie lampy studyjne o dużej mocy.', 'is_correct': 0, 'sort_order': 0}, {'id': '894396e5-c059-4d23-a377-c75ce7366172', 'question_id': '1fee40d9-1499-4b25-a480-4f03fbe3e372', 'text': 'Lampa wbudowana w korpus (mała moc, stała pozycja), lampa na stopce (systemowa, TTL, wymienna pozycja), lampy studyjne (monobloki i generatory z głowicami); różnią się mocą, czasem recyklingu i możliwością modyfikacji światła.', 'is_correct': 1, 'sort_order': 1}, {'id': 'bb028e10-28af-4fba-85c2-bdd47df71264', 'question_id': '1fee40d9-1499-4b25-a480-4f03fbe3e372', 'text': 'Wyłącznie lampy biurkowe biurowe.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b3ef80c6-1768-4bd3-ae8c-4a9d4ef843a6', 'question_id': '1fee40d9-1499-4b25-a480-4f03fbe3e372', 'text': 'Wyłącznie lampy uliczne i ogrodowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0e4dbad9-c5fa-40bb-9823-5ed0dedf2409', 'chapter_id': 2, 'text': 'Sklasyfikuj i omów lampy błyskowe stosowane w fotografii.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Lampy błyskowe dzielimy na: wbudowane w korpus aparatu – małej mocy, o stałym kierunku światła, służące jako doświetlenie awaryjne; systemowe na stopce (np. Canon Speedlite, Nikon Speedlight) – pracujące w trybie TTL, z możliwością odchylania głowicy i zdalnego sterowania, stanowiące kompromis między mobilnością a mocą; oraz lampy studyjne – monobloki (zintegrowany zasilacz i głowica) i generatory (zasilacz centralny z kilkoma głowicami), charakteryzujące się dużą mocą, krótkim czasem recyklingu i szeroką gamą modyfikatorów (softboxy, parasole, snooty).'}, {'id': '5b6b8294-d969-4f63-a9ee-4e0f03d8f5eb', 'chapter_id': 2, 'text': 'Wyjaśnij pojęcie synchronizacji błysku pomiędzy lampą błyskową a aparatem fotograficznym.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '910a7955-5923-4200-a66b-f2a6c8c34607', 'question_id': '5b6b8294-d969-4f63-a9ee-4e0f03d8f5eb', 'text': 'Łączenie aparatu z komputerem przez sieć Wi-Fi.', 'is_correct': 0, 'sort_order': 0}, {'id': '47690699-3842-4f1f-a5e2-cf412e116ffc', 'question_id': '5b6b8294-d969-4f63-a9ee-4e0f03d8f5eb', 'text': 'Zsynchronizowanie momentu otwarcia migawki z wyładowaniem lampy tak, aby błysk padł na materiał światłoczuły w pełni otwartej migawce; rodzaje: X (standardowa), FP (dla krótkich czasów z migawką szczelinową).', 'is_correct': 1, 'sort_order': 1}, {'id': '79d0b0a5-cd11-4c73-b127-9525db7e085e', 'question_id': '5b6b8294-d969-4f63-a9ee-4e0f03d8f5eb', 'text': 'Synchronizacja zegara w aparacie z czasem światowym UTC.', 'is_correct': 0, 'sort_order': 2}, {'id': '1ac438ed-b088-4041-b48c-5837c8d0b0ee', 'question_id': '5b6b8294-d969-4f63-a9ee-4e0f03d8f5eb', 'text': 'Dopasowanie koloru obudowy lampy do koloru korpusu aparatu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'eac40812-e9b3-4673-abb3-6a5dbb22dc81', 'chapter_id': 2, 'text': 'Wyjaśnij pojęcie synchronizacji błysku pomiędzy lampą błyskową a aparatem fotograficznym.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Synchronizacja błysku to precyzyjne zsynchronizowanie momentu wyładowania lampy z czasem, w którym migawka aparatu jest w pełni otwarta. W synchronizacji standardowej (X-sync) błysk następuje w chwili pełnego otwarcia migawki centralnej lub gdy szczelina migawki płaszczyznowej przesuwa się nad całym kadrze. Synchronizacja FP (focal plane) pozwala na pracę z krótszymi czasami niż czas synchronizacji poprzez emitowanie przez lampę serii szybkich impulsów naświetlających kolejne fragmenty kadru przesuwającej się szczeliny.'}, {'id': '84f64a84-e410-4212-878d-6c01311ec699', 'chapter_id': 2, 'text': 'Omów budowę lustrzanki małoobrazkowej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5b6e1748-1f82-45fd-bc77-36ede3704271', 'question_id': '84f64a84-e410-4212-878d-6c01311ec699', 'text': 'Wyłącznie korpus i obiektyw.', 'is_correct': 0, 'sort_order': 0}, {'id': '3ea8ae01-42ff-4e49-8d5a-e6d7fc157e69', 'question_id': '84f64a84-e410-4212-878d-6c01311ec699', 'text': 'Korpus, bagnet obiektywu, lustro ustawione pod kątem 45 stopni, matówka, pryzmat pentagonalny, wizjer optyczny, migawka szczelinowa, szpula filmu, zasłona, mechanizm przewijania, układ pomiaru światła TTL.', 'is_correct': 1, 'sort_order': 1}, {'id': '1e3414cb-fad0-41fc-9210-a0a5744f3671', 'question_id': '84f64a84-e410-4212-878d-6c01311ec699', 'text': 'Wyłącznie matryca światłoczuła i wyświetlacz LCD.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd439c401-17ec-4467-b3d4-961884fdae91', 'question_id': '84f64a84-e410-4212-878d-6c01311ec699', 'text': 'Wyłącznie lampa błyskowa i karta pamięci.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '003350b0-ea5f-44c8-8d95-7a9f29f71a9e', 'chapter_id': 2, 'text': 'Omów budowę lustrzanki małoobrazkowej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Lustrzanka małoobrazkowa składa się z metalowego lub kompozytowego korpusu z bagnetem mocującym obiektyw, lustra umieszczonego pod kątem 45 stopni, które odbija światło na matówkę, pryzmatu pentagonalnego prostującego obraz w wizjerze optycznym, migawki szczelinowej umieszczonej przed płaszczyzną filmu, mechanizmu przewijania filmu 35 mm z szpulą zasłaniającą, układu pomiaru światła TTL oraz systemu sterowania przysłoną i czasem ekspozycji.'}, {'id': '3806096b-2752-4dd3-a096-113a08739ad0', 'chapter_id': 2, 'text': 'Omów budowę maszyny do wywoływania zdjęć.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '9da7b1e6-368e-4a07-97e4-df3fd0a60b9b', 'question_id': '3806096b-2752-4dd3-a096-113a08739ad0', 'text': 'Wyłącznie komputer stacjonarny i drukarka atramentowa.', 'is_correct': 0, 'sort_order': 0}, {'id': '530f9f30-e8fa-4c83-9182-48314f7275bb', 'question_id': '3806096b-2752-4dd3-a096-113a08739ad0', 'text': 'Minilab: sekcja ładowania filmu lub papieru, tanki chemiczne (C-41/RA-4) z pompami cyrkulacyjnymi, system kaskadowego płukania, suszarnia, moduł naświetlający (laser lub diody LED), układ transportu materiału oraz sterownik temperatury.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f84c4b40-78e6-408b-b8ac-aa1acbca710b', 'question_id': '3806096b-2752-4dd3-a096-113a08739ad0', 'text': 'Wyłącznie żelazko i deska do prasowania.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b4336f53-fb6f-4a6f-92c7-262519a0c98d', 'question_id': '3806096b-2752-4dd3-a096-113a08739ad0', 'text': 'Wyłącznie skaner płaski i kserokopiarka.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '21b976ae-d947-4368-a07b-3e90c9f5f606', 'chapter_id': 2, 'text': 'Omów budowę maszyny do wywoływania zdjęć.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Maszyna do wywoływania zdjęć (minilab) to zautomatyzowane urządzenie składające się z modułu ładowania, w którym film lub papier jest podawany do wnętrza maszyny, szeregu tanków chemicznych utrzymywanych w stałej temperaturze przez termostaty i pompy cyrkulacyjne, kaskadowego systemu płukania z wodą demineralizowaną, suszarni z wentylatorami i filtrami, modułu naświetlającego (w minilabach cyfrowych laser RGB lub diody LED rzutujące obraz na papier światłoczuły) oraz precyzyjnego układu transportu rolek napędowych.'}, {'id': 'b402a88c-8d2e-4c3d-8abe-b143161be453', 'chapter_id': 2, 'text': 'Sklasyfikuj aparaty fotograficzne pod względem konstrukcji i formatów negatywowych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '20b49f46-6a5e-412f-8b8b-5eb22e05fbf5', 'question_id': 'b402a88c-8d2e-4c3d-8abe-b143161be453', 'text': 'Wyłącznie cyfrowe i analogowe.', 'is_correct': 0, 'sort_order': 0}, {'id': 'aeba771d-2795-4934-af38-6dcb0c5a14e2', 'question_id': 'b402a88c-8d2e-4c3d-8abe-b143161be453', 'text': 'Konstrukcja: kompakty, lustrzanki jednoobiektywowe (SLR), dwuobiektywowe (TLR), bezlusterkowce, aparaty wielkoformatowe. Format: małoobrazkowe (135), średnioformatowe (120), wielkoformatowe (4x5 cala), instancyjne.', 'is_correct': 1, 'sort_order': 1}, {'id': '3a4f04fe-6fcd-416f-b1c5-673a0ebb9564', 'question_id': 'b402a88c-8d2e-4c3d-8abe-b143161be453', 'text': 'Wyłącznie czarno-białe i kolorowe.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b37c7047-eec7-4615-bea1-21b2d20c3287', 'question_id': 'b402a88c-8d2e-4c3d-8abe-b143161be453', 'text': 'Wyłącznie profesjonalne i amatorskie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3a6f72da-940e-4699-8877-fcea0cebb7d5', 'chapter_id': 2, 'text': 'Sklasyfikuj aparaty fotograficzne pod względem konstrukcji i formatów negatywowych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Ze względu na konstrukcję aparaty dzielimy na: kompakty (wbudowana optyka, automatyczne sterowanie), lustrzanki jednoobiektywowe (SLR – wizja przez obiektyw, wymienna optyka), lustrzanki dwuobiektywowe (TLR – dwa obiektywy, format średni), bezlusterkowce (wymienna optyka, wizja elektroniczna lub hybrydowa) oraz aparaty wielkoformatowe (klisze płaskie). Ze względu na format negatywu: małoobrazkowe (24×36 mm, film 135), średnioformatowe (6×4,5; 6×6; 6×7; 6×9 cm, film 120), wielkoformatowe (4×5", 8×10", klisze płaskie) oraz formaty instancyjne (np. Polaroid).'}, {'id': '98118203-5630-49b4-904c-8f16bd6264b7', 'chapter_id': 2, 'text': 'Omów sposoby zastosowania obiektywów zmiennoogniskowych w zależności od długości ogniskowej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f3f13c2d-abc3-416d-8551-001183483b74', 'question_id': '98118203-5630-49b4-904c-8f16bd6264b7', 'text': 'Wyłącznie do fotografii makro.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f05ade35-d5b4-46d0-bc95-12dceb2fe6c7', 'question_id': '98118203-5630-49b4-904c-8f16bd6264b7', 'text': 'Szeroki kąt (krajobraz, architektura, wnętrza), standard (reportaż, fotografia uliczna), tele (portret, sport, przyroda), supertele (dzika przyroda, astrofotografia); zoom pozwala płynnie zmieniać pole widzenia bez konieczności wymiany obiektywu.', 'is_correct': 1, 'sort_order': 1}, {'id': '83d59e1a-6df6-42d5-977b-06362561b22c', 'question_id': '98118203-5630-49b4-904c-8f16bd6264b7', 'text': 'Wyłącznie do fotografii portretowej w studio.', 'is_correct': 0, 'sort_order': 2}, {'id': '5d1e5c19-a404-4513-815d-27362989667d', 'question_id': '98118203-5630-49b4-904c-8f16bd6264b7', 'text': 'Wyłącznie do fotografii nocnej i astronomicznej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1d76e84f-7e49-4613-a194-8e8dbb7b02ad', 'chapter_id': 2, 'text': 'Omów sposoby zastosowania obiektywów zmiennoogniskowych w zależności od długości ogniskowej.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obiektywy zmiennoogniskowe (zoom) pozwalają na płynną zmianę kąta widzenia bez wymiany optyki. Przy krótkich ogniskowych (szeroki kąt, np. 16–35 mm) wykorzystuje się je w fotografii krajobrazowej, architektury i wnętrz. Zakres standardowy (np. 24–70 mm) sprawdza się w reportażu i fotografii ulicznej. Tele (np. 70–200 mm) jest uniwersalny w portrecie, sporcie i fotografii przyrodniczej. Supertele (powyżej 300 mm) służy do fotografowania dzikiej przyrody, ptaków oraz obiektów astronomicznych, gdzie kluczowe jest duże powiększenie obrazu.'}, {'id': 'af29fbe5-a850-41fc-9700-a2ee4680c353', 'chapter_id': 2, 'text': 'Co to jest paralaksa (błąd paralaksy) i w jakich aparatach występuje.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '9c84d1a8-f644-4af9-9a3b-c6fa647444fa', 'question_id': 'af29fbe5-a850-41fc-9700-a2ee4680c353', 'text': 'Błąd w odwzorowaniu kolorów na zdjęciu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd6ca97ae-03e1-4f5e-b80f-4f3101da51cc', 'question_id': 'af29fbe5-a850-41fc-9700-a2ee4680c353', 'text': 'Różnica między obrazem widzianym przez wizjer a obrazem rejestrowanym przez obiektyw; występuje w aparatach z wizjerem dalmierzowym, kompaktach i lustrzankach dwuobiektywowych (TLR), nie występuje w lustrzankach jednoobiektywowych i bezlusterkowcach z podglądem na żywo.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b9c348f4-3b2a-4e87-a8d3-83e9cd2760f1', 'question_id': 'af29fbe5-a850-41fc-9700-a2ee4680c353', 'text': 'Błąd w ustawieniu ostrości obiektywu.', 'is_correct': 0, 'sort_order': 2}, {'id': '5d5ee8bc-b062-4c5c-9c3d-7b211dbca70e', 'question_id': 'af29fbe5-a850-41fc-9700-a2ee4680c353', 'text': 'Rodzaj filtra fotograficznego stosowanego w portrecie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'fd7debb0-69d4-43c3-ad0b-d438255c132e', 'chapter_id': 2, 'text': 'Co to jest paralaksa (błąd paralaksy) i w jakich aparatach występuje.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Paralaksa to zjawisko polegające na różnicy między polem widzenia wizjera a polem widzenia obiektywu rejestrującego obraz. Występuje w aparatach z wizjerem dalmierzowym (oddzielny obiektyw wizjera), kompaktach z optycznym wizjerem oraz lustrzankach dwuobiektywowych (TLR), gdzie górny obiektyw służy do obserwacji, a dolny do ekspozycji. Paralaksa jest szczególnie widoczna przy fotografowaniu z bliska. Nie występuje w lustrzankach jednoobiektywowych (SLR), gdzie wizja odbywa się przez ten sam obiektyw, ani w bezlusterkowcach z elektronicznym podglądem na żywo.'}, {'id': '7e2a90eb-1a29-46b2-a0f5-fc72992e0955', 'chapter_id': 2, 'text': 'Omów budowę printera do robienia zdjęć.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '2ba64228-2b1e-4d44-978d-66131ae27dcd', 'question_id': '7e2a90eb-1a29-46b2-a0f5-fc72992e0955', 'text': 'Wyłącznie papier fotograficzny i tusz.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f63d94cc-03ec-4cd9-987f-943e4b1c19cc', 'question_id': '7e2a90eb-1a29-46b2-a0f5-fc72992e0955', 'text': 'Podajnik papieru, mechanizm druku (głowica atramentowa z mikrodyszami lub sublimacyjna z folią barwną), sterownik z procesorem, wyświetlacz, złącza komunikacyjne (USB, Wi-Fi, sloty kart pamięci) oraz zasilacz.', 'is_correct': 1, 'sort_order': 1}, {'id': '6134e938-ec46-4a03-b734-5136eece7bfe', 'question_id': '7e2a90eb-1a29-46b2-a0f5-fc72992e0955', 'text': 'Wyłącznie obiektyw i migawka.', 'is_correct': 0, 'sort_order': 2}, {'id': '0bbe542b-6760-4c4f-8a50-bd4ff4083db2', 'question_id': '7e2a90eb-1a29-46b2-a0f5-fc72992e0955', 'text': 'Wyłącznie klawiatura i ekran dotykowy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c11a615a-a499-4a94-bcfc-cccf625de436', 'chapter_id': 2, 'text': 'Omów budowę printera do robienia zdjęć.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Printer fotograficzny to urządzenie składające się z podajnika papieru fotograficznego, mechanizmu druku (w drukarkach atramentowych są to głowice z mikrodyszami rozpylającymi pigment, w sublimacyjnych – głowica termiczna transferująca barwnik z folii na papier), sterownika z procesorem zarządzającego kolorystyką i rozdzielczością, wyświetlacza do podglądu i obsługi menu, złącz komunikacyjnych (USB, Wi-Fi, Bluetooth, sloty kart SD) oraz zasilacza zapewniającego energię dla całego układu.'}, {'id': '1cc2e1f5-99df-49df-b32e-8bd088d05c0a', 'chapter_id': 2, 'text': 'Wyjaśnij pojęcia: „lustrzanka”, „kompakt”.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '322ceb68-c311-4937-bed1-bb321d6942a1', 'question_id': '1cc2e1f5-99df-49df-b32e-8bd088d05c0a', 'text': 'Lustrzanka to aparat z lustrem i wymienną optyką oferujący pełną kontrolę nad parametrami. Kompakt to mały aparat z wbudowanym obiektywem, automatyką i ograniczoną możliwością sterowania.', 'is_correct': 1, 'sort_order': 0}, {'id': 'd75e8300-60ee-443e-aa21-8d870dcc3762', 'question_id': '1cc2e1f5-99df-49df-b32e-8bd088d05c0a', 'text': 'Lustrzanka to rodzaj lampy błyskowej, a kompakt to statyw fotograficzny.', 'is_correct': 0, 'sort_order': 1}, {'id': '4692eaf3-e7ba-44d1-9cfa-eca3da24193b', 'question_id': '1cc2e1f5-99df-49df-b32e-8bd088d05c0a', 'text': 'To dwa różne rodzaje filmów fotograficznych.', 'is_correct': 0, 'sort_order': 2}, {'id': '2275457d-89ef-44bc-bb8a-7b5c8131d3ff', 'question_id': '1cc2e1f5-99df-49df-b32e-8bd088d05c0a', 'text': 'Lustrzanka to drukarka laserowa, a kompakt to skaner płaski.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '99743cf7-2cb1-4705-b6f2-8093ed575a7c', 'chapter_id': 2, 'text': 'Wyjaśnij pojęcia: „lustrzanka”, „kompakt”.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Lustrzanka (SLR/DSLR) to aparat fotograficzny wyposażony w lustro odbijające światło do wizjera optycznego, zazwyczaj z bagnetem umożliwiającym wymianę obiektywów i zaawansowanym trybem manualnym, co daje fotografowi pełną kontrolę nad ekspozycją, głębią ostrości i kadrem. Kompakt to niewielki aparat z wbudowanym, najczęściej zmiennoogniskowym obiektywem, zorientowany na automatykę i prostotę obsługi, przeznaczony dla użytkowników amatorskich lub jako aparat codzienny (tzw. point-and-shoot).'}, {'id': '48d347ec-7d00-4f4d-881a-b9a2d75084f1', 'chapter_id': 2, 'text': 'Omów najprostszy obiektyw, jego wady i zalety.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1805de8e-03cf-481a-943d-7fb4ec2ed809', 'question_id': '48d347ec-7d00-4f4d-881a-b9a2d75084f1', 'text': 'Obiektyw anamorfotyczny.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c64d7981-8a0e-4f10-99b6-1f0c517565e0', 'question_id': '48d347ec-7d00-4f4d-881a-b9a2d75084f1', 'text': 'Obiektyw pojedynczej soczewki (monokl); zalety: prosta konstrukcja, duża jasność, charakterystyczne rozmycie (bokeh). Wady: aberracje chromatyczna i sferyczna, winietowanie, niska ostrość na brzegach kadru.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b320788d-4f84-4edd-957e-e5128066d9f1', 'question_id': '48d347ec-7d00-4f4d-881a-b9a2d75084f1', 'text': 'Obiektyw zoom zmiennoogniskowy.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd6303e12-61fa-439d-aa4a-22c499248075', 'question_id': '48d347ec-7d00-4f4d-881a-b9a2d75084f1', 'text': 'Obiektyw wieloelementowy z soczewkami asferycznymi.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '9112c32c-4630-4316-b7c8-d2295fdd7f80', 'chapter_id': 2, 'text': 'Omów najprostszy obiektyw, jego wady i zalety.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Najprostszym obiektywem jest obiektyw z pojedynczą soczewką (monokl). Jego zaletami są niezwykle prosta konstrukcja, niska masa, duża jasność oraz charakterystyczne, malarskie rozmycie tła (bokeh). Jednak pojedyncza soczewka cierpi na liczne wady optyczne: aberrację chromatyczną (nieostre, kolorowe brzegi), aberrację sferyczną (miękkość obrazu przy pełnym otwarciu), winietowanie (przyciemnione narożniki) oraz niską ostrość na brzegach kadru, dlatego współczesne obiektywy składają się z wielu soczewek korygujących te błędy.'}, {'id': 'f3e8cf51-26e6-45a3-b1ea-6b3a600242a6', 'chapter_id': 2, 'text': 'Co to jest pryzmat pentagonalny i jakie ma zastosowanie?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '8245d647-eb6b-4d78-addd-7c89e2e0c260', 'question_id': 'f3e8cf51-26e6-45a3-b1ea-6b3a600242a6', 'text': 'Rodzaj statywu fotograficznego z pięcioma nogami.', 'is_correct': 0, 'sort_order': 0}, {'id': '49f4798a-3f59-48d1-979d-7d9eaa60b1a8', 'question_id': 'f3e8cf51-26e6-45a3-b1ea-6b3a600242a6', 'text': 'Układ optyczny z pięcioma ściankami umieszczony w lustrzance, który odbija obraz z matówki do wizjera, prostując go (nieodwrócony i nie lustrzany) i ułatwiając prawidłowe kadrowanie.', 'is_correct': 1, 'sort_order': 1}, {'id': '4fca0ce4-f223-4e69-8f22-783115d5b303', 'question_id': 'f3e8cf51-26e6-45a3-b1ea-6b3a600242a6', 'text': 'Rodzaj filtra fotograficznego o pięciu warstwach.', 'is_correct': 0, 'sort_order': 2}, {'id': 'dee14bc6-04ea-4ce8-bc5f-8f084cfa631e', 'question_id': 'f3e8cf51-26e6-45a3-b1ea-6b3a600242a6', 'text': 'Rodzaj karty pamięci o pojemności 5 GB.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'de2784e7-5948-443e-ab3c-6791ff632a91', 'chapter_id': 2, 'text': 'Co to jest pryzmat pentagonalny i jakie ma zastosowanie?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Pryzmat pentagonalny (często w wersji pentapryzmatu lub pentalustra) to element optyczny umieszczony w lustrzankach jednoobiektywowych pomiędzy matówką a wizjerem. Posiada pięć ścian odbijających, które korygują obraz: odwracają go w pionie i w poziomie, dzięki czemu fotograf widzi scenę w wizjerze w taki sam sposób, jak widzi ją gołym okiem (nieodwróconą i nie lustrzaną). Jest to kluczowy element umożliwiający intuicyjne i precyzyjne kadrowanie.'}, {'id': '068ee5a6-2bdf-46a1-b93e-758926f0055a', 'chapter_id': 2, 'text': 'Wyjaśnij pojęcia: ZOOM, „rybie oko”.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'd7db4982-05df-430a-a7b8-67755b9a687d', 'question_id': '068ee5a6-2bdf-46a1-b93e-758926f0055a', 'text': 'Zoom to zmiana ogniskowej obiektywu, a rybie oko to obiektyw ultrawide z bardzo krótką ogniskową i silnymi zniekształceniami beczkowymi.', 'is_correct': 1, 'sort_order': 0}, {'id': '0da1c9cc-6db6-4f41-8194-5c16a9eb31b4', 'question_id': '068ee5a6-2bdf-46a1-b93e-758926f0055a', 'text': 'Zoom to przybliżanie cyfrowe obrazu, a rybie oko to filtr dostępny w aplikacji Instagram.', 'is_correct': 0, 'sort_order': 1}, {'id': '24ccce5b-5c13-4682-9e98-be9841815941', 'question_id': '068ee5a6-2bdf-46a1-b93e-758926f0055a', 'text': 'Zoom to rodzaj statywu, a rybie oko to lampa błyskowa.', 'is_correct': 0, 'sort_order': 2}, {'id': '2f703c87-6be0-4a2f-8c18-dff1a27209fa', 'question_id': '068ee5a6-2bdf-46a1-b93e-758926f0055a', 'text': 'Zoom to program komputerowy, a rybie oko to rodzaj papieru fotograficznego.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e2144ab3-5de3-440d-82c6-0fc99c0dd7c0', 'chapter_id': 2, 'text': 'Wyjaśnij pojęcia: ZOOM, „rybie oko”.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Zoom (obiektyw zmiennoogniskowy) to obiektyw pozwalający na płynną zmianę długości ogniskowej, a co za tym idzie – kąta widzenia i powiększenia obrazu, bez konieczności zmiany pozycji fotografa ani wymiany optyki. „Rybie oko" (fisheye) to obiektyw o ekstremalnie krótkiej ogniskowej (zazwyczaj poniżej 16 mm dla małego obrazka), charakteryzujący się bardzo szerokim kątem widzenia, często sięgającym 180 stopni, oraz wyraźnymi zniekształceniami beczkowymi, które celowo wykorzystuje się w fotografii kreatywnej, architektury i astrofotografii.'}, {'id': '14bd9304-dd20-49e1-96bb-3f442ce81d25', 'chapter_id': 2, 'text': 'Czy w studio fotograficznym w dobie aparatów cyfrowych potrzebny jest światłomierz? Uzasadnij.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '63591476-01e0-48ff-b875-ddef78765bc8', 'question_id': '14bd9304-dd20-49e1-96bb-3f442ce81d25', 'text': 'Nie, ponieważ aparat cyfrowy ma wbudowany światłomierz i wyświetlacz podglądu na żywo.', 'is_correct': 0, 'sort_order': 0}, {'id': 'a25a546f-2fda-4f59-95f1-a5654cd74154', 'question_id': '14bd9304-dd20-49e1-96bb-3f442ce81d25', 'text': 'Tak, ponieważ światłomierz zewnętrzny (zwłaszcza mierzący światło padające na modela) pozwala precyzyjnie kontrolować oświetlenie sceny niezależnie od odbicia od fotografowanego obiektu, co jest kluczowe przy ustawianiu lamp studyjnych i modyfikatorów.', 'is_correct': 1, 'sort_order': 1}, {'id': 'fce3f813-b50c-40c6-a753-44753da7267d', 'question_id': '14bd9304-dd20-49e1-96bb-3f442ce81d25', 'text': 'Nie, ponieważ światłomierz zawsze podaje błędne wskazania.', 'is_correct': 0, 'sort_order': 2}, {'id': '2778065e-1446-4054-b5ed-b38200f38825', 'question_id': '14bd9304-dd20-49e1-96bb-3f442ce81d25', 'text': 'Tak, ale wyłącznie przy fotografowaniu w całkowitej ciemności.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2833ee1c-6556-4f4e-8528-662b26ebf076', 'chapter_id': 2, 'text': 'Czy w studio fotograficznym w dobie aparatów cyfrowych potrzebny jest światłomierz? Uzasadnij.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Mimo że współczesne aparaty cyfrowe posiadają zaawansowane światłomierze TTL, w studio fotograficznym zewnętrzny światłomierz (flashmeter) wciąż jest niezastąpiony. Mierzy on światło padające na fotografowaną scenę lub modela, a nie światło odbite, co pozwala precyzyjnie ustalić moc poszczególnych lamp, kontrolować stosunek oświetlenia kluczowego do wypełniającego i tła, oraz zachować powtarzalność ustawień między kolejnymi sesjami, niezależnie od koloru ubrań czy tonacji skóry modela.'}, {'id': '24bbe04a-adb2-497e-b44b-d00ba260c602', 'chapter_id': 2, 'text': 'Jakie zastosowanie w fotografii ma filtr polaryzacyjny, a jakie filtr UV?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'fd605310-11c7-4b1b-b770-0839a483bb17', 'question_id': '24bbe04a-adb2-497e-b44b-d00ba260c602', 'text': 'Polaryzacyjny: eliminacja odblasków z powierzchni niebieszczących, wzmocnienie nasycenia barw, przyciemnianie błękitu nieba. UV: blokowanie promieniowania ultrafioletowego, ochrona przedniej soczewki (w aparatach cyfrowych pełni głównie funkcję ochronną).', 'is_correct': 1, 'sort_order': 0}, {'id': 'b1cd7466-6918-442c-a418-1549fbbf37b9', 'question_id': '24bbe04a-adb2-497e-b44b-d00ba260c602', 'text': 'Polaryzacyjny: zmiana temperatury barwowej zdjęcia. UV: powiększanie obrazu optycznego.', 'is_correct': 0, 'sort_order': 1}, {'id': 'b83f4019-afe0-49e0-acf7-510f9c44c566', 'question_id': '24bbe04a-adb2-497e-b44b-d00ba260c602', 'text': 'Polaryzacyjny: wyłącznie do fotografii nocnej. UV: wyłącznie do fotografii podwodnej.', 'is_correct': 0, 'sort_order': 2}, {'id': '9519341a-9657-4e53-a450-985d88a114d6', 'question_id': '24bbe04a-adb2-497e-b44b-d00ba260c602', 'text': 'Oba filtry służą wyłącznie do zmiany kolorystyki zdjęcia na sepia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f72e2e94-e129-4e0d-81f3-8da2d6c958c9', 'chapter_id': 2, 'text': 'Jakie zastosowanie w fotografii ma filtr polaryzacyjny, a jakie filtr UV?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Filtr polaryzacyjny (circular polarizing filter – CPL) przepuszcza fale świetlne o określonej polaryzacji, co pozwala eliminować niepożądane odblaski od wody, szkła, lakieru oraz liści, a także wzmacnia nasycenie barw (szczególnie nieba i roślinności) i przyciemnia błękit nieba. Filtr UV (ultrafioletowy) pierwotnie służył do blokowania promieniowania UV, które powodowało mglistość w fotografii górskiej i nadmorskiej; w erze cyfrowej jego rola zredukowała się głównie do fizycznej ochrony przedniej soczewki obiektywu przed zarysowaniami, kurzem i wilgocią.'}, {'id': 'b11f28f3-170a-4619-9ff5-afaab5ffead0', 'chapter_id': 2, 'text': 'Co to jest liczba przewodnia lampy błyskowej?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '3bb410a7-1cde-4309-8165-1dc7e78068bc', 'question_id': 'b11f28f3-170a-4619-9ff5-afaab5ffead0', 'text': 'Waga lampy wyrażona w gramach.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e19f216d-fb4f-4983-9c2f-18ffbbdf1436', 'question_id': 'b11f28f3-170a-4619-9ff5-afaab5ffead0', 'text': 'Wskaźnik mocy lampy, określający iloczyn odległości od obiektu (w metrach) i wartości przysłony przy czułości ISO 100.', 'is_correct': 1, 'sort_order': 1}, {'id': '7211b3b7-d06e-47e4-a2a4-5f6ddbe733da', 'question_id': 'b11f28f3-170a-4619-9ff5-afaab5ffead0', 'text': 'Czas trwania błysku wyrażony w sekundach.', 'is_correct': 0, 'sort_order': 2}, {'id': '43573e71-7812-4f2e-8e2d-d5cd1982d9a3', 'question_id': 'b11f28f3-170a-4619-9ff5-afaab5ffead0', 'text': 'Temperatura barwowa światła błyskowego wyrażona w kelwinach.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '37ec831a-b903-43c3-8cf7-6f05559142f1', 'chapter_id': 2, 'text': 'Co to jest liczba przewodnia lampy błyskowej?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Liczba przewodnia (Guide Number, GN) to parametr określający moc lampy błyskowej. Jest to iloczyn odległości od fotografowanego obiektu (w metrach) i wartości przysłony, przy której uzyskamy prawidłową ekspozycję przy standardowej czułości ISO 100. Na przykład lampa o GN 40 pozwala na zdjęcie z odległości 10 m przy przysłonie f/4. Im wyższa liczba przewodnia, tym mocniejsza lampa i tym dalej można efektywnie doświetlić scenę.'}, {'id': 'd5e95356-e4cf-44c6-b546-dc925c8bfe5a', 'chapter_id': 2, 'text': 'Z jakich części zbudowany jest powiększalnik?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '14d7db62-6ea4-4c84-9b54-c4be708a30d0', 'question_id': 'd5e95356-e4cf-44c6-b546-dc925c8bfe5a', 'text': 'Wyłącznie obiektyw i papier światłoczuły.', 'is_correct': 0, 'sort_order': 0}, {'id': 'cf9fe628-c90d-4bf3-8943-f1d9f1e6c7c8', 'question_id': 'd5e95356-e4cf-44c6-b546-dc925c8bfe5a', 'text': 'Podstawa, pionowa kolumna, głowica z obiektywem powiększalnikowym, źródło światła, kondensor, karetka na negatyw z maskownicą oraz układ filtrów barwnych (w wersji do odbitek kolorowych).', 'is_correct': 1, 'sort_order': 1}, {'id': '17b417b8-95b9-4c8f-8d7c-3b92ecb781fb', 'question_id': 'd5e95356-e4cf-44c6-b546-dc925c8bfe5a', 'text': 'Wyłącznie komputer stacjonarny i drukarka atramentowa.', 'is_correct': 0, 'sort_order': 2}, {'id': '50c0cb6e-1294-42ac-a2ef-13e847ff69ac', 'question_id': 'd5e95356-e4cf-44c6-b546-dc925c8bfe5a', 'text': 'Wyłącznie klawiatura i myszka komputerowa.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'ebe726b3-490b-4fd6-b685-e56f8bb83568', 'chapter_id': 2, 'text': 'Z jakich części zbudowany jest powiększalnik?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Powiększalnik składa się z solidnej podstawy z miejscem na kuwety, pionowej kolumny z głowicą zawierającą obiektyw powiększalnikowy z pierścieniem ostrości, źródła światła (lampy z reflektorem), kondensora skupiającego promienie na negatywie, karetki na negatyw z maskownicą do kadrowania oraz, w przypadku powiększalników barwnych, głowicy z zestawem filtrów do korekcji barwnej. Wszystkie te elementy współpracują, aby precyzyjnie rzutować i powiększać obraz negatywu na papier fotograficzny.'}, {'id': '0e55a136-bee8-4375-bb1b-42392413ca69', 'chapter_id': 2, 'text': 'Omów urządzenia do wywoływania odbitek fotograficznych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '3e0fccc2-4735-4158-8bef-71b109003a14', 'question_id': '0e55a136-bee8-4375-bb1b-42392413ca69', 'text': 'Wyłącznie minilab.', 'is_correct': 0, 'sort_order': 0}, {'id': '21a62bba-e754-45bb-8e30-d1cb49c49b83', 'question_id': '0e55a136-bee8-4375-bb1b-42392413ca69', 'text': 'Minilab (automatyczny), powiększalnik ciemniowy (ręczny, optyczny), drukarka cyfrowa (atramentowa, sublimacyjna), ekspozytory LED naświetlające tradycyjny papier światłoczuły.', 'is_correct': 1, 'sort_order': 1}, {'id': 'ff89ee0c-698b-4ac3-b524-a935d4debad3', 'question_id': '0e55a136-bee8-4375-bb1b-42392413ca69', 'text': 'Wyłącznie żelazko parowe.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c9593957-a15a-4aa2-bcb5-ef2408e07a76', 'question_id': '0e55a136-bee8-4375-bb1b-42392413ca69', 'text': 'Wyłącznie skaner płaski.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '39ffd5fa-085b-49df-aaff-abd4b3cf3bb9', 'chapter_id': 2, 'text': 'Omów urządzenia do wywoływania odbitek fotograficznych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Do wywoływania odbitek fotograficznych służą: minilaby – zautomatyzowane maszyny przetwarzające negatywy i wykonujące odbitki chemicznie lub cyfrowo; powiększalniki ciemniowe – urządzenia optyczne do ręcznego naświetlania papieru światłoczułego z negatywu; drukarki cyfrowe – atramentowe i sublimacyjne, wywołujące odbitki z plików cyfrowych; oraz ekspozytory LED – nowoczesne urządzenia naświetlające papier światłoczuły RA-4 za pomocą diod LED sterowanych cyfrowo, łączące tradycyjną chemię z przetwarzaniem plików.'}, {'id': '7654917b-9962-48df-b916-bdf93ed2eb32', 'chapter_id': 2, 'text': 'Na której karcie pamięci można wykonać więcej zdjęć – 16MB czy 32MB?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5c082cd5-fdba-413a-bc8a-8c4b87182cba', 'question_id': '7654917b-9962-48df-b916-bdf93ed2eb32', 'text': 'Na karcie 16MB, ponieważ mniejsza pojemność oznacza szybszy zapis danych.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ab3daa45-da76-47ad-8681-b139769c36e4', 'question_id': '7654917b-9962-48df-b916-bdf93ed2eb32', 'text': 'Na karcie 32MB, ponieważ ma ona dwukrotnie większą pojemność pamięci niż karta 16MB.', 'is_correct': 1, 'sort_order': 1}, {'id': 'de274ca9-487b-47d1-bd6d-c540b00b29f5', 'question_id': '7654917b-9962-48df-b916-bdf93ed2eb32', 'text': 'Na obu kartach można wykonać dokładnie tyle samo zdjęć, ponieważ pojemność nie ma znaczenia.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c632dfd9-4c9d-46f3-92aa-0531476a36e4', 'question_id': '7654917b-9962-48df-b916-bdf93ed2eb32', 'text': 'Na żadnej, ponieważ karty pamięci służą wyłącznie do przechowywania plików muzycznych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4c9d02e3-d8fd-42e1-8d9c-2588f4e9b544', 'chapter_id': 2, 'text': 'Na której karcie pamięci można wykonać więcej zdjęć – 16MB czy 32MB?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Na karcie pamięci o pojemności 32 MB można zapisać dwukrotnie więcej danych niż na karcie 16 MB, co przy tym samym formacie i kompresji plików przekłada się na możliwość wykonania około dwukrotnie większej liczby zdjęć. Pojemność karty bezpośrednio determinuje ilość dostępnego miejsca na pliki graficzne.'}, {'id': '0bb82e9e-6408-4e8c-b085-2b1ff60027e8', 'chapter_id': 2, 'text': 'Kupując aparat cyfrowy na jakie elementy zestawu oraz parametry techniczne należy zwrócić uwagę?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '6c239616-4f5e-4b32-8a2d-56520247ad4f', 'question_id': '0bb82e9e-6408-4e8c-b085-2b1ff60027e8', 'text': 'Wyłącznie na kolor obudowy i design aparatu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd0d35641-31e7-4396-a5ec-1040b4a20b69', 'question_id': '0bb82e9e-6408-4e8c-b085-2b1ff60027e8', 'text': 'Matryca (fizyczny rozmiar i rozdzielczość), procesor obrazu, zakres czułości ISO, system autofokusa, stabilizacja obrazu, wymienna optyka/bagnet, ergonomia i wytrzymałość korpusu, wyświetlacz, pojemność baterii oraz obsługa formatu RAW.', 'is_correct': 1, 'sort_order': 1}, {'id': '57bf5c15-8635-48c5-b87c-2b04c3510464', 'question_id': '0bb82e9e-6408-4e8c-b085-2b1ff60027e8', 'text': 'Wyłącznie na wagę i wymiary aparatu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a1973fca-345a-497c-9786-c334c731caaf', 'question_id': '0bb82e9e-6408-4e8c-b085-2b1ff60027e8', 'text': 'Wyłącznie na cenę i markę producenta.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '63169b57-ab43-484c-9ea9-b26fe9f49751', 'chapter_id': 2, 'text': 'Kupując aparat cyfrowy na jakie elementy zestawu oraz parametry techniczne należy zwrócić uwagę?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Przy zakupie aparatu cyfrowego kluczowe są: rozmiar matrycy (większa matryca to lepsza jakość w słabym świetle), rozdzielczość, wydajny procesor obrazu, szeroki zakres ISO, zaawansowany i szybki system AF, stabilizacja (w korpusie lub obiektywie), dostępność wymiennej optyki (bagnet), ergonomia i uszczelnienie korpusu, jakość wyświetlacza i wizjera, pojemność baterii oraz możliwość zapisu w formacie RAW. Warto też zwrócić uwagę na dostępność akcesoriów i oprogramowania.'}, {'id': '74481c01-1606-413d-9d14-3c5b0a85f850', 'chapter_id': 2, 'text': 'Rodzaje soczewek. W jakich jednostkach wyrażana jest moc soczewki?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '5e08787e-3556-492d-afe5-438823308e07', 'question_id': '74481c01-1606-413d-9d14-3c5b0a85f850', 'text': 'Wyłącznie soczewki szklane i plastikowe; moc wyrażana w watach.', 'is_correct': 0, 'sort_order': 0}, {'id': '398b93b6-3c85-4d33-b38d-c39764e61cad', 'question_id': '74481c01-1606-413d-9d14-3c5b0a85f850', 'text': 'Soczewki skupiające (zbieżne, wypukłe) i rozpraszające (rozbieżne, wklęsłe); moc wyrażana jest w dioptriach [dpt].', 'is_correct': 1, 'sort_order': 1}, {'id': '1150262e-6fdc-4dad-b54d-0e32b4c70bf3', 'question_id': '74481c01-1606-413d-9d14-3c5b0a85f850', 'text': 'Wyłącznie soczewki duże i małe; moc wyrażana w lumenach.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f94c851e-196e-4b7b-80e7-e3a3af448ca1', 'question_id': '74481c01-1606-413d-9d14-3c5b0a85f850', 'text': 'Wyłącznie soczewki okrągłe i kwadratowe; moc wyrażana w megapikselach.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7687f663-751d-40a2-adb6-5163c4150378', 'chapter_id': 2, 'text': 'Rodzaje soczewek. W jakich jednostkach wyrażana jest moc soczewki?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W optyce wyróżniamy soczewki skupiające (zbieżne, wypukłe), które skupiają równoległe promienie świetlne w jednym punkcie (ognisku), oraz soczewki rozpraszające (rozbieżne, wklęsłe), które rozpraszają promienie. Moc optyczną soczewki wyraża się w dioptriach [dpt], gdzie 1 dpt = 1/m (odwrotność ogniskowej wyrażonej w metrach). Soczewki skupiające mają dodatnią moc, a rozpraszające – ujemną.'}, {'id': 'ca167914-1a90-44b7-896c-d9d6da7c96f9', 'chapter_id': 2, 'text': 'Omów jaka jest różnica między soczewkami rozpraszającymi a ujemnymi.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '21ee057a-121c-466e-b36a-cb0f381139d8', 'question_id': 'ca167914-1a90-44b7-896c-d9d6da7c96f9', 'text': 'To są dwa różne określenia tego samego typu soczewki (wklęsłej, rozbieżnej), która rozprasza promienie świetlne i ma ujemną moc wyrażoną w minusowych dioptriach.', 'is_correct': 1, 'sort_order': 0}, {'id': '53d7286e-5488-433f-bc09-c50312606635', 'question_id': 'ca167914-1a90-44b7-896c-d9d6da7c96f9', 'text': 'Soczewki rozpraszające skupiają światło, a ujemne je rozpraszają.', 'is_correct': 0, 'sort_order': 1}, {'id': 'ab945c8c-f444-4ccc-96b0-356b1e27cca6', 'question_id': 'ca167914-1a90-44b7-896c-d9d6da7c96f9', 'text': 'Soczewki rozpraszające wykonane są wyłącznie ze szkła, a ujemne wyłącznie z tworzywa sztucznego.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f009885e-a805-4708-a798-f794c0c7f528', 'question_id': 'ca167914-1a90-44b7-896c-d9d6da7c96f9', 'text': 'Nie ma między nimi żadnej różnicy fizycznej ani optycznej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0e0360b5-feab-4427-a4ae-827c85382688', 'chapter_id': 2, 'text': 'Omów jaka jest różnica między soczewkami rozpraszającymi a ujemnymi.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Soczewki rozpraszające i ujemne to to samo. Są to soczewki wklęsłe (wklęsło-wypukłe lub obustronnie wklęsłe), które powodują rozbieżność padających na nie promieni równoległych. W fotografii i optyce korekcyjnej określa się je jako soczewki o ujemnej mocy (ujemne dioptrie). Termin „rozpraszająca" podkreśla funkcję (rozpraszanie światła), a „ujemna" – znak mocy optycznej. Nie ma między nimi różnic konstrukcyjnych.'}, {'id': '03efcc91-5349-47c9-8f46-499da4dd2bf6', 'chapter_id': 2, 'text': 'Rodzaje i zastosowanie filtrów fotograficznych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '7d254ab5-157b-4ec9-8d2e-4e1b7b721ef8', 'question_id': '03efcc91-5349-47c9-8f46-499da4dd2bf6', 'text': 'Wyłącznie filtry UV.', 'is_correct': 0, 'sort_order': 0}, {'id': '5f698f57-b832-489a-a814-8a18f36f128f', 'question_id': '03efcc91-5349-47c9-8f46-499da4dd2bf6', 'text': 'Polaryzacyjne (eliminacja połysków), szare ND (redukcja ilości światła), korekcyjne barwne (korekta temperatury), UV/ochronne, efektowe (rozmywające, gwieździste), barwne do fotografii czarno-białej (kontrola tonalności).', 'is_correct': 1, 'sort_order': 1}, {'id': 'beab76f5-5749-4653-ac91-022e9ffeb3f5', 'question_id': '03efcc91-5349-47c9-8f46-499da4dd2bf6', 'text': 'Wyłącznie filtry przeciwsłoneczne nakładane na obiektyw.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b2245641-e9bd-411d-b086-fb448fc27153', 'question_id': '03efcc91-5349-47c9-8f46-499da4dd2bf6', 'text': 'Wyłącznie filtry cyfrowe dostępne w aplikacjach mobilnych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '46267e5d-96ce-4307-84d8-7f1b163b83d5', 'chapter_id': 2, 'text': 'Rodzaje i zastosowanie filtrów fotograficznych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Filtry fotograficzne dzielą się na: polaryzacyjne – usuwające odblaski i wzmacniające nasycenie barw; szare ND – redukujące ilość światła, co pozwala na dłuższe czasy lub większe przysłony; korekcyjne barwne (konwersyjne) – dostosowujące temperaturę barwową do rodzaju filmu lub źródła światła; UV i ochronne – blokujące promieniowanie ultrafioletowe i zabezpieczające przednią soczewkę; efektowe (rozmywające, gwieździste, makro) – tworzące kreatywne efekty; oraz barwne do fotografii czarno-białej (żółty, pomarańczowy, czerwony, zielony) – kontrolujące tonalność szarości poszczególnych barw.'}, {'id': 'a6b879e5-9f53-4329-aeff-42587fe4f8cd', 'chapter_id': 2, 'text': 'Opisz zasadę powstawania obrazu w fotografii natychmiastowej (Polaroid).', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'c4cea8fd-2712-48c1-93c1-046455a9e87e', 'question_id': 'a6b879e5-9f53-4329-aeff-42587fe4f8cd', 'text': 'Obraz malowany jest ręcznie przez operatora aparatu.', 'is_correct': 0, 'sort_order': 0}, {'id': '437df0ff-a435-4235-bb25-aee0167a026b', 'question_id': 'a6b879e5-9f53-4329-aeff-42587fe4f8cd', 'text': 'Wielowarstwowy pakiet zawiera negatyw, papier pozytywowy i kapsułki z chemikaliami; po naświetleniu wałki rozbijają kapsułki, rozprowadzając reagenty, które wywołują obraz w ciągu kilku minut.', 'is_correct': 1, 'sort_order': 1}, {'id': '01612010-5342-40ee-b030-d11101a0087a', 'question_id': 'a6b879e5-9f53-4329-aeff-42587fe4f8cd', 'text': 'Obraz drukowany jest atramentem wewnątrz komory aparatu.', 'is_correct': 0, 'sort_order': 2}, {'id': '7f10bb4d-979b-4815-a3b1-60915fd78a36', 'question_id': 'a6b879e5-9f53-4329-aeff-42587fe4f8cd', 'text': 'Zdjęcie wysyłane jest pocztą elektroniczną do zewnętrznego laboratorium.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '8a81b69f-8d93-4902-9c2e-6b0ff1618c71', 'chapter_id': 2, 'text': 'Opisz zasadę powstawania obrazu w fotografii natychmiastowej (Polaroid).', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W fotografii natychmiastowej (Polaroid/Instax) wykorzystuje się wielowarstwowy pakiet zawierający negatyw naświetlany przez obiektyw, warstwę papieru pozytywowego oraz wbudowane kapsułki z pastą chemiczną (reagentami). Po naciśnięciu spustu migawki i wysunięciu zdjęcia z aparatu, wałki ciśnieniowe rozbijają kapsułki, rozprowadzając chemikalia pomiędzy negatyw a pozytyw. Reagenty wywołują obraz, który stopniowo pojawia się na powierzchni papieru w ciągu kilku sekund do kilku minut, w zależności od temperatury otoczenia i rodzaju materiału.'}, {'id': '3ac3a23a-a3d3-41c3-b646-45c2e24ce5b1', 'chapter_id': 2, 'text': 'Kiedy używamy filtrów zmiękczających?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '33c641e0-ddad-4900-86e3-ee7316a68d3b', 'question_id': '3ac3a23a-a3d3-41c3-b646-45c2e24ce5b1', 'text': 'Do fotografii sportowej, aby zamrozić szybki ruch.', 'is_correct': 0, 'sort_order': 0}, {'id': 'bccb9f41-aeb4-4019-a664-bfbc627b00be', 'question_id': '3ac3a23a-a3d3-41c3-b646-45c2e24ce5b1', 'text': 'Do portretów, aby ukryć drobne niedoskonałości skóry, zmarszczki i nadać efekt romantycznego, eterycznego rozmycia; stosuje się je również w fotografii reklamowej i modowej.', 'is_correct': 1, 'sort_order': 1}, {'id': '4dd89ec4-72b4-4626-a82e-2f68c99bcacd', 'question_id': '3ac3a23a-a3d3-41c3-b646-45c2e24ce5b1', 'text': 'Do fotografii architektury, aby wyostrzyć linie pionowe i poziome.', 'is_correct': 0, 'sort_order': 2}, {'id': '0a80a183-b4fb-422d-956a-1ad8a4b98f8e', 'question_id': '3ac3a23a-a3d3-41c3-b646-45c2e24ce5b1', 'text': 'Do fotografii makro, aby zwiększyć głębię ostrości.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '80b9b1c6-96ac-44ce-88ae-5e968b5d0da0', 'chapter_id': 2, 'text': 'Kiedy używamy filtrów zmiękczających?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Filtry zmiękczające (soft, diffusion filters) stosuje się przede wszystkim w fotografii portretowej, aby subtelnie rozmyć drobne niedoskonałości skóry, zmarszczki i pory, nadając twarzy efekt delikatności i eteryczności. Są również popularne w fotografii reklamowej, modowej i ślubnej, gdzie pożądany jest romantyczny, „rozmyty" look. Filtr ten działa poprzez rozproszenie światła, co obniża ostrość mikrokontrastu przy zachowaniu ogólnej ostrości konturów.'}, {'id': '0436699c-0bc0-463a-8be4-70a694ee9a04', 'chapter_id': 2, 'text': 'Wymień błędy optyczne soczewek.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'f3438b24-ce7c-4098-9a4c-0cb0361096cb', 'question_id': '0436699c-0bc0-463a-8be4-70a694ee9a04', 'text': 'Aberracja chromatyczna, sferyczna, astygmatyzm, komę, dystorsję, winietowanie, krzywiznę pola.', 'is_correct': 1, 'sort_order': 0}, {'id': '0fe71850-4290-4544-ab8f-4f39bd29377d', 'question_id': '0436699c-0bc0-463a-8be4-70a694ee9a04', 'text': 'Tylko błąd ekspozycji i błąd balansu bieli.', 'is_correct': 0, 'sort_order': 1}, {'id': 'cb6679ab-a877-44be-9986-91a8a9d3df2b', 'question_id': '0436699c-0bc0-463a-8be4-70a694ee9a04', 'text': 'Tylko zarysowanie obiektywu i pęknięcie soczewki.', 'is_correct': 0, 'sort_order': 2}, {'id': '75fed268-7c1b-4483-aee7-3e595a2c2e04', 'question_id': '0436699c-0bc0-463a-8be4-70a694ee9a04', 'text': 'Błędy optyczne to wyłącznie kurz na matrycy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1034e3ac-f4ee-4d22-a2fd-e1942ae25866', 'chapter_id': 2, 'text': 'Wymień błędy optyczne soczewek.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Główne błędy optyczne soczewek to: aberracja chromatyczna (nieostre, kolorowe brzegi wynikające z różnego załamania światła o różnej długości fali), aberracja sferyczna (promienie brzegowe skupiają się w innym punkcie niż osiowe), astygmatyzm (pionowe i poziome linie ostrość mają w różnych płaszczyznach), komę (punktowe źródła światła przy brzegach kadru wyglądają na kometopodobne), dystorsja (zniekształcenie geometryczne – beczkowe lub poduszkowe), winietowanie (przyciemnienie narożników) oraz krzywizna pola (brzegi kadru są ogniskowane na wypukłej powierzchni zamiast na płaszczyźnie).'}, {'id': 'ab03ac73-4c20-48fe-adbc-98854c68b773', 'chapter_id': 2, 'text': 'Do czego służą soczewki nasadkowe?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '3dd9e845-940e-40ee-bb36-190a3d467e4b', 'question_id': 'ab03ac73-4c20-48fe-adbc-98854c68b773', 'text': 'Do czyszczenia obiektywu z kurzu.', 'is_correct': 0, 'sort_order': 0}, {'id': '4033513f-c011-4e56-af85-8b9c512d53c8', 'question_id': 'ab03ac73-4c20-48fe-adbc-98854c68b773', 'text': 'Do zmiany ogniskowej obiektywu (zwiększania lub zmniejszania), umożliwiającej makrofotografię lub telefotografię bez wymiany obiektywu.', 'is_correct': 1, 'sort_order': 1}, {'id': '33d51e26-0745-4a41-b41c-4c124bcdfe43', 'question_id': 'ab03ac73-4c20-48fe-adbc-98854c68b773', 'text': 'Do zmiany temperatury barwowej zdjęcia.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c594e8a0-a347-4b55-b8e0-705fcd9cd2e2', 'question_id': 'ab03ac73-4c20-48fe-adbc-98854c68b773', 'text': 'Do ładowania baterii w aparacie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4390ac2a-d981-4ee9-8177-22f057811a00', 'chapter_id': 2, 'text': 'Do czego służą soczewki nasadkowe?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Soczewki nasadkowe (konwertery) to dodatkowe elementy optyczne nakładane na przednią soczewkę obiektywu. Telekonwerter zwiększa ogniskową (np. 1,4x lub 2x), a konwerter szerokokątny ją zmniejsza. Nasadki makro pozwalająą na fotografowanie z mniejszej odległości, zwiększając skalę odwzorowania. Są tańszą alternatywą dla zakupu nowego obiektywu, choć mogą nieznacznie obniżać jakość obrazu i zmniejszać ilość docierającego światła.'}, {'id': 'c97c3306-5115-4e11-a822-9991485bf2f9', 'chapter_id': 2, 'text': 'Czy pojedyncza soczewka może być obiektywem? Jeżeli tak, to jaka?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '29a4347e-c2f6-431a-910f-ac3b2d5d62bb', 'question_id': 'c97c3306-5115-4e11-a822-9991485bf2f9', 'text': 'Nie, obiektyw musi składać się z co najmniej pięciu soczewek.', 'is_correct': 0, 'sort_order': 0}, {'id': '0e74be4b-df85-4d54-85d3-b84cb0332002', 'question_id': 'c97c3306-5115-4e11-a822-9991485bf2f9', 'text': 'Tak, pojedyncza soczewka (monokl) może być obiektywem, ale charakteryzuje się dużą liczbą aberracji.', 'is_correct': 1, 'sort_order': 1}, {'id': 'cdb52d88-94bc-4d90-ad93-78db0644cd33', 'question_id': 'c97c3306-5115-4e11-a822-9991485bf2f9', 'text': 'Tak, ale wyłącznie soczewka wielowarstwowa z powłokami antyrefleksyjnymi.', 'is_correct': 0, 'sort_order': 2}, {'id': '604c9615-1375-4890-804b-a637c46dce4c', 'question_id': 'c97c3306-5115-4e11-a822-9991485bf2f9', 'text': 'Nie, pojedyncza soczewka służy tylko do korekcji wzroku.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '6b9e22b1-ea57-4dfd-b45d-13dc7ba02dcd', 'chapter_id': 2, 'text': 'Czy pojedyncza soczewka może być obiektywem? Jeżeli tak, to jaka?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Tak, pojedyncza soczewka może pełnić funkcję obiektywu – jest to tzw. monokl. W przeszłości takie obiektywy były stosowane w prostych aparatach (np. szkła powiększalnikowe, proste aparaty otworkowe z soczewką). Jednak pojedyncza soczewka cierpi na aberrację chromatyczną, sferyczną, winietowanie i krzywiznę pola, dlatego współczesne obiektywy fotograficzne składają się z wielu soczewek korygujących te wady.'}, {'id': '67a51305-8d0c-4ade-beb8-613f5a3a5e40', 'chapter_id': 2, 'text': 'Scharakteryzuj nośnik obrazu fotograficznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '890238a2-154b-4cad-8d42-e4e04773877c', 'question_id': '67a51305-8d0c-4ade-beb8-613f5a3a5e40', 'text': 'Wyłącznie papier fotograficzny.', 'is_correct': 0, 'sort_order': 0}, {'id': '77a616fd-3bbf-4716-b611-c244d9029021', 'question_id': '67a51305-8d0c-4ade-beb8-613f5a3a5e40', 'text': 'Materiał światłoczuły rejestrujący obraz: film fotograficzny (emulsja srebrowa na podłożu celuloidowym lub poliestrowym), matryca cyfrowa (CMOS/CCD), papier światłoczuły; charakteryzuje się czułością ISO, rozdzielczością, zakresem dynamiki tonalnej.', 'is_correct': 1, 'sort_order': 1}, {'id': 'bea7a774-3143-4533-bb40-2ca6e4dc36c3', 'question_id': '67a51305-8d0c-4ade-beb8-613f5a3a5e40', 'text': 'Wyłącznie karta pamięci SD.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a439672a-f321-46ce-ac1b-e0556e774b5a', 'question_id': '67a51305-8d0c-4ade-beb8-613f5a3a5e40', 'text': 'Wyłącznie dysk twardy komputera.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '251a663e-721c-4410-8410-6375a264969d', 'chapter_id': 2, 'text': 'Scharakteryzuj nośnik obrazu fotograficznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Nośnik obrazu fotograficznego to medium rejestrujące światło. W fotografii analogowej jest to film fotograficzny – podłoże (celuloid, poliester) pokryte emulsją z halogenkami srebra, charakteryzujące się czułością ISO, ziarnistością i kontrastem. W fotografii cyfrowej rolę nośnika pełni matryca półprzewodnikowa (CMOS lub CCD) zamieniająca światło na sygnał elektryczny, a dane zapisywane są na karcie pamięci. W fotografii tradycyjnej nośnikiem pozytywowym jest papier światłoczuły. Każdy nośnik charakteryzuje się rozdzielczością, zakresem tonalnym i trwałością archiwalną.'}, {'id': '40cf1a69-f65f-43dc-9253-d59b697c678e', 'chapter_id': 2, 'text': 'Podaj nazwę i scharakteryzuj pierwszy obiektyw portretowy?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '52f293c1-d997-4338-a016-bb407f7acc08', 'question_id': '40cf1a69-f65f-43dc-9253-d59b697c678e', 'text': 'Obiektyw szerokokątny 24 mm.', 'is_correct': 0, 'sort_order': 0}, {'id': '27f7e2dd-d463-485f-b62c-209cff68f499', 'question_id': '40cf1a69-f65f-43dc-9253-d59b697c678e', 'text': 'Petzvala (ok. 1840 r.) – obiektyw czteroelementowy, bardzo jasny (f/3,6), dający charakterystyczne rozmycie tła (bokeh) i ostry obraz w centrum przy zmiękczeniu na brzegach.', 'is_correct': 1, 'sort_order': 1}, {'id': 'bc8f34b1-fa4e-4982-8b2c-71705074b6c2', 'question_id': '40cf1a69-f65f-43dc-9253-d59b697c678e', 'text': 'Obiektyw makro 100 mm.', 'is_correct': 0, 'sort_order': 2}, {'id': '65869640-92fc-4162-b787-6a6973c3c91c', 'question_id': '40cf1a69-f65f-43dc-9253-d59b697c678e', 'text': 'Obiektyw rybie oko 8 mm.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'daa8eb3d-f227-4f2c-9c48-9d9c6a577a23', 'chapter_id': 2, 'text': 'Podaj nazwę i scharakteryzuj pierwszy obiektyw portretowy?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Pierwszym obiektywem zaprojektowanym specjalnie do portretu był obiektyw Petzvala, skonstruowany w 1840 roku przez Josepha Petzvala. Składał się z czterech soczewek w dwóch grupach i charakteryzował się niezwykłą jak na owe czasy jasnością f/3,6. Dawał ostry obraz w centrum kadru przy jednoczesnym delikatnym zmiękczeniu i winietowaniu na brzegach, co idealnie nadawało się do portretów, oddzielając modela od tła. Jego konstrukcja stała się wzorcem dla późniejszych portretowych obiektywów długoogniskowych.'}, {'id': '4253c914-f886-44b2-9727-359d980b14a0', 'chapter_id': 2, 'text': 'Dlaczego w powiększalnikach używamy obiektywów o różnych ogniskowych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '716e86ce-05d2-475e-98e3-abc41d345216', 'question_id': '4253c914-f886-44b2-9727-359d980b14a0', 'text': 'Aby zmienić kolor obrazu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd5864262-e430-4fa7-ae93-7507e4b089c7', 'question_id': '4253c914-f886-44b2-9727-359d980b14a0', 'text': 'Ponieważ ogniskowa powiększalnika determinuje wielkość odbitki przy danej wysokości kolumny; krótsze ogniskowe do małych formatów i odbitek, dłuższe do dużych formatów i powiększeń.', 'is_correct': 1, 'sort_order': 1}, {'id': 'bf0de3c7-28d1-421d-bc09-ae96c5e85a7f', 'question_id': '4253c914-f886-44b2-9727-359d980b14a0', 'text': 'Aby zwiększyć temperaturę w ciemni.', 'is_correct': 0, 'sort_order': 2}, {'id': '657e20bb-ae3a-4eb7-a3b3-cd6ea5e9b25f', 'question_id': '4253c914-f886-44b2-9727-359d980b14a0', 'text': 'Aby skrócić czas wywoływania papieru.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'b5a11f3b-0546-4952-8e6a-558cf296de78', 'chapter_id': 2, 'text': 'Dlaczego w powiększalnikach używamy obiektywów o różnych ogniskowych?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'W powiększalniku ogniskowa obiektywu determinuje wielkość uzyskiwanej odbitki przy danej wysokości rzutowania (wysokości kolumny). Obiektywy o krótszych ogniskowych (np. 50 mm) stosuje się do powiększania negatywów małoobrazkowych na standardowe formaty odbitek (np. 10×15 cm, 13×18 cm). Obiektywy o dłuższych ogniskowych (np. 80 mm, 105 mm) pozwalają na uzyskanie większych odbitek przy tej samej wysokości kolumny lub są używane do powiększania negatywów średnioformatowych. Dłuższe ogniskowe dają też większą odległość roboczą między obiektywem a papierem, co ułatwia pracę przy dużych formatach.'}, {'id': '45de0303-28bd-4df9-83f1-573ce95aa4a6', 'chapter_id': 2, 'text': 'Jakie filtry i dlaczego należy stosować nad morzem?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '6c6d9939-84b9-402e-928c-b061c1597cde', 'question_id': '45de0303-28bd-4df9-83f1-573ce95aa4a6', 'text': 'Wyłącznie filtry czerwone.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e15b1fad-a21d-4b32-baef-a96fbf2ca558', 'question_id': '45de0303-28bd-4df9-83f1-573ce95aa4a6', 'text': 'Filtr polaryzacyjny (eliminacja połysków z wody, wzmocnienie kolorów nieba i morza), filtr UV lub ochronny (zabezpieczenie przedni soczewki przed piaskiem i solą), filtr szary ND (dłuższe czasy naświetlania, płynne rozmycie wody).', 'is_correct': 1, 'sort_order': 1}, {'id': '2476cc20-990b-44d8-b84a-b1f6aff446c1', 'question_id': '45de0303-28bd-4df9-83f1-573ce95aa4a6', 'text': 'Wyłącznie filtry żółte do fotografii czarno-białej.', 'is_correct': 0, 'sort_order': 2}, {'id': 'eeb78696-e926-4f82-88b8-c0bc6b51d56f', 'question_id': '45de0303-28bd-4df9-83f1-573ce95aa4a6', 'text': 'Wyłącznie filtry rozmywające.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7f7499a4-86d7-4f60-939c-e30bbf6684f7', 'chapter_id': 2, 'text': 'Jakie filtry i dlaczego należy stosować nad morzem?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Nad morzem najbardziej przydatne są trzy rodzaje filtrów. Filtr polaryzacyjny eliminuje niepożądane odbicia słońca od powierzchni wody i mokrych skał, jednocześnie wzmacniając nasycenie nieba i morza. Filtr UV lub ochronny jest niezbędny ze względu na silne promieniowanie ultrafioletowego i chroni przednią soczewkę przed uszkodzeniem przez piasek, sól i wiatr. Filtr szary ND pozwala na wydłużenie czasu naświetlania, co umożliwia uzyskanie efektu jedwabiście płynnej wody lub mglistych fal przy jasnym świetle dziennym.'}, {'id': '1cc28171-3fab-435c-a382-a0c90bdc1d41', 'chapter_id': 2, 'text': 'Który filtr pochłania promienie ultrafioletowe i gdzie się go stosuje?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '50721d84-87fe-4c39-880a-36623f54c43b', 'question_id': '1cc28171-3fab-435c-a382-a0c90bdc1d41', 'text': 'Filtr polaryzacyjny; stosuje się go wyłącznie w studio.', 'is_correct': 0, 'sort_order': 0}, {'id': '1fa262c7-8b75-4053-94d9-5aa600c65b28', 'question_id': '1cc28171-3fab-435c-a382-a0c90bdc1d41', 'text': 'Filtr UV (ultrafioletowy); stosuje się go w fotografii górskiej, nadmorskiej i jako ochronę przedniej soczewki obiektywu.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f9191b1a-5c1c-437a-9a4c-de538359a931', 'question_id': '1cc28171-3fab-435c-a382-a0c90bdc1d41', 'text': 'Filtr czerwony; stosuje się go w fotografii portretowej.', 'is_correct': 0, 'sort_order': 2}, {'id': 'bd32787a-0c81-4692-a1ba-8e774c9efa80', 'question_id': '1cc28171-3fab-435c-a382-a0c90bdc1d41', 'text': 'Filtr szary ND; stosuje się go wyłącznie nocą.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4348ca9b-152d-47da-acf1-4b9c6cad9d9a', 'chapter_id': 2, 'text': 'Który filtr pochłania promienie ultrafioletowe i gdzie się go stosuje?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Filtr UV (ultrafioletowy, często oznaczany jako Skylight lub Haze) pochłania promieniowanie ultrafioletowe, które w warunkach dużej ilości UV (góry, morze, otwarte przestrzenie) może powodować niebieskawą mgiełkę i obniżenie kontrastu. W fotografii cyfrowej jego rola korekcyjna jest znikoma, ponieważ matryce są mało czułe na UV, dlatego filtr UV stosuje się przede wszystkim jako stała ochrona przedniej soczewki obiektywu przed zarysowaniami, kurzem, wilgocią i zabrudzeniami.'}, {'id': 'f580f1b7-b20d-447c-b30c-c61c19a8f976', 'chapter_id': 2, 'text': 'Co to jest filtr UV i w jakich przypadkach ma zastosowanie?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '88ee2fdc-38a3-4fe2-a501-9a30f630b2d7', 'question_id': 'f580f1b7-b20d-447c-b30c-c61c19a8f976', 'text': 'Filtr zmieniający zdjęcie na czarno-białe.', 'is_correct': 0, 'sort_order': 0}, {'id': 'cffa75be-35cd-4b00-8ab1-734ffab1500f', 'question_id': 'f580f1b7-b20d-447c-b30c-c61c19a8f976', 'text': 'Filtr przepuszczający światło widzialne i blokujący promieniowanie UV; stosuje się go w fotografii krajobrazowej (góry, morze) oraz jako ochronę przedniej soczewki obiektywu.', 'is_correct': 1, 'sort_order': 1}, {'id': '76e13a35-9c2a-4dd6-9951-f8886d978eab', 'question_id': 'f580f1b7-b20d-447c-b30c-c61c19a8f976', 'text': 'Filtr do fotografii podwodnej.', 'is_correct': 0, 'sort_order': 2}, {'id': '2aeaf216-a817-483e-957b-8e85fc2471b8', 'question_id': 'f580f1b7-b20d-447c-b30c-c61c19a8f976', 'text': 'Filtr do zmiany ogniskowej obiektywu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '97ef0b79-9ab2-4f91-a73a-d421127f5d95', 'chapter_id': 2, 'text': 'Co to jest filtr UV i w jakich przypadkach ma zastosowanie?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Filtr UV to filtr optyczny, który przepuszcza światło widzialne i blokuje krótsze fale ultrafioletowe. W fotografii analogowej stosowany był do eliminacji niebieskawej mgiełki powodowanej przez promieniowanie UV w górach i nad morzem. W erze cyfrowej jego funkcja korekcyjna jest marginalna, ponieważ matryce cyfrowe są mało wrażliwe na UV. Obecnie filtr UV pełni głównie rolę ochronną – zabezpiecza przednią soczewkę obiektywu przed zarysowaniami, zabrudzeniami, wilgocią i piaskiem, pozwalając na łatwiejsze czyszczenie i zachowanie wartości optyki.'}, {'id': '30b561e7-5b18-40e9-a90c-b5e49df4be2f', 'chapter_id': 2, 'text': 'Omów właściwości, zastosowanie obiektywu szerokokątnego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'c8e6da00-1c3f-493c-be2c-baeb873150dd', 'question_id': '30b561e7-5b18-40e9-a90c-b5e49df4be2f', 'text': 'Właściwości: duże pole widzenia, silna perspektywa, głęboka głębia ostrości; zastosowanie: krajobraz, architektura, wnętrza, fotografia reportażowa.', 'is_correct': 1, 'sort_order': 0}, {'id': '50a1f3ef-95c1-4184-a9b5-5e45a370e90a', 'question_id': '30b561e7-5b18-40e9-a90c-b5e49df4be2f', 'text': 'Właściwości: wąskie pole widzenia, płytka głębia ostrości; zastosowanie: wyłącznie portret.', 'is_correct': 0, 'sort_order': 1}, {'id': 'b2475371-147e-49b1-b926-dbca001eed09', 'question_id': '30b561e7-5b18-40e9-a90c-b5e49df4be2f', 'text': 'Właściwości: powiększenie rzędu 1:1; zastosowanie: wyłącznie mikrofotografia.', 'is_correct': 0, 'sort_order': 2}, {'id': '96430fb0-901a-4e1f-af42-be8504a265af', 'question_id': '30b561e7-5b18-40e9-a90c-b5e49df4be2f', 'text': 'Właściwości: brak zniekształceń optycznych; zastosowanie: astrofotografia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '862ca6e9-77c2-4eb3-876d-bfdd7e7bb338', 'chapter_id': 2, 'text': 'Omów właściwości, zastosowanie obiektywu szerokokątnego.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obiektyw szerokokątny charakteryzuje się kątem widzenia szerszym niż standardowy obiektyw (powyżej 60–70 stopni), co pozwala na uwzględnienie dużej części sceny w kadrze. Właściwościami charakterystycznymi są: wyraźna perspektywa (przedmioty bliższe wydają się większe w stosunku do oddalonych), duża głębia ostrości przy tej samej przysłonie oraz potencjalne zniekształcenia beczkowe na brzegach kadru. Stosuje się go w fotografii krajobrazowej, architektonicznej, wnętrz, reportażu (gdzie fotograf musi pracować w ciasnych przestrzeniach) oraz astrofotografii.'}, {'id': '5aa11184-6d88-4133-84aa-ecb0aaee191c', 'chapter_id': 2, 'text': 'W jakim miejscu w aparacie fotograficznym najczęściej umiejscowiona jest migawka centralna?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'b19709fe-5014-40dd-ad7c-2e932eb22e30', 'question_id': '5aa11184-6d88-4133-84aa-ecb0aaee191c', 'text': 'W płaszczyźnie ogniskowej obrazu, przed matrycą lub filmem.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c99b55ea-c555-44d3-97c5-b633e75ee728', 'question_id': '5aa11184-6d88-4133-84aa-ecb0aaee191c', 'text': 'W obiektywie, pomiędzy soczewkami lub tuż za przysłoną.', 'is_correct': 1, 'sort_order': 1}, {'id': '7edd5097-7e99-4d97-a744-fe6c3bfce276', 'question_id': '5aa11184-6d88-4133-84aa-ecb0aaee191c', 'text': 'Na górze aparatu, obok wizjera.', 'is_correct': 0, 'sort_order': 2}, {'id': '2f9fd7b0-9fe2-440a-97e1-e18ed049146e', 'question_id': '5aa11184-6d88-4133-84aa-ecb0aaee191c', 'text': 'Wewnątrz lampy błyskowej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'cd248cce-2fa4-43b4-8318-ffcd944f4697', 'chapter_id': 2, 'text': 'W jakim miejscu w aparacie fotograficznym najczęściej umiejscowiona jest migawka centralna?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Migawka centralna (migawka obiektywowa) umiejscowiona jest najczęściej wewnątrz obiektywu, pomiędzy elementami optycznymi lub tuż za przysłoną. Taka lokalizacja pozwala na synchronizację z lampą błyskową przy każdym dostępnym czasie naświetlania, ponieważ cała powierzchnia kliszy lub matrycy jest naświetlana jednocześnie. Występuje ona przede wszystkim w aparatach średnioformatowych, wielkoformatowych oraz w obiektywach do systemów z migawką centralną (np. Hasselblad, Rolleiflex).'}, {'id': 'd0a3726f-4dd4-492b-925e-14ac32186289', 'chapter_id': 2, 'text': 'Kiedy stosujemy filtry polaryzacyjne?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '99c1e996-9ca9-4320-b4c6-2682a6e04b0c', 'question_id': 'd0a3726f-4dd4-492b-925e-14ac32186289', 'text': 'Wyłącznie w fotografii nocnej.', 'is_correct': 0, 'sort_order': 0}, {'id': '63dbd7b1-6361-490a-b219-738d0a801330', 'question_id': 'd0a3726f-4dd4-492b-925e-14ac32186289', 'text': 'Przy silnym świetle, do eliminacji niepożądanych odbić od wody, szkła, lakieru, do wzmacniania nasycenia barw (szczególnie nieba i roślinności) oraz do przyciemniania błękitu nieba w fotografii krajobrazowej.', 'is_correct': 1, 'sort_order': 1}, {'id': '9af38ae0-06df-4447-872d-bc61297770a9', 'question_id': 'd0a3726f-4dd4-492b-925e-14ac32186289', 'text': 'Wyłącznie w fotografii podwodnej.', 'is_correct': 0, 'sort_order': 2}, {'id': '53c2499e-fe05-4e3a-83ea-02d569f0640f', 'question_id': 'd0a3726f-4dd4-492b-925e-14ac32186289', 'text': 'Wyłącznie przy fotografowaniu w sztucznym świetle neonowym.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'bd338ba0-7bd9-41e7-9ed5-7fb6f4c81565', 'chapter_id': 2, 'text': 'Kiedy stosujemy filtry polaryzacyjne?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Filtry polaryzacyjne stosuje się przede wszystkim w słoneczny dzień lub przy silnym, spolaryzowanym świetle. Są niezastąpione przy fotografowaniu powierzchni wodnych (eliminacja odbić słońca, przezroczystość wody), okien i szyb (redukcja refleksów), mokrych liści i lakierowanych powierzchni. Ponadto filtr polaryzacyjny nasyca barwy – szczególnie zieleń roślin i błękit nieba – oraz pozwala na kontrolowane przyciemnianie nieba, co zwiększa kontrast chmur. Nie zaleca się go używać przy szerokokątnych obiektywach, gdzie może powodować nierównomierne przyciemnienie nieba.'}, {'id': 'cbcffd0a-f719-4ab1-9882-564ff28cdc90', 'chapter_id': 2, 'text': 'Kiedy obiektyw nazywamy długoogniskowym? Omów jego zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1656653a-c673-4a1d-92d3-c89da99d6e90', 'question_id': 'cbcffd0a-f719-4ab1-9882-564ff28cdc90', 'text': 'Gdy ogniskowa jest krótsza od przekątnej formatu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'bb37d80d-554c-4e8d-9498-ab72e37134e0', 'question_id': 'cbcffd0a-f719-4ab1-9882-564ff28cdc90', 'text': 'Gdy ogniskowa jest znacznie dłuższa od przekątnej formatu (dla małego obrazka powyżej 70–85 mm); zastosowanie: portret, sport, dzika przyroda, fotografia astronomiczna.', 'is_correct': 1, 'sort_order': 1}, {'id': '6488d0b6-d896-4c1c-941e-2efb2521f6bc', 'question_id': 'cbcffd0a-f719-4ab1-9882-564ff28cdc90', 'text': 'Gdy obiektyw ma wbudowaną lampę błyskową.', 'is_correct': 0, 'sort_order': 2}, {'id': '5cd14fd3-07d0-4b7e-9a5a-9bd6df9333ad', 'question_id': 'cbcffd0a-f719-4ab1-9882-564ff28cdc90', 'text': 'Gdy średnica filtra wynosi więcej niż 95 mm.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7c279108-da46-486b-affe-7de2a19d00c7', 'chapter_id': 2, 'text': 'Kiedy obiektyw nazywamy długoogniskowym? Omów jego zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obiektyw nazywamy długoogniskowym (teleobiektywem), gdy jego ogniskowa jest znacznie dłuższa od przekątnej formatu. Dla filmu małoobrazkowego (przekątna ok. 43 mm) obiektywy powyżej 70–85 mm zaczynają wykazywać cechy tele. Im dłuższa ogniskowa, tym większe powiększenie obrazu i węższe pole widzenia. Zastosowanie: portret (flattering dla twarzy, płytka głębia ostrości), sport (zamrażanie akcji z daleka), fotografia dzikiej przyrody (ptaki, zwierzęta bez zachodzenia im na drogę), astrofotografia (duże powiększenie obiektów niebieskich) oraz fotografia paparazzi i reporterska.'}, {'id': '8fe0cf96-e77f-4075-b204-8e959f79118e', 'chapter_id': 2, 'text': 'Kiedy obiektyw nazwiemy szerokokątnym? Omów jego zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '4f0230f0-6f12-4eaf-9cfa-06e52df73998', 'question_id': '8fe0cf96-e77f-4075-b204-8e959f79118e', 'text': 'Gdy ogniskowa jest dłuższa od przekątnej formatu.', 'is_correct': 0, 'sort_order': 0}, {'id': '7fb76e51-321f-42d8-80fb-bde01e1c83c7', 'question_id': '8fe0cf96-e77f-4075-b204-8e959f79118e', 'text': 'Gdy ogniskowa jest krótsza od przekątnej formatu (dla małego obrazka poniżej 35–40 mm); zastosowanie: krajobraz, architektura, wnętrza, reportaż.', 'is_correct': 1, 'sort_order': 1}, {'id': 'ba01a764-10f1-4b62-b0ab-dbdadeb2f73e', 'question_id': '8fe0cf96-e77f-4075-b204-8e959f79118e', 'text': 'Gdy obiektyw ma wbudowany filtr polaryzacyjny.', 'is_correct': 0, 'sort_order': 2}, {'id': 'aa79b496-a1e9-4263-a75c-cd15b2af1134', 'question_id': '8fe0cf96-e77f-4075-b204-8e959f79118e', 'text': 'Gdy średnica gwintu filtra wynosi mniej niż 40 mm.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '12715ec7-b7c8-470a-a7df-e9fc75520da3', 'chapter_id': 2, 'text': 'Kiedy obiektyw nazwiemy szerokokątnym? Omów jego zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obiektyw szerokokątny to taki, którego ogniskowa jest krótsza od przekątnej formatu. Dla małego obrazka (24×36 mm) są to ogniskowe poniżej ok. 35–40 mm. Charakteryzuje się szerokim kątem widzenia (powyżej 60°), dużą głębią ostrości oraz wyraźnymi zniekształceniami perspektywy, szczególnie przy bardzo krótkich ogniskowych. Stosuje się go w fotografii krajobrazowej (ujęcie rozległych widoków), architektonicznej (wąskie ulice, wnętrza budynków), wnętrz (małe pomieszczenia) oraz reportażu (praca w ciasnych przestrzeniach, uwzględnienie otoczenia wokół bohatera).'}, {'id': '06d52288-82ba-4388-b11f-5098f0fb6458', 'chapter_id': 2, 'text': 'Do czego służą i jakie korzyści dają obiektywy szerokokątne?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '24ee0d47-92ad-449f-9919-9632c5215129', 'question_id': '06d52288-82ba-4388-b11f-5098f0fb6458', 'text': 'Wyłącznie do fotografii makro.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ad6d8828-9b89-4c7e-8579-1abb2a6666c3', 'question_id': '06d52288-82ba-4388-b11f-5098f0fb6458', 'text': 'Służą do fotografowania szerokich scen; korzyści: duże pole widzenia, duża głębia ostrości, możliwość pracy w ciasnych przestrzeniach, wyraźna perspektywa podkreślająca pierwszy plan.', 'is_correct': 1, 'sort_order': 1}, {'id': '5c212465-02de-4d81-ac07-4f0361cb7103', 'question_id': '06d52288-82ba-4388-b11f-5098f0fb6458', 'text': 'Wyłącznie do fotografii portretowej z płytką głębią ostrości.', 'is_correct': 0, 'sort_order': 2}, {'id': '842823a2-8466-4af3-ba43-6bada5b68fe6', 'question_id': '06d52288-82ba-4388-b11f-5098f0fb6458', 'text': 'Wyłącznie do fotografii astronomicznej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '706b58df-75c7-4561-a144-609ad5aa5274', 'chapter_id': 2, 'text': 'Do czego służą i jakie korzyści dają obiektywy szerokokątne?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obiektywy szerokokątne służą do rejestracji szerokich scen, gdzie konieczne jest uwzględnienie dużej ilości elementów w kadrze. Główne korzyści to: duże pole widzenia pozwalające na uchwycenie rozległych krajobrazów lub wnętrz, znacznie większa głębia ostrości przy tej samej przysłonie (przydatna w architekturze i reportażu), możliwość pracy w ciasnych przestrzeniach, gdzie nie ma miejsca na oddalenie się od obiektu, oraz wyraźna perspektywa, która potęguje wrażenie głębi i dynamiki, szczególnie gdy pierwszy plan znajduje się blisko obiektywu.'}, {'id': 'b281ac10-5c1d-4f10-8363-09e68452d0c6', 'chapter_id': 2, 'text': 'Jaki aparat fotograficzny jest właściwy do zdjęć reklamowych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'a89744f6-7e0a-4a4c-aeb1-ce8321e0eb7d', 'question_id': 'b281ac10-5c1d-4f10-8363-09e68452d0c6', 'text': 'Wyłącznie kompaktowy aparat cyfrowy.', 'is_correct': 0, 'sort_order': 0}, {'id': 'cbfc8de8-8efc-4779-a23b-fcdaf4cfc936', 'question_id': 'b281ac10-5c1d-4f10-8363-09e68452d0c6', 'text': 'Aparat z dużą matrycą (pełna klatka, średni format), możliwością wymiany optyki, zapisem RAW, synchronizacją z lampami studyjnymi, wysoką rozdzielczością i precyzyjnym odwzorowaniem barw.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b57c6fd2-0a83-4741-8387-fc9921471aa4', 'question_id': 'b281ac10-5c1d-4f10-8363-09e68452d0c6', 'text': 'Wyłącznie aparat jednorazowy z filmem.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ba258462-58ba-4a6d-b249-f1fcc7751cf1', 'question_id': 'b281ac10-5c1d-4f10-8363-09e68452d0c6', 'text': 'Wyłącznie telefon komórkowy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '08910730-9b2b-4248-b21f-6dea397928a7', 'chapter_id': 2, 'text': 'Jaki aparat fotograficzny jest właściwy do zdjęć reklamowych?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Do fotografii reklamowej wymagany jest aparat oferujący najwyższą jakość obrazu i pełną kontrolę nad parametrami. Najczęściej są to aparaty z matrycą pełnoklatkową (24×36 mm) lub średnioformatową (np. 44×33 mm, 6×4,5 cm), które zapewniają dużą rozdzielczość, szeroki zakres dynamiki tonalnej i doskonałe odwzorowanie barw. Kluczowa jest możliwość wymiany optyki, zapis w formacie RAW do późniejszej obróbki, synchronizacja z lampami studyjnymi (gniazdo PC lub system bezprzewodowy), a także precyzyjny system autofokusa i możliwość pracy w trybie manualnym.'}, {'id': '80f396f5-d54f-4e51-a60a-84f9f5bf7a5f', 'chapter_id': 2, 'text': 'Teleobiektyw – zastosowanie, zalety i wady.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '65285e65-0a28-4699-92d4-2b9cb22c7cca', 'question_id': '80f396f5-d54f-4e51-a60a-84f9f5bf7a5f', 'text': 'Zastosowanie: wyłącznie fotografia nocna. Zalety: mała waga. Wady: brak ostrości.', 'is_correct': 0, 'sort_order': 0}, {'id': '789e8edc-b4ed-472f-a139-8b23b9af1a6b', 'question_id': '80f396f5-d54f-4e51-a60a-84f9f5bf7a5f', 'text': 'Zastosowanie: portret, sport, dzika przyroda. Zalety: duże powiększenie, płytka głębia ostrości, kompresja perspektywy. Wady: duża masa i wymiary, wrażliwość na drgania, wysoka cena.', 'is_correct': 1, 'sort_order': 1}, {'id': '69af2b44-d6a9-40d8-bdf9-4157479389ce', 'question_id': '80f396f5-d54f-4e51-a60a-84f9f5bf7a5f', 'text': 'Zastosowanie: wyłącznie fotografia architektoniczna. Zalety: szerokie pole widzenia. Wady: niska jakość obrazu.', 'is_correct': 0, 'sort_order': 2}, {'id': '0db89b66-1362-4793-b45f-86e7477a3691', 'question_id': '80f396f5-d54f-4e51-a60a-84f9f5bf7a5f', 'text': 'Zastosowanie: wyłącznie fotografia podwodna. Zalety: wodoodporność. Wady: niska rozdzielczość.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'dd1c1b3c-227f-4031-9ec6-c21ef2d7d641', 'chapter_id': 2, 'text': 'Teleobiektyw – zastosowanie, zalety i wady.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Teleobiektyw stosuje się w fotografii portretowej (flattering perspektywa, płytka głębia ostrości oddzielająca modela od tła), sportowej (zamrażanie akcji z dużej odległości), przyrodniczej (fotografowanie dzikich zwierząt bez zakłócania ich spokoju) oraz paparazzi. Zalety to duże powiększenie obrazu, kompresja perspektywy (tło wydaje się bliżej), możliwość pracy z daleka i efektowne rozmycie tła. Wady to znaczna masa i gabaryty utrudniające pracę bez statywu, wysoka podatność na drgania (wymagana stabilizacja lub krótkie czasy), duża średnica filtrów i wysoka cena, szczególnie przy jasnych optykach.'}, {'id': '32c25b09-730f-42bd-bb70-1dc8d9a0cc91', 'chapter_id': 2, 'text': 'Co to jest osłona przeciwsłoneczna i kiedy należy ją stosować?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '6c852622-316f-40fc-a0e1-5725f2627a89', 'question_id': '32c25b09-730f-42bd-bb70-1dc8d9a0cc91', 'text': 'Rodzaj filtra zmieniającego kolorystykę zdjęcia.', 'is_correct': 0, 'sort_order': 0}, {'id': '0b64a768-2525-4253-b29b-d8def4e4ab1d', 'question_id': '32c25b09-730f-42bd-bb70-1dc8d9a0cc91', 'text': 'Element montowany na gwincie obiektywu lub na bagnetowym uchwycie, zasłaniający soczewkę przed bocznym, rozpraszającym światłem; stosuje się ją zawsze, szczególnie przy fotografowaniu pod słońce, w podświetleniu i w silnym świetle bocznym.', 'is_correct': 1, 'sort_order': 1}, {'id': '7d6c4730-1f03-40d8-bdbf-367b8af73519', 'question_id': '32c25b09-730f-42bd-bb70-1dc8d9a0cc91', 'text': 'Pokrowiec na aparat do przechowywania w domu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'eb19638b-4345-4bff-8ec3-df109d4cd285', 'question_id': '32c25b09-730f-42bd-bb70-1dc8d9a0cc91', 'text': 'Rodzaj statywu przeciwwiatrowego.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3c6ba3c7-a8cf-4e47-a964-274f7b09f25e', 'chapter_id': 2, 'text': 'Co to jest osłona przeciwsłoneczna i kiedy należy ją stosować?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Osłona przeciwsłoneczna (lens hood) to element z tworzywa sztucznego, metalu lub gumy montowany na przedniej części obiektywu. Jej zadaniem jest zasłanianie przedniej soczewki przed bocznym, rozpraszającym światłem, które powoduje flary, ghosting i obniżenie kontrastu. Należy ją stosować zawsze, gdy fotografujemy pod słońce, w podświetleniu, przy silnym świetle bocznym lub w warunkach, gdzie mogą wystąpić refleksy. Chroni również przednią soczewkę przed deszczem, kurzem i mechanicznymi uszkodzeniami.'}, {'id': 'eb8f8fd9-fde6-44ff-bcd8-3798ca7ca261', 'chapter_id': 2, 'text': 'Co to jest camera obscura?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'e1a14ba1-590f-41a8-aa21-02ba4921c41e', 'question_id': 'eb8f8fd9-fde6-44ff-bcd8-3798ca7ca261', 'text': 'Nowoczesny aparat cyfrowy z wbudowanym lustrem.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c1b7f3ed-cf27-4df6-a0e1-f9961d9e7593', 'question_id': 'eb8f8fd9-fde6-44ff-bcd8-3798ca7ca261', 'text': 'Ciemna komora z małym otworem, przez który światło projektuje odwrócony obraz na przeciwległej ścianie; przodek współczesnego aparatu fotograficznego.', 'is_correct': 1, 'sort_order': 1}, {'id': '4d399b40-5f00-4635-b2fd-820aca4ff719', 'question_id': 'eb8f8fd9-fde6-44ff-bcd8-3798ca7ca261', 'text': 'Rodzaj obiektywu szerokokątnego.', 'is_correct': 0, 'sort_order': 2}, {'id': 'bdb32336-ba37-413f-9f34-31e5d6daffce', 'question_id': 'eb8f8fd9-fde6-44ff-bcd8-3798ca7ca261', 'text': 'Program komputerowy do edycji zdjęć.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '61b2c77d-4e96-4218-8599-1dd65d39b2f4', 'chapter_id': 2, 'text': 'Co to jest camera obscura?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Camera obscura (łac. ciemna komora) to najstarsze znane urządzenie optyczne, składające się z zamkniętej, ciemnej przestrzeni z malutkim otworem w jednej ze ścian. Przechodzące przez otwór światło rzutuje na przeciwległą ścianę odwrócony do góry nogami i lustrzany obraz otoczenia. Zjawisko to było znane już w starożytności. W epoce nowożytnej camera obscura stała się narzędziem malarzy do precyzyjnego kopiowania perspektywy, a w XIX wieku, po wynalezieniu materiałów światłoczułych, przekształciła się w pierwszy aparat fotograficzny.'}, {'id': 'ffbadd21-22de-4a07-8fae-a81b1ced27ee', 'chapter_id': 2, 'text': 'Co można zastosować, aby zmienić ogniskową?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '2dd4d819-b859-4188-ae8f-bdafffaa9cc2', 'question_id': 'ffbadd21-22de-4a07-8fae-a81b1ced27ee', 'text': 'Wyłącznie wymiana całego aparatu na nowy.', 'is_correct': 0, 'sort_order': 0}, {'id': '1ddf2dd5-3050-4cca-b881-1aa7cdaf7afd', 'question_id': 'ffbadd21-22de-4a07-8fae-a81b1ced27ee', 'text': 'Wymiana obiektywu na inny, użycie telekonwertera lub konwertera szerokokątnego, użycie obiektywu zmiennoogniskowego (zoom) lub soczewek nasadkowych.', 'is_correct': 1, 'sort_order': 1}, {'id': 'df174340-7451-49e8-a702-7dc94dec47e9', 'question_id': 'ffbadd21-22de-4a07-8fae-a81b1ced27ee', 'text': 'Wyłącznie zmiana przysłony w obiektywie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e09342df-b3fe-454b-932a-b2d8bcada9da', 'question_id': 'ffbadd21-22de-4a07-8fae-a81b1ced27ee', 'text': 'Wyłącznie zmiana czułości ISO w aparacie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'da424a65-d6a9-414b-bef4-a19f81d68885', 'chapter_id': 2, 'text': 'Co można zastosować, aby zmienić ogniskową?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Aby zmienić ogniskową, można zastosować kilka rozwiązań. Najprostszym jest wymiana obiektywu na inny o innej ogniskowej (np. z 50 mm na 200 mm). Można również użyć telekonwertera (zwiększającego ogniskową, np. 1,4x, 2x) lub konwertera szerokokątnego (zmniejszającego ogniskową) nakładanego na istniejący obiektyw. Najwygodniejszym rozwiązaniem jest użycie obiektywu zmiennoogniskowego (zoom), który pozwala na płynną zmianę ogniskowej w zadanym zakresie bez wymiany optyki. Alternatywnie można użyć soczewek nasadkowych nakładanych na filtr gwintowany.'}, {'id': '1f711615-94a5-428f-9f5e-3add904a52a6', 'chapter_id': 2, 'text': 'Do czego służą i jakie korzyści dają obiektywy długoogniskowe?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '00b100b7-4f7d-484c-8823-625fa322d835', 'question_id': '1f711615-94a5-428f-9f5e-3add904a52a6', 'text': 'Wyłącznie do fotografii makro.', 'is_correct': 0, 'sort_order': 0}, {'id': '407155c8-e7d5-489d-8c00-1835a0961b7e', 'question_id': '1f711615-94a5-428f-9f5e-3add904a52a6', 'text': 'Służą do fotografowania z dużej odległości; korzyści: duże powiększenie, izolowanie obiektu z otoczenia, płytka głębia ostrości, kompresja perspektywy, możliwość pracy bez zakłócania fotografowanego obiektu.', 'is_correct': 1, 'sort_order': 1}, {'id': '19b64ed1-988f-4b49-8c1b-8c99ed426904', 'question_id': '1f711615-94a5-428f-9f5e-3add904a52a6', 'text': 'Wyłącznie do fotografii architektonicznej.', 'is_correct': 0, 'sort_order': 2}, {'id': '2c5cde72-d689-4c5b-b11d-22fd1cf7ba67', 'question_id': '1f711615-94a5-428f-9f5e-3add904a52a6', 'text': 'Wyłącznie do fotografii podwodnej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '33e8a223-0f0b-405d-8769-6b50cad66073', 'chapter_id': 2, 'text': 'Do czego służą i jakie korzyści dają obiektywy długoogniskowe?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Obiektywy długoogniskowe (teleobiektywy) służą do rejestracji obiektów znajdujących się w dużej odległości. Główne korzyści to: znaczne powiększenie obrazu, co pozwala fotografować szczegóły niedostępne gołym okiem, możliwość silnego odseparowania fotografowanego obiektu od tła dzięki płytkej głębi ostrości, kompresja perspektywy (tło wydaje się bliżej i większe w stosunku do pierwszego planu), a także możliwość pracy z bezpiecznej odległości bez zakłócania zachowania zwierząt lub prywatności osób. Są niezastąpione w fotografii sportowej, przyrodniczej, portretowej i reporterskiej.'}, {'id': 'e00e5c03-49f8-4386-b6cc-595de648f30f', 'chapter_id': 2, 'text': 'Jaka jest standardowa ogniskowa obiektywu dla klatki małoobrazkowej 24×36mm?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '1ec67e54-d612-4588-b94f-f5a79446ff8b', 'question_id': 'e00e5c03-49f8-4386-b6cc-595de648f30f', 'text': '24 mm.', 'is_correct': 0, 'sort_order': 0}, {'id': '2b35f471-f388-4af9-a90e-a5f5499c1171', 'question_id': 'e00e5c03-49f8-4386-b6cc-595de648f30f', 'text': '50 mm (dokładniej ok. 43 mm odpowiadających przekątnej kadru, ale przyjęło się 50 mm jako standard).', 'is_correct': 1, 'sort_order': 1}, {'id': '96b41f90-5e38-424a-83e8-5152860e3cf8', 'question_id': 'e00e5c03-49f8-4386-b6cc-595de648f30f', 'text': '85 mm.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ceac35a5-83bf-4c2f-9176-0c3d26715255', 'question_id': 'e00e5c03-49f8-4386-b6cc-595de648f30f', 'text': '200 mm.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c46803a5-35b3-4949-970b-a43e42de6a1f', 'chapter_id': 2, 'text': 'Jaka jest standardowa ogniskowa obiektywu dla klatki małoobrazkowej 24×36mm?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Dla formatu małoobrazkowego 24×36 mm standardową ogniskową uznaje się 50 mm, choć matematycznie przekątna kadru wynosi ok. 43 mm, co czyniłoby idealnym obiektyw ok. 45 mm. Obiektyw 50 mm został przyjęty jako standard ze względu na prostą konstrukcję optyczną (planar, tessar), dużą jasność i kąt widzenia zbliżony do naturalnego pola widzenia ludzkiego oka. Daje on perspektywę najbardziej zbliżoną do postrzegania rzeczywistości, bez wyraźnych zniekształceń.'}, {'id': '1abe10d0-f1fa-4280-b398-cbc5035117da', 'chapter_id': 2, 'text': 'Co to jest kondensor i jaką spełnia rolę?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '53c064fa-69a1-46fa-a7dd-7126af05d9f0', 'question_id': '1abe10d0-f1fa-4280-b398-cbc5035117da', 'text': 'Element optyczny w obiektywie aparatu zmieniający ogniskową.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ffdf9503-e37e-4b96-b2c6-2b132ae12e99', 'question_id': '1abe10d0-f1fa-4280-b398-cbc5035117da', 'text': 'Układ soczewek w powiększalniku lub projektorze skupiający światło z źródła i równomiernie oświetlający negatyw lub slajd.', 'is_correct': 1, 'sort_order': 1}, {'id': 'e2cf2134-5128-4632-a735-30ce6c61ec2d', 'question_id': '1abe10d0-f1fa-4280-b398-cbc5035117da', 'text': 'Rodzaj filtra fotograficznego.', 'is_correct': 0, 'sort_order': 2}, {'id': '8f9ac2bd-c758-4415-9b1c-8c0f6d6c6f01', 'question_id': '1abe10d0-f1fa-4280-b398-cbc5035117da', 'text': 'Element w lampie błyskowej wydłużający czas błysku.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '5612afa4-305d-4923-9055-c221c97223ec', 'chapter_id': 2, 'text': 'Co to jest kondensor i jaką spełnia rolę?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Kondensor to układ jednej lub kilku soczewek skupiających umieszczony w powiększalniku, projektorze diapozytywów lub mikroskopie pomiędzy źródłem światła a rzutowanym obiektem (negatywem, slajdem). Jego rolą jest zebranie promieni świetlnych z źródła i skierowanie ich w postaci równoległego lub zbliżonego do równoległego strumienia na całą powierzchnię negatywu, co zapewnia równomierne, jasne i kontrastowe naświetlenie bez strat światła na brzegach kadru.'}, {'id': '2f7572f5-64c0-4bbb-8fab-1b6caca1a85e', 'chapter_id': 2, 'text': 'Jaką rolę spełnia migawka, omów zalety i wady. Jakie mamy rodzaje migawek?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '6082e267-d77b-4d3f-bd90-5558243320d7', 'question_id': '2f7572f5-64c0-4bbb-8fab-1b6caca1a85e', 'text': 'Migawka służy do zmiany ogniskowej obiektywu.', 'is_correct': 0, 'sort_order': 0}, {'id': '43fc89b1-e930-4f07-9fd9-6b9af9638949', 'question_id': '2f7572f5-64c0-4bbb-8fab-1b6caca1a85e', 'text': 'Migawka kontroluje czas ekspozycji; zalety: możliwość zamrażania lub rozmazywania ruchu, wady: ograniczenia synchronizacji i zniekształcenia. Rodzaje: centralna, szczelinowa, elektroniczna.', 'is_correct': 1, 'sort_order': 1}, {'id': 'ddf83c85-71eb-4dec-9851-9c4363f5e661', 'question_id': '2f7572f5-64c0-4bbb-8fab-1b6caca1a85e', 'text': 'Migawka służy do zmiany temperatury barwowej.', 'is_correct': 0, 'sort_order': 2}, {'id': '3ae46115-3a73-428b-9e4a-a0ed2052652e', 'question_id': '2f7572f5-64c0-4bbb-8fab-1b6caca1a85e', 'text': 'Migawka to rodzaj filtra.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'b46f62eb-5b89-48e5-95ca-a1cce6573cb4', 'chapter_id': 2, 'text': 'Jaką rolę spełnia migawka, omów zalety i wady. Jakie mamy rodzaje migawek?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Migawka to mechanizm sterujący czasem, przez jaki materiał światłoczuły lub matryca jest eksponowana na światło. Jej rolą jest kontrola ekspozycji oraz wyrażenie ruchu – krótkie czasy zamrażają akcję, długie rozmazują ruch. Zalety to precyzyjna regulacja czasu i możliwość kreatywnej pracy z ruchem. Wady to ograniczenia techniczne: migawka szczelinowa wprowadza zniekształcenia kadłubowe i ogranicza synchronizację z lampą, a migawka centralna ma ograniczoną prędkość maksymalną. Rodzaje migawek to: centralna (w obiektywie), szczelinowa (w płaszczyźnie ogniskowej) oraz elektroniczna (w matrycach cyfrowych – global i rolling shutter).'}, {'id': '1718f8f0-a59d-47cc-8475-bb3711494a33', 'chapter_id': 2, 'text': 'Co oznaczają skróty TTL, MC, DX, AF, FixFocus, Free Focus, Auto Focus?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '637e1ba7-d64e-4afc-84a3-7772a2d189c6', 'question_id': '1718f8f0-a59d-47cc-8475-bb3711494a33', 'text': 'TTL – Through The Lens (pomiar światła przez obiektyw), MC – Multi-Coated (wielowarstwowe powłoki antyrefleksyjne), DX – kodowanie czułości filmu/matrycy (Nikon), AF – Auto Focus (autofokus), FixFocus – stałe ustawienie ostrości, Free Focus – ręczne ustawianie ostrości, Auto Focus – automatyczne ustawianie ostrości.', 'is_correct': 1, 'sort_order': 0}, {'id': 'cb7deb53-420f-4313-af1b-0e31faf0af7f', 'question_id': '1718f8f0-a59d-47cc-8475-bb3711494a33', 'text': 'TTL – Total Time Light, MC – Macro Camera, DX – Digital X-ray, AF – Auto Flash, FixFocus – naprawa ostrości, Free Focus – darmowe skupienie, Auto Focus – automatyczne oświetlenie.', 'is_correct': 0, 'sort_order': 1}, {'id': 'b4993a67-e2b7-4a3a-a5a8-a69f977e40c6', 'question_id': '1718f8f0-a59d-47cc-8475-bb3711494a33', 'text': 'To wszystko oznaczenia rodzajów statywów fotograficznych.', 'is_correct': 0, 'sort_order': 2}, {'id': '3f7f0479-23da-4ef1-851c-16d0b58bfaa7', 'question_id': '1718f8f0-a59d-47cc-8475-bb3711494a33', 'text': 'To nazwy programów komputerowych do edycji zdjęć.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '6590a0b4-87e6-4682-bd1e-1ded6ca130e7', 'chapter_id': 2, 'text': 'Co oznaczają skróty TTL, MC, DX, AF, FixFocus, Free Focus, Auto Focus?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'TTL (Through The Lens) oznacza pomiar światła realizowany przez obiektyw aparatu. MC (Multi-Coated) to wielowarstwowe powłoki antyrefleksyjne na soczewkach. DX to system kodowania czułości filmu (w aparatach Nikon także oznaczenie formatu APS-C). AF (Auto Focus) to automatyczne ustawianie ostrości. FixFocus to obiektyw z niezmienną, fabrycznie ustawioną ostrością (zazwyczaj w aparatach jednorazowych). Free Focus to termin określający ręczne ustawianie ostrości przez fotografa (manual focus). Auto Focus to ogólne określenie systemu automatycznego ustawiania ostrości w aparacie lub obiektywie.'}, {'id': 'ae0ef793-06c5-4857-860b-10093794428d', 'chapter_id': 2, 'text': 'Wymień urządzenia stosowane do wywoływania błon barwnych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '336a0d76-d3fd-4630-82c6-f90a072d464b', 'question_id': 'ae0ef793-06c5-4857-860b-10093794428d', 'text': 'Wyłącznie koreksy.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e1d6ae58-d06a-45a5-9d6a-9a12c9568291', 'question_id': 'ae0ef793-06c5-4857-860b-10093794428d', 'text': 'Koreksy, wywoływarki rotacyjne, minilaby, kuwety ciemniowe z termostatem; wszystkie zapewniają kontrolę temperatury i czasu procesu C-41.', 'is_correct': 1, 'sort_order': 1}, {'id': 'da431c92-b169-4ef4-82ca-098348bc81fb', 'question_id': 'ae0ef793-06c5-4857-860b-10093794428d', 'text': 'Wyłącznie żelazka parowe.', 'is_correct': 0, 'sort_order': 2}, {'id': '79b01acb-a551-4133-a1d2-694ed03c95df', 'question_id': 'ae0ef793-06c5-4857-860b-10093794428d', 'text': 'Wyłącznie drukarki atramentowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4c530bec-a78b-4f79-ac0b-8d5cd1d62abb', 'chapter_id': 2, 'text': 'Wymień urządzenia stosowane do wywoływania błon barwnych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Do wywoływania błon barwnych (filmów kolorowych) stosuje się: koreksy – szczelne pojemniki do ręcznego wywoływania w kontrolowanych warunkach; wywoływarki rotacyjne – bębny obracające się w wannie wodnej, zapewniające stałą temperaturę i równomierną agitację chemii; minilaby – zautomatyzowane maszyny przetwarzające filmy w procesie C-41; oraz tradycyjne kuwety ciemniowe umieszczone w wannie z termostatem, używane przy wywoływaniu na szpulach. Kluczowe jest utrzymanie temperatury wywoływacza na poziomie 37,8°C.'}, {'id': '071cd64f-3e6a-4404-9bcf-ec11750f7605', 'chapter_id': 2, 'text': 'Omów rodzaje aparatów cyfrowych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '487359f3-f4a1-4213-9454-b60d279703bd', 'question_id': '071cd64f-3e6a-4404-9bcf-ec11750f7605', 'text': 'Wyłącznie lustrzanki.', 'is_correct': 0, 'sort_order': 0}, {'id': '29dfc481-fd22-454c-a956-0b05d9fc5a79', 'question_id': '071cd64f-3e6a-4404-9bcf-ec11750f7605', 'text': 'Kompakty (ultrakompakty, superzoomy), bezlusterkowce (z wymienną optyką i wizjerem elektronicznym), lustrzanki cyfrowe (DSLR), aparaty średnioformatowe cyfrowe, smartfony z zaawansowanymi modułami fotograficznymi.', 'is_correct': 1, 'sort_order': 1}, {'id': '66342625-2465-4ace-beb9-d92e8a4192ce', 'question_id': '071cd64f-3e6a-4404-9bcf-ec11750f7605', 'text': 'Wyłącznie aparaty jednorazowe.', 'is_correct': 0, 'sort_order': 2}, {'id': '68db9da0-9c41-44b3-ad84-ddfda03b978a', 'question_id': '071cd64f-3e6a-4404-9bcf-ec11750f7605', 'text': 'Wyłącznie telefony komórkowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'cf456e05-2451-4ae4-952c-d25576588a72', 'chapter_id': 2, 'text': 'Omów rodzaje aparatów cyfrowych.', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Aparaty cyfrowe dzielimy na: kompakty (w tym ultrakompakty do kieszeni, superzoomy z dużym zakresem ogniskowych oraz zaawansowane kompakty z dużymi matrycami), bezlusterkowce (systemy z wymienną optyką, wizjerem elektronicznym lub hybrydowym i matrycą APS-C lub pełnoklatkową), lustrzanki cyfrowe (DSLR – z lustrem, pryzmatem i wizjerem optycznym), aparaty średnioformatowe cyfrowe (z matrycami większymi niż pełna klatka, stosowane w studiach komercyjnych) oraz smartfony z zaawansowanymi modułami fotograficznymi wykorzystującymi fotografię obliczeniową i sztuczną inteligencję.'}, {'id': 'b6e4a1c9-ed08-49eb-a804-3fe7169296f8', 'chapter_id': 2, 'text': 'Wyjaśnij czy obiektyw o ogniskowej 50mm jest standardowym dla aparatu cyfrowego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '855450f3-3899-4d5f-96d9-87e86aefca4a', 'question_id': 'b6e4a1c9-ed08-49eb-a804-3fe7169296f8', 'text': 'Tak, zawsze, niezależnie od wielkości matrycy.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f57fd128-292e-4761-819a-688ce656fd64', 'question_id': 'b6e4a1c9-ed08-49eb-a804-3fe7169296f8', 'text': 'Zależy od wielkości matrycy; dla pełnej klatki (24×36 mm) tak, ale dla matrycy APS-C (crop 1,5x–1,6x) odpowiednikiem jest ok. 33–35 mm, a dla Micro 4/3 ok. 25 mm.', 'is_correct': 1, 'sort_order': 1}, {'id': '1a5b387c-b490-448e-873d-a9d15393ad39', 'question_id': 'b6e4a1c9-ed08-49eb-a804-3fe7169296f8', 'text': 'Nie, dla wszystkich aparatów cyfrowych standardem jest 35 mm.', 'is_correct': 0, 'sort_order': 2}, {'id': '4b9c521a-b351-4863-8cc3-5e662186237b', 'question_id': 'b6e4a1c9-ed08-49eb-a804-3fe7169296f8', 'text': 'Nie, dla aparatów cyfrowych standardem jest zawsze 85 mm.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '17f98822-b492-49e0-bfcc-8cb6a57ff802', 'chapter_id': 2, 'text': 'Wyjaśnij czy obiektyw o ogniskowej 50mm jest standardowym dla aparatu cyfrowego?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Czy obiektyw 50 mm jest standardowy dla aparatu cyfrowego, zależy od fizycznego rozmiaru matrycy. Dla pełnoklatkowej matrycy (24×36 mm) 50 mm pozostaje klasyczną ogniskową standardową. Jednak w aparatach z mniejszymi matrycami (APS-C z crop faktorem 1,5x–1,6x, Micro 4/3 z crop 2x) ogniskowa 50 mm daje kąt widzenia odpowiadający teleobiektywowi (75–80 mm lub 100 mm). Aby uzyskać kąt widzenia standardowy na mniejszych matrycach, należy użyć ogniskowych 33–35 mm (APS-C) lub 25 mm (Micro 4/3).'}, {'id': '8af23889-d68b-40fc-8e8f-9f32fba9559e', 'chapter_id': 2, 'text': 'Jakie znasz rodzaje nośników pamięci cyfrowej?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'e00739fa-cc64-44a0-a3fb-a2862b86a011', 'question_id': '8af23889-d68b-40fc-8e8f-9f32fba9559e', 'text': 'Wyłącznie dyskietki 3,5 cala.', 'is_correct': 0, 'sort_order': 0}, {'id': '4415bff6-a606-4bf4-b8a7-077d7221ad5e', 'question_id': '8af23889-d68b-40fc-8e8f-9f32fba9559e', 'text': "Karty pamięci (SD, microSD, CF, CFexpress, XQD), dyski twarde (HDD, SSD), pamięci flash (pendrive'y), pamięć wewnętrzna aparatu, dyski sieciowe i chmura.", 'is_correct': 1, 'sort_order': 1}, {'id': 'c87cf8d9-6741-46b3-9308-ea54b215da21', 'question_id': '8af23889-d68b-40fc-8e8f-9f32fba9559e', 'text': 'Wyłącznie kasety magnetofonowe.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a0589e79-f3b7-4d84-84bc-0bb80a9e1b16', 'question_id': '8af23889-d68b-40fc-8e8f-9f32fba9559e', 'text': 'Wyłącznie filmy fotograficzne.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '63dd7e39-27df-46fc-ab72-3944db2c5b8c', 'chapter_id': 2, 'text': 'Jakie znasz rodzaje nośników pamięci cyfrowej?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': "Nośniki pamięci cyfrowej stosowane w fotografii to przede wszystkim karty pamięci: SD (Secure Digital, w tym SDHC i SDXC o dużych pojemnościach), microSD (w kamerach sportowych i dronach), CompactFlash (CF, starsze profesjonalne lustrzanki), CFexpress oraz XQD (najszybsze karty do aparatów profesjonalnych). Ponadto używa się dysków twardych HDD i SSD do archiwizacji, pendrive'ów (pamięci flash), pamięci wewnętrznej aparatu (bufor), a w nowoczesnych rozwiązaniach – dysków sieciowych (NAS) oraz usług chmurowych do przechowywania i backupu plików."}, {'id': '8219414e-912f-4836-bf01-4d7bf8731aa0', 'chapter_id': 2, 'text': 'Jaka jest standardowa ogniskowa obiektywu dla formatu 6 x 9?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'b985b108-164c-4ac3-a8c7-573e8e3a79ec', 'question_id': '8219414e-912f-4836-bf01-4d7bf8731aa0', 'text': '50 mm.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f6f711b2-f71e-4548-ae15-9f1ce5193661', 'question_id': '8219414e-912f-4836-bf01-4d7bf8731aa0', 'text': '80 mm (dokładniej ok. 80–105 mm, przy czym 105 mm odpowiada standardowi małoobrazkowemu 50 mm ze względu na przekątną ok. 100 mm formatu 6×9 cm).', 'is_correct': 1, 'sort_order': 1}, {'id': 'd9cb8026-8ac1-404e-8882-4357dbc807f5', 'question_id': '8219414e-912f-4836-bf01-4d7bf8731aa0', 'text': '35 mm.', 'is_correct': 0, 'sort_order': 2}, {'id': '00143158-4e9d-4b11-9818-88360ca4e8e6', 'question_id': '8219414e-912f-4836-bf01-4d7bf8731aa0', 'text': '150 mm.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '18679656-819d-4079-8f21-e7de6b1f45ef', 'chapter_id': 2, 'text': 'Jaka jest standardowa ogniskowa obiektywu dla formatu 6 x 9?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Format 6×9 cm ma przekątną ok. 100 mm. Aby uzyskać kąt widzenia zbliżony do standardowego obiektywu 50 mm dla małego obrazka, należy użyć ogniskowej ok. 100–105 mm. Jednak w praktyce wśród obiektywów do aparatów średnioformatowych często za standardową uznaje się ogniskową 80 mm (dla formatu 6×6 cm) lub 105 mm (dla 6×9 cm), ponieważ dają one perspektywę najbardziej zbliżoną do naturalnego widzenia ludzkiego oka przy tym formacie.'}, {'id': 'e3758a89-aeb9-4214-97be-b59c26bcd337', 'chapter_id': 2, 'text': 'Do czego służy miech a do czego kompendium?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': '3703c115-fbf6-4eb5-893f-95e4eaab63de', 'question_id': 'e3758a89-aeb9-4214-97be-b59c26bcd337', 'text': 'Mieh służy do przechowywania aparatu, a kompendium do czyszczenia obiektywu.', 'is_correct': 0, 'sort_order': 0}, {'id': '98ae0b65-ecfe-41fd-956e-dc1d04a2b6bb', 'question_id': 'e3758a89-aeb9-4214-97be-b59c26bcd337', 'text': 'Mieh to składany, lekki element łączący korpus z obiektywem w aparatach wielkoformatowych, umożliwiający zmianę ogniskowej i korektę perspektywy. Kompendium to osłona przeciwsłoneczna montowana na obiektywach dużego formatu, zapobiegająca flarom.', 'is_correct': 1, 'sort_order': 1}, {'id': 'd5735e73-cd79-426c-94de-01e4fd8f62fb', 'question_id': 'e3758a89-aeb9-4214-97be-b59c26bcd337', 'text': 'Mieh to rodzaj statywu, a kompendium to rodzaj filtra.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e8fd642d-22b5-4529-ba24-100cbb922c06', 'question_id': 'e3758a89-aeb9-4214-97be-b59c26bcd337', 'text': 'Mieh to torba na aparat, a kompendium to lampa błyskowa.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c9eac625-21a7-425c-9029-26d87bb736b7', 'chapter_id': 2, 'text': 'Do czego służy miech a do czego kompendium?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Mieh to składany, harmonijkowy element w aparatach wielkoformatowych (np. 4×5", 8×10") łączący korpus z obiektywem. Umożliwia on przesuwanie i pochylanie obiektywu oraz przesuwanie płaszczyzny filmu, co pozwala na korektę perspektywy (np. zachowanie pionów w architekturze) i sterowanie głębią ostrości (efekt Scheimpfluga). Kompendium to duża, regulowana osłona przeciwsłoneczna montowana na obiektywach dużego i średniego formatu, która skuteczniej niż standardowa osłona zasłania soczewkę przed bocznym światłem, eliminując flary i ghosting.'}, {'id': '721b2f43-f571-4d8e-831c-5a4aefc9687d', 'chapter_id': 2, 'text': 'Omów jakie jest zastosowanie skanera w praktyce fotograficznej?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'fe9de5d9-a0a2-4f40-a028-33bf42c8176f', 'question_id': '721b2f43-f571-4d8e-831c-5a4aefc9687d', 'text': 'Wyłącznie do drukowania dokumentów biurowych.', 'is_correct': 0, 'sort_order': 0}, {'id': 'a26c4a52-cc66-4326-8464-7d206820cadd', 'question_id': '721b2f43-f571-4d8e-831c-5a4aefc9687d', 'text': 'Digitalizacja negatywów, slajdów i odbitek fotograficznych; archiwizacja, retusz cyfrowy, reprodukcja starych zdjęć, przygotowanie materiału do druku i publikacji w internecie.', 'is_correct': 1, 'sort_order': 1}, {'id': '30b22c6e-eb26-4445-81e2-83a79cebf4c3', 'question_id': '721b2f43-f571-4d8e-831c-5a4aefc9687d', 'text': 'Wyłącznie do skanowania kodów kreskowych.', 'is_correct': 0, 'sort_order': 2}, {'id': 'fde50780-a8d7-473f-a475-7679dc836ce7', 'question_id': '721b2f43-f571-4d8e-831c-5a4aefc9687d', 'text': 'Wyłącznie do czyszczenia matrycy aparatu cyfrowego.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a6b0ed59-2417-40d7-b2fe-29c38418600f', 'chapter_id': 2, 'text': 'Omów jakie jest zastosowanie skanera w praktyce fotograficznej?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Skaner w praktyce fotograficznej służy przede wszystkim do digitalizacji materiałów analogowych: negatywów (przy użyciu adapterów do filmów), slajdów (przez podświetlenie) oraz odbitek fotograficznych (skanowanie płaskie). Umożliwia archiwizację starych zdjęć w formie cyfrowej, retusz i restaurację uszkodzonych fotografii, a także przygotowanie materiału do druku, publikacji w internecie czy tworzenia fotoksiążek. Skanery płaskie o wysokiej rozdzielczości (600–6400 dpi) oraz skanery bębnowe zapewniają jakość wystarczającą do profesjonalnych zastosowań.'}, {'id': '95ee39fb-575f-47b9-8434-bc420ad65c31', 'chapter_id': 2, 'text': 'Do czego służy kondensor i komora mieszania?', 'type': 'closed', 'created_at': '2026-05-09 17:17:28', 'answers': [{'id': 'e958cbe9-cd9c-4d09-8957-dcba7bfbe751', 'question_id': '95ee39fb-575f-47b9-8434-bc420ad65c31', 'text': 'Kondensor służy do chłodzenia aparatu, a komora mieszania do przechowywania filmu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c09611fd-4b33-4791-bd1e-1da73e21f649', 'question_id': '95ee39fb-575f-47b9-8434-bc420ad65c31', 'text': 'Kondensor to układ soczewek skupiających światło w powiększalniku/projektorze, a komora mieszania to przestrzeń w lampie błyskowej lub oświetleniu ciągłym, w której światło jest rozpraszane i mieszane dla uzyskania równomiernego oświetlenia.', 'is_correct': 1, 'sort_order': 1}, {'id': 'fd6d4dc2-53ea-47a7-b4f3-f5604cf2e69b', 'question_id': '95ee39fb-575f-47b9-8434-bc420ad65c31', 'text': 'Kondensor to rodzaj filtra, a komora mieszania to torba na aparat.', 'is_correct': 0, 'sort_order': 2}, {'id': '8ee7572d-6720-4c7a-95ff-df750fa97390', 'question_id': '95ee39fb-575f-47b9-8434-bc420ad65c31', 'text': 'Kondensor to obiektyw, a komora mieszania to statyw.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '809341ac-87cc-4644-9d9c-945aaa96d9dc', 'chapter_id': 2, 'text': 'Do czego służy kondensor i komora mieszania?', 'type': 'open', 'created_at': '2026-05-09 17:17:28', 'sample_answer': 'Kondensor to układ soczewek skupiających umieszczony w powiększalniku, projektorze lub mikroskopie, którego zadaniem jest zebranie światła z źródła i skierowanie go w postaci równomiernego strumienia na negatyw lub slajd, co zapewnia jasne i kontrastowe rzutowanie. Komora mieszania to natomiast przestrzeń wewnątrz lampy błyskowej studyjnej lub oprawie oświetleniowej ciągłej, w której światło emitowane przez żarnik lub lampę jest wielokrotnie odbijane od ścianek i rozpraszane, co eliminuje punktowe źródło światła i tworzy duże, miękkie i równomierne oświetlenie wychodzące przez dyfuzor.'}, {'id': 'df476253-383d-4a6e-abc5-b3cb497726f1', 'chapter_id': 3, 'text': 'Uzasadnij jaki materiał negatywowy należy zastosować do zdjęć portretowych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'aed89b3c-4c1f-4639-a500-72cb2ae073de', 'question_id': 'df476253-383d-4a6e-abc5-b3cb497726f1', 'text': 'Film wysokoczuły 3200 ISO do portretów nocnych.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd50f150b-6951-4d39-8920-ffa80c34d172', 'question_id': 'df476253-383d-4a6e-abc5-b3cb497726f1', 'text': 'Film portretowy o czułości 100-400 ISO, drobnoziarnisty, o niskim kontraście i delikatnych przejściach tonalnych (np. Kodak Portra).', 'is_correct': 1, 'sort_order': 1}, {'id': '3dfc4f33-8563-4931-bf62-35e55496b899', 'question_id': 'df476253-383d-4a6e-abc5-b3cb497726f1', 'text': 'Film diapozytywowy (slajdowy) o wysokim kontraście.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f2f909d1-1087-4e0b-b776-47dabd191531', 'question_id': 'df476253-383d-4a6e-abc5-b3cb497726f1', 'text': 'Film czarno-biały dokumentacyjny o czułości 25 ISO.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c2ba53ac-16b5-428d-a182-7eef276be592', 'chapter_id': 3, 'text': 'Uzasadnij jaki materiał negatywowy należy zastosować do zdjęć portretowych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Do zdjęć portretowych najlepiej stosować filmy kolorowe negatywowe typu portretowego (np. Kodak Portra, Fujifilm Pro 400H) lub drobnoziarniste filmy czarno-białe o czułości 100-400 ISO. Charakteryzują się one niskim lub średnim kontrastem, delikatnymi przejściami tonalnymi w skórze, niską ziarnistością i szeroką paletą odcieni, co pozwala na łagodne odwzorowanie twarzy i łatwy retusz.'}, {'id': '9d03e316-cf66-4f12-9858-6c08e72ea430', 'chapter_id': 3, 'text': 'Co to jest Kod DX i jakie ma zastosowanie?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '99c91186-23fe-4a48-b513-1b04a0c9d0fd', 'question_id': '9d03e316-cf66-4f12-9858-6c08e72ea430', 'text': 'Kod kreskowy na opakowaniu filmu do skanowania w sklepie.', 'is_correct': 0, 'sort_order': 0}, {'id': '9596a9b2-8dec-4598-bfa6-910f69f31dea', 'question_id': '9d03e316-cf66-4f12-9858-6c08e72ea430', 'text': 'System kodowania czułości filmu (ISO), długości klatki i tolerancji ekspozycji w postaci metalowych kontaktów na kasetce, odczytywany przez aparat.', 'is_correct': 1, 'sort_order': 1}, {'id': '1c7d785f-eb1d-40da-b24f-578c94fa8f7e', 'question_id': '9d03e316-cf66-4f12-9858-6c08e72ea430', 'text': 'Rodzaj filtra fotograficznego.', 'is_correct': 0, 'sort_order': 2}, {'id': '354291bc-3da3-4da8-9dd6-5e32458af4e4', 'question_id': '9d03e316-cf66-4f12-9858-6c08e72ea430', 'text': 'Format zapisu zdjęć cyfrowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7ad1e74f-8501-42dc-98a8-e4dbeccd982c', 'chapter_id': 3, 'text': 'Co to jest Kod DX i jakie ma zastosowanie?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Kod DX (Digital indeX) to system kodowania parametrów filmu fotograficznego w postaci metalowych płytek kontaktowych na kasetce filmu 35 mm. Aparaty wyposażone w czytnik DX odczytują z nich czułość ISO (z zakresu 25-5000), liczbę klatek na filmie oraz tolerancję ekspozycji, co pozwala na automatyczne ustawienie tych parametrów przez aparat.'}, {'id': 'a2b84795-cd16-4ae0-a15f-cb4d38667bc9', 'chapter_id': 3, 'text': 'Wymień materiały fotograficzne pozytywowe i negatywowe.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '1186f700-1b02-4c4e-a69e-3a91e2fb9f5a', 'question_id': 'a2b84795-cd16-4ae0-a15f-cb4d38667bc9', 'text': 'Tylko filmy i matryce cyfrowe.', 'is_correct': 0, 'sort_order': 0}, {'id': '11c4f985-0e7e-46da-abf3-da31799f09b9', 'question_id': 'a2b84795-cd16-4ae0-a15f-cb4d38667bc9', 'text': 'Negatywowe: filmy negatywowe kolorowe i czarno-białe; pozytywowe: papier fotograficzny (kolorowy i czarno-biały), filmy odwracalne (slajdy/diapozytywy).', 'is_correct': 1, 'sort_order': 1}, {'id': '3398fa6f-4d07-4a6b-941e-6bbf16096cfc', 'question_id': 'a2b84795-cd16-4ae0-a15f-cb4d38667bc9', 'text': 'Tylko tusze do drukarek.', 'is_correct': 0, 'sort_order': 2}, {'id': '6db3ef5a-8be0-449b-9455-a2dcdc182404', 'question_id': 'a2b84795-cd16-4ae0-a15f-cb4d38667bc9', 'text': 'Tylko karty pamięci SD.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '7a2a3fb7-3272-4938-a1c9-ef7137f2bf63', 'chapter_id': 3, 'text': 'Wymień materiały fotograficzne pozytywowe i negatywowe.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Materiały negatywowe to filmy kolorowe (np. Kodak Gold, Portra) i czarno-białe (np. Ilford HP5, Kodak Tri-X), na których obraz jest odwzorowany w odwróconych tonach. Materiały pozytywowe to papier fotograficzny czarno-biały (np. Ilford Multigrade) i kolorowy (RA-4), na których uzyskuje się obraz zgodny z rzeczywistością, oraz filmy odwracalne (slajdy, diapozytywy), które po wywołaniu dają pozytywowy obraz.'}, {'id': '441e5ea8-844d-4432-8a7a-ed02fa1d150b', 'chapter_id': 3, 'text': 'Wymień znane filmy, które spotykamy na rynku fotograficznym i firmy je produkujące.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '4a059779-fae7-4a2d-93fd-09917af5bb7f', 'question_id': '441e5ea8-844d-4432-8a7a-ed02fa1d150b', 'text': 'Tylko Kodak i Fuji.', 'is_correct': 0, 'sort_order': 0}, {'id': '0c4369d4-3a96-4996-8497-c4b883b84ee4', 'question_id': '441e5ea8-844d-4432-8a7a-ed02fa1d150b', 'text': 'Kodak (Gold, Portra, Tri-X, Ektar), Fujifilm (Superia, Pro 400H, Acros), Ilford (HP5, Delta, Pan F), Agfa, Foma, Rollei, CineStill, Lomography.', 'is_correct': 1, 'sort_order': 1}, {'id': '61b36036-b14e-4f76-be15-0e2e8dbd99c7', 'question_id': '441e5ea8-844d-4432-8a7a-ed02fa1d150b', 'text': 'Tylko Polaroid i Instax.', 'is_correct': 0, 'sort_order': 2}, {'id': '3c2d151f-9f75-48af-87ff-a9d83057dd82', 'question_id': '441e5ea8-844d-4432-8a7a-ed02fa1d150b', 'text': 'Tylko Sony i Canon.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '55332550-0c1b-4f16-aaac-cc146ead8928', 'chapter_id': 3, 'text': 'Wymień znane filmy, które spotykamy na rynku fotograficznym i firmy je produkujące.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Na współczesnym rynku fotograficznym spotykamy filmy produkowane przez: Kodak (Portra, Gold, UltraMax, Tri-X, T-Max, Ektar), Fujifilm (Superia, Pro 400H, Velvia, Provia, Acros), Ilford (HP5 Plus, Delta, Pan F Plus, Kentmere), Foma (Fomapan), Agfa (APX), Rollei (Retro, Ortho), CineStill (800T, 50D) oraz Lomography (Color Negative, Purple). Wśród filmów instancyjnych dominują Polaroid i Fujifilm Instax.'}, {'id': '820cc010-bbea-458a-a0f2-dcd224c502d2', 'chapter_id': 3, 'text': 'Podaj nazwę firmy, która pierwsza wyprodukowała film zwojowy.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '8ebb233d-5632-4a55-b47a-046557ae4ba8', 'question_id': '820cc010-bbea-458a-a0f2-dcd224c502d2', 'text': 'Canon.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ce12d536-152e-4dd0-8d9c-e50e605a1bbc', 'question_id': '820cc010-bbea-458a-a0f2-dcd224c502d2', 'text': 'Eastman Kodak (George Eastman) w 1888 roku wraz z aparatem Kodak No. 1.', 'is_correct': 1, 'sort_order': 1}, {'id': '2f2d9212-9d78-416d-8f2c-75956f08a92a', 'question_id': '820cc010-bbea-458a-a0f2-dcd224c502d2', 'text': 'Nikon.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ec37881b-8f5d-44c1-adf5-8e532435adc2', 'question_id': '820cc010-bbea-458a-a0f2-dcd224c502d2', 'text': 'Sony.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4f567295-6e6e-4113-ad9c-0da36b91bb70', 'chapter_id': 3, 'text': 'Podaj nazwę firmy, która pierwsza wyprodukowała film zwojowy.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': "Pierwszą firmą, która wyprodukowała film zwojowy (na podłożu celuloidowym) była Eastman Kodak Company założona przez George'a Eastmana. W 1888 roku wprowadził na rynek aparat Kodak No. 1 wraz z filmem na zwoju, co zrewolucjonizowało fotografię, czyniąc ją dostępną dla szerokiego grona amatorów."}, {'id': '21385954-6d54-44d9-a862-42b6b7fc857b', 'chapter_id': 3, 'text': 'Wymień skład chemiczny osłabiacza. Jakie negatywy nadają się do osłabiania?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'ce74800a-2f6f-4a8d-98eb-3a4442017486', 'question_id': '21385954-6d54-44d9-a862-42b6b7fc857b', 'text': 'Woda i sól; wszystkie negatywy.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ee967e9d-59b3-4ca7-8968-09d9f77e2898', 'question_id': '21385954-6d54-44d9-a862-42b6b7fc857b', 'text': 'Zazwyczaj roztwór mocznika (karbamidu), siarczanu miedzi lub nadmanganianu potasu; nadają się negatywy prześwietlone lub zbyt gęste.', 'is_correct': 1, 'sort_order': 1}, {'id': 'c7a1af0d-0233-4bab-b13d-fe0ae2bba7df', 'question_id': '21385954-6d54-44d9-a862-42b6b7fc857b', 'text': 'Tylko woda destylowana; żadne negatywy nie nadają się do osłabiania.', 'is_correct': 0, 'sort_order': 2}, {'id': 'dd2a8273-74b3-45d4-bcb7-6a4046fde80a', 'question_id': '21385954-6d54-44d9-a862-42b6b7fc857b', 'text': 'Tylko alkohol etylowy; negatywy czarno-białe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f4107161-c0e4-4122-b97e-30e57b97c7b6', 'chapter_id': 3, 'text': 'Wymień skład chemiczny osłabiacza. Jakie negatywy nadają się do osłabiania?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': "Osłabiacz (reducer) to roztwór chemiczny zmniejszający gęstość optyczną negatywu. Najczęściej stosuje się roztwory na bazie mocznika (karbamidu), siarczanu miedzi (Farmer's reducer na bazie cyjanku potasu i siarczanu miedzi, obecnie rzadziej używany ze względu na toksyczność) lub nadmanganianu potasu z kwasem siarkowym. Osłabianiu poddaje się negatywy prześwietlone, zbyt gęste lub o zbyt wysokim kontraście, które trudno byłoby powiększyć standardowo."}, {'id': '8d882a7c-d986-445c-b4d2-effcd6296988', 'chapter_id': 3, 'text': 'Wymień rodzaje filtrów fotograficznych i do jakich celów ich użyjesz?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '26523d0d-7c18-4918-ad60-32d4ea8be2ab', 'question_id': '8d882a7c-d986-445c-b4d2-effcd6296988', 'text': 'Tylko UV i polaryzacyjne.', 'is_correct': 0, 'sort_order': 0}, {'id': 'dec1d5b8-c9e9-4920-a6df-f4fc183c4138', 'question_id': '8d882a7c-d986-445c-b4d2-effcd6296988', 'text': 'Polaryzacyjne (eliminacja połysków), szare ND (redukcja światła), korekcyjne barwne (temperatura barw), UV (ochrona), efektowe (rozmywające, gwieździste), barwne do cz-b (tonalność).', 'is_correct': 1, 'sort_order': 1}, {'id': 'd1d5f7f6-55a4-4d47-be32-07754ba51e1c', 'question_id': '8d882a7c-d986-445c-b4d2-effcd6296988', 'text': 'Tylko czerwone i niebieskie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'eb476da8-f8cb-4e74-b6aa-42e08aec579d', 'question_id': '8d882a7c-d986-445c-b4d2-effcd6296988', 'text': 'Tylko filtry cyfrowe w Photoshopie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '73e677fe-abd8-4139-8ae2-81fe8349ffcb', 'chapter_id': 3, 'text': 'Wymień rodzaje filtrów fotograficznych i do jakich celów ich użyjesz?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Rodzaje filtrów fotograficznych to: polaryzacyjne – do eliminacji połysków i wzmocnienia nasycenia barw; szare (ND) – do redukcji ilości światła, co pozwala na dłuższe czasy lub większe przysłony; korekcyjne barwne (konwersyjne) – do dostosowania temperatury barwowej filmu do źródła światła; UV i ochronne – do blokowania promieniowania UV i ochrony przedniej soczewki; efektowe (rozmywające, gwieździste, makro) – do tworzenia efektów specjalnych; oraz barwne do fotografii czarno-białej (żółty, pomarańczowy, czerwony, zielony) – do kontroli tonalności szarości.'}, {'id': 'efe13e15-45b5-404e-8615-a353c81b3755', 'chapter_id': 3, 'text': 'Podaj skład utrwalacza kwaśnego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '1a7f07c9-596b-4474-81d6-9e5c9e677155', 'question_id': 'efe13e15-45b5-404e-8615-a353c81b3755', 'text': 'Tylko woda i sól.', 'is_correct': 0, 'sort_order': 0}, {'id': '98b106f7-7401-4463-b81b-1220718d37c4', 'question_id': 'efe13e15-45b5-404e-8615-a353c81b3755', 'text': 'Tiosiarczan sodu (lub amonu) jako czynnik utrwalający, kwas siarkawy (lub kwas octowy/metabisulfit) jako czynnik zakwaszający, siarczan sodu lub glinowy jako środek utrwalający właściwości fizyczne emulsji.', 'is_correct': 1, 'sort_order': 1}, {'id': '688d55ac-b866-4ed6-821b-04680adbec3b', 'question_id': 'efe13e15-45b5-404e-8615-a353c81b3755', 'text': 'Tylko metol i hydrochinon.', 'is_correct': 0, 'sort_order': 2}, {'id': '35bd043f-75c1-40fc-a56e-f8dca8d8f6a6', 'question_id': 'efe13e15-45b5-404e-8615-a353c81b3755', 'text': 'Tylko węglan sodu i kwas borowy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'cd3163a7-23cf-4000-afd4-c75493c05f32', 'chapter_id': 3, 'text': 'Podaj skład utrwalacza kwaśnego.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Utrwalacz kwaśny (F-24 lub podobny) składa się z trzech głównych składników: tiosiarczanu sodu (lub amonu) – czynnika chemicznego rozpuszczającego nienaświetlone halogenki srebra; kwasu siarkawego (lub kwasu octowego, węglanu sodu z kwasem, metabisulfitu sodu) – utrzymującego kwaśne pH, co zapobiega rozkładowi tiosiarczanu i wypłukaniu wywołanego srebra; oraz siarczanu sodu lub siarczanu glinu – środka utrwalającego właściwości fizyczne żelatyny emulsji i zapobiegającego jej mięknięciu w ciepłej wodzie.'}, {'id': '84375713-dcd2-4aef-a8a7-c9839bd4b92e', 'chapter_id': 3, 'text': 'Co to jest ziarnistość materiału fotograficznego i od czego zależy?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '6a43a673-9c6a-4016-bff9-d7f8f19c804f', 'question_id': '84375713-dcd2-4aef-a8a7-c9839bd4b92e', 'text': 'Wielkość ziaren srebra w emulsji; zależy od czułości ISO, rodzaju wywoływacza, czasu i temperatury wywoływania.', 'is_correct': 1, 'sort_order': 0}, {'id': 'a39bc211-ac59-40bb-b80b-5fe4f89a7102', 'question_id': '84375713-dcd2-4aef-a8a7-c9839bd4b92e', 'text': 'Grubość podłoża filmu; zależy wyłącznie od marki aparatu.', 'is_correct': 0, 'sort_order': 1}, {'id': '0c49c57a-851c-41bd-984b-d82ff9602371', 'question_id': '84375713-dcd2-4aef-a8a7-c9839bd4b92e', 'text': 'Kolor obudowy kasetki; zależy od pory dnia.', 'is_correct': 0, 'sort_order': 2}, {'id': '8b0065f6-0bc1-4681-ad8c-15fe07ea046a', 'question_id': '84375713-dcd2-4aef-a8a7-c9839bd4b92e', 'text': 'Rodzaj statywu użytego podczas zdjęć.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '44f6a5b3-d7cc-4714-9584-35d3bdf2665a', 'chapter_id': 3, 'text': 'Co to jest ziarnistość materiału fotograficznego i od czego zależy?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Ziarnistość to widoczna struktura ziaren metalicznego srebra (w filmach czarno-białych) lub barwników (w kolorowych) tworzących obraz. Zależy ona przede wszystkim od czułości materiału światłoczułego (wyższe ISO = większe ziarno), ale także od rodzaju użytego wywoływacza (energiczne wywoływacze wzmagają ziarnistość), temperatury i czasu wywoływania, sposobu agitacji oraz rodzaju emulsji (krystaliczna struktura halogenków srebra).'}, {'id': '114aa881-3220-4abc-8515-2ca084b4ab80', 'chapter_id': 3, 'text': 'Wymień rodzaje materiałów negatywowych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '075f6ebc-1ca0-4106-96b8-ec6cf7720ad5', 'question_id': '114aa881-3220-4abc-8515-2ca084b4ab80', 'text': 'Tylko filmy czarno-białe.', 'is_correct': 0, 'sort_order': 0}, {'id': '2f72ad99-db8d-4498-a997-253ad32b8d88', 'question_id': '114aa881-3220-4abc-8515-2ca084b4ab80', 'text': 'Filmy negatywowe czarno-białe, negatywowe kolorowe (C-41), materiały odwracalne (slajdy E-6), papiery negatywowe (w fotografii wielkoformatowej).', 'is_correct': 1, 'sort_order': 1}, {'id': '9e764624-f4d8-4352-a07e-314cf2256750', 'question_id': '114aa881-3220-4abc-8515-2ca084b4ab80', 'text': 'Tylko matryce CMOS.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd7cc6474-3a99-4782-8750-3dbac98c5974', 'question_id': '114aa881-3220-4abc-8515-2ca084b4ab80', 'text': 'Tylko karty pamięci SD.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'cfa77cc3-ac42-4179-b67a-4ef6fdcc3902', 'chapter_id': 3, 'text': 'Wymień rodzaje materiałów negatywowych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Rodzaje materiałów negatywowych to: filmy negatywowe czarno-białe (różne czułości, kontrasty, ziarnistości), filmy negatywowe kolorowe (proces C-41, np. Kodak Portra, Gold), materiały odwracalne (filmy pozytywowe/diapozytywy proces E-6, np. Fujifilm Velvia, Provia), które technicznie dają obraz pozytywowy, ale są czasem mylone z negatywami, oraz specjalistyczne papiery negatywowe stosowane w fotografii wielkoformatowej (procesy alternatywne).'}, {'id': 'bf43abf5-69e9-43df-9c6f-a696c5b7a73a', 'chapter_id': 3, 'text': 'Dlaczego produkuje się papier fotograficzny o różnych rodzajach powierzchni?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '6ec37b6f-c8ae-40e1-9a33-cf5e84c45011', 'question_id': 'bf43abf5-69e9-43df-9c6f-a696c5b7a73a', 'text': 'Aby zwiększyć wagę papieru.', 'is_correct': 0, 'sort_order': 0}, {'id': '35997796-48c3-420c-9285-fa245109dbfb', 'question_id': 'bf43abf5-69e9-43df-9c6f-a696c5b7a73a', 'text': 'Aby dostosować odbitkę do charakteru zdjęcia: błysk (współczesny, kontrastowy), półmat (uniwersalny), mat (artystyczny, retro), jedwabisty (delikatny połysk, portrety), perłowy (efektowny).', 'is_correct': 1, 'sort_order': 1}, {'id': 'a1c30d51-0149-48f1-93e5-f3c199c95227', 'question_id': 'bf43abf5-69e9-43df-9c6f-a696c5b7a73a', 'text': 'Aby papier był tańszy w produkcji.', 'is_correct': 0, 'sort_order': 2}, {'id': '99992e3d-1fb6-41fd-beba-2504a1df594e', 'question_id': 'bf43abf5-69e9-43df-9c6f-a696c5b7a73a', 'text': 'Aby zmienić rozmiar negatywu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3875e9f1-00f6-4b5a-b5ca-629607ba51ff', 'chapter_id': 3, 'text': 'Dlaczego produkuje się papier fotograficzny o różnych rodzajach powierzchni?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Papier fotograficzny produkuje się w różnych powierzchniach, aby fotograf mógł dobrać charakter odbitki do tematu i własnej wizji artystycznej. Powierzchnia błyszcząca (glossy) daje głęboką czerń, wysoki kontrast i ostrość, nadając się do zdjęć komercyjnych i krajobrazów. Półmat (lustre, pearl) jest uniwersalny i mniej podatny na odciski palców. Mat (matte) nadaje zdjęciom charakterystykę artystyczną, retro, eliminuje refleksy. Jedwabisty (silk, satin) ma delikatny połysk i jest ceniony w portrecie. Perłowy (pearl, metallic) daje efektowne, niemal metaliczne przejścia tonalne.'}, {'id': '2ce33f7c-b422-4538-836c-0269d5a6b613', 'chapter_id': 3, 'text': 'W jakiej wodzie i o jakiej temperaturze powinniśmy rozpuszczać składniki wywoływacza?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '8b145605-ac9e-445c-87fb-6cc13b2c02d0', 'question_id': '2ce33f7c-b422-4538-836c-0269d5a6b613', 'text': 'W gorącej wodzie powyżej 60°C.', 'is_correct': 0, 'sort_order': 0}, {'id': '109763ee-da97-4222-95c7-b84f6246a98b', 'question_id': '2ce33f7c-b422-4538-836c-0269d5a6b613', 'text': 'W wodzie destylowanej lub demineralizowanej o temperaturze ok. 40-50°C (do rozpuszczania), a następnie dolewamy zimną wodę do temperatury pracy (zazwyczaj 20°C).', 'is_correct': 1, 'sort_order': 1}, {'id': '96fe0d5c-25ce-4e91-9ff7-872036bbd03b', 'question_id': '2ce33f7c-b422-4538-836c-0269d5a6b613', 'text': 'W wodzie morskiej o temperaturze 0°C.', 'is_correct': 0, 'sort_order': 2}, {'id': '92a09442-ace3-4772-887f-94fc205a2bf9', 'question_id': '2ce33f7c-b422-4538-836c-0269d5a6b613', 'text': 'W wodzie z kranu o dowolnej temperaturze.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '5f5ff398-bb6c-41bf-bee2-e0688d46521c', 'chapter_id': 3, 'text': 'W jakiej wodzie i o jakiej temperaturze powinniśmy rozpuszczać składniki wywoływacza?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Składniki wywoływacza należy rozpuszczać w wodzie destylowanej lub przynajmniej demineralizowanej, aby uniknąć osadzania się kamienia i niepożądanych reakcji chemicznych z chlorem czy metalami ciężkimi. Najpierw rozpuszcza się substancje w niewielkiej ilości ciepłej wody (ok. 40-50°C), a następnie dolewa zimną wodę do docelowej objętości i temperatury pracy, która dla większości wywoływaczy czarno-białych wynosi 20°C.'}, {'id': '22dee8ec-3b4e-4c81-a7a8-441c13bd1eb2', 'chapter_id': 3, 'text': 'Który film posiada większe ziarno: 25 ASA czy 400 ASA?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '9c37cbb5-af53-4a7d-b8cb-609ee681713e', 'question_id': '22dee8ec-3b4e-4c81-a7a8-441c13bd1eb2', 'text': '25 ASA.', 'is_correct': 0, 'sort_order': 0}, {'id': 'adab529e-804e-4b37-9411-589118dc3a67', 'question_id': '22dee8ec-3b4e-4c81-a7a8-441c13bd1eb2', 'text': '400 ASA.', 'is_correct': 1, 'sort_order': 1}, {'id': '2a07011d-1156-4e89-a7d0-cf6bcd7727d4', 'question_id': '22dee8ec-3b4e-4c81-a7a8-441c13bd1eb2', 'text': 'Oba mają takie samo ziarno.', 'is_correct': 0, 'sort_order': 2}, {'id': 'af8d33c6-eed4-4ed6-9f1c-3677903dc35f', 'question_id': '22dee8ec-3b4e-4c81-a7a8-441c13bd1eb2', 'text': 'Zależy to od koloru opakowania.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'dea451d1-4fc0-4d51-ae4b-d77481d63ccb', 'chapter_id': 3, 'text': 'Który film posiada większe ziarno: 25 ASA czy 400 ASA?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Film o czułości 400 ASA posiada znacznie większe ziarno niż film 25 ASA. Jest to zasada ogólna fotografii analogowej: im wyższa czułość ISO/ASA, tym większe kryształy halogenków srebra w emulsji, co przekłada się na większą ziarnistość obrazu po wywołaniu. Filmy 25 ASA (np. Adox CMS 20) są niemal pozbawione widocznego ziarna, podczas gdy filmy 400 ASA (np. Ilford HP5 Plus) mają wyraźną, często pożądaną artystycznie strukturę ziarna.'}, {'id': 'b87b7bd5-944b-415b-afdf-977c4dbef8cf', 'chapter_id': 3, 'text': 'Co oznaczają skróty AF, MC, DX, TTL, ASA?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '11cd9d7a-bca6-4372-821d-51dca723e2ab', 'question_id': 'b87b7bd5-944b-415b-afdf-977c4dbef8cf', 'text': 'AF – Auto Focus, MC – Multi-Coated, DX – Digital indeX, TTL – Through The Lens, ASA – American Standards Association (skala czułości).', 'is_correct': 1, 'sort_order': 0}, {'id': 'edce30e1-cda5-469b-9fc7-6b13ba87f161', 'question_id': 'b87b7bd5-944b-415b-afdf-977c4dbef8cf', 'text': 'AF – Auto Flash, MC – Macro Camera, DX – Digital X-ray, TTL – Total Time Light, ASA – Automatic Shutter Aperture.', 'is_correct': 0, 'sort_order': 1}, {'id': '073cc8f8-fb72-45cb-83a4-b6c34440fc37', 'question_id': 'b87b7bd5-944b-415b-afdf-977c4dbef8cf', 'text': 'To wszystko oznaczenia rodzajów statywów.', 'is_correct': 0, 'sort_order': 2}, {'id': 'fd8eba87-634f-4dd5-b765-c82e801ad600', 'question_id': 'b87b7bd5-944b-415b-afdf-977c4dbef8cf', 'text': 'To nazwy programów do obróbki zdjęć.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '779b4334-8d8b-4830-a61d-d52b341ca23d', 'chapter_id': 3, 'text': 'Co oznaczają skróty AF, MC, DX, TTL, ASA?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'AF (Auto Focus) – automatyczne ustawianie ostrości. MC (Multi-Coated) – wielowarstwowe powłoki antyrefleksyjne na soczewkach. DX (Digital indeX) – system kodowania czułości filmu na kasetce. TTL (Through The Lens) – pomiar światła przez obiektyw. ASA (American Standards Association) – amerykańska skala czułości materiałów światłoczułych, obecnie zastąpiona przez ISO, choć wartości są identyczne (np. ASA 100 = ISO 100).'}, {'id': '13be8a80-36f2-42b1-9297-9429c844a346', 'chapter_id': 3, 'text': 'Wymień kilka substancji trujących w fotografii.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'aff692f1-1df3-4aec-af3b-a301c49aadfe', 'question_id': '13be8a80-36f2-42b1-9297-9429c844a346', 'text': 'Woda destylowana i papier fotograficzny.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c39b250b-e59d-48ef-aae5-4128e67ca8fd', 'question_id': '13be8a80-36f2-42b1-9297-9429c844a346', 'text': 'Metol (monometylo-p-aminofenol), hydrochinon, kwas chromowy, cyjanek potasu, siarczan miedzi, nadmanganian potasu, paraformaldehyd, kwas siarkawy.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b06ce0d4-f562-41ce-9d46-1d99ad97c6d7', 'question_id': '13be8a80-36f2-42b1-9297-9429c844a346', 'text': 'Tylko sól kuchenna i cukier.', 'is_correct': 0, 'sort_order': 2}, {'id': '70353351-4f18-489c-8ac0-e73ddb07d872', 'question_id': '13be8a80-36f2-42b1-9297-9429c844a346', 'text': 'Tylko powietrze i światło.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '60368322-6b5a-4f57-ab1b-d12bd3de4d42', 'chapter_id': 3, 'text': 'Wymień kilka substancji trujących w fotografii.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'W procesach fotograficznych spotyka się wiele substancji toksycznych i szkodliwych. Należą do nich: metol (monometylo-p-aminofenol) – silny alergen działający na skórę; hydrochinon – toksyczny dla układu nerwowego; kwas chromowy (używany w procesach pigmentowych) – rakotwórczy; cyjanek potasu (w osłabiaczach) – wysoce trujący; siarczan miedzi; nadmanganian potasu – silny utleniacz; paraformaldehyd (w utrwalaczach kolorowych); oraz kwasy (siarkawy, octowy) powodujące oparzenia. Wymagana jest ostrożność i praca w wentylowanych pomieszczeniach.'}, {'id': 'ecc469cc-676c-45ba-b406-7950adce76a1', 'chapter_id': 3, 'text': 'Dokonaj podziału materiałów światłoczułych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '8e39bbc2-5fe0-4064-bba2-e3c992d41a2a', 'question_id': 'ecc469cc-676c-45ba-b406-7950adce76a1', 'text': 'Tylko na czarno-białe i kolorowe.', 'is_correct': 0, 'sort_order': 0}, {'id': '8a6bb1f3-1dfe-4f1c-860e-6877a3b2b645', 'question_id': 'ecc469cc-676c-45ba-b406-7950adce76a1', 'text': 'Ze względu na przebieg procesu: negatywowe (czarno-białe, kolorowe C-41), pozytywowe (papiery, slajdy E-6), odwracalne; ze względu na format: małoobrazkowe, średnioformatowe, wielkoformatowe.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b4b0c368-75a1-4b55-8cd7-3ca744807b66', 'question_id': 'ecc469cc-676c-45ba-b406-7950adce76a1', 'text': 'Tylko na drogie i tanie.', 'is_correct': 0, 'sort_order': 2}, {'id': '6cd7e941-5fb5-4dd9-8347-9b719a0fecc6', 'question_id': 'ecc469cc-676c-45ba-b406-7950adce76a1', 'text': 'Tylko na cyfrowe i analogowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '18b6ec39-87e6-4de6-98bd-dca3d03ddaac', 'chapter_id': 3, 'text': 'Dokonaj podziału materiałów światłoczułych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Materiały światłoczułe dzielimy ze względu na przebieg procesu chemicznego na: negatywowe (filmy czarno-białe i kolorowe C-41, które dają obraz odwrócony tonalnie), pozytywowe (papiery fotograficzne czarno-białe i kolorowe RA-4, filmy odwracalne/diapozytywy E-6) oraz materiały do procesów alternatywnych (bromolej, cyjanotypia). Ze względu na format dzielimy je na: małoobrazkowe (24×36 mm, film 135), średnioformatowe (film 120/220, formaty 6×4,5 do 6×9 cm) oraz wielkoformatowe (klisze płaskie 4×5", 8×10" i większe).'}, {'id': 'fa5a8292-23e6-4dae-a2ae-82be6632f981', 'chapter_id': 3, 'text': 'Co to jest papier MULTIGRADE, podaj producentów.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '212c5b68-f190-43e0-974e-e0beacf1ec7b', 'question_id': 'fa5a8292-23e6-4dae-a2ae-82be6632f981', 'text': 'Papier do drukarek laserowych.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f716e75d-5295-48c9-b824-f530e581eae1', 'question_id': 'fa5a8292-23e6-4dae-a2ae-82be6632f981', 'text': 'Papier czarno-biały o zmiennej gradacji (kontraście), uzyskiwanej przez filtry pod powiększalnikiem; producenci: Ilford, Kodak, Foma, Adox.', 'is_correct': 1, 'sort_order': 1}, {'id': '417f73b9-397c-430b-b134-f941d410849e', 'question_id': 'fa5a8292-23e6-4dae-a2ae-82be6632f981', 'text': 'Papier kolorowy do odbitek z minilabu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd2f77014-4d83-4aec-9fb7-da2f72160d5d', 'question_id': 'fa5a8292-23e6-4dae-a2ae-82be6632f981', 'text': 'Papier do rysowania ołówkiem.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a0e488f2-2403-4e26-a457-3cf24e05608b', 'chapter_id': 3, 'text': 'Co to jest papier MULTIGRADE, podaj producentów.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Papier Multigrade (zmienno-kontrastowy) to papier fotograficzny czarno-biały, którego kontrast można regulować za pomocą zestawu filtrów (zazwyczaj od 00 – bardzo miękki, do 5 – bardzo twardy) umieszczanych w głowicy powiększalnika. Dzięki temu z jednego rodzaju papieru można uzyskać odbitki o różnym kontraście dopasowanym do negatywu. Główni producenci to Ilford (Multigrade IV, V), Kodak (Polymax), Foma (Fomaspeed), Adox (MCC) oraz Oriental.'}, {'id': 'f4ba082e-fe3c-4199-95e9-51c1d54aa65e', 'chapter_id': 3, 'text': 'Wymień substancje przyspieszające w wywoływaczu czarno-białym.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'd26dc8e4-6f9a-4dd6-b36e-21718ec714fb', 'question_id': 'f4ba082e-fe3c-4199-95e9-51c1d54aa65e', 'text': 'Tylko woda.', 'is_correct': 0, 'sort_order': 0}, {'id': '15b5e2cd-ef60-44da-9d54-748bc34b4f72', 'question_id': 'f4ba082e-fe3c-4199-95e9-51c1d54aa65e', 'text': 'Węglan sodu, wodorotlenek sodu, wodorotlenek potasu, boraks (tetraboran sodu) – substancje alkaliczne podwyższające pH i przyspieszające działanie reduktorów.', 'is_correct': 1, 'sort_order': 1}, {'id': '0dbeb0af-8477-4771-b5f2-3f8a2b3ae34a', 'question_id': 'f4ba082e-fe3c-4199-95e9-51c1d54aa65e', 'text': 'Tylko sól kuchenna.', 'is_correct': 0, 'sort_order': 2}, {'id': '474c6bf4-b47a-42e1-906d-644463a186d5', 'question_id': 'f4ba082e-fe3c-4199-95e9-51c1d54aa65e', 'text': 'Tylko alkohol etylowy.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '8d2cd170-f7c7-4606-a38a-554129c5a846', 'chapter_id': 3, 'text': 'Wymień substancje przyspieszające w wywoływaczu czarno-białym.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Substancje przyspieszające (akceleratory) w wywoływaczach czarno-białych to związki alkaliczne podwyższające pH roztworu, co przyspiesza redukcję halogenków srebra przez czynniki wywołujące. Najczęściej stosuje się: węglan sodu (soda), wodorotlenek sodu (ług sodowy), wodorotlenek potasu oraz boraks (tetraboran dekahydrat sodu). Im wyższe pH, tym wywoływacz działa energiczniej, ale może zwiększać ziarnistość.'}, {'id': '81bd1cc3-e9f7-4efa-96ea-8b0fb2c82726', 'chapter_id': 3, 'text': 'Jakiego rodzaju podłoże stosuje się obecnie do materiałów światłoczułych negatywowych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'a00b8c8b-bf2e-45cd-816f-930426f4f732', 'question_id': '81bd1cc3-e9f7-4efa-96ea-8b0fb2c82726', 'text': 'Wyłącznie szkło.', 'is_correct': 0, 'sort_order': 0}, {'id': 'cc53ef7d-f88a-40c7-ba9d-fed9a6429ffe', 'question_id': '81bd1cc3-e9f7-4efa-96ea-8b0fb2c82726', 'text': 'Podłoże z poliestru (PET) lub celulozowego triacetylu (acetat), wcześniej celuloid (nitroceluloza).', 'is_correct': 1, 'sort_order': 1}, {'id': '4111faba-6ea3-417c-ba34-1202ff04af1c', 'question_id': '81bd1cc3-e9f7-4efa-96ea-8b0fb2c82726', 'text': 'Wyłącznie papier.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c947524c-78b7-425c-ba00-e5d3bf6c5e33', 'question_id': '81bd1cc3-e9f7-4efa-96ea-8b0fb2c82726', 'text': 'Wyłącznie aluminium.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '488bb764-ceba-4255-bf2a-922612e16992', 'chapter_id': 3, 'text': 'Jakiego rodzaju podłoże stosuje się obecnie do materiałów światłoczułych negatywowych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Współczesne materiały światłoczułe negatywowe stosują jako podłoże folię poliestrową (PET – polietylen tereftalan) lub celulozowy triacetyl (bezpieczny acetat). W przeszłości używano celuloidu (nitrocelulozy), który był łatwopalny i kruchy. Poliester jest trwalszy mechanicznie, odporny na wilgoć i temperaturę, nie kurczy się i nie pęka, co czyni go idealnym podłożem dla archiwalnych materiałów filmowych.'}, {'id': '3fd4a528-1b4e-4a62-ad39-a469f40eb2a5', 'chapter_id': 3, 'text': 'Porównaj film o czułości 15ºDIN z filmem o czułości 27ºDIN.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '2a093d7d-dc69-4eed-bc29-ac7509ae86d4', 'question_id': '3fd4a528-1b4e-4a62-ad39-a469f40eb2a5', 'text': '15 DIN to film wysokoczuły, a 27 DIN to film małoczuły.', 'is_correct': 0, 'sort_order': 0}, {'id': '36af32ca-4379-44e0-a093-b0ed610299a4', 'question_id': '3fd4a528-1b4e-4a62-ad39-a469f40eb2a5', 'text': '15 DIN to film małoczuły (ok. 25 ASA), drobnoziarnisty, o niskim kontraście; 27 DIN to film wysokoczuły (ok. 400 ASA), ziarnisty, do pracy w słabym świetle.', 'is_correct': 1, 'sort_order': 1}, {'id': '94304ed1-6cff-4eb1-a09f-f9aa1e91923d', 'question_id': '3fd4a528-1b4e-4a62-ad39-a469f40eb2a5', 'text': 'Oba filmy mają identyczną czułość.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b41b3a33-c4cd-4a96-aa82-0a84c2d54586', 'question_id': '3fd4a528-1b4e-4a62-ad39-a469f40eb2a5', 'text': 'DIN to skala temperatury, nie czułości.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '8c37c80c-05c3-42ef-b0b7-f702f699719f', 'chapter_id': 3, 'text': 'Porównaj film o czułości 15ºDIN z filmem o czułości 27ºDIN.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Skala DIN (Deutsche Industrie Norm) to logarytmiczna skala czułości materiałów światłoczułych. Film 15 DIN odpowiada około 25 ASA (ISO) – jest to materiał małoczuły, charakteryzujący się bardzo drobnym ziarnem, wysoką rozdzielczością, delikatnymi przejściami tonalnymi i przeznaczony do pracy w bardzo dobrym świetle lub na statywie. Film 27 DIN odpowiada około 400 ASA – jest to materiał wysokoczuły, o wyraźnym ziarnie, większym kontraście, przeznaczony do fotografii w słabym świetle, reportażu i fotografii ulicznej bez statywu.'}, {'id': 'a499e6b3-63f5-40d6-a907-ae483aaf246f', 'chapter_id': 3, 'text': 'Czy istnieje zależność między czułością ogólną a ziarnistością materiałów fotograficznych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '4c0020fd-04d4-410f-8dcc-8344fea7e714', 'question_id': 'a499e6b3-63f5-40d6-a907-ae483aaf246f', 'text': 'Nie, nie ma żadnej zależności.', 'is_correct': 0, 'sort_order': 0}, {'id': 'cdae2563-cf31-415f-8cff-67a31ed66e38', 'question_id': 'a499e6b3-63f5-40d6-a907-ae483aaf246f', 'text': 'Tak, istnieje bezpośrednia zależność: im wyższa czułość, tym większe ziarno materiału.', 'is_correct': 1, 'sort_order': 1}, {'id': '404c863d-1c44-4c16-8533-2215f92bf265', 'question_id': 'a499e6b3-63f5-40d6-a907-ae483aaf246f', 'text': 'Zależność jest odwrotna: im wyższa czułość, tym mniejsze ziarno.', 'is_correct': 0, 'sort_order': 2}, {'id': '5a08e176-f2ba-48af-93f8-f1fa6abab2dd', 'question_id': 'a499e6b3-63f5-40d6-a907-ae483aaf246f', 'text': 'Zależy to wyłącznie od koloru opakowania filmu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '27246c90-d489-4a42-9167-f86a92894303', 'chapter_id': 3, 'text': 'Czy istnieje zależność między czułością ogólną a ziarnistością materiałów fotograficznych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Tak, istnieje bezpośrednia zależność między czułością a ziarnistością materiałów fotograficznych. Im wyższa czułość ISO/DIN, tym większe kryształy halogenków srebra w emulsji, co przekłada się na większą ziarnistość końcowego obrazu. Wynika to z faktu, że większe ziarna srebra są bardziej światłoczułe i wymagają mniejszej ilości energii świetlnej do wywołania reakcji chemicznej. Filmy małoczułe (np. ISO 25-50) mają niemal niewidoczne ziarno, podczas gdy filmy wysokoczułe (np. ISO 3200) charakteryzują się wyraźną, często estetyczną strukturą ziarna.'}, {'id': '6cedae48-a879-415e-a640-a4c393e86d72', 'chapter_id': 3, 'text': 'Jaka jest długość filmu małoobrazkowego 24 x 36mm i ile zdjęć można na nim wykonać?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'ce408198-b725-4e1d-b2a0-43d2cf5f3267', 'question_id': '6cedae48-a879-415e-a640-a4c393e86d72', 'text': '5 metrów i 12 zdjęć.', 'is_correct': 0, 'sort_order': 0}, {'id': 'cef284c5-b39e-4e8d-9f94-b7cd5bd3da39', 'question_id': '6cedae48-a879-415e-a640-a4c393e86d72', 'text': 'Standardowa długość to ok. 1,65 m (przy 36 klatkach) lub ok. 1,5 m (przy 24 klatkach); na filmie można wykonać 36 (czasem 24 lub 72 w wersji półformatowej) zdjęć.', 'is_correct': 1, 'sort_order': 1}, {'id': 'd4cf2538-8a16-4e80-97d8-a91f15449067', 'question_id': '6cedae48-a879-415e-a640-a4c393e86d72', 'text': '10 metrów i 100 zdjęć.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd104d94d-f7bb-4562-8e63-b656e4cf21c9', 'question_id': '6cedae48-a879-415e-a640-a4c393e86d72', 'text': '30 cm i 6 zdjęć.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '31f6e830-1cba-4b00-a8c7-dcc6b033f73b', 'chapter_id': 3, 'text': 'Jaka jest długość filmu małoobrazkowego 24 x 36mm i ile zdjęć można na nim wykonać?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Standardowa kasetka filmu małoobrazkowego (typ 135) zawiera zazwyczaj około 1,65 metra taśmy filmowej o szerokości 35 mm, co pozwala na wykonanie 36 klatek formatu 24×36 mm. Istnieją też wersje na 24 klatki (krótsza taśma, ok. 1,5 m) oraz rzadziej spotykane filmy na 12 klatek. W aparatach półformatowych (18×24 mm) liczba zdjęć wzrasta dwukrotnie (72 z 36-klatkowego filmu).'}, {'id': '55c16d48-d8d3-4cb9-99d1-388bb692ce22', 'chapter_id': 3, 'text': 'Z podanych substancji utwórz skład utrwalacza: metol, tiomocznik, węglan sodu, tiosiarczan sodu, rodanek potasu, kwaśny siarczyn sodu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'e76343ba-5f54-4db5-b46c-d2054509a96c', 'question_id': '55c16d48-d8d3-4cb9-99d1-388bb692ce22', 'text': 'Metol + hydrochinon + węglan sodu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f91ee654-b6c8-4e22-90b7-135180c4c5f6', 'question_id': '55c16d48-d8d3-4cb9-99d1-388bb692ce22', 'text': 'Tiosiarczan sodu (czynnik utrwalający) + kwaśny siarczyn sodu (czynnik zakwaszający) + opcjonalnie węglan sodu (środek utrwalający fizycznie).', 'is_correct': 1, 'sort_order': 1}, {'id': '26baebac-23f7-4c5c-abe2-16971cc0ba69', 'question_id': '55c16d48-d8d3-4cb9-99d1-388bb692ce22', 'text': 'Metol + tiomocznik + rodanek potasu.', 'is_correct': 0, 'sort_order': 2}, {'id': '393a095c-aba3-4a67-b100-d0ab698a3c9b', 'question_id': '55c16d48-d8d3-4cb9-99d1-388bb692ce22', 'text': 'Wszystkie substancje razem w losowych proporcjach.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd9e0c841-32eb-4161-bbe7-ab93d4181654', 'chapter_id': 3, 'text': 'Z podanych substancji utwórz skład utrwalacza: metol, tiomocznik, węglan sodu, tiosiarczan sodu, rodanek potasu, kwaśny siarczyn sodu.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Ze wskazanych substancji skład utrwalacza tworzą: tiosiarczan sodu (Na2S2O3) jako główny czynnik chemiczny rozpuszczający nienaświetlone halogenki srebra; kwaśny siarczyn sodu (NaHSO3) lub metabisulfit sodu jako czynnik utrzymujący kwaśne pH, zapobiegający rozkładowi tiosiarczanu; oraz węglan sodu (Na2CO3) w niektórych formułach jako środek alkaliczny w utrwalaczach szybkich, choć w klasycznym utrwalaczu kwaśnym rolę zakwaszającą pełni właśnie siarczyn/metabisulfit. Metol i tiomocznik to składniki wywoływaczy, a rodanek potasu stosuje się w osłabiaczach lub utrwalaczach szybkich.'}, {'id': 'bd96c611-b050-489a-a7a3-12efe5c8e603', 'chapter_id': 3, 'text': 'Omów zasady przechowywania materiałów światłoczułych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'f864e360-da19-436d-bb3e-59038eeae3b8', 'question_id': 'bd96c611-b050-489a-a7a3-12efe5c8e603', 'text': 'W pełnym słońcu i wysokiej temperaturze.', 'is_correct': 0, 'sort_order': 0}, {'id': 'a2525b42-2b69-460a-a59a-a14f3d994342', 'question_id': 'bd96c611-b050-489a-a7a3-12efe5c8e603', 'text': 'W chłodnym (najlepiej 4-10°C), suchym i ciemnym miejscu, w oryginalnych opakowaniach, z dala od promieniowania RTG i chemikaliów; filmy kolorowe najlepiej w lodówce.', 'is_correct': 1, 'sort_order': 1}, {'id': '6ccb0be9-9c7a-48d3-8c07-f3d47085f17b', 'question_id': 'bd96c611-b050-489a-a7a3-12efe5c8e603', 'text': 'W wilgotnym i ciepłym pomieszczeniu bez opakowań.', 'is_correct': 0, 'sort_order': 2}, {'id': '2a6b526a-50e4-4835-b7d0-047bd3b44a86', 'question_id': 'bd96c611-b050-489a-a7a3-12efe5c8e603', 'text': 'W zamrażarce w temperaturze -50°C.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2c8586df-7363-47c3-8375-574883498b99', 'chapter_id': 3, 'text': 'Omów zasady przechowywania materiałów światłoczułych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Materiały światłoczułe należy przechowywać w chłodnym, suchym i całkowicie ciemnym miejscu, z dala od źródeł ciepła, wilgoci, promieniowania RTG (lotniska, szpitale) oraz oparów chemicznych. Optymalna temperatura to 4-10°C, dlatego filmy kolorowe i wysokoczułe zaleca się przechowywać w lodówce (nie w zamrażarce, by uniknąć kondensacji wilgoci). Przed użyciem należy odczekać, aż film osiągnie temperaturę pokojową. Opakowania powinny być szczelne, najlepiej oryginalne puszki lub folie z woreczkiem silica gel.'}, {'id': 'a9215418-5f4f-4c73-b4c9-6eba42922a43', 'chapter_id': 3, 'text': 'Omów zasady przechowywania substancji chemicznych wykorzystywanych w zakładach fotograficznych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'd2cf9a0d-c8f2-46ab-bc49-f26821817c9b', 'question_id': 'a9215418-5f4f-4c73-b4c9-6eba42922a43', 'text': 'W otwartych pojemnikach na parapecie w słoneczny dzień.', 'is_correct': 0, 'sort_order': 0}, {'id': '0cd42507-ca6c-4e97-bc46-3b222d2dde95', 'question_id': 'a9215418-5f4f-4c73-b4c9-6eba42922a43', 'text': 'W szczelnie zamkniętych, oznakowanych pojemnikach z ciemnego szkła lub tworzywa, w suchym, chłodnym, wentylowanym pomieszczeniu, z dala od źródeł ciepła i światła; rozdzielenie kwasów od zasad i substancji toksycznych.', 'is_correct': 1, 'sort_order': 1}, {'id': '51647cda-ddb3-4995-9f31-a0bc406af0ac', 'question_id': 'a9215418-5f4f-4c73-b4c9-6eba42922a43', 'text': 'Wraz z żywnością w lodówce kuchennej.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd1dfbc73-3624-48c5-8491-9511699e54d6', 'question_id': 'a9215418-5f4f-4c73-b4c9-6eba42922a43', 'text': 'W plastikowych butelkach po napojach bez etykiet.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'fd94f15b-7298-42b8-b21f-3cef052d2dc4', 'chapter_id': 3, 'text': 'Omów zasady przechowywania substancji chemicznych wykorzystywanych w zakładach fotograficznych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Substancje chemiczne w zakładach fotograficznych należy przechowywać w szczelnie zamkniętych, odpowiednio oznakowanych pojemnikach wykonanych z ciemnego szkła lub odpornego tworzywa sztucznego, w suchym, chłodnym (15-20°C) i dobrze wentylowanym pomieszczeniu. Należy chronić je przed bezpośrednim działaniem światła słonecznego i źródeł ciepła. Kwasów nie wolno przechowywać razem z zasadami (ryzyko gwałtownej reakcji), a substancje toksyczne (cyjanki, chrom) powinny być zamykane na klucz i oddzielone od pozostałych. Zużyte chemikalia należy utylizować zgodnie z przepisami ochrony środowiska.'}, {'id': 'a6687896-bfe3-4668-a72c-a0c41b192fb0', 'chapter_id': 3, 'text': 'Opisz budowę błony fotograficznej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '1483dd05-a27b-4ef1-bf65-40053610507f', 'question_id': 'a6687896-bfe3-4668-a72c-a0c41b192fb0', 'text': 'Wyłącznie podłoże papierowe.', 'is_correct': 0, 'sort_order': 0}, {'id': '3e2933bc-16ac-4032-b843-fded1711cfaf', 'question_id': 'a6687896-bfe3-4668-a72c-a0c41b192fb0', 'text': 'Podłoże (poliester/triacetyl), warstwa przylepna, emulsja światłoczuła (żelatyna z halogenkami srebra), warstwa ochronna (overcoat), czasem warstwa antyhalacyjna (na spodzie).', 'is_correct': 1, 'sort_order': 1}, {'id': 'febcd65a-c7e4-4658-8c23-cb34e09f07ff', 'question_id': 'a6687896-bfe3-4668-a72c-a0c41b192fb0', 'text': 'Wyłącznie szkło i emulsja.', 'is_correct': 0, 'sort_order': 2}, {'id': '53840843-0cb0-4ade-9b00-a0e90d7564cb', 'question_id': 'a6687896-bfe3-4668-a72c-a0c41b192fb0', 'text': 'Wyłącznie plastikowa kasetka.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '67bfc70c-bb77-4251-b71b-dd088f8d4630', 'chapter_id': 3, 'text': 'Opisz budowę błony fotograficznej.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Błona fotograficzna składa się z kilku warstw: podłoża (folia poliestrowa lub celulozowa), warstwy przylepnej łączącej podłoże z emulsją, emulsji światłoczułej zawierającej żelatynę z zawieszonymi w niej kryształami halogenków srebra (bromku, jodku, chlorku) oraz barwnikami spektralnymi (w filmach kolorowych), warstwy ochronnej (overcoat) zabezpieczającej emulsję przed zarysowaniami, a często także warstwy antyhalacyjnej na spodniej stronie podłoża, zapobiegającej odbiciu światła od tyłu filmu i powstawaniu halacji.'}, {'id': 'dc7004c1-9e42-4128-a852-e80f37dd2369', 'chapter_id': 3, 'text': 'Jakie znasz substancje w składzie wywoływacza?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'ac36b145-d6b5-4d56-86be-06c79b9c79d8', 'question_id': 'dc7004c1-9e42-4128-a852-e80f37dd2369', 'text': 'Tylko woda i sól.', 'is_correct': 0, 'sort_order': 0}, {'id': 'b746402d-8ec6-4588-8f64-ec2ba2cda359', 'question_id': 'dc7004c1-9e42-4128-a852-e80f37dd2369', 'text': 'Reduktory (metol, hydrochinon, fenidon), przyspieszacz (węglan sodu, boraks, wodorotlenek sodu), konserwant (siarczyn sodu/metabisulfit), rozpuszczalnik (woda).', 'is_correct': 1, 'sort_order': 1}, {'id': '35f1ced7-1ef8-4e2f-b9a7-64675f389f60', 'question_id': 'dc7004c1-9e42-4128-a852-e80f37dd2369', 'text': 'Tylko alkohol i ocet.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f369a1fc-d18c-405a-bfe4-c61efd21dde0', 'question_id': 'dc7004c1-9e42-4128-a852-e80f37dd2369', 'text': 'Tylko mleko i miód.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0570a212-dc17-4084-8143-5cd290c22706', 'chapter_id': 3, 'text': 'Jakie znasz substancje w składzie wywoływacza?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Wywoływacz czarno-biały składa się z: reduktorów (czynników wywołujących) – najczęściej metolu (energiczny, daje delikatne tony), hydrochinon (wolniejszy, daje kontrast) lub fenidonu (nowoczesny zamiennik metolu o niższej toksyczności); przyspieszacza (akceleratora) – substancji alkalicznych takich jak węglan sodu, boraks lub wodorotlenek sodu podwyższających pH; konserwantu – siarczynu sodu lub metabisulfitu sodu zapobiegającego utlenianiu się wywoływacza przez powietrze; oraz rozpuszczalnika – wody destylowanej lub demineralizowanej.'}, {'id': '62ac7f57-b02f-447b-b726-c4ed4bd235d8', 'chapter_id': 3, 'text': 'Jaki odczyn chemiczny ma utrwalacz, a jaki wywoływacz?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '0ddfa67b-5a0d-41ae-9c27-5c6afa4e06d7', 'question_id': '62ac7f57-b02f-447b-b726-c4ed4bd235d8', 'text': 'Utrwalacz ma odczyn zasadowy, a wywoływacz kwaśny.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e3cb426e-165d-4da7-8c91-562690ec8a4e', 'question_id': '62ac7f57-b02f-447b-b726-c4ed4bd235d8', 'text': 'Utrwalacz ma odczyn kwaśny (pH 4-6), a wywoływacz ma odczyn zasadowy (pH 9-11).', 'is_correct': 1, 'sort_order': 1}, {'id': 'd476a0f4-d69d-4dea-b0cf-ac09c566671d', 'question_id': '62ac7f57-b02f-447b-b726-c4ed4bd235d8', 'text': 'Oba mają odczyn neutralny.', 'is_correct': 0, 'sort_order': 2}, {'id': '3b4137ff-f140-47ed-9254-ba666fe8a85b', 'question_id': '62ac7f57-b02f-447b-b726-c4ed4bd235d8', 'text': 'Utrwalacz ma odczyn zasadowy, a wywoływacz neutralny.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3d62b452-91ad-4aee-804d-3ef2e82564ca', 'chapter_id': 3, 'text': 'Jaki odczyn chemiczny ma utrwalacz, a jaki wywoływacz?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Wywoływacz ma odczyn zasadowy (alkaliczny), zazwyczaj o pH w zakresie 9-11, co jest konieczne do aktywacji reduktorów i przyspieszenia procesu redukcji halogenków srebra. Utrwalacz natomiast ma odczyn kwaśny, zazwyczaj o pH 4-6, co zapobiega rozkładowi tiosiarczanu (siarczynku) w roztworze i wypłukiwaniu wywołanego obrazu srebra, a także neutralizuje resztki alkalicznego wywoływacza na emulsji.'}, {'id': '1418e9dd-aa3f-4ef6-a283-6d7b321de76b', 'chapter_id': 3, 'text': 'Co to jest starzenie się materiału światłoczułego i jaki ma wpływ na zmianę cech charakterystycznych emulsji?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'd73e19f1-dfd2-467c-8ff7-7f907df20717', 'question_id': '1418e9dd-aa3f-4ef6-a283-6d7b321de76b', 'text': 'Proces polepszania jakości filmu z czasem.', 'is_correct': 0, 'sort_order': 0}, {'id': '49cd2dd2-4d68-40aa-a9f2-95fee4f4e699', 'question_id': '1418e9dd-aa3f-4ef6-a283-6d7b321de76b', 'text': 'Stopniowa degradacja emulsji pod wpływem czasu, temperatury, wilgoci i promieniowania; objawia się zmianą czułości, wzrostem zaciemnienia podstawy (fog), zmianą balansu barwnego (w kolorze) i wzrostem ziarnistości.', 'is_correct': 1, 'sort_order': 1}, {'id': '4eb4a733-d5f8-41a0-ac04-59ee4ca8a9b8', 'question_id': '1418e9dd-aa3f-4ef6-a283-6d7b321de76b', 'text': 'Proces samoczynnego wywoływania filmu bez chemii.', 'is_correct': 0, 'sort_order': 2}, {'id': '6a7d2e81-b93d-4714-8372-48e9d4df1135', 'question_id': '1418e9dd-aa3f-4ef6-a283-6d7b321de76b', 'text': 'Zmiana koloru opakowania kasetki.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a7b57b8f-84bd-4b69-978b-4e9970426e2a', 'chapter_id': 3, 'text': 'Co to jest starzenie się materiału światłoczułego i jaki ma wpływ na zmianę cech charakterystycznych emulsji?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Starzenie się materiału światłoczułego to naturalny proces degradacji emulsji fotograficznej pod wpływem upływu czasu, niewłaściwej temperatury, wilgoci, promieniowania jonizującego i światła. Skutkuje to obniżeniem czułości (lub jej wzrostem w przypadku niektórych filmów), wzrostem zaciemnienia podstawy (fog – mgiełka), zmianą balansu barwnego w filmach kolorowych (dominata barwna), wzrostem ziarnistości oraz obniżeniem rozdzielczości i kontrastu. Dlatego filmy powinny być przechowywane w chłodzie i używane przed upływem daty ważności.'}, {'id': 'ce08533e-4969-4c22-a27b-a99536090d8e', 'chapter_id': 3, 'text': 'Jakie materiały negatywowe są bardziej kontrastowe, mało czułe czy wysoko czułe?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'b9fa7890-62ff-4e0a-b375-f7072290d17f', 'question_id': 'ce08533e-4969-4c22-a27b-a99536090d8e', 'text': 'Wysoko czułe.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f5aba5a2-bcf5-4e7a-a5a5-66fbc64a917e', 'question_id': 'ce08533e-4969-4c22-a27b-a99536090d8e', 'text': 'Mało czułe (niskie ISO) są zazwyczaj bardziej kontrastowe i mają większą rozdzielczość; wysoko czułe mają niższy kontrast i większe ziarno.', 'is_correct': 1, 'sort_order': 1}, {'id': 'fb10aa1d-88e9-487c-b80d-69ee4d361420', 'question_id': 'ce08533e-4969-4c22-a27b-a99536090d8e', 'text': 'Oba rodzaje mają identyczny kontrast.', 'is_correct': 0, 'sort_order': 2}, {'id': '44d31a6b-41a4-4bab-8cdc-13624de0d33c', 'question_id': 'ce08533e-4969-4c22-a27b-a99536090d8e', 'text': 'Kontrast zależy wyłącznie od temperatury wywoływania.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'ed82f7f5-7c3f-4300-be20-bfaee9008895', 'chapter_id': 3, 'text': 'Jakie materiały negatywowe są bardziej kontrastowe, mało czułe czy wysoko czułe?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Materiały negatywowe małoczułe (niskie ISO, np. 25-100) są zazwyczaj bardziej kontrastowe i charakteryzują się wyższą rozdzielczością oraz drobniejszym ziarnem. Wynika to z faktu, że mniejsze kryształy halogenków srebra w emulsji dają ostrzejszy obraz i bardziej strome przejścia tonalne. Natomiast materiały wysokoczułe (wysokie ISO, np. 800-3200) mają zazwyczaj niższy kontrast, szerszą paletę pośrednich tonów i wyraźniejsze ziarno, co jest efektem większych kryształów srebra i bardziej rozmytej struktury emulsji.'}, {'id': '1b4627f2-7a15-496f-9d58-7d91538e2f8a', 'chapter_id': 3, 'text': 'Jaki odczyn chemiczny ma utrwalacz?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '3e7f85c5-f495-4dbb-8d81-2ea9f84c81e2', 'question_id': '1b4627f2-7a15-496f-9d58-7d91538e2f8a', 'text': 'Zasadowy (pH 9-11)', 'is_correct': 0, 'sort_order': 0}, {'id': 'e0903d1c-b157-46a6-a542-af6c10870c79', 'question_id': '1b4627f2-7a15-496f-9d58-7d91538e2f8a', 'text': 'Kwaśny (pH 4-6)', 'is_correct': 1, 'sort_order': 1}, {'id': '6ea22961-c7dc-4604-870b-5e045bf131c9', 'question_id': '1b4627f2-7a15-496f-9d58-7d91538e2f8a', 'text': 'Neutralny (pH 7)', 'is_correct': 0, 'sort_order': 2}, {'id': '29aaec12-c2cd-4d8c-b8e0-662ca7665c9a', 'question_id': '1b4627f2-7a15-496f-9d58-7d91538e2f8a', 'text': 'Zasadowo-kwaśny (pH zmienny)', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'b4aee23a-246c-44c8-9e65-ae3c5cccf44a', 'chapter_id': 3, 'text': 'Jaki odczyn chemiczny ma utrwalacz?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Utrwalacz ma odczyn kwaśny, zazwyczaj w zakresie pH 4-6. Kwaśne środowisko zapobiega rozkładowi tiosiarczanu sodu, neutralizuje resztki zasadowego wywoływacza i stabilizuje wywołany obraz srebra w emulsji.'}, {'id': '2bf8792d-cfcb-4c8e-b6b3-941603078fff', 'chapter_id': 3, 'text': 'Podaj skład utrwalacza, opisz proces utrwalania. Jak poznajemy zużyty utrwalacz?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'e452fadf-8bfb-4e56-87d2-781cd57ab119', 'question_id': '2bf8792d-cfcb-4c8e-b6b3-941603078fff', 'text': 'Skład: metol, hydrochinon, węglan sodu; proces: wywoływanie; zużyty: przez kolor opakowania', 'is_correct': 0, 'sort_order': 0}, {'id': 'becc5d1e-31a8-40e8-992a-c34779ff2e28', 'question_id': '2bf8792d-cfcb-4c8e-b6b3-941603078fff', 'text': 'Skład: tiosiarczan sodu, kwaśny siarczyn sodu, siarczan sodu; proces: rozpuszczanie nienaświetlonych halogenków srebra i zakwaszenie; zużyty: test jodkowy, wydłużony czas, zmętnienie', 'is_correct': 1, 'sort_order': 1}, {'id': '31642506-4656-40e2-a86c-2239a866c72b', 'question_id': '2bf8792d-cfcb-4c8e-b6b3-941603078fff', 'text': 'Skład: tylko woda i sól; proces: suszenie; zużyty: przez wagę', 'is_correct': 0, 'sort_order': 2}, {'id': 'f06c59a1-29ed-4853-acf0-1936aa376cba', 'question_id': '2bf8792d-cfcb-4c8e-b6b3-941603078fff', 'text': 'Skład: alkohol i ocet; proces: czyszczenie; zużyty: przez zapach', 'is_correct': 0, 'sort_order': 3}]}, {'id': '9d84e455-e384-4952-8386-111e46a196d6', 'chapter_id': 3, 'text': 'Podaj skład utrwalacza, opisz proces utrwalania. Jak poznajemy zużyty utrwalacz?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Utrwalacz składa się z tiosiarczanu sodu (rozpuszcza nienaświetlone halogenki srebra), kwaśnego siarczynu sodu lub metabisulfitu (utrzymuje kwaśne pH) oraz siarczanu sodu lub glinu (utrwala fizycznie żelatynę). Proces utrwalania polega na usunięciu nienaświetlonych związków srebra, które w przyszłości mogłyby ulec wywołaniu pod wpływem światła. Zużyty utrwalacz poznajemy po wydłużonym czasie działania, zmętnieniu roztworu oraz teście z jodkiem potasu (żółte zabarwienie wskazuje na obecność wytrąconego jodu, świadcząca o wyczerpaniu zdolności wiązania siarczanu).'}, {'id': 'b0663104-6b1b-4953-b4e1-44b6281b850d', 'chapter_id': 3, 'text': 'W jakiej temperaturze płuczemy materiały światłoczułe w obróbce?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'b6e168d4-c4e9-4f83-b798-f6e132b08622', 'question_id': 'b0663104-6b1b-4953-b4e1-44b6281b850d', 'text': 'W temperaturze wrzenia 100°C', 'is_correct': 0, 'sort_order': 0}, {'id': '88f3e9ff-74a1-4a35-aa03-af13dead17fb', 'question_id': 'b0663104-6b1b-4953-b4e1-44b6281b850d', 'text': 'W temperaturze ok. 18-20°C, zbliżonej do temperatury procesu, końcowe płukanie w wodzie destylowanej lub z dodatkiem środka przeciwko wodzie', 'is_correct': 1, 'sort_order': 1}, {'id': '04cc007a-a0c4-406f-9449-4371f23887c9', 'question_id': 'b0663104-6b1b-4953-b4e1-44b6281b850d', 'text': 'W temperaturze 0°C', 'is_correct': 0, 'sort_order': 2}, {'id': 'cef0f95f-0ae8-4d98-a100-a0e5e9c4a6a9', 'question_id': 'b0663104-6b1b-4953-b4e1-44b6281b850d', 'text': 'W temperaturze 50°C', 'is_correct': 0, 'sort_order': 3}]}, {'id': '11ade782-7ee4-4675-99b7-6cdfe707fae1', 'chapter_id': 3, 'text': 'W jakiej temperaturze płuczemy materiały światłoczułe w obróbce?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Materiały światłoczułe płucze się w wodzie o temperaturze zbliżonej do temperatury procesu chemicznego, zazwyczaj około 18-20°C. Zbyt zimna woda może spowodować kurczenie się żelatyny i powstanie zacieków, a zbyt ciepła – jej mięknięcie i uszkodzenie. Końcowe płukanie wykonuje się często w wodzie destylowanej lub z dodatkiem środka przeciwko wodzie (wetting agent), co zapobiega powstawaniu plam i smug podczas suszenia.'}, {'id': 'f1060b63-369d-4cf1-850d-0c131e470f6b', 'chapter_id': 3, 'text': 'Jakie znasz rodzaje fotograficznych materiałów światłoczułych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '338b8984-0ad2-4a1f-bbff-870cdbbe7301', 'question_id': 'f1060b63-369d-4cf1-850d-0c131e470f6b', 'text': 'Tylko filmy cyfrowe', 'is_correct': 0, 'sort_order': 0}, {'id': 'fb01f3c1-476b-4d2a-820d-58dcc789d59c', 'question_id': 'f1060b63-369d-4cf1-850d-0c131e470f6b', 'text': 'Negatywowe (filmy cz-b i kolor), pozytywowe (papiery, slajdy), odwracalne, materiały instancyjne', 'is_correct': 1, 'sort_order': 1}, {'id': '101f5dcd-6eae-45bb-a17f-d4a5a695d689', 'question_id': 'f1060b63-369d-4cf1-850d-0c131e470f6b', 'text': 'Tylko papiery biurowe', 'is_correct': 0, 'sort_order': 2}, {'id': 'c8bed5c3-ca77-41bd-9790-2dd9ea475f65', 'question_id': 'f1060b63-369d-4cf1-850d-0c131e470f6b', 'text': 'Tylko matryce CMOS', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'aa2457cd-5d2f-4554-9065-47dbfb8d435a', 'chapter_id': 3, 'text': 'Jakie znasz rodzaje fotograficznych materiałów światłoczułych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Rodzaje materiałów światłoczułych to: negatywowe (filmy czarno-białe i kolorowe), pozytywowe (papiery fotograficzne czarno-białe i kolorowe, filmy odwracalne/diapozytywy), materiały instancyjne (samowywołujące się odbitki, np. Polaroid, Instax) oraz materiały do procesów alternatywnych (papiery bez żelatyny do cyjanotypii, bromoleju itp.).'}, {'id': '0d97d214-9eb0-4b04-8d7f-0aa90beef713', 'chapter_id': 3, 'text': 'Jakie informacje podaje producent na opakowaniu papieru fotograficznego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '226ccb5c-cc0a-4efe-b239-87ed9c4b35ce', 'question_id': '0d97d214-9eb0-4b04-8d7f-0aa90beef713', 'text': 'Tylko cenę i wagę', 'is_correct': 0, 'sort_order': 0}, {'id': 'e179e070-c7fc-4dab-9469-fd96181b51ac', 'question_id': '0d97d214-9eb0-4b04-8d7f-0aa90beef713', 'text': 'Format, ilość arkuszy, rodzaj powierzchni, gradacja/kontrast, czułość spektralna, data ważności, zalecany proces wywoływania', 'is_correct': 1, 'sort_order': 1}, {'id': '6211b4ba-cc8c-417f-baea-47134853d09a', 'question_id': '0d97d214-9eb0-4b04-8d7f-0aa90beef713', 'text': 'Tylko kolor opakowania', 'is_correct': 0, 'sort_order': 2}, {'id': '80c93e9c-facd-4335-b1b1-0916e429201c', 'question_id': '0d97d214-9eb0-4b04-8d7f-0aa90beef713', 'text': 'Tylko nazwa producenta', 'is_correct': 0, 'sort_order': 3}]}, {'id': '211c2e83-dc6d-4998-87ac-f9833b46cf3d', 'chapter_id': 3, 'text': 'Jakie informacje podaje producent na opakowaniu papieru fotograficznego?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Producent na opakowaniu papieru fotograficznego podaje: format i ilość arkuszy, rodzaj powierzchni (błysk, mat, półmat, jedwabisty), gradację lub informację o zmienno-kontrastowości (Multigrade), czułość spektralną (do jakiego źródła światła jest przystosowany), datę ważności, numer partii, zalecany proces wywoływania (np. RA-4 dla koloru), temperaturę i czas wywoływania.'}, {'id': 'd3d6a52d-87f9-4352-ac99-e9ad56d4749c', 'chapter_id': 3, 'text': 'Jakie właściwości materiałów światłoczułych trzeba wziąć pod uwagę aby odpowiednio dobrać papier fotograficzny do negatywu?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '59083738-72d2-4076-ab47-3043a4a4e172', 'question_id': 'd3d6a52d-87f9-4352-ac99-e9ad56d4749c', 'text': 'Tylko wagę papieru', 'is_correct': 0, 'sort_order': 0}, {'id': '2ad1107a-12e7-4af3-818d-6adecac1e665', 'question_id': 'd3d6a52d-87f9-4352-ac99-e9ad56d4749c', 'text': 'Kontrast negatywu (twardy/miękki), gęstość optyczna, zakres tonalny, ziarnistość; do negatywu kontrastowego papier miękki, do płaskiego – twardy', 'is_correct': 1, 'sort_order': 1}, {'id': '9d2128e8-ae83-43a9-b167-5733af923929', 'question_id': 'd3d6a52d-87f9-4352-ac99-e9ad56d4749c', 'text': 'Tylko kolor opakowania', 'is_correct': 0, 'sort_order': 2}, {'id': '32e0af0b-7289-4bc4-996d-32ee6ebb5618', 'question_id': 'd3d6a52d-87f9-4352-ac99-e9ad56d4749c', 'text': 'Tylko cenę papieru', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1f952ecb-a58b-42b5-82b8-9b892ff3f5ac', 'chapter_id': 3, 'text': 'Jakie właściwości materiałów światłoczułych trzeba wziąć pod uwagę aby odpowiednio dobrać papier fotograficzny do negatywu?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Aby dobrać papier fotograficzny do negatywu, należy uwzględnić: kontrast negatywu (negatyw kontrastowy wymaga papieru miękkiego, a negatyw płaski – twardego), gęstość optyczną (średnia gęstość powinna odpowiadać światłoczułości papieru), zakres tonalny oraz ziarnistość. Papier zmienno-kontrastowy (Multigrade) ułatwia dopasowanie, ponieważ pozwala regulować kontrast za pomocą filtrów pod powiększalnikiem.'}, {'id': 'edf7d4fd-0e6e-4a71-8e36-6bc325b48fc7', 'chapter_id': 3, 'text': 'Jaki kontrast musi posiadać negatyw aby można było go kopiować na papierze twardym, bardzo twardy lub nawet ultra twardym?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '8a51f824-62f7-48b3-afbb-a575a11eb4df', 'question_id': 'edf7d4fd-0e6e-4a71-8e36-6bc325b48fc7', 'text': 'Bardzo kontrastowy', 'is_correct': 0, 'sort_order': 0}, {'id': '69ab7be1-11da-47cb-9f1c-40fc1021d910', 'question_id': 'edf7d4fd-0e6e-4a71-8e36-6bc325b48fc7', 'text': 'Niski kontrast (miękki, płaski), ponieważ twardy papier podbija kontrast; negatyw kontrastowy na twardym papierze da zbyt wysoki kontrast bez półtonów', 'is_correct': 1, 'sort_order': 1}, {'id': '054d14ff-2d55-4407-8015-169aac584d78', 'question_id': 'edf7d4fd-0e6e-4a71-8e36-6bc325b48fc7', 'text': 'Średni kontrast', 'is_correct': 0, 'sort_order': 2}, {'id': '17a30e70-172d-4c66-9699-c79a6e56f2c2', 'question_id': 'edf7d4fd-0e6e-4a71-8e36-6bc325b48fc7', 'text': 'Kontrast nie ma znaczenia', 'is_correct': 0, 'sort_order': 3}]}, {'id': '77f1a353-a34a-40b0-a4a9-365ab4b69ca5', 'chapter_id': 3, 'text': 'Jaki kontrast musi posiadać negatyw aby można było go kopiować na papierze twardym, bardzo twardy lub nawet ultra twardym?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Aby kopiować negatyw na papierze twardym, bardzo twardym lub ultra twardym, negatyw musi charakteryzować się niskim kontrastem (być miękki lub płaski). Twardy papier podbija różnice tonalne, więc przy negatywie kontrastowym uzyskalibyśmy zbyt wysoki kontrast końcowy z utratą półtonów i szczegółów w cieniach oraz światłach. Negatyw płaski na twardym papierze daje natomiast odbitkę o bogatej skali szarości i odpowiednim kontraście.'}, {'id': 'f4ad0c69-3ed5-4304-b437-29dce17a4273', 'chapter_id': 3, 'text': 'Jakie składniki wchodzą w skład wywoływacza – podaj przykłady?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '2b61b46e-6628-4fab-8358-17de96d3dddd', 'question_id': 'f4ad0c69-3ed5-4304-b437-29dce17a4273', 'text': 'Tylko woda i sól', 'is_correct': 0, 'sort_order': 0}, {'id': 'd7caea24-fc06-4d77-a7a3-dcf99517bef3', 'question_id': 'f4ad0c69-3ed5-4304-b437-29dce17a4273', 'text': 'Reduktory (metol, hydrochinon), przyspieszacz (węglan sodu, boraks), konserwant (siarczyn sodu), rozpuszczalnik (woda)', 'is_correct': 1, 'sort_order': 1}, {'id': 'd771c420-965b-41f6-9ef2-c726b1f0093f', 'question_id': 'f4ad0c69-3ed5-4304-b437-29dce17a4273', 'text': 'Tylko alkohol i ocet', 'is_correct': 0, 'sort_order': 2}, {'id': '3e4f5aba-9a8f-48ea-b123-65eec31f7eee', 'question_id': 'f4ad0c69-3ed5-4304-b437-29dce17a4273', 'text': 'Tylko mleko i miód', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c3ef1ff2-2700-4270-9206-f2d35aa6ff50', 'chapter_id': 3, 'text': 'Jakie składniki wchodzą w skład wywoływacza – podaj przykłady?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Wywoływacz składa się z: reduktorów, czyli czynników wywołujących – np. metolu (monometylo-p-aminofenolu), hydrochinonu lub fenidonu; przyspieszacza (akceleratora) – substancji alkalicznych takich jak węglan sodu (soda), boraks (tetraboran sodu) lub wodorotlenek sodu; konserwantu – np. siarczynu sodu lub metabisulfitu sodu, zapobiegającego utlenianiu się wywoływacza przez powietrze; oraz rozpuszczalnika, którym jest woda destylowana lub demineralizowana.'}, {'id': 'b6dfa405-9b15-4a3c-99e2-35279f0b0200', 'chapter_id': 3, 'text': 'Omów działanie substancji konserwującej w wywoływaczu?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'f2aa8f12-57b6-434f-8757-ec6f99997d9f', 'question_id': 'b6dfa405-9b15-4a3c-99e2-35279f0b0200', 'text': 'Przyspiesza wywoływanie', 'is_correct': 0, 'sort_order': 0}, {'id': '382ccb76-adc9-40e0-a6ac-fd72853ef60f', 'question_id': 'b6dfa405-9b15-4a3c-99e2-35279f0b0200', 'text': 'Zapobiega utlenianiu się wywoływacza przez powietrze, wydłużając jego trwałość i zapobiegając zmianie właściwości chemicznych', 'is_correct': 1, 'sort_order': 1}, {'id': '0289c3bb-5682-4ba4-9ccc-d1f1829f027f', 'question_id': 'b6dfa405-9b15-4a3c-99e2-35279f0b0200', 'text': 'Zmienia temperaturę barwową', 'is_correct': 0, 'sort_order': 2}, {'id': '2f7442a0-c8ed-4fa4-883b-6cd9cc605e9c', 'question_id': 'b6dfa405-9b15-4a3c-99e2-35279f0b0200', 'text': 'Zwiększa ziarnistość obrazu', 'is_correct': 0, 'sort_order': 3}]}, {'id': '386c596d-9035-4d90-bca2-bd3c9689caf8', 'chapter_id': 3, 'text': 'Omów działanie substancji konserwującej w wywoływaczu?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Substancja konserwująca (np. siarczyn sodu, metabisulfit sodu) działa jako reduktor utleniający się pierwszy w kontakcie z powietrzem, zamiast reduktorów wywołujących (metolu, hydrochinonu). Dzięki temu zapobiega utlenianiu i degradacji wywoływacza, wydłużając jego trwałość w czasie, utrzymując stałe właściwości chemiczne roztworu i zapobiegając powstawaniu zabarwienia oraz osadów.'}, {'id': '13346564-8cca-4731-8a98-5c2d1a5e58c4', 'chapter_id': 3, 'text': 'Opisz, jak zbudowany jest negatywowy materiał barwny.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '2df25ee5-0863-4473-a3d2-286b0ca81101', 'question_id': '13346564-8cca-4731-8a98-5c2d1a5e58c4', 'text': 'Wyłącznie jedna warstwa emulsji.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f1de38a4-2ead-4d3b-863f-60e1c004bb61', 'question_id': '13346564-8cca-4731-8a98-5c2d1a5e58c4', 'text': 'Trzy warstwy emulsji światłoczułych (na czerwień, zieleń, niebiesk) z barwnikami spektralnymi, rozdzielone warstwami filtrującymi, na podłożu z poliestru lub triacetylu, z warstwą ochronną i antyhalacyjną.', 'is_correct': 1, 'sort_order': 1}, {'id': '973e5091-8068-4fdb-affa-32337ec72a93', 'question_id': '13346564-8cca-4731-8a98-5c2d1a5e58c4', 'text': 'Wyłącznie dwie warstwy.', 'is_correct': 0, 'sort_order': 2}, {'id': '4894c984-8067-433d-98c8-7b81dec95559', 'question_id': '13346564-8cca-4731-8a98-5c2d1a5e58c4', 'text': 'Wyłącznie podłoże papierowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'ee992423-a3d9-4448-ac21-4ae1fe7d4da0', 'chapter_id': 3, 'text': 'Opisz, jak zbudowany jest negatywowy materiał barwny.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Negatywowy materiał barwny składa się z podłoża (poliester lub triacetyl), na którym nałożone są trzy warstwy emulsji światłoczułych zawierających halogenki srebra i barwniki spektralne: warstwa czuła na niebieskie światło (tworząca barwnik żółty), warstwa czuła na zielone (tworząca barwnik purpurowy/magenta) oraz warstwa czuła na czerwone (tworząca barwnik błękitny/cyjan). Warstwy te rozdzielone są warstwami filtrującymi (np. żółta warstwa filtrująca pod warstwą czułą na niebiesko, aby nie naświetlała jej światło niebieskie z głębszych warstw). Na wierzchu znajduje się warstwa ochronna, a od spodu warstwa antyhalacyjna.'}, {'id': '09768f19-7c03-48f5-ac43-a28aa4867205', 'chapter_id': 3, 'text': 'Podaj, jakie informacje znajdują się na opakowaniu papieru fotograficznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '1588d350-4280-44a0-9657-497bb147cc3e', 'question_id': '09768f19-7c03-48f5-ac43-a28aa4867205', 'text': 'Tylko cena', 'is_correct': 0, 'sort_order': 0}, {'id': 'aef0227a-5df3-46c9-9d09-6e8ac301e9a4', 'question_id': '09768f19-7c03-48f5-ac43-a28aa4867205', 'text': 'Format, ilość arkuszy, rodzaj powierzchni, gradacja, czułość spektralna, data ważności, instrukcja wywoływania, numer partii', 'is_correct': 1, 'sort_order': 1}, {'id': '4d9e7d76-790e-4ecf-a093-ebb66e356e78', 'question_id': '09768f19-7c03-48f5-ac43-a28aa4867205', 'text': 'Tylko kolor opakowania', 'is_correct': 0, 'sort_order': 2}, {'id': '75017042-938e-4226-b820-784b326cae42', 'question_id': '09768f19-7c03-48f5-ac43-a28aa4867205', 'text': 'Tylko nazwa producenta', 'is_correct': 0, 'sort_order': 3}]}, {'id': '325cc9f1-7b08-40a0-b3d6-08d0f28026ae', 'chapter_id': 3, 'text': 'Podaj, jakie informacje znajdują się na opakowaniu papieru fotograficznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Na opakowaniu papieru fotograficznego producent umieszcza: format arkuszy, ich liczbę, rodzaj powierzchni (błysk, mat, półmat, jedwabisty), gradację (twardość) lub informację o zmienno-kontrastowości (Multigrade), czułość spektralną, datę ważności i numer partii, zalecany proces chemiczny (np. RA-4), temperaturę i czas wywoływania, a czasem też diagram charakterystyki światłoczułości.'}, {'id': '54185b5f-648c-4498-b700-4e9adb4811da', 'chapter_id': 3, 'text': 'Na czym zapisywany jest obraz w fotografii cyfrowej?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'd404e1b5-14f7-436a-a11f-d2a0f1b7cb25', 'question_id': '54185b5f-648c-4498-b700-4e9adb4811da', 'text': 'Na filmie fotograficznym', 'is_correct': 0, 'sort_order': 0}, {'id': 'fab8927a-fc7a-48cc-8fba-434eeb742e87', 'question_id': '54185b5f-648c-4498-b700-4e9adb4811da', 'text': 'Na matrycy światłoczułej (CMOS/CCD), a następnie w postaci danych cyfrowych na karcie pamięci (np. SD, CF) w formacie JPEG, RAW, TIFF', 'is_correct': 1, 'sort_order': 1}, {'id': '01ed32b6-9259-4c7a-bc56-54c5e987e72a', 'question_id': '54185b5f-648c-4498-b700-4e9adb4811da', 'text': 'Na papierze fotograficznym', 'is_correct': 0, 'sort_order': 2}, {'id': 'b57335ef-ef5e-4ffd-80b4-2c8b7a22111f', 'question_id': '54185b5f-648c-4498-b700-4e9adb4811da', 'text': 'Na taśmie magnetofonowej', 'is_correct': 0, 'sort_order': 3}]}, {'id': '198d2437-15d6-41ef-a8db-ffe54b42fd72', 'chapter_id': 3, 'text': 'Na czym zapisywany jest obraz w fotografii cyfrowej?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'W fotografii cyfrowej obraz najpierw rejestrowany jest przez matrycę światłoczułą (CMOS lub CCD), gdzie fotony zamieniane są na ładunki elektryczne. Następnie przetwornik analogowo-cyfrowy (ADC) zamienia te sygnały na dane binarne, które po przetworzeniu przez procesor obrazu zapisywane są na karcie pamięci (SD, CF, CFexpress) w formacie JPEG, RAW, TIFF lub HEIF.'}, {'id': 'd77b13b9-7b21-4ce2-8ae5-8e03ede5de98', 'chapter_id': 3, 'text': 'Jak zbudowany jest negatywowy materiał czarno-biały?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '049d4348-fa65-4181-a63a-d14472b0ce7c', 'question_id': 'd77b13b9-7b21-4ce2-8ae5-8e03ede5de98', 'text': 'Wyłącznie podłoże i warstwa srebra.', 'is_correct': 0, 'sort_order': 0}, {'id': '3a1ca7f8-2154-48eb-8620-e87d2c074132', 'question_id': 'd77b13b9-7b21-4ce2-8ae5-8e03ede5de98', 'text': 'Podłoże (poliester/triacetyl), warstwa przylepna, emulsja światłoczuła (żelatyna z halogenkami srebra), warstwa ochronna (overcoat), często warstwa antyhalacyjna.', 'is_correct': 1, 'sort_order': 1}, {'id': '5b26011f-7b93-4b60-8cf4-d30e019dfa77', 'question_id': 'd77b13b9-7b21-4ce2-8ae5-8e03ede5de98', 'text': 'Trzy warstwy barwne.', 'is_correct': 0, 'sort_order': 2}, {'id': '3bf42a6a-b38a-42ad-9a94-ebf15efbf5fc', 'question_id': 'd77b13b9-7b21-4ce2-8ae5-8e03ede5de98', 'text': 'Wyłącznie szkło.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4d47ce38-dc5b-401d-8af0-8828aa48261b', 'chapter_id': 3, 'text': 'Jak zbudowany jest negatywowy materiał czarno-biały?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Negatywowy materiał czarno-biały składa się z podłoża (folia poliestrowa lub celulozowa), warstwy przylepnej łączącej podłoże z emulsją, emulsji światłoczułej zawierającej żelatynę z zawieszonymi kryształami halogenków srebra (bromku, jodku, czasem chlorku), warstwy ochronnej (overcoat) zabezpieczającej przed zarysowaniami oraz często warstwy antyhalacyjnej na spodniej stronie podłoża, zapobiegającej powstawaniu halacji.'}, {'id': '58d679f8-59af-47b8-bf4f-ec94f82886be', 'chapter_id': 3, 'text': 'Wymień podstawowe składniki utrwalacza.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '79ca6022-812f-4523-b6b3-02580094a0fb', 'question_id': '58d679f8-59af-47b8-bf4f-ec94f82886be', 'text': 'Metol, hydrochinon, węglan sodu', 'is_correct': 0, 'sort_order': 0}, {'id': 'd5064df4-e166-4c3c-804b-77a3fe211b50', 'question_id': '58d679f8-59af-47b8-bf4f-ec94f82886be', 'text': 'Tiosiarczan sodu (czynnik utrwalający), kwas siarkawy/kwaśny siarczyn sodu (zakwaszenie), siarczan sodu/glinu (utrwalenie fizyczne), woda', 'is_correct': 1, 'sort_order': 1}, {'id': '96f4f134-ad66-45b7-81cd-3ac61fb1ecc9', 'question_id': '58d679f8-59af-47b8-bf4f-ec94f82886be', 'text': 'Tylko woda i sól', 'is_correct': 0, 'sort_order': 2}, {'id': '063f2566-d0cf-47ac-ac1c-ed6e9546bc79', 'question_id': '58d679f8-59af-47b8-bf4f-ec94f82886be', 'text': 'Alkohol i ocet', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'deb97bba-0600-46ad-8782-da479a4c439f', 'chapter_id': 3, 'text': 'Wymień podstawowe składniki utrwalacza.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Podstawowe składniki utrwalacza to: tiosiarczan sodu (lub amonu) jako czynnik chemiczny rozpuszczający nienaświetlone halogenki srebra; kwas siarkawy, kwaśny siarczyn sodu lub metabisulfit sodu utrzymujące kwaśne pH; siarczan sodu lub siarczan glinu jako środek utrwalający fizycznie żelatynę emulsji; oraz woda destylowana jako rozpuszczalnik.'}, {'id': 'f271c8fd-1403-4550-992e-9528946b7d37', 'chapter_id': 3, 'text': 'Z jakich warstw zbudowana jest błona fotograficzna?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'd6b7b427-37ad-4675-8aec-d5492d5f4a23', 'question_id': 'f271c8fd-1403-4550-992e-9528946b7d37', 'text': 'Tylko podłoże.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c8151205-9844-49e6-ac28-341473397f85', 'question_id': 'f271c8fd-1403-4550-992e-9528946b7d37', 'text': 'Podłoże, warstwa przylepna, emulsja światłoczuła, warstwa ochronna, warstwa antyhalacyjna.', 'is_correct': 1, 'sort_order': 1}, {'id': 'ae89f2a2-08db-4f1d-b3ea-ab7f74265f61', 'question_id': 'f271c8fd-1403-4550-992e-9528946b7d37', 'text': 'Tylko emulsja.', 'is_correct': 0, 'sort_order': 2}, {'id': '572a1f67-b1e0-4576-94cb-b1157322ecb3', 'question_id': 'f271c8fd-1403-4550-992e-9528946b7d37', 'text': 'Tylko warstwa ochronna.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a38fdfb1-7dbb-463d-bf89-53059560cd10', 'chapter_id': 3, 'text': 'Z jakich warstw zbudowana jest błona fotograficzna?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Błona fotograficzna zbudowana jest z kolejnych warstw: podłoża (poliester lub triacetyl), warstwy przylepnej (łączącej podłoże z emulsją), emulsji światłoczułej (żelatyna z halogenkami srebra i ewentualnie barwnikami), warstwy ochronnej (overcoat) na wierzchu oraz często warstwy antyhalacyjnej na spodniej stronie podłoża.'}, {'id': 'c0499ff6-0718-414d-b3cb-8adb2c4663f9', 'chapter_id': 3, 'text': 'Jaką funkcję pełni światłoczuła warstwa żelatynowa w emulsji fotograficznej?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'dd4926f4-0a02-456d-b8d1-80a5d6ac415a', 'question_id': 'c0499ff6-0718-414d-b3cb-8adb2c4663f9', 'text': 'Tylko ochronę przed zarysowaniami.', 'is_correct': 0, 'sort_order': 0}, {'id': '4295887d-66cd-48f9-a29c-9b78db1ba083', 'question_id': 'c0499ff6-0718-414d-b3cb-8adb2c4663f9', 'text': 'Jest nośnikiem dla kryształów halogenków srebra, umożliwia ich równomierne rozprowadzenie, przepuszcza światło do kryształów i pęcznieje podczas obróbki chemicznej, umożliwiając dostęp odczynników.', 'is_correct': 1, 'sort_order': 1}, {'id': '1dfae688-3247-45d4-a405-b68d81c72b57', 'question_id': 'c0499ff6-0718-414d-b3cb-8adb2c4663f9', 'text': 'Tylko zmianę koloru obrazu.', 'is_correct': 0, 'sort_order': 2}, {'id': '82698b8c-f7cb-4a5a-b9b2-2ebfa5971d4e', 'question_id': 'c0499ff6-0718-414d-b3cb-8adb2c4663f9', 'text': 'Tylko utrwalenie obrazu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '75619174-6446-4923-b441-2a41032ba741', 'chapter_id': 3, 'text': 'Jaką funkcję pełni światłoczuła warstwa żelatynowa w emulsji fotograficznej?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Światłoczuła warstwa żelatynowa w emulsji fotograficznej pełni funkcję nośnika dla kryształów halogenków srebra, umożliwiając ich równomierne rozprowadzenie na podłożu. Żelatyna jest przezroczysta, więc przepuszcza światło do kryształów srebra, a podczas obróbki chemicznej pęcznieje, co pozwala wywoływaczowi i innym odczynnikom na swobodny dostęp do emulsji. Po wywołaniu żelatyna twardnieje, utrwalając obraz srebra w swojej strukturze.'}, {'id': 'fe22daca-fff6-417c-bba1-e4bb2e32cbb7', 'chapter_id': 3, 'text': 'Z jakich warstw zbudowany jest papier fotograficzny?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'ccc88fdb-1a12-422d-875c-11a12a374a03', 'question_id': 'fe22daca-fff6-417c-bba1-e4bb2e32cbb7', 'text': 'Tylko podłoże papierowe.', 'is_correct': 0, 'sort_order': 0}, {'id': '3bfb46dd-875e-43df-b0cb-fff5b7cc1a88', 'question_id': 'fe22daca-fff6-417c-bba1-e4bb2e32cbb7', 'text': 'Podłoże papierowe (barytowe lub RC – z żywicą), warstwa barytowa (w papierach barytowych), emulsja światłoczuła (żelatyna z halogenkami srebra), warstwa ochronna (overcoat).', 'is_correct': 1, 'sort_order': 1}, {'id': '6c7da676-0734-4fff-aa0e-50f8ff88ba8b', 'question_id': 'fe22daca-fff6-417c-bba1-e4bb2e32cbb7', 'text': 'Tylko emulsja.', 'is_correct': 0, 'sort_order': 2}, {'id': '8b8dae24-53d7-4cc7-bf6d-d179fd5c2735', 'question_id': 'fe22daca-fff6-417c-bba1-e4bb2e32cbb7', 'text': 'Tylko podłoże plastikowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '5afa78e0-60e9-4b56-ae41-8bb78499a690', 'chapter_id': 3, 'text': 'Z jakich warstw zbudowany jest papier fotograficzny?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Papier fotograficzny składa się z podłoża papierowego (w papierach barytowych – wysokiej jakości papier pokryty warstwą siarczanu baru, w papierach RC – papier powlekany żywicą polietylenową), emulsji światłoczułej zawierającej żelatynę z halogenkami srebra oraz warstwy ochronnej (overcoat) na wierzchu. Papier barytowy (FB – fiber base) jest ceniony za archiwalność i głębię obrazu, a RC (resin coated) za szybkość wywoływania i płaskość.'}, {'id': '650850d8-dd95-4536-aee1-374b459074fa', 'chapter_id': 3, 'text': 'Wymień właściwości użytkowe materiałów światłoczułych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '64e66648-4025-4741-a410-b4510244a077', 'question_id': '650850d8-dd95-4536-aee1-374b459074fa', 'text': 'Tylko kolor.', 'is_correct': 0, 'sort_order': 0}, {'id': '5ded903a-6dd1-4238-8925-f280af7c3358', 'question_id': '650850d8-dd95-4536-aee1-374b459074fa', 'text': 'Czułość (ISO), kontrast, ziarnistość, rozdzielczość, zakres tonalny/dynamika, czułość spektralna, odczyn na światło błyskowe.', 'is_correct': 1, 'sort_order': 1}, {'id': 'd4d383ca-f719-45c7-b741-3cfe9158315e', 'question_id': '650850d8-dd95-4536-aee1-374b459074fa', 'text': 'Tylko waga.', 'is_correct': 0, 'sort_order': 2}, {'id': '14de3ddf-467b-4784-8697-6d4b31edd132', 'question_id': '650850d8-dd95-4536-aee1-374b459074fa', 'text': 'Tylko cena.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f7072bcf-c6af-4ea1-9a29-2f2a70b6782c', 'chapter_id': 3, 'text': 'Wymień właściwości użytkowe materiałów światłoczułych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Właściwości użytkowe materiałów światłoczułych to: czułość (ISO/ASA/DIN) określająca zdolność rejestracji w słabym świetle, kontrast (twardość/miękkość emulsji), ziarnistość (wielkość kryształów srebra), rozdzielczość (zdolność odwzorowania drobnych szczegółów), zakres tonalny (dynamika – zdolność rejestracji szczegółów w cieniach i światłach), czułość spektralna (reakcja na różne długości fali świetlnej) oraz odczyn na światło błyskowe (reciprocity failure).'}, {'id': 'b00dfc14-0a94-4c59-aea7-14617fed75ed', 'chapter_id': 3, 'text': 'Wymień czynniki wpływające na ziarnistość obrazu.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '091ecc07-d515-454b-90a3-6f3a67243ed5', 'question_id': 'b00dfc14-0a94-4c59-aea7-14617fed75ed', 'text': 'Tylko marka aparatu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'adef2018-11be-4809-b701-eb66ed10e6d4', 'question_id': 'b00dfc14-0a94-4c59-aea7-14617fed75ed', 'text': 'Czułość materiału (ISO), rodzaj wywoływacza, temperatura i czas wywoływania, sposób agitacji, rodzaj emulsji, rozcieńczenie wywoływacza.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b0c90763-1de7-4582-aecf-823ae2778eb6', 'question_id': 'b00dfc14-0a94-4c59-aea7-14617fed75ed', 'text': 'Tylko kolor obudowy filmu.', 'is_correct': 0, 'sort_order': 2}, {'id': '9209ac7f-52dd-445f-a466-618006238d20', 'question_id': 'b00dfc14-0a94-4c59-aea7-14617fed75ed', 'text': 'Tylko pora dnia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '04a743b5-62a0-4de8-81da-27040bb92955', 'chapter_id': 3, 'text': 'Wymień czynniki wpływające na ziarnistość obrazu.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Na ziarnistość obrazu wpływają: czułość materiału światłoczułego (wyższe ISO = większe ziarno), rodzaj użytego wywoływacza (energiczne wywoływacze wzmagają ziarnistość), temperatura i czas wywoływania (wyższa temperatura i dłuższy czas zwiększają ziarno), sposób agitacji (intensywne mieszanie może zwiększyć ziarno), rodzaj emulsji (krystaliczna struktura halogenków srebra) oraz rozcieńczenie wywoływacza (bardziej rozcieńczony wywoływacz zazwyczaj daje drobniejsze ziarno przy wydłużonym czasie).'}, {'id': 'ec63bd17-3bf8-4a93-a6a0-f25687b3f5ab', 'chapter_id': 3, 'text': 'Porównaj barwny film negatywowy i pozytywowy.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '4c449110-b3e4-4d9c-9a88-15ec507cbeee', 'question_id': 'ec63bd17-3bf8-4a93-a6a0-f25687b3f5ab', 'text': 'Nie ma między nimi różnic.', 'is_correct': 0, 'sort_order': 0}, {'id': '8b85cc60-4db7-4059-812a-8e72a34d3877', 'question_id': 'ec63bd17-3bf8-4a93-a6a0-f25687b3f5ab', 'text': 'Negatywowy: obraz odwrócony tonalnie i barwnie, szeroka tolerancja ekspozycji, proces C-41. Pozytywowy (slajd): obraz zgodny z rzeczywistością, wąska tolerancja, wysoki kontrast, proces E-6.', 'is_correct': 1, 'sort_order': 1}, {'id': '7bacc9cd-a888-48ab-b2e3-f27f64b10893', 'question_id': 'ec63bd17-3bf8-4a93-a6a0-f25687b3f5ab', 'text': 'Oba to ten sam materiał.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ec96dd6b-bbb1-42a1-977e-6b6e4645d005', 'question_id': 'ec63bd17-3bf8-4a93-a6a0-f25687b3f5ab', 'text': 'Negatywowy jest tylko czarno-biały.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '6561f4a1-3f16-4dc6-98a3-5efed9a54da6', 'chapter_id': 3, 'text': 'Porównaj barwny film negatywowy i pozytywowy.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Film negatywowy barwny daje obraz odwrócony tonalnie i barwnie (jasne partie są ciemne, a kolory dopełniające), charakteryzuje się szeroką tolerancją ekspozycji i łatwością korekty w druku, wywołuje się w procesie C-41. Film pozytywowy (odwracalny, slajdowy) daje obraz zgodny z rzeczywistością, ma wąską tolerancję ekspozycji, wysoki kontrast i nasycenie barw, wywołuje się w procesie E-6. Slajdy służą do projekcji i reprodukcji bezpośredniej, podczas gdy negatywy są pośrednim materiałem do wykonywania odbitek.'}, {'id': '416f8b20-ac33-4bbc-a30c-1c8302d2e779', 'chapter_id': 3, 'text': 'Wymień podstawowe składniki wywoływacza.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '479927d6-ba6f-4b57-a7a0-ff5a1c3cae2f', 'question_id': '416f8b20-ac33-4bbc-a30c-1c8302d2e779', 'text': 'Tylko woda.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ecbb6994-5f0d-402d-9bbf-c3f9c7f87e7c', 'question_id': '416f8b20-ac33-4bbc-a30c-1c8302d2e779', 'text': 'Reduktory (metol, hydrochinon, fenidon), przyspieszacz (węglan sodu, boraks), konserwant (siarczyn sodu), rozpuszczalnik (woda)', 'is_correct': 1, 'sort_order': 1}, {'id': '392464d3-cf9a-4173-9452-487f87e9072c', 'question_id': '416f8b20-ac33-4bbc-a30c-1c8302d2e779', 'text': 'Tylko sól i cukier.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c7397eaa-3d2b-4c44-9a25-5eaa4ee2537a', 'question_id': '416f8b20-ac33-4bbc-a30c-1c8302d2e779', 'text': 'Tylko alkohol.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '729ffcd0-3fc9-44e6-bfd5-4078747a1846', 'chapter_id': 3, 'text': 'Wymień podstawowe składniki wywoływacza.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Podstawowe składniki wywoływacza czarno-białego to: reduktory (czynniki wywołujące) takie jak metol, hydrochinon lub fenidon; przyspieszacz (akcelerator) – substancje alkaliczne np. węglan sodu, boraks lub wodorotlenek sodu; konserwant – np. siarczyn sodu lub metabisulfit sodu zapobiegający utlenianiu; oraz rozpuszczalnik, którym jest woda destylowana lub demineralizowana.'}, {'id': 'a289a54a-7622-4f59-8e3b-c40e72556f7b', 'chapter_id': 3, 'text': 'Wymień wywoływacze i utrwalacze.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '2b554e23-9068-47a4-afca-96c42b7bf62e', 'question_id': 'a289a54a-7622-4f59-8e3b-c40e72556f7b', 'text': 'Wywoływacze: woda, sól. Utrwalacze: alkohol.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd36ad840-733e-472e-a97a-4165a04b44a0', 'question_id': 'a289a54a-7622-4f59-8e3b-c40e72556f7b', 'text': 'Wywoływacze: D-76, Rodinal, ID-11, XTOL, HC-110. Utrwalacze: F-24, F-5, Ilford Rapid Fixer, Kodafix.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f288dcaf-c30a-4dea-9a7b-d40ae2787858', 'question_id': 'a289a54a-7622-4f59-8e3b-c40e72556f7b', 'text': 'Wywoływacze: Photoshop, Lightroom. Utrwalacze: drukarka.', 'is_correct': 0, 'sort_order': 2}, {'id': '2b666f0b-bdfc-4f72-baf5-816fd0cb3b1f', 'question_id': 'a289a54a-7622-4f59-8e3b-c40e72556f7b', 'text': 'Wywoływacze: mleko. Utrwalacze: ocet.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '957813ce-45d2-4426-be15-945bc9ed89f7', 'chapter_id': 3, 'text': 'Wymień wywoływacze i utrwalacze.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Przykłady wywoływaczy czarno-białych: D-76 (Kodak), ID-11 (Ilford), Rodinal (Agfa R09), XTOL, HC-110, Perceptol, Microphen. Przykłady utrwalaczy: F-24, F-5 (formuły klasyczne), Ilford Rapid Fixer, Kodak Kodafix, Tetenal Superfix, Foma Fomafix. W fotografii kolorowej stosuje się wywoływacze procesów C-41 (kolor negatyw), E-6 (slajdy) i RA-4 (papiery kolorowe).'}, {'id': 'b027b12f-fbfa-49e5-abf7-d0c48a102530', 'chapter_id': 3, 'text': 'Omów zasady przechowywania materiałów światłoczułych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '21d80905-6613-4823-b7de-3adb51349806', 'question_id': 'b027b12f-fbfa-49e5-abf7-d0c48a102530', 'text': 'W słońcu i cieple.', 'is_correct': 0, 'sort_order': 0}, {'id': 'b1b039a3-e3f1-4914-911b-f945ff1a903e', 'question_id': 'b027b12f-fbfa-49e5-abf7-d0c48a102530', 'text': 'W chłodzie (4-10°C, lodówka), suchu, ciemności, w oryginalnych opakowaniach, z dala od RTG i chemikaliów; filmy kolorowe szczególnie wymagają niskich temperatur.', 'is_correct': 1, 'sort_order': 1}, {'id': 'a75d773a-391b-4b97-9077-f8c7889b1ef8', 'question_id': 'b027b12f-fbfa-49e5-abf7-d0c48a102530', 'text': 'W wilgoci i wysokiej temperaturze.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c13381f7-b8db-4773-b98a-f9f0720a03c4', 'question_id': 'b027b12f-fbfa-49e5-abf7-d0c48a102530', 'text': 'W zamrażarce w temperaturze -50°C.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0b20661a-6d6b-4d61-be68-2abc6a4586e7', 'chapter_id': 3, 'text': 'Omów zasady przechowywania materiałów światłoczułych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Materiały światłoczułe należy przechowywać w chłodnym (najlepiej 4-10°C, filmy kolorowe w lodówce), suchym, ciemnym miejscu, w oryginalnych, szczelnych opakowaniach. Należy chronić je przed promieniowaniem RTG (lotniska, szpitale), oparami chemicznymi i bezpośrednim światłem. Przed użyciem film należy odczekać, aż osiągnie temperaturę pokojową, aby uniknąć kondensacji wilgoci. Zamrażarka jest niewskazana ze względu na ryzyko kondensacji po wyjęciu.'}, {'id': '9851b6c3-bebd-4a63-9fae-19470a153ba4', 'chapter_id': 3, 'text': 'Scharakteryzuj filmy odwracalne i podaj ich zastosowanie.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '0408d06b-a2b3-43f2-990a-75e93cdd1486', 'question_id': '9851b6c3-bebd-4a63-9fae-19470a153ba4', 'text': 'Filmy dające obraz odwrócony tonalnie; zastosowanie: odbitki papierowe.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c2e60893-b284-40a0-b696-d900b7412b64', 'question_id': '9851b6c3-bebd-4a63-9fae-19470a153ba4', 'text': 'Filmy pozytywowe (slajdy) wywoływane w procesie E-6, dające obraz zgodny z rzeczywistością, o wysokim kontraście i nasyceniu; zastosowanie: projekcja, reprodukcja, fotografia przyrodnicza, reklamowa.', 'is_correct': 1, 'sort_order': 1}, {'id': '7ccb1fe4-3998-43f0-9226-3930913f6106', 'question_id': '9851b6c3-bebd-4a63-9fae-19470a153ba4', 'text': 'Filmy czarno-białe o niskim kontraście.', 'is_correct': 0, 'sort_order': 2}, {'id': '71f8802e-e3b9-47f1-8c19-b1cc669ecd5a', 'question_id': '9851b6c3-bebd-4a63-9fae-19470a153ba4', 'text': 'Filmy do aparatów jednorazowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '78a17e17-866f-4cda-9338-b69436acb9e6', 'chapter_id': 3, 'text': 'Scharakteryzuj filmy odwracalne i podaj ich zastosowanie.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Filmy odwracalne (pozytywowe, slajdowe, np. Fujifilm Velvia, Provia, Kodak Ektachrome) to materiały, które po wywołaniu w procesie E-6 dają obraz pozytywowy zgodny z rzeczywistością, a nie odwrócony jak negatyw. Charakteryzują się wysokim kontrastem, żywym nasyceniem barw, wąską tolerancją ekspozycji i drobnym ziarnem. Zastosowanie: projekcja na ekranie, reprodukcja bezpośrednia do druku, fotografia przyrodnicza, krajobrazowa, reklamowa i archiwalna ze względu na trwałość barw.'}, {'id': 'c8d56e87-9183-4e34-a662-c7432b61ca4d', 'chapter_id': 3, 'text': 'Jak można podzielić materiały światłoczułe?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '31e163fc-e225-420f-8a02-6597d5c8112f', 'question_id': 'c8d56e87-9183-4e34-a662-c7432b61ca4d', 'text': 'Tylko na drogie i tanie.', 'is_correct': 0, 'sort_order': 0}, {'id': '1c78c23c-8dc6-445b-8ebd-09c6ea207140', 'question_id': 'c8d56e87-9183-4e34-a662-c7432b61ca4d', 'text': 'Ze względu na przebieg procesu: negatywowe, pozytywowe, odwracalne; ze względu na format: małoobrazkowe, średnie, wielkoformatowe; ze względu na barwę: czarno-białe, kolorowe.', 'is_correct': 1, 'sort_order': 1}, {'id': '17f70df7-877f-4776-a416-0481534540c4', 'question_id': 'c8d56e87-9183-4e34-a662-c7432b61ca4d', 'text': 'Tylko na małe i duże.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e669992d-579f-4f8d-8fb4-110a6fb4b59a', 'question_id': 'c8d56e87-9183-4e34-a662-c7432b61ca4d', 'text': 'Tylko na nowe i stare.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'f82a10da-a81a-47d2-bb1c-5ea8c16d387b', 'chapter_id': 3, 'text': 'Jak można podzielić materiały światłoczułe?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Materiały światłoczułe dzielimy ze względu na przebieg procesu chemicznego na negatywowe (dające obraz odwrócony), pozytywowe (papiery, slajdy dające obraz zgodny) i odwracalne (instancyjne). Ze względu na format: małoobrazkowe (135), średnioformatowe (120), wielkoformatowe (klisze płaskie). Ze względu na barwę: czarno-białe i kolorowe. Ze względu na rodzaj podłoża: na papierowe, foliowe (filmy) i szklane (płyty).'}, {'id': '2eefcc64-1242-48d1-ae11-e2b7b9df413a', 'chapter_id': 3, 'text': 'Opisz budowę czarno-białych papierów fotograficznych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'a82c4d3a-bc02-4bbb-a175-a284372c53c3', 'question_id': '2eefcc64-1242-48d1-ae11-e2b7b9df413a', 'text': 'Tylko podłoże papierowe.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd7fd6d2b-31b9-4537-9047-7377dc782bfd', 'question_id': '2eefcc64-1242-48d1-ae11-e2b7b9df413a', 'text': 'Podłoże papierowe (barytowe lub RC z powłoką polietylenową), warstwa barytowa (w FB), emulsja światłoczuła (żelatyna z halogenkami srebra), warstwa ochronna (overcoat).', 'is_correct': 1, 'sort_order': 1}, {'id': '49c9f0b7-43a4-4d2b-8b3c-9983e8eb9465', 'question_id': '2eefcc64-1242-48d1-ae11-e2b7b9df413a', 'text': 'Trzy warstwy barwne.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a1de00d7-4e8f-4c84-981e-2ae03b0b95a1', 'question_id': '2eefcc64-1242-48d1-ae11-e2b7b9df413a', 'text': 'Tylko emulsja.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '395f958e-0f5f-4e5f-91d7-246931fb9818', 'chapter_id': 3, 'text': 'Opisz budowę czarno-białych papierów fotograficznych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Czarno-biały papier fotograficzny składa się z podłoża papierowego – w wersji barytowej (FB) jest to wysokiej jakości papier pokryty warstwą siarczanu baru (barytu), a w wersji RC (resin coated) papier jest powlekany od spodu i od góry warstwą polietylenu. Na podłożu znajduje się emulsja światłoczuła zawierająca żelatynę z halogenkami srebra (zazwyczaj bromek srebra z domieszką jodku) oraz warstwa ochronna (overcoat). Papier może być jedno- lub wielogradacyjny (Multigrade).'}, {'id': '026309fd-3755-4f66-af44-aafcb05ef271', 'chapter_id': 3, 'text': 'Podaj skład emulsji światłoczułej.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'ad663df1-4ff0-4c50-ac2f-e4729c0a19db', 'question_id': '026309fd-3755-4f66-af44-aafcb05ef271', 'text': 'Tylko woda.', 'is_correct': 0, 'sort_order': 0}, {'id': '7bf79a2e-90ef-4fa0-85e2-923700b5386f', 'question_id': '026309fd-3755-4f66-af44-aafcb05ef271', 'text': 'Żelatyna jako nośnik, halogenki srebra (bromek, jodek, chlorek) jako czynnik światłoczuły, barwniki spektralne (w materiałach kolorowych i ortochromatycznych), środki utwardzające i plastyfikatory.', 'is_correct': 1, 'sort_order': 1}, {'id': '1668d0da-ec99-4a92-bab1-353471d40323', 'question_id': '026309fd-3755-4f66-af44-aafcb05ef271', 'text': 'Tylko sól kuchenna.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ce0c0800-a9e2-4f21-99bb-9a2e0cce4814', 'question_id': '026309fd-3755-4f66-af44-aafcb05ef271', 'text': 'Tylko alkohol.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e8cf0cf6-4bf9-470a-ba9d-0e9bdbedaa21', 'chapter_id': 3, 'text': 'Podaj skład emulsji światłoczułej.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Emulsja światłoczuła składa się przede wszystkim z żelatyny pełniącej funkcję nośnika oraz zawieszonych w niej kryształów halogenków srebra (bromku, jodku, czasem chlorku), które są czynnikiem światłoczułym. W materiałach kolorowych i ortochromatycznych dodaje się barwniki spektralne, które poszerzają zakres czułości na określone długości fali. Emulsja zawiera też środki utwardzające żelatynę, plastyfikatory oraz środki zapobiegające tworzeniu się mgiełki (fog).'}, {'id': 'd81e3892-a761-4fd3-a181-df37256109c1', 'chapter_id': 3, 'text': 'Jaki wpływ na proces wywoływania ma rozcieńczenie wywoływacza?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '7a3e5366-b9e6-4562-9265-25e9e0ae39dd', 'question_id': 'd81e3892-a761-4fd3-a181-df37256109c1', 'text': 'Brak wpływu.', 'is_correct': 0, 'sort_order': 0}, {'id': '8beeea34-4ec8-48f5-8d01-ad248ae44d91', 'question_id': 'd81e3892-a761-4fd3-a181-df37256109c1', 'text': 'Większe rozcieńczenie wydłuża czas wywoływania, zazwyczaj zmniejsza kontrast i ziarnistość, wydłuża zakres tonalny; mniejsze rozcieńczenie przyspiesza proces i zwiększa kontrast.', 'is_correct': 1, 'sort_order': 1}, {'id': '60c9b514-4cc5-4468-bd20-6bfee759cae6', 'question_id': 'd81e3892-a761-4fd3-a181-df37256109c1', 'text': 'Zmienia temperaturę barwową.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c4c0bc5a-f087-416f-badb-05d653e1c6e0', 'question_id': 'd81e3892-a761-4fd3-a181-df37256109c1', 'text': 'Zwiększa czułość filmu dwukrotnie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e3bbacc6-c0ae-4bc8-ae7b-5dbe5339bd6e', 'chapter_id': 3, 'text': 'Jaki wpływ na proces wywoływania ma rozcieńczenie wywoływacza?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Rozcieńczenie wywoływacza wydłuża czas wywoływania, ponieważ stężenie reduktorów jest niższe. Zazwyczaj bardziej rozcieńczony wywoływacz daje obraz o niższym kontraście, drobniejszym ziarnie i szerszym zakresie tonalnym, co jest wykorzystywane przy wywoływaniu negatywów kontrastowych. Mniej rozcieńczony (bardziej stężony) wywoływacz działa szybciej, zwiększa kontrast i ziarnistość, co może być pożądane przy materiałach płaskich lub przy pracy z papierem fotograficznym.'}, {'id': '1766fc5a-b917-4c3d-b7d7-9a801a2f692c', 'chapter_id': 3, 'text': 'Scharakteryzuj powierzchnie papieru fotograficznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '1dc0fcc9-7710-4b5e-a9cf-82086ae819aa', 'question_id': '1766fc5a-b917-4c3d-b7d7-9a801a2f692c', 'text': 'Wszystkie powierzchnie są identyczne.', 'is_correct': 0, 'sort_order': 0}, {'id': 'b373125b-a261-4d49-8720-b09216ee6524', 'question_id': '1766fc5a-b917-4c3d-b7d7-9a801a2f692c', 'text': 'Błysk (głęboka czerń, kontrast, odbicia), półmat (uniwersalny, mniej odbić), mat (artystyczny, brak odbić, tekstura), jedwabisty (delikatny połysk, portrety), perłowy (metaliczny efekt).', 'is_correct': 1, 'sort_order': 1}, {'id': 'cae8a2aa-c3b9-4dca-a696-b8d119245d57', 'question_id': '1766fc5a-b917-4c3d-b7d7-9a801a2f692c', 'text': 'Tylko błyszcząca i matowa.', 'is_correct': 0, 'sort_order': 2}, {'id': 'd7cf63db-7108-4620-a049-196da85fdbf6', 'question_id': '1766fc5a-b917-4c3d-b7d7-9a801a2f692c', 'text': 'Powierzchnia nie ma znaczenia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '05abfae2-0dd5-4749-ab02-fc345fc630cc', 'chapter_id': 3, 'text': 'Scharakteryzuj powierzchnie papieru fotograficznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Powierzchnie papieru fotograficznego to: błyszcząca (glossy) – daje najgłębszą czerń, wysoki kontrast i ostrość, ale jest podatna na odciski palców i refleksy; półmat (lustre, pearl) – kompromis między błyskiem a matem, uniwersalna, mniej odbija światło; mat (matte) – eliminuje refleksy, nadaje zdjęciom charakterystykę artystyczną i retro; jedwabista (silk, satin) – delikatny połysk, często stosowana w portrecie; perłowa (pearl) lub metaliczna (metallic) – daje efektowne, niemal metaliczne przejścia tonalne, szczególnie przy zdjęciach o dużej ilości świateł.'}, {'id': '4da57696-5098-45f5-ba97-010f51e85418', 'chapter_id': 3, 'text': 'Jakie informacje umieszcza się na opakowaniu materiałów negatywowych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'a1076651-215d-4c3a-99b3-31d024579652', 'question_id': '4da57696-5098-45f5-ba97-010f51e85418', 'text': 'Tylko cena.', 'is_correct': 0, 'sort_order': 0}, {'id': '1b582e7f-05b0-4b50-9790-b3f917ae25af', 'question_id': '4da57696-5098-45f5-ba97-010f51e85418', 'text': 'Nazwa produktu, czułość (ISO/DIN), format, liczba klatek, data ważności, numer partii, rodzaj procesu chemicznego (C-41, E-6, DX), zalecenia przechowywania.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f9df7220-12bb-4adf-b3d1-5d1f83bf3b48', 'question_id': '4da57696-5098-45f5-ba97-010f51e85418', 'text': 'Tylko kolor opakowania.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f31cc645-b82b-4cba-b0ad-72cb766e8f43', 'question_id': '4da57696-5098-45f5-ba97-010f51e85418', 'text': 'Tylko nazwa producenta.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '95f52733-11e2-49fb-ae54-4bb2593e9474', 'chapter_id': 3, 'text': 'Jakie informacje umieszcza się na opakowaniu materiałów negatywowych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Na opakowaniu materiałów negatywowych producent umieszcza: nazwę produktu i producenta, czułość (ISO/ASA/DIN), format (np. 135/36), liczbę klatek, datę ważności i numer partii, rodzaj zalecanego procesu chemicznego (np. C-41, E-6, czarno-biały), informacje o kodzie DX (dla filmów 35 mm), zalecenia dotyczące przechowywania (temperatura, wilgotność), a czasem diagram charakterystyki tonalnej i informacje o balansie barwnym (dla filmów kolorowych – daylight lub tungsten).'}, {'id': '0ce42a84-b4e8-4ec5-b2a3-ff4285356828', 'chapter_id': 3, 'text': 'Scharakteryzuj wymiary konfekcjonowanych materiałów negatywowych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '0f77a57e-cd82-4f37-9a4b-3f52427a4069', 'question_id': '0ce42a84-b4e8-4ec5-b2a3-ff4285356828', 'text': 'Tylko format 24×36 mm.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ceafe96d-3f0b-447b-b20c-cc4002f77843', 'question_id': '0ce42a84-b4e8-4ec5-b2a3-ff4285356828', 'text': 'Mały obrazek 24×36 mm (film 135), średni format 6×4,5; 6×6; 6×7; 6×9 cm (film 120), wielki format 4×5"; 8×10" (klisze płaskie w kasetach), formaty instancyjne.', 'is_correct': 1, 'sort_order': 1}, {'id': '352b8964-661a-4f09-a22f-5730792567e1', 'question_id': '0ce42a84-b4e8-4ec5-b2a3-ff4285356828', 'text': 'Tylko format A4.', 'is_correct': 0, 'sort_order': 2}, {'id': '1e145fad-81e7-4ccb-a0cf-42259dd795f9', 'question_id': '0ce42a84-b4e8-4ec5-b2a3-ff4285356828', 'text': 'Tylko format 10×15 cm.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '5cbe0412-37cd-446c-9812-7ce98ede99e3', 'chapter_id': 3, 'text': 'Scharakteryzuj wymiary konfekcjonowanych materiałów negatywowych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Konfekcjonowane materiały negatywowe występują w wymiarach: małoobrazkowych 24×36 mm na filmie typ 135 w kasetkach na 24 lub 36 klatek; średnioformatowych na filmie typ 120/220 w formatach 6×4,5 cm, 6×6 cm, 6×7 cm i 6×9 cm; wielkoformatowych jako klisze płaskie w kasetach szczelnych, najczęściej 4×5 cala i 8×10 cala; oraz formatach instancyjnych (np. Polaroid, Instax) o różnych wymiarach odbitki.'}, {'id': 'a9ae9bb8-1cc2-4363-bd98-cf0fa87fa7fa', 'chapter_id': 3, 'text': 'Co to jest substancja przyspieszająca i jakie ma znaczenie w wywoływaniu?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '7a628f01-708f-4981-b545-e39ab8d62336', 'question_id': 'a9ae9bb8-1cc2-4363-bd98-cf0fa87fa7fa', 'text': 'Substancja zwalniająca proces wywoływania.', 'is_correct': 0, 'sort_order': 0}, {'id': '175f84b2-8e72-4c1d-9777-600ce84a987b', 'question_id': 'a9ae9bb8-1cc2-4363-bd98-cf0fa87fa7fa', 'text': 'Substancja alkaliczna (np. węglan sodu, boraks, wodorotlenek sodu) podwyższająca pH wywoływacza, co przyspiesza redukcję halogenków srebra i skraca czas wywoływania.', 'is_correct': 1, 'sort_order': 1}, {'id': '979226c3-5c79-4780-a239-cbc849f5b3a9', 'question_id': 'a9ae9bb8-1cc2-4363-bd98-cf0fa87fa7fa', 'text': 'Substancja zmieniająca kolor obrazu na zielony.', 'is_correct': 0, 'sort_order': 2}, {'id': 'f7cda16c-17fe-4b54-af8a-916e0dffabfe', 'question_id': 'a9ae9bb8-1cc2-4363-bd98-cf0fa87fa7fa', 'text': 'Substancja do czyszczenia obiektywu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '470a7367-b2d1-4a72-8707-91e79eedea4b', 'chapter_id': 3, 'text': 'Co to jest substancja przyspieszająca i jakie ma znaczenie w wywoływaniu?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Substancja przyspieszająca (akcelerator) to związek alkaliczny, najczęściej węglan sodu (soda), boraks (tetraboran sodu) lub wodorotlenek sodu (ług sodowy). Podwyższa ona pH roztworu wywoływacza, co aktywuje reduktory (metol, hydrochinon) i przyspiesza proces redukcji nienaświetlonych halogenków srebra na metaliczne srebro. Im wyższe pH, tym szybsze wywoływanie, ale także większa ziarnistość i kontrast.'}, {'id': 'ca2eafb0-741a-4609-a600-f8941fd10e18', 'chapter_id': 3, 'text': 'Jakie znasz rodzaje filmów fotograficznych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '596c4bbe-113b-4769-b6ee-7e567f2a4286', 'question_id': 'ca2eafb0-741a-4609-a600-f8941fd10e18', 'text': 'Tylko czarno-białe.', 'is_correct': 0, 'sort_order': 0}, {'id': '95776dfd-bcf7-4900-b1e8-52df2761de24', 'question_id': 'ca2eafb0-741a-4609-a600-f8941fd10e18', 'text': 'Negatywowe czarno-białe, negatywowe kolorowe (C-41), odwracalne pozytywowe (slajdy, E-6), instancyjne (samowywołujące się), czarno-białe odwracalne, infrachromatyczne, ortochromatyczne.', 'is_correct': 1, 'sort_order': 1}, {'id': '472e0347-a6fc-4134-bfc7-37c586968db0', 'question_id': 'ca2eafb0-741a-4609-a600-f8941fd10e18', 'text': 'Tylko kolorowe.', 'is_correct': 0, 'sort_order': 2}, {'id': '74b26b33-6def-4d93-a19e-39f135d9eb4f', 'question_id': 'ca2eafb0-741a-4609-a600-f8941fd10e18', 'text': 'Tylko cyfrowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '22f5ab00-9c1c-4470-883b-f0b5b7aeb5f3', 'chapter_id': 3, 'text': 'Jakie znasz rodzaje filmów fotograficznych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Rodzaje filmów fotograficznych to: negatywowe czarno-białe (różne czułości i kontrasty), negatywowe kolorowe (proces C-41), odwracalne pozytywowe (slajdy, proces E-6), instancyjne (samowywołujące się, np. Polaroid, Instax), czarno-białe odwracalne (np. Fomapan R100), infrachromatyczne (czułe na podczerwień), ortochromatyczne (niewrażliwe na czerwień, stosowane w procesach drukarskich i artystycznych), panchromatyczne (czułe na całe widmo światła widzialnego).'}, {'id': '03fb8eaf-2cee-4662-ae45-5487b870652e', 'chapter_id': 3, 'text': 'Jaka jest rola żelatyny w materiałach światłoczułych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'd7d0ed29-94f3-4800-a6cf-9af97ef530f1', 'question_id': '03fb8eaf-2cee-4662-ae45-5487b870652e', 'text': 'Tylko ochrona przed zarysowaniami.', 'is_correct': 0, 'sort_order': 0}, {'id': 'e6ad8b1b-1e9e-4e90-891b-a98f1bb33d91', 'question_id': '03fb8eaf-2cee-4662-ae45-5487b870652e', 'text': 'Nośnik dla kryształów halogenków srebra, zapewnia równomierne rozprowadzenie emulsji, przepuszcza światło, pęcznieje podczas obróbki chemicznej, utrwala obraz po wywołaniu.', 'is_correct': 1, 'sort_order': 1}, {'id': '0990a62c-6ee9-4b25-9a94-1b4f16adc37a', 'question_id': '03fb8eaf-2cee-4662-ae45-5487b870652e', 'text': 'Tylko zmiana koloru obrazu.', 'is_correct': 0, 'sort_order': 2}, {'id': '9f8e867b-a2a4-474f-9d6d-e529290f1d20', 'question_id': '03fb8eaf-2cee-4662-ae45-5487b870652e', 'text': 'Tylko zwiększanie czułości filmu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2fafd7c7-3846-4c56-9a9f-928ec7fd8f71', 'chapter_id': 3, 'text': 'Jaka jest rola żelatyny w materiałach światłoczułych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Żelatyna w materiałach światłoczułych pełni kluczowe funkcje: jest nośnikiem dla kryształów halogenków srebra, umożliwiając ich równomierne rozprowadzenie na podłożu; jest przezroczysta, więc nie przeszkadza światłu w docieraniu do kryształów; podczas obróbki chemicznej pęcznieje, co pozwala odczynnikom na swobodny dostęp do emulsji; po wywołaniu i utrwaleniu twardnieje, mechanicznie utrwalając obraz srebra w swojej strukturze; oraz zabezpiecza kryształy przed przesuwaniem się i zapewnia odpowiednią grubość emulsji.'}, {'id': 'ed7ac20b-81c0-47b6-85dd-217cc22377c5', 'chapter_id': 3, 'text': 'Wymień sposoby przechowywania negatywów nienaświetlonych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'df857c0b-b916-4d4d-9864-095abac31f47', 'question_id': 'ed7ac20b-81c0-47b6-85dd-217cc22377c5', 'text': 'W słońcu i cieple.', 'is_correct': 0, 'sort_order': 0}, {'id': '18270f99-beff-48b9-858f-a0bf6d8fea97', 'question_id': 'ed7ac20b-81c0-47b6-85dd-217cc22377c5', 'text': 'W lodówce (4-10°C), w zamrażarce (dla długiego przechowywania, w szczelnym opakowaniu), w suchym, ciemnym miejscu, w oryginalnych opakowaniach z workiem silica gel, z dala od RTG i chemikaliów.', 'is_correct': 1, 'sort_order': 1}, {'id': 'd5749546-ce44-4a8c-acfe-744b9a9853f0', 'question_id': 'ed7ac20b-81c0-47b6-85dd-217cc22377c5', 'text': 'W wilgotnym i ciepłym pomieszczeniu.', 'is_correct': 0, 'sort_order': 2}, {'id': '9e971b79-97f6-4e32-b2c4-3878efa68d96', 'question_id': 'ed7ac20b-81c0-47b6-85dd-217cc22377c5', 'text': 'W otwartych pojemnikach na parapecie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'b84d58f8-b7ad-4398-939f-3785a68203a2', 'chapter_id': 3, 'text': 'Wymień sposoby przechowywania negatywów nienaświetlonych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Negatywy nienaświetlone przechowuje się w chłodzie (lodówka 4-10°C dla filmów kolorowych, zamrażarka dla długoterminowego przechowywania w szczelnych opakowaniach zapobiegających kondensacji), w suchim i całkowicie ciemnym miejscu, w oryginalnych, szczelnych opakowaniach z workiem pochłaniacza wilgoci (silica gel). Należy chronić je przed promieniowaniem RTG (lotniska, szpitale), oparami chemicznymi i bezpośrednim światłem. Przed użyciem film należy odczekać, aż osiągnie temperaturę pokojową.'}, {'id': '4f0cd958-bb54-4dc4-aa0d-b5b89ca9647c', 'chapter_id': 3, 'text': 'Omów zastosowanie filmów o czułości 100ASA, 200ASA i 400ASA.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '7baaf75a-4fe6-4347-8245-a94fee354499', 'question_id': '4f0cd958-bb54-4dc4-aa0d-b5b89ca9647c', 'text': 'Wszystkie trzy służą wyłącznie do fotografii nocnej.', 'is_correct': 0, 'sort_order': 0}, {'id': 'cabb8095-d28b-41c7-8277-fd3709b048be', 'question_id': '4f0cd958-bb54-4dc4-aa0d-b5b89ca9647c', 'text': '100 ASA – krajobraz, studio, statyw, drobne ziarno; 200 ASA – uniwersalny, reportaż dzienny; 400 ASA – reportaż, sport, słabe światło, większe ziarno.', 'is_correct': 1, 'sort_order': 1}, {'id': 'bde38c24-779d-4427-b3f4-7926af3e1b7e', 'question_id': '4f0cd958-bb54-4dc4-aa0d-b5b89ca9647c', 'text': 'Wszystkie trzy mają identyczne zastosowanie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'e2ae29d8-fb87-4b7e-ac1f-fd0c04b9789f', 'question_id': '4f0cd958-bb54-4dc4-aa0d-b5b89ca9647c', 'text': '100 ASA – wyłącznie fotografia makro; 200 ASA – wyłącznie portret; 400 ASA – wyłącznie architektura.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '064f983e-76dd-490c-a2e1-07cdb3809056', 'chapter_id': 3, 'text': 'Omów zastosowanie filmów o czułości 100ASA, 200ASA i 400ASA.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Film 100 ASA to materiał małoczuły o drobnym ziarnie i szerokim zakresie tonalnym, idealny do fotografii krajobrazowej w dobrym świetle, pracy w studio ze statywem i lampami, architektury oraz sytuacji wymagających najwyższej jakości obrazu. Film 200 ASA to kompromis między czułością a jakością, uniwersalny do reportażu dziennego, turystyki i fotografii ulicznej w umiarkowanym świetle. Film 400 ASA to materiał wysokoczuły stosowany w reportażu, sporcie, fotografii ulicznej i koncertowej, w słabym świetle bez statywu; charakteryzuje się większym ziarnem i szerszą tolerancją ekspozycji.'}, {'id': '98cac700-646a-47ec-8b30-8246c190e3f5', 'chapter_id': 3, 'text': 'Podaj parametry temperatury i czasu obróbki wybranego procesu chemicznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'fa9d7f2e-8609-49c7-ae0f-122aa19eb225', 'question_id': '98cac700-646a-47ec-8b30-8246c190e3f5', 'text': 'Proces C-41: temperatura dowolna, czas dowolny.', 'is_correct': 0, 'sort_order': 0}, {'id': '5084f899-b76c-4991-8be8-caf4bedd425a', 'question_id': '98cac700-646a-47ec-8b30-8246c190e3f5', 'text': 'Proces C-41: temperatura wywoływacza 37,8°C (±0,1°C), czas wywoływania 3 minuty 15 sekund; wybielanie 6 minut 30 sekund; utrwalanie 6 minut 30 sekund.', 'is_correct': 1, 'sort_order': 1}, {'id': '4e43f453-fa3a-4e57-94b0-05a0f7c13516', 'question_id': '98cac700-646a-47ec-8b30-8246c190e3f5', 'text': 'Proces C-41: temperatura 20°C, czas 10 minut.', 'is_correct': 0, 'sort_order': 2}, {'id': '276abcb7-2e8a-4642-8cb8-619c18d90c43', 'question_id': '98cac700-646a-47ec-8b30-8246c190e3f5', 'text': 'Proces C-41: temperatura 50°C, czas 1 minuta.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'fb398411-4bad-4100-b704-e6f6a6cee847', 'chapter_id': 3, 'text': 'Podaj parametry temperatury i czasu obróbki wybranego procesu chemicznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Proces C-41 (obróbka kolorowych filmów negatywowych) wymaga rygorystycznego przestrzegania parametrów: temperatura wywoływacza barwnego to dokładnie 37,8°C (100°F) z tolerancją ±0,1°C, czas wywoływania wynosi 3 minuty 15 sekund. Kolejne etapy to: wybielanie (bleach) – ok. 6 minut 30 sekund przy 37,8°C, utrwalanie (fixer) – ok. 6 minut 30 sekund przy 37,8°C, płukanie – ok. 3 minuty 15 sekund, stabilizacja – ok. 1 minuta 30 sekund. Proces czarno-biały standardowy (np. D-76) pracuje przy 20°C przez 7-10 minut w zależności od filmu.'}, {'id': '4ff85fae-fb76-4d21-ba04-5b8e676bcca5', 'chapter_id': 3, 'text': 'Omów związki chemiczne stosowane w fotografii.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'b47d2f13-e164-48ed-a2e7-008d835025af', 'question_id': '4ff85fae-fb76-4d21-ba04-5b8e676bcca5', 'text': 'Tylko woda i sól.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c5f11cb1-0348-4a6f-a947-1f7c64713e92', 'question_id': '4ff85fae-fb76-4d21-ba04-5b8e676bcca5', 'text': 'Halogenki srebra (bromek, jodek), żelatyna, reduktory (metol, hydrochinon, fenidon), zasady (węglan sodu, boraks), tiosiarczan sodu, kwas siarkawy, siarczyn sodu, barwniki spektralne, utleniacze (nadmanganian).', 'is_correct': 1, 'sort_order': 1}, {'id': 'c5311aba-3f48-40be-84eb-ee9c32db44c8', 'question_id': '4ff85fae-fb76-4d21-ba04-5b8e676bcca5', 'text': 'Tylko alkohol i ocet.', 'is_correct': 0, 'sort_order': 2}, {'id': '4d87f059-4d5f-478f-92b7-986c5ca809e7', 'question_id': '4ff85fae-fb76-4d21-ba04-5b8e676bcca5', 'text': 'Tylko mleko i cukier.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd2bf9f1a-f9c6-44fa-8acb-6b8db3bbdd19', 'chapter_id': 3, 'text': 'Omów związki chemiczne stosowane w fotografii.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'W fotografii stosuje się liczne związki chemiczne: halogenki srebra (bromek AgBr, jodek AgI, chlorek AgCl) jako czynnik światłoczuły w emulsjach; żelatynę jako nośnik emulsji; reduktory (metol, hydrochinon, fenidon, pirogalol) w wywoływaczach; zasady (węglan sodu, boraks, wodorotlenek sodu) jako przyspieszacze; tiosiarczan sodu w utrwalaczach; kwasy (siarkawy, octowy, cytrynowy) do zakwaszania; siarczyn sodu i metabisulfit jako konserwanty; barwniki spektralne w filmach kolorowych; nadmanganian potasu w osłabiaczach; cyjanek potasu w niektórych osłabiaczach; chromiany w procesach pigmentowych; oraz wiele innych substancji pomocniczych.'}, {'id': 'd2d3adc7-d08e-484f-b2b7-a5fef32e4a93', 'chapter_id': 3, 'text': 'Jakiej wody używamy w fotografii do przygotowania procesów chemicznych i uzasadnij dlaczego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '5d044ce5-686d-4d30-91b9-998312639ef0', 'question_id': 'd2d3adc7-d08e-484f-b2b7-a5fef32e4a93', 'text': 'Wody z kranu, ponieważ jest najtańsza.', 'is_correct': 0, 'sort_order': 0}, {'id': '060d6c8a-4364-4e4a-9266-0f9fd3a4810b', 'question_id': 'd2d3adc7-d08e-484f-b2b7-a5fef32e4a93', 'text': 'Wody destylowanej lub demineralizowanej, ponieważ woda kranowa zawiera chlory, sole mineralne i metale ciężkie, które mogą zakłócać proces chemiczny, powodować osady i plamy na materiałach.', 'is_correct': 1, 'sort_order': 1}, {'id': '792eaf46-b098-4728-a714-09fd88ad2f73', 'question_id': 'd2d3adc7-d08e-484f-b2b7-a5fef32e4a93', 'text': 'Wody morskiej, ponieważ zawiera sól.', 'is_correct': 0, 'sort_order': 2}, {'id': '70ac8a81-671f-4f77-b359-59b7137557cf', 'question_id': 'd2d3adc7-d08e-484f-b2b7-a5fef32e4a93', 'text': 'Wody deszczowej, ponieważ jest naturalna.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '2a91e049-bdd2-413c-b9bc-1bbfcc6786d3', 'chapter_id': 3, 'text': 'Jakiej wody używamy w fotografii do przygotowania procesów chemicznych i uzasadnij dlaczego?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'W fotografii do przygotowania odczynników chemicznych używa się wyłącznie wody destylowanej lub demineralizowanej. Woda z kranu zawiera chlory (stosowane do dezynfekcji, które mogą utleniać wywoływacze), sole wapnia i magnezu (powodujące osadzanie się kamienia na emulsji i w kuwetach), metale ciężkie oraz inne zanieczyszczenia organiczne. Te substancje mogą zakłócać proces chemiczny, zmieniać pH, powodować plamy, smugi i nieprzewidywalne zmiany w obrazie, a także skracać trwałość odczynników.'}, {'id': '5355e527-0b02-4869-ab25-c413d4805cea', 'chapter_id': 3, 'text': 'Dokonaj podziału światłoczułych materiałów negatywowych.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '49043d2f-419b-4b60-aef0-1e0ed4fbaa3c', 'question_id': '5355e527-0b02-4869-ab25-c413d4805cea', 'text': 'Tylko na czarno-białe i kolorowe.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c6c4dbb5-a873-448b-8256-38a8b30cffea', 'question_id': '5355e527-0b02-4869-ab25-c413d4805cea', 'text': 'Ze względu na barwę: czarno-białe, kolorowe; ze względu na format: małoobrazkowe, średnioformatowe, wielkoformatowe; ze względu na czułość: mało-, średnio- i wysokoczułe; ze względu na kontrast: miękkie, normalne, twarde.', 'is_correct': 1, 'sort_order': 1}, {'id': '2eece023-2917-4ba0-bcf5-8719a93d4483', 'question_id': '5355e527-0b02-4869-ab25-c413d4805cea', 'text': 'Tylko na drogie i tanie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'df77fe8f-f3e1-40d1-8850-72ef92dbcbc7', 'question_id': '5355e527-0b02-4869-ab25-c413d4805cea', 'text': 'Tylko na nowe i stare.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'a51467fb-a3cb-4a75-9859-79fee41c9994', 'chapter_id': 3, 'text': 'Dokonaj podziału światłoczułych materiałów negatywowych.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Światłoczułe materiały negatywowe dzielimy: ze względu na barwę – czarno-białe (ortochromatyczne, panchromatyczne) i kolorowe (proces C-41); ze względu na format – małoobrazkowe (135), średnioformatowe (120), wielkoformatowe (klisze płaskie); ze względu na czułość – małoczułe (ISO 25-64), średnioczułe (ISO 100-200), wysokoczułe (ISO 400-3200); ze względu na kontrast – miękkie (niski kontrast), normalne, twarde (wysoki kontrast); oraz ze względu na zastosowanie – portretowe, dokumentacyjne, techniczne, artystyczne.'}, {'id': 'dc6d296b-9f3d-417a-8871-95ac2bbd0acf', 'chapter_id': 3, 'text': 'Podziel papier fotograficzny ze względu na rodzaj powierzchni.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '58c6f37f-93e9-459b-a3f2-96e48da3a7ad', 'question_id': 'dc6d296b-9f3d-417a-8871-95ac2bbd0acf', 'text': 'Tylko błyszczący i matowy.', 'is_correct': 0, 'sort_order': 0}, {'id': '19aa232a-b7c5-4217-bf65-4ce8569ced9b', 'question_id': 'dc6d296b-9f3d-417a-8871-95ac2bbd0acf', 'text': 'Błyszczący (glossy), półmat (lustre, pearl), mat (matte), jedwabisty (silk, satin), perłowy (pearl), metaliczny (metallic).', 'is_correct': 1, 'sort_order': 1}, {'id': 'af2fe269-1ff9-4d35-9a6c-631faeb384dd', 'question_id': 'dc6d296b-9f3d-417a-8871-95ac2bbd0acf', 'text': 'Tylko czerwony i niebieski.', 'is_correct': 0, 'sort_order': 2}, {'id': '63939212-92cb-47d5-ad70-dd2020e1fe1c', 'question_id': 'dc6d296b-9f3d-417a-8871-95ac2bbd0acf', 'text': 'Tylko gruby i cienki.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c9f082a6-faaf-42d2-bdd1-41263ebf4384', 'chapter_id': 3, 'text': 'Podziel papier fotograficzny ze względu na rodzaj powierzchni.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Papier fotograficzny dzielimy ze względu na powierzchnię na: błyszczącą (glossy) – dającą głęboką czerń i wysoki kontrast; półmatową (lustre, pearl, satin) – kompromis między błyskiem a matem, mniej podatną na odciski; matową (matte) – eliminującą refleksy, nadającą charakter artystyczny; jedwabistą (silk) – o delikatnym połysku; perłową (pearl) – z drobną strukturą perłową; oraz metaliczną (metallic) – dającą efektowne, niemal metaliczne przejścia tonalne.'}, {'id': '166d6870-d68a-4387-9d03-44e544791f38', 'chapter_id': 3, 'text': 'Podziel papier fotograficzny ze względu na szerokość rolek.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '53153edf-55de-4990-85e8-745416960ab8', 'question_id': '166d6870-d68a-4387-9d03-44e544791f38', 'text': 'Tylko format A4.', 'is_correct': 0, 'sort_order': 0}, {'id': 'bcff1df9-f940-4239-ad48-dbebd2d5b28d', 'question_id': '166d6870-d68a-4387-9d03-44e544791f38', 'text': 'Standardowe szerokości: 8,9 cm (3,5"), 10,2 cm (4"), 12,7 cm (5"), 15,2 cm (6"), 17,8 cm (7"), 20,3 cm (8"), 25,4 cm (10"), 30,5 cm (12"), 40,6 cm (16"), 50,8 cm (20"), 61 cm (24"), 76,2 cm (30"), 106,7 cm (42"), 127 cm (50").', 'is_correct': 1, 'sort_order': 1}, {'id': 'cf483977-f437-4192-8c06-ad55eb716c60', 'question_id': '166d6870-d68a-4387-9d03-44e544791f38', 'text': 'Tylko 10 cm i 20 cm.', 'is_correct': 0, 'sort_order': 2}, {'id': '385e3fe5-2ad3-4e63-b19a-46883a04d71b', 'question_id': '166d6870-d68a-4387-9d03-44e544791f38', 'text': 'Tylko formaty arkuszowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '10741575-2a32-4d84-82ff-50269c5b488c', 'chapter_id': 3, 'text': 'Podziel papier fotograficzny ze względu na szerokość rolek.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Papier fotograficzny w rolach produkowany jest w szerokościach odpowiadających standardom calowym i metrycznym. Najpopularniejsze to: 8,9 cm (3,5 cala), 10,2 cm (4"), 12,7 cm (5"), 15,2 cm (6"), 17,8 cm (7"), 20,3 cm (8"), 25,4 cm (10"), 30,5 cm (12"), 40,6 cm (16"), 50,8 cm (20"), 61 cm (24"), 76,2 cm (30"), 106,7 cm (42"), 127 cm (50") oraz większe formaty do ploterów fotograficznych. Szerokość rolek dobierana jest do formatu odbitek produkowanych w danym minilabie lub studiu.'}, {'id': '3790b71d-4f92-4160-a83f-258e127b5226', 'chapter_id': 3, 'text': 'Omów kolejność przygotowania wywoływacza.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '36a96053-959c-4f6a-909f-d938fe6982e2', 'question_id': '3790b71d-4f92-4160-a83f-258e127b5226', 'text': 'Wszystkie składniki wrzucamy naraz do zimnej wody.', 'is_correct': 0, 'sort_order': 0}, {'id': '1cb07d96-0ddc-43d1-9a04-5b7d1ec114f8', 'question_id': '3790b71d-4f92-4160-a83f-258e127b5226', 'text': 'Rozpuszczamy składniki w niewielkiej ilości ciepłej wody (40-50°C) w kolejności: rozpuszczalnik, konserwant, reduktory, przyspieszacz; dolewamy zimną wodę do docelowej objętości i temperatury pracy (20°C).', 'is_correct': 1, 'sort_order': 1}, {'id': 'eb05c8ff-0723-4733-add1-195129fe64a3', 'question_id': '3790b71d-4f92-4160-a83f-258e127b5226', 'text': 'Mieszamy wszystko w lodzie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c0f225d6-5c66-452a-a68b-2a95dfea99b4', 'question_id': '3790b71d-4f92-4160-a83f-258e127b5226', 'text': 'Dodajemy składniki w losowej kolejności.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '74019007-1c95-4176-a9eb-ff706e525036', 'chapter_id': 3, 'text': 'Omów kolejność przygotowania wywoływacza.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Przygotowanie wywoływacza polega na rozpuszczeniu składników w ściśle określonej kolejności w niewielkiej ilości ciepłej wody (40-50°C): najpierw rozpuszczalnik (woda destylowana), następnie konserwant (siarczyn sodu), potem reduktory (metol, hydrochinon – metol rozpuszcza się w cieplejszej wodzie, hydrochinon w chłodniejszej), a na końcu przyspieszacz (węglan sodu lub boraks). Każdy składnik należy dokładnie rozpuścić przed dodaniem następnego. Po rozpuszczeniu wszystkich składników dolewa się zimną wodę do docelowej objętości i sprawdza temperaturę pracy (zazwyczaj 20°C).'}, {'id': '57e9c71d-5acd-45f6-b824-18a097173b90', 'chapter_id': 3, 'text': 'Bromek potasu: omów zastosowanie w fotografii. Czym można go zastąpić?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '1e37e952-a1ca-4e2b-b14f-b084ccde1d47', 'question_id': '57e9c71d-5acd-45f6-b824-18a097173b90', 'text': 'Służy do czyszczenia obiektywu; zastępuje się go wodą.', 'is_correct': 0, 'sort_order': 0}, {'id': '367c3e04-42c2-453b-90cd-c155c9425f57', 'question_id': '57e9c71d-5acd-45f6-b824-18a097173b90', 'text': 'Stosuje się go w wywoływaczach jako środek hamujący (restrainer) ograniczający wywoływanie nienaświetlonych kryształów srebra, redukujący mgiełkę i ziarnistość; można go zastąpić jodkiem potasu (w mniejszych dawkach).', 'is_correct': 1, 'sort_order': 1}, {'id': 'cf94ef47-103b-4e8c-a3a9-591e315b0d9e', 'question_id': '57e9c71d-5acd-45f6-b824-18a097173b90', 'text': 'Służy do barwienia zdjęć na czerwono; zastępuje się go farbą.', 'is_correct': 0, 'sort_order': 2}, {'id': '2cf5bb1c-1584-4cf1-b78e-b5f104058b05', 'question_id': '57e9c71d-5acd-45f6-b824-18a097173b90', 'text': 'Służy do suszenia filmu; zastępuje się go suszarką.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '9a624711-e91a-46d5-8149-fc89b8cb80cd', 'chapter_id': 3, 'text': 'Bromek potasu: omów zastosowanie w fotografii. Czym można go zastąpić?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Bromek potasu (KBr) stosuje się w wywoływaczach czarno-białych jako środek hamujący (restrainer). Działa on na zasadzie efektu wspólnego jonu – obecność jonów bromkowych w roztworze spowalnia wywoływanie nienaświetlonych lub słabo naświetlonych kryształów srebra, co redukuje mgiełkę (fog), zmniejsza ziarnistość i poprawia czystość bieli. Można go zastąpić jodkiem potasu (KI), który działa silniej w mniejszych stężeniach, lub w niektórych formułach – benzotriazolem.'}, {'id': '64efe74e-5361-4549-8e94-2e5c0a08fabf', 'chapter_id': 3, 'text': 'Jakie czynniki wpływają na ziarnistość materiałów fotograficznych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '45737124-b3e8-4c8b-8892-6355cd159ead', 'question_id': '64efe74e-5361-4549-8e94-2e5c0a08fabf', 'text': 'Tylko marka aparatu.', 'is_correct': 0, 'sort_order': 0}, {'id': '282d520f-f053-4bd3-ac81-22c35870605b', 'question_id': '64efe74e-5361-4549-8e94-2e5c0a08fabf', 'text': 'Czułość materiału (ISO), rodzaj wywoływacza, temperatura i czas wywoływania, sposób agitacji, rozcieńczenie wywoływacza, rodzaj emulsji, wiek materiału.', 'is_correct': 1, 'sort_order': 1}, {'id': 'c127adce-ab24-4c2b-a977-27540ff9bb21', 'question_id': '64efe74e-5361-4549-8e94-2e5c0a08fabf', 'text': 'Tylko kolor opakowania.', 'is_correct': 0, 'sort_order': 2}, {'id': '6ced3352-d11a-4be7-aeea-0e4499e49449', 'question_id': '64efe74e-5361-4549-8e94-2e5c0a08fabf', 'text': 'Tylko pora dnia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '809f0405-a84d-47ed-8c5d-29ffa3c9d172', 'chapter_id': 3, 'text': 'Jakie czynniki wpływają na ziarnistość materiałów fotograficznych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Na ziarnistość materiałów fotograficznych wpływają: czułość ISO (wyższa = większe ziarno), rodzaj wywoływacza (energiczne zwiększają ziarno), temperatura wywoływania (wyższa temperatura = większe ziarno), czas wywoływania (dłuższy czas może zwiększyć ziarno), sposób agitacji (intensywna agitacja zazwyczaj zwiększa ziarno), rozcieńczenie wywoływacza (większe rozcieńczenie przy wydłużonym czasie zmniejsza ziarno), rodzaj emulsji (krystaliczna struktura halogenków srebra) oraz wiek i sposób przechowywania materiału (starzenie zwiększa ziarno i fog).'}, {'id': '70c88ddf-8db6-4f99-bb5d-6193f095a14b', 'chapter_id': 3, 'text': 'Omów różnice pomiędzy negatywem, a diapozytywem.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '5eacc293-adac-4adf-939b-ac71f7f6990a', 'question_id': '70c88ddf-8db6-4f99-bb5d-6193f095a14b', 'text': 'Nie ma między nimi różnic.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f6584b39-658a-4cf1-9507-bf5e682cb98a', 'question_id': '70c88ddf-8db6-4f99-bb5d-6193f095a14b', 'text': 'Negatyw: obraz odwrócony tonalnie i barwnie, szeroka tolerancja ekspozycji, proces C-41, pośredni materiał do odbitek. Diapozytyw (slajd): obraz zgodny z rzeczywistością, wąska tolerancja, wysoki kontrast, proces E-6, bezpośredni materiał do projekcji.', 'is_correct': 1, 'sort_order': 1}, {'id': '2af61145-a2fe-489b-ad40-94cfb78513ed', 'question_id': '70c88ddf-8db6-4f99-bb5d-6193f095a14b', 'text': 'Oba to ten sam materiał.', 'is_correct': 0, 'sort_order': 2}, {'id': '9be9681d-5298-4a18-aade-99b45d2bbfcf', 'question_id': '70c88ddf-8db6-4f99-bb5d-6193f095a14b', 'text': 'Negatyw jest tylko czarno-biały.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e5a8d2af-e2f4-412b-9361-ec9cb74ad80d', 'chapter_id': 3, 'text': 'Omów różnice pomiędzy negatywem, a diapozytywem.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Negatyw to materiał, na którym obraz jest odwrócony tonalnie (jasne partie są ciemne, a ciemne jasne) i barwnie (kolory zastąpione są barwami dopełniającymi). Charakteryzuje się szeroką tolerancją ekspozycji, umiarkowanym kontrastem i służy jako pośredni materiał do wykonywania odbitek. Wywołuje się go w procesie C-41. Diapozytyw (slajd, film odwracalny) daje obraz pozytywowy zgodny z rzeczywistością, ma wąską tolerancję ekspozycji, wysoki kontrast i nasycenie barw. Służy bezpośrednio do projekcji na ekranie i reprodukcji; wywołuje się go w procesie E-6.'}, {'id': '4ca8dd9e-ab85-4741-b11f-3cc2ca5d5f92', 'chapter_id': 3, 'text': 'W jaki sposób i w jakich warunkach należy przechowywać materiały fotograficzne? (np. filmy fotograficzne, odczynniki chemiczne, papiery fotograficzne).', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '38a58bb3-65bf-4f57-837a-6adcb39a5ee6', 'question_id': '4ca8dd9e-ab85-4741-b11f-3cc2ca5d5f92', 'text': 'W słońcu i cieple.', 'is_correct': 0, 'sort_order': 0}, {'id': '279a7e98-312e-442b-b774-bbab18311986', 'question_id': '4ca8dd9e-ab85-4741-b11f-3cc2ca5d5f92', 'text': 'Filmy: chłodno (4-10°C, lodówka), sucho, ciemno; odczynniki: szczelne pojemniki, chłodno, wentylowane pomieszczenie, z dala od światła; papiery: chłodno, sucho, w oryginalnych opakowaniach.', 'is_correct': 1, 'sort_order': 1}, {'id': '7503e8fc-2d9f-4cdf-af06-1e6e2562c8aa', 'question_id': '4ca8dd9e-ab85-4741-b11f-3cc2ca5d5f92', 'text': 'W wilgoci i wysokiej temperaturze.', 'is_correct': 0, 'sort_order': 2}, {'id': '7be296a7-9051-4ae6-bf0b-39670a49c0d0', 'question_id': '4ca8dd9e-ab85-4741-b11f-3cc2ca5d5f92', 'text': 'W otwartych pojemnikach na parapecie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '752c1528-fc28-4721-b54a-55669edfdd65', 'chapter_id': 3, 'text': 'W jaki sposób i w jakich warunkach należy przechowywać materiały fotograficzne? (np. filmy fotograficzne, odczynniki chemiczne, papiery fotograficzne).', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Filmy fotograficzne przechowuje się w chłodzie (4-10°C w lodówce, dla długiego przechowywania w zamrażarce w szczelnych opakowaniach), w suchości i ciemności, z dala od promieniowania RTG i chemikaliów. Odczynniki chemiczne należy przechowywać w szczelnie zamkniętych, oznakowanych pojemnikach z ciemnego szkła lub tworzywa, w chłodnym (15-20°C), suchym i dobrze wentylowanym pomieszczeniu, z dala od źródeł ciepła i światła, rozdzielając kwasy od zasad i substancje toksyczne. Papiery fotograficzne przechowuje się w oryginalnych, szczelnych opakowaniach, w chłodzie i suchości, chroniąc przed światłem i wilgocią.'}, {'id': 'a53824de-0161-4f99-a21f-bbf57c68b34f', 'chapter_id': 3, 'text': 'Co to jest tiosiarczan sodowy, do czego służy i jaki ma odczyn chemiczny?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'a34352c8-5da6-4234-93e1-011497b1deda', 'question_id': 'a53824de-0161-4f99-a21f-bbf57c68b34f', 'text': 'Substancja do czyszczenia obiektywu; odczyn neutralny.', 'is_correct': 0, 'sort_order': 0}, {'id': '8f15faf4-773e-47aa-8b4d-310e5b030754', 'question_id': 'a53824de-0161-4f99-a21f-bbf57c68b34f', 'text': 'Siarczan sodu (Na2S2O3), główny składnik utrwalacza rozpuszczający nienaświetlone halogenki srebra; odczyn zazwyczaj kwaśny w gotowym utrwalaczu.', 'is_correct': 1, 'sort_order': 1}, {'id': 'ea8e3076-234d-49c7-bc40-0741a5c8652e', 'question_id': 'a53824de-0161-4f99-a21f-bbf57c68b34f', 'text': 'Substancja barwiąca zdjęcia na czerwono; odczyn zasadowy.', 'is_correct': 0, 'sort_order': 2}, {'id': 'c31f08f8-45da-42c1-bd25-d09cbdda5587', 'question_id': 'a53824de-0161-4f99-a21f-bbf57c68b34f', 'text': 'Substancja do suszenia filmu; odczyn kwaśny.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1a89dd16-3c54-4e5e-8b8c-4511c0b56b27', 'chapter_id': 3, 'text': 'Co to jest tiosiarczan sodowy, do czego służy i jaki ma odczyn chemiczny?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Tiosiarczan sodu (Na2S2O3), potocznie nazywany siarczanem sodu lub „hipo", to podstawowy składnik utrwalacza fotograficznego. Jego zadaniem jest rozpuszczenie nienaświetlonych halogenków srebra (bromku, jodku) z emulsji, które w przeciwnym razie mogłyby z czasem ulec wywołaniu pod wpływem światła. Sam tiosiarczan w roztworze wodnym ma odczyn słabo zasadowy, jednak w gotowym utrwalaczu, gdzie dodaje się kwasy (siarkawy, octowy), odczyn jest kwaśny (pH 4-6).'}, {'id': 'f8ce71d6-8a27-4694-87de-4e6b94dc1580', 'chapter_id': 3, 'text': 'Jakich materiałów użyjesz do wykonania zdjęć nocnych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '9c578aa5-43ee-466c-89fe-534be528027a', 'question_id': 'f8ce71d6-8a27-4694-87de-4e6b94dc1580', 'text': 'Wyłącznie filmu 25 ISO i krótkich czasów.', 'is_correct': 0, 'sort_order': 0}, {'id': '4d6855f5-ffbc-4c64-8549-e1a2dbb553ca', 'question_id': 'f8ce71d6-8a27-4694-87de-4e6b94dc1580', 'text': 'Filmu wysokoczułego (400-3200 ISO), statywu, wężyka spustowego lub samowyzwalacza, lampy błyskowej jako doświetlenia; aparat z możliwością długich czasów i trybem B.', 'is_correct': 1, 'sort_order': 1}, {'id': 'a5438fa2-9e93-4e45-b9e9-10e083c7a32d', 'question_id': 'f8ce71d6-8a27-4694-87de-4e6b94dc1580', 'text': 'Wyłącznie filtra UV.', 'is_correct': 0, 'sort_order': 2}, {'id': '6f46c9b1-909e-4cf1-8e11-fd8e36007bf8', 'question_id': 'f8ce71d6-8a27-4694-87de-4e6b94dc1580', 'text': 'Wyłącznie papieru fotograficznego.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '8deda16d-399e-4def-a4a9-eafd53a9e1e9', 'chapter_id': 3, 'text': 'Jakich materiałów użyjesz do wykonania zdjęć nocnych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Do fotografii nocnej używa się filmu lub matrycy o wysokiej czułości (ISO 400-3200), który pozwala na krótsze czasy lub mniejsze przysłony w słabym światle. Niezbędny jest stabilny statyw, aby uniknąć drgań przy długich czasach naświetlania (sekundy, minuty), wężyk spustowy lub samowyzwalacz do wyzwalania migawki bez dotykania aparatu, oraz ewentualnie lampa błyskowa do doświetlenia pierwszego planu. Aparat powinien umożliwiać tryb manualny, długie czasy i tryb B (bulb) dla ekspozycji przekraczających 30 sekund.'}, {'id': 'c51b150b-d568-4276-9b8d-9fab5930c668', 'chapter_id': 3, 'text': 'Jakie znasz aktualne rodzaje powierzchni papierów czarno-białych i barwnych?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '5c508faf-1ff0-4c1a-9b53-e361a0154fdc', 'question_id': 'c51b150b-d568-4276-9b8d-9fab5930c668', 'text': 'Tylko błyszcząca i matowa.', 'is_correct': 0, 'sort_order': 0}, {'id': '5d29add4-50a7-409a-b280-8d6c1c9f79aa', 'question_id': 'c51b150b-d568-4276-9b8d-9fab5930c668', 'text': 'Czarno-białe: błysk, półmat, mat, jedwabisty, perłowy. Barwne: błysk, półmat, mat, jedwabisty, metaliczny, perłowy.', 'is_correct': 1, 'sort_order': 1}, {'id': '0e4a9dc6-4365-4200-b393-71c82f266a15', 'question_id': 'c51b150b-d568-4276-9b8d-9fab5930c668', 'text': 'Tylko czerwona i niebieska.', 'is_correct': 0, 'sort_order': 2}, {'id': '962cdb48-6052-486e-a45b-f3955b60c929', 'question_id': 'c51b150b-d568-4276-9b8d-9fab5930c668', 'text': 'Tylko gruba i cienka.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '4fe9680b-e5ea-4041-b84e-d88ab75256e2', 'chapter_id': 3, 'text': 'Jakie znasz aktualne rodzaje powierzchni papierów czarno-białych i barwnych?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Aktualne rodzaje powierzchni papierów czarno-białych to: błyszcząca (glossy), półmatowa (lustre, pearl), matowa (matte), jedwabista (silk, satin) i perłowa (pearl). W papierach barwnych (RA-4) spotyka się: błyszczącą, półmatową, matową, jedwabistą, metaliczną (metallic) i perłową. Papier barytowy (FB) występuje głównie w wersjach błyszczącej i matowej, podczas gdy papier RC oferuje szerszą gamę powierzchni.'}, {'id': '4c002809-7c22-40f3-b429-f748747a2ac2', 'chapter_id': 3, 'text': 'Co to jest materiał odwracalny (pozytywowy)? Wymień jego cechy.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '898bb4b4-c94a-440b-924e-c0319369305b', 'question_id': '4c002809-7c22-40f3-b429-f748747a2ac2', 'text': 'Materiał dający obraz odwrócony; cechy: niski kontrast.', 'is_correct': 0, 'sort_order': 0}, {'id': '478d785c-a69f-41a9-9078-070ee5699a41', 'question_id': '4c002809-7c22-40f3-b429-f748747a2ac2', 'text': 'Materiał dający po wywołaniu obraz pozytywowy zgodny z rzeczywistością; cechy: wysoki kontrast, wysokie nasycenie barw, wąska tolerancja ekspozycji, drobne ziarno, proces E-6.', 'is_correct': 1, 'sort_order': 1}, {'id': '858f8dda-d26e-4d7a-aadb-6bccabec3a9f', 'question_id': '4c002809-7c22-40f3-b429-f748747a2ac2', 'text': 'Materiał samowywołujący się bez chemii.', 'is_correct': 0, 'sort_order': 2}, {'id': 'b2c206d8-16f6-401d-ad93-0298f5d21006', 'question_id': '4c002809-7c22-40f3-b429-f748747a2ac2', 'text': 'Materiał cyfrowy zapisujący dane na karcie pamięci.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '95b49fc5-4def-4337-b608-ae8634fcf153', 'chapter_id': 3, 'text': 'Co to jest materiał odwracalny (pozytywowy)? Wymień jego cechy.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Materiał odwracalny (pozytywowy, slajdowy) to film, który po wywołaniu w procesie E-6 daje obraz pozytywowy zgodny z rzeczywistością, a nie odwrócony jak negatyw. Jego cechy charakterystyczne to: wysoki kontrast, bardzo żywe nasycenie barw, wąska tolerancja ekspozycji (wymaga precyzyjnego naświetlenia), drobne ziarno, wysoka rozdzielczość, trwałość archiwalna barw oraz bezpośrednia przydatność do projekcji i reprodukcji bez konieczności wykonywania odbitek.'}, {'id': '72903472-8ca5-4b53-be7f-3acd2788d42d', 'chapter_id': 3, 'text': 'Co to jest emulsja fotograficzna i z ilu warstw się składa?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '1e0c6e92-6c64-4b4f-b92c-3505c5c0e2d2', 'question_id': '72903472-8ca5-4b53-be7f-3acd2788d42d', 'text': 'Tylko jedna warstwa farby.', 'is_correct': 0, 'sort_order': 0}, {'id': 'bceea2af-a480-4d05-8fb2-6768490e1658', 'question_id': '72903472-8ca5-4b53-be7f-3acd2788d42d', 'text': 'Warstwa światłoczuła zawierająca żelatynę z halogenkami srebra; składa się z podłoża, warstwy przylepnej, emulsji światłoczułej, warstwy ochronnej i warstwy antyhalacyjnej.', 'is_correct': 1, 'sort_order': 1}, {'id': 'eb78ccd0-9fc6-45f2-9493-bdcba459a089', 'question_id': '72903472-8ca5-4b53-be7f-3acd2788d42d', 'text': 'Tylko dwie warstwy.', 'is_correct': 0, 'sort_order': 2}, {'id': '568d54ad-2b83-4c0a-b399-98ba09c8871b', 'question_id': '72903472-8ca5-4b53-be7f-3acd2788d42d', 'text': 'Wyłącznie podłoże papierowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '65ecc471-08a1-41e0-8958-3e591f9ae503', 'chapter_id': 3, 'text': 'Co to jest emulsja fotograficzna i z ilu warstw się składa?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Emulsja fotograficzna to warstwa światłoczuła zawierająca żelatynę z zawieszonymi w niej kryształami halogenków srebra (bromku, jodku, chlorku) oraz ewentualnie barwnikami spektralnymi. W filmach fotograficznych emulsja wraz z podłożem tworzy strukturę składającą się z: podłoża (poliester/triacetyl), warstwy przylepnej, emulsji światłoczułej (która sama może składać się z wielu warstw w filmach kolorowych), warstwy ochronnej (overcoat) oraz warstwy antyhalacyjnej.'}, {'id': 'bfa08a67-864d-4d9e-b5fa-4d62593bbaba', 'chapter_id': 3, 'text': 'Jakie filmy wywołasz w procesie E-6?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'a11cd6b3-385b-4371-90c4-633304e98f60', 'question_id': 'bfa08a67-864d-4d9e-b5fa-4d62593bbaba', 'text': 'Filmy negatywowe kolorowe (C-41).', 'is_correct': 0, 'sort_order': 0}, {'id': '3e1cba24-57b8-4676-b03b-e659bd481257', 'question_id': 'bfa08a67-864d-4d9e-b5fa-4d62593bbaba', 'text': 'Filmy odwracalne pozytywowe (slajdy), np. Fujifilm Velvia, Provia, Kodak Ektachrome.', 'is_correct': 1, 'sort_order': 1}, {'id': 'aa1955a5-d140-457f-bfd0-c6f1acd5fc30', 'question_id': 'bfa08a67-864d-4d9e-b5fa-4d62593bbaba', 'text': 'Filmy czarno-białe.', 'is_correct': 0, 'sort_order': 2}, {'id': '2473d2ea-120e-4377-897f-b6a5e44077e2', 'question_id': 'bfa08a67-864d-4d9e-b5fa-4d62593bbaba', 'text': 'Papiery fotograficzne.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3cc52193-6383-4c30-aeca-3db6f93274d0', 'chapter_id': 3, 'text': 'Jakie filmy wywołasz w procesie E-6?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'W procesie E-6 wywołuje się filmy odwracalne pozytywowe, popularnie nazywane slajdami lub diapozytywami. Należą do nich m.in. Fujifilm Velvia (słynący z wyjątkowo wysokiego nasycenia barw, szczególnie czerwieni), Fujifilm Provia (bardziej neutralny, wszechstronny), Kodak Ektachrome (E100 – nowoczesny slajd o niskim ziarnie). Proces E-6 składa się z: wywoływania czarno-białego, wywoływania barwnego, wybielania, utrwalania, płukania i stabilizacji.'}, {'id': 'f70d2df5-f209-4db6-9181-5813226dc1b5', 'chapter_id': 3, 'text': 'Wymień jakiego rodzaju papieru należy użyć do negatywów kontrastowych, normalnych, miękkich.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'c593aa8f-7f7b-4669-9817-9f28bdbe391d', 'question_id': 'f70d2df5-f209-4db6-9181-5813226dc1b5', 'text': 'Do wszystkich negatywów papier twardy.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd499eb23-dd0b-40ab-b1d7-d1bfcff3757b', 'question_id': 'f70d2df5-f209-4db6-9181-5813226dc1b5', 'text': 'Do negatywów kontrastowych – papier miękki (niski kontrast); do negatywów normalnych – papier normalny (średni kontrast); do negatywów miękkich – papier twardy (wysoki kontrast).', 'is_correct': 1, 'sort_order': 1}, {'id': '990e3d32-10b0-47b7-8c8a-0dd0ec32b9cb', 'question_id': 'f70d2df5-f209-4db6-9181-5813226dc1b5', 'text': 'Do wszystkich negatywów papier miękki.', 'is_correct': 0, 'sort_order': 2}, {'id': 'aa9c6aca-5eb2-48a1-9b23-ce36a0502ebe', 'question_id': 'f70d2df5-f209-4db6-9181-5813226dc1b5', 'text': 'Rodzaj papieru nie ma znaczenia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e47c72b9-fbb5-41a4-a3cb-61ed53c473cb', 'chapter_id': 3, 'text': 'Wymień jakiego rodzaju papieru należy użyć do negatywów kontrastowych, normalnych, miękkich.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Dobór papieru do negatywu opiera się na zasadzie kompensacji kontrastu. Do negatywów kontrastowych (twardych, o wysokim kontraście) należy używać papieru miękkiego (soft, niski kontrast), aby uzyskać odbitkę o zbalansowanym kontraście. Do negatywów normalnych stosuje się papier o normalnej gradacji (medium). Do negatywów miękkich (płaskich, o niskim kontraście) należy użyć papieru twardego (hard, wysoki kontrast), który podbije różnice tonalne. Najwygodniejszym rozwiązaniem jest papier zmienno-kontrastowy (Multigrade), gdzie kontrast reguluje się filtrami.'}, {'id': '31275bce-be06-4888-bafc-4512408df906', 'chapter_id': 3, 'text': 'Co to są substancje redukujące? Wymień znane reduktory.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'fd93cbfc-da1e-4d2c-a866-f3bc030d3ffd', 'question_id': '31275bce-be06-4888-bafc-4512408df906', 'text': 'Substancje do czyszczenia obiektywu.', 'is_correct': 0, 'sort_order': 0}, {'id': '4f1e4036-f7bf-4c60-aec9-267e142d5da7', 'question_id': '31275bce-be06-4888-bafc-4512408df906', 'text': 'Związki chemiczne w wywoływaczu, które redukują (odtwarzają) naświetlone halogenki srebra do metalicznego srebra; np. metol, hydrochinon, fenidon, pirogalol, katechol, amidol.', 'is_correct': 1, 'sort_order': 1}, {'id': 'e9fe4f76-3dca-4768-b028-bcd6adcde1cb', 'question_id': '31275bce-be06-4888-bafc-4512408df906', 'text': 'Substancje do barwienia zdjęć.', 'is_correct': 0, 'sort_order': 2}, {'id': '4f2c42a8-a252-40c0-8aa2-b92477a259c4', 'question_id': '31275bce-be06-4888-bafc-4512408df906', 'text': 'Substancje do suszenia filmu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '503803ce-fe69-4263-9dc4-bfd6cd095551', 'chapter_id': 3, 'text': 'Co to są substancje redukujące? Wymień znane reduktory.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Substancje redukujące (reduktory, czynniki wywołujące) to związki chemiczne zawarte w wywoływaczu, które w środowisku alkalicznym redukują naświetlone kryształy halogenków srebra do czarnego, metalicznego srebra, tworząc widzialny obraz. Najpopularniejsze reduktory to: metol (monometylo-p-aminofenol) – szybki, daje delikatne tony; hydrochinon – wolniejszy, zwiększa kontrast; fenidon – nowoczesny zamiennik metolu o niższej toksyczności; pirogalol (kwas pirogalusowy) – daje ciepłe, brązowe tony; katechol; oraz amidol (używany w niektórych procesach alternatywnych).'}, {'id': '0a0bc350-592b-4a6a-b885-de6dafa9ac4a', 'chapter_id': 3, 'text': 'Gdzie się znajduje warstwa przeciwodblaskowa i jaką funkcję spełnia?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '1ba871d9-8666-4b68-924a-095253569eca', 'question_id': '0a0bc350-592b-4a6a-b885-de6dafa9ac4a', 'text': 'Na wierzchu obiektywu aparatu.', 'is_correct': 0, 'sort_order': 0}, {'id': '2935195c-97f4-4df5-a9e5-6a0e557f4260', 'question_id': '0a0bc350-592b-4a6a-b885-de6dafa9ac4a', 'text': 'Na spodniej stronie podłoża filmu lub jako warstwa w emulsji; zapobiega odbiciu światła od tyłu podłoża i powstawaniu halacji (rozmytych plam światła wokół jasnych punktów).', 'is_correct': 1, 'sort_order': 1}, {'id': 'b6a84be2-c3f9-471e-915c-00849c9b2674', 'question_id': '0a0bc350-592b-4a6a-b885-de6dafa9ac4a', 'text': 'Na przedniej soczewce obiektywu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'daf7c77a-96b6-4d12-9648-053ed7b303ce', 'question_id': '0a0bc350-592b-4a6a-b885-de6dafa9ac4a', 'text': 'Wewnątrz lampy błyskowej.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd7033c3a-96ad-4235-a0b5-564962d258f4', 'chapter_id': 3, 'text': 'Gdzie się znajduje warstwa przeciwodblaskowa i jaką funkcję spełnia?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Warstwa przeciwodblaskowa (antyhalacyjna, antihalation layer) znajduje się na spodniej stronie podłoża filmu fotograficznego (lub czasem jako warstwa wewnątrz emulsji). Jej funkcją jest pochłanianie światła, które przeszło przez emulsję i odbiłoby się od tyłu podłoża z powrotem do emulsji. Zapobiega to powstawaniu halacji – rozmytych, świetlistych otoczek wokół jasnych punktów na zdjęciu (np. żarówek, reflektorów). W niektórych filmach warstwa ta jest barwna (zazwyczaj zielona lub ciemnoczerwona) i wypłukuje się podczas wywoływania.'}, {'id': 'db17b748-941d-4508-87ce-d8596ae8c956', 'chapter_id': 3, 'text': 'Czy starzenie się materiału światłoczułego ma wpływ na zmianę cech charakterystycznych emulsji? Wyjaśnij.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '48e25e09-574a-4672-839f-a2e2687120d9', 'question_id': 'db17b748-941d-4508-87ce-d8596ae8c956', 'text': 'Nie, starzenie nie ma żadnego wpływu.', 'is_correct': 0, 'sort_order': 0}, {'id': 'bc9ed31a-4df8-4429-875d-c7c05bf4d7e0', 'question_id': 'db17b748-941d-4508-87ce-d8596ae8c956', 'text': 'Tak, starzenie powoduje zmianę czułości, wzrost zaciemnienia podstawy (fog), zmianę balansu barwnego, wzrost ziarnistości i obniżenie kontrastu.', 'is_correct': 1, 'sort_order': 1}, {'id': '87010350-424c-4ad0-a8d1-895de9c054a6', 'question_id': 'db17b748-941d-4508-87ce-d8596ae8c956', 'text': 'Tak, ale tylko poprawia jakość materiału.', 'is_correct': 0, 'sort_order': 2}, {'id': 'a27846e4-b4b2-4019-bb74-ab3cb498522d', 'question_id': 'db17b748-941d-4508-87ce-d8596ae8c956', 'text': 'Nie, starzenie zmienia tylko kolor opakowania.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3099bb17-9ce5-42f9-bde8-be6ca0a8fcb6', 'chapter_id': 3, 'text': 'Czy starzenie się materiału światłoczułego ma wpływ na zmianę cech charakterystycznych emulsji? Wyjaśnij.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Starzenie się materiału światłoczułego ma istotny wpływ na cechy charakterystyczne emulsji. W miarę upływu czasu, szczególnie przy niewłaściwych warunkach przechowywania (ciepło, wilgoć, światło), dochodzi do: zmiany czułości (zazwyczaj obniżenia lub wzrostu w zależności od typu filmu), wzrostu zaciemnienia podstawy (fog – mgiełka), zmiany balansu barwnego w filmach kolorowych (dominata barwna, najczęściej czerwona lub magenta), wzrostu ziarnistości, obniżenia kontrastu i rozdzielczości oraz skrócenia zakresu tonalnego. Dlatego filmy powinny być używane przed datą ważności i przechowywane w chłodzie.'}, {'id': '124381c6-8d71-40bd-bace-4d5aaebaca87', 'chapter_id': 3, 'text': 'Jakich materiałów i sprzętu użyjesz do fotografowania architektury i jakimi zasadami będziesz się kierować?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '7855918e-d7bf-4d66-88e7-5ebc9686a3df', 'question_id': '124381c6-8d71-40bd-bace-4d5aaebaca87', 'text': 'Teleobiektyw, wysokie ISO, fotografowanie pod słońce.', 'is_correct': 0, 'sort_order': 0}, {'id': 'cbf6c9a7-f13c-42f7-a3b5-fd4a4a4346e0', 'question_id': '124381c6-8d71-40bd-bace-4d5aaebaca87', 'text': 'Aparat z obiektywem szerokokątnym lub Tilt-Shift, statyw, poziomica; zasada zachowania pionów, odpowiednia pora dnia (złota godzina), niskie ISO, mała przysłona dla dużej głębi ostrości.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f0a07ac5-63e0-4b28-b4c2-ac64bf7ea267', 'question_id': '124381c6-8d71-40bd-bace-4d5aaebaca87', 'text': 'Kompakt z lampą błyskową, brak statywu.', 'is_correct': 0, 'sort_order': 2}, {'id': '7960a1a2-1507-4a3b-b243-1c8e48282bd5', 'question_id': '124381c6-8d71-40bd-bace-4d5aaebaca87', 'text': 'Wyłącznie aparat średnioformatowy z filmem czarno-białym.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '3a7d4ce1-a165-47ff-975a-79d31536a6af', 'chapter_id': 3, 'text': 'Jakich materiałów i sprzętu użyjesz do fotografowania architektury i jakimi zasadami będziesz się kierować?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Do fotografowania architektury używa się aparatu z obiektywem szerokokątnym (np. 16-35 mm dla pełnej klatki) lub specjalistycznym Tilt-Shift do korekcji perspektywy, stabilnego statywu, poziomicy i wężyka spustowego. Kieruje się zasadą zachowania pionów linii budynku (lub ich korekty), wybiera odpowiednią porę dnia (złota godzina, błękitna godzina) dla ciekawego oświetlenia, używa niskiego ISO dla najwyższej jakości, małej przysłony (f/8-f/11) dla dużej głębi ostrości oraz filtra polaryzacyjnego do kontroli odbić od szyb.'}, {'id': 'eff1b16d-3aa4-4edf-a39a-fff49165e5b6', 'chapter_id': 3, 'text': 'Omów zasadę przygotowania wywoływacza do obróbki chemicznej papieru fotograficznego.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '3a977ffe-7d16-4a94-9d2f-46cc6bed05d9', 'question_id': 'eff1b16d-3aa4-4edf-a39a-fff49165e5b6', 'text': 'Wszystkie składniki wrzuca się naraz do zimnej wody.', 'is_correct': 0, 'sort_order': 0}, {'id': 'f3321ea9-d13b-4b98-aa8b-3e83bce85828', 'question_id': 'eff1b16d-3aa4-4edf-a39a-fff49165e5b6', 'text': 'Rozpuszcza się składniki w ciepłej wodzie (40-50°C) w kolejności: woda, konserwant, reduktory, przyspieszacz; dolewa zimną wodę do temperatury pracy (20°C); sprawdza pH i temperaturę.', 'is_correct': 1, 'sort_order': 1}, {'id': 'abedd2d0-63ba-48e2-9787-72eb15483c65', 'question_id': 'eff1b16d-3aa4-4edf-a39a-fff49165e5b6', 'text': 'Miesza się w lodzie.', 'is_correct': 0, 'sort_order': 2}, {'id': 'ea678c35-118a-430c-a0d8-f2978e917c4b', 'question_id': 'eff1b16d-3aa4-4edf-a39a-fff49165e5b6', 'text': 'Dodaje składniki w losowej kolejności.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '61333f89-c612-4faa-b7bd-5cd101dea53c', 'chapter_id': 3, 'text': 'Omów zasadę przygotowania wywoływacza do obróbki chemicznej papieru fotograficznego.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Przygotowanie wywoływacza do papieru fotograficznego polega na rozpuszczeniu składników w ściśle określonej kolejności w niewielkiej ilości ciepłej wody (40-50°C): najpierw woda destylowana, następnie konserwant (siarczyn sodu), potem reduktory (metol, hydrochinon), a na końcu przyspieszacz (węglan sodu lub boraks). Każdy składnik należy dokładnie rozpuścić przed dodaniem następnego. Następnie dolewa się zimną wodę do docelowej objętości i sprawdza temperaturę pracy (zazwyczaj 20°C dla czarno-białych, 37,8°C dla kolorowych). Gotowy wywoływacz powinien mieć odczyn zasadowy (pH 9-11).'}, {'id': 'f3c4d26f-4440-4ef1-a72f-060ce761b4f3', 'chapter_id': 3, 'text': 'W jakim celu zakwaszamy utrwalacz?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '6f7bbec1-88df-4280-8fa0-4fc1ec425ab3', 'question_id': 'f3c4d26f-4440-4ef1-a72f-060ce761b4f3', 'text': 'Aby zwiększyć jego odczyn zasadowy.', 'is_correct': 0, 'sort_order': 0}, {'id': 'b99a2ae6-34d3-41b8-8203-cafabeaab75f', 'question_id': 'f3c4d26f-4440-4ef1-a72f-060ce761b4f3', 'text': 'Aby zapobiec rozkładowi tiosiarczanu, wypłukaniu wywołanego srebra, neutralizować resztki zasadowego wywoływacza i ustabilizować obraz.', 'is_correct': 1, 'sort_order': 1}, {'id': '6f993ccf-671c-4720-bcd2-b4fa45b74c15', 'question_id': 'f3c4d26f-4440-4ef1-a72f-060ce761b4f3', 'text': 'Aby zmienić kolor utrwalacza na czerwony.', 'is_correct': 0, 'sort_order': 2}, {'id': '3dec788b-267f-46b5-bf9d-8effde2832a7', 'question_id': 'f3c4d26f-4440-4ef1-a72f-060ce761b4f3', 'text': 'Aby przyspieszyć wywoływanie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'd0bde2b5-9874-413a-a148-f9ee0d202d3f', 'chapter_id': 3, 'text': 'W jakim celu zakwaszamy utrwalacz?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Utrwalacz zakwasza się (do pH 4-6) z kilku powodów: kwaśne środowisko zapobiega rozkładowi tiosiarczanu sodu w roztworze, który w środowisku zasadowym ulega dekompozycji; zapobiega wypłukiwaniu wywołanego obrazu srebra z emulsji; neutralizuje resztki zasadowego wywoływacza pozostałe na emulsji po wywoływaniu; utwardza żelatynę emulsji, zwiększając jej odporność mechaniczną; oraz przygotowuje materiał do końcowego płukania, zapobiegając powstawaniu plam alkalicznych.'}, {'id': '0544d8c9-98a6-4dbd-9cd0-6bd722a8707b', 'chapter_id': 3, 'text': 'Czym różni się negatyw „prześwietlony" od „przewołanego"?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '0c095dfd-6239-4e7d-9f59-1f60bf03940b', 'question_id': '0544d8c9-98a6-4dbd-9cd0-6bd722a8707b', 'text': 'Nie ma między nimi różnicy.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c50d8446-b228-46ed-851c-881071fe7396', 'question_id': '0544d8c9-98a6-4dbd-9cd0-6bd722a8707b', 'text': 'Prześwietlony: zbyt duża ekspozycja przy naświetlaniu (zbyt jasny, gęsty negatyw). Przewołany: zbyt długi czas lub zbyt wysoka temperatura przy wywoływaniu (zbyt ciemny, gęsty negatyw z utratą szczegółów).', 'is_correct': 1, 'sort_order': 1}, {'id': 'eb54add0-d067-497d-9a20-64b661073fba', 'question_id': '0544d8c9-98a6-4dbd-9cd0-6bd722a8707b', 'text': 'Prześwietlony to dobry negatyw, a przewołany to zepsuty.', 'is_correct': 0, 'sort_order': 2}, {'id': '0aa71205-85d6-432b-a49c-a3ff255fb72d', 'question_id': '0544d8c9-98a6-4dbd-9cd0-6bd722a8707b', 'text': 'Oba to synonimy tego samego błędu.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '8f72eb8a-2c94-4dc7-9265-87d8d3d305db', 'chapter_id': 3, 'text': 'Czym różni się negatyw „prześwietlony" od „przewołanego"?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Negatyw prześwietlony to taki, który otrzymał zbyt dużą dawkę światła podczas ekspozycji w aparacie – jest zbyt ciemny, gęsty, z utraconą strukturą w światłach i trudny do powiększenia. Negatyw przewołany to taki, który był wywoływany zbyt długo, w zbyt wysokiej temperaturze lub w zbyt stężonym wywoływaczu – również jest zbyt ciemny i gęsty, ale przyczyna leży po stronie procesu chemicznego, a nie ekspozycji. Oba błędy prowadzą do podobnego efektu wizualnego, ale wymagają innej korekty w przyszłości.'}, {'id': 'd89c36e8-59d7-4bbb-9ec8-87dfb36a1b0c', 'chapter_id': 3, 'text': 'Podaj skład utrwalacza, opisz proces utrwalania. Jak poznajemy zużyty utrwalacz?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '65c00b24-5fa7-4cc5-b062-4dfcfff0aa11', 'question_id': 'd89c36e8-59d7-4bbb-9ec8-87dfb36a1b0c', 'text': 'Skład: metol, hydrochinon, węglan sodu; proces: wywoływanie.', 'is_correct': 0, 'sort_order': 0}, {'id': 'cab05786-29be-42a4-a8cc-f0e43a2fe1ed', 'question_id': 'd89c36e8-59d7-4bbb-9ec8-87dfb36a1b0c', 'text': 'Skład: tiosiarczan sodu (rozpuszcza nienaświetlone halogenki), kwas siarkawy/kwaśny siarczyn sodu (zakwaszenie), siarczan sodu/glinu (utrwalenie fizyczne). Proces: chemiczne usunięcie nienaświetlonych halogenków srebra i zakwaszenie emulsji. Zużyty: test jodkowy, wydłużony czas działania, zmętnienie.', 'is_correct': 1, 'sort_order': 1}, {'id': 'fb5efcdd-b6a1-4a8f-bd7b-12e5c9a89e3c', 'question_id': 'd89c36e8-59d7-4bbb-9ec8-87dfb36a1b0c', 'text': 'Skład: tylko woda i sól; proces: suszenie.', 'is_correct': 0, 'sort_order': 2}, {'id': '966df98a-9803-4be1-9228-cebac6e33d22', 'question_id': 'd89c36e8-59d7-4bbb-9ec8-87dfb36a1b0c', 'text': 'Skład: alkohol i ocet; proces: czyszczenie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '9cbcf63a-bd24-43e8-a401-5eda3f232383', 'chapter_id': 3, 'text': 'Podaj skład utrwalacza, opisz proces utrwalania. Jak poznajemy zużyty utrwalacz?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Utrwalacz składa się z: tiosiarczanu sodu (Na2S2O3) jako czynnika chemicznego rozpuszczającego nienaświetlone halogenki srebra; kwasu siarkawego, kwaśnego siarczynu sodu lub metabisulfitu sodu utrzymujących kwaśne pH (4-6); oraz siarczanu sodu lub siarczanu glinu utrwalających fizycznie żelatynę emulsji. Proces utrwalania polega na rozpuszczeniu nienaświetlonych związków srebra, które mogłyby w przyszłości ulec wywołaniu pod wpływem światła, oraz na zakwaszeniu emulsji, co neutralizuje resztki wywoływacza i utwardza żelatynę. Zużyty utrwalacz poznajemy po: wydłużonym czasie działania (zamiast 5-10 minut trzeba utrwalać dłużej), zmętnieniu roztworu, teście z jodkiem potasu (żółte zabarwienie wskazuje na obecność wytrąconego jodu, świadcząca o wyczerpaniu zdolności wiązania siarczanu) oraz słabym zapachu zamiast charakterystycznego odoru siarkowodoru.'}, {'id': 'aaacb8fc-b125-42fd-9fb3-7cddbc5ae31b', 'chapter_id': 3, 'text': 'Co to jest emulsja fotograficzna i z ilu warstw się składa?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '9848a718-6fa8-47ff-a3ae-5d6db780e2b0', 'question_id': 'aaacb8fc-b125-42fd-9fb3-7cddbc5ae31b', 'text': 'Tylko jedna warstwa farby na papierze.', 'is_correct': 0, 'sort_order': 0}, {'id': 'c72c2e14-07c0-4585-8617-936ef770cf90', 'question_id': 'aaacb8fc-b125-42fd-9fb3-7cddbc5ae31b', 'text': 'Warstwa światłoczuła zawierająca żelatynę z halogenkami srebra; w filmie składa się z podłoża, warstwy przylepnej, emulsji światłoczułej, warstwy ochronnej i warstwy antyhalacyjnej.', 'is_correct': 1, 'sort_order': 1}, {'id': 'd054c09f-c437-4e44-9c39-2ba0acfd0f75', 'question_id': 'aaacb8fc-b125-42fd-9fb3-7cddbc5ae31b', 'text': 'Tylko dwie warstwy.', 'is_correct': 0, 'sort_order': 2}, {'id': '66529f7a-9dee-4bc4-9463-862038e62343', 'question_id': 'aaacb8fc-b125-42fd-9fb3-7cddbc5ae31b', 'text': 'Wyłącznie podłoże papierowe.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '6eb393b6-2688-4c98-8037-7f8e2cc1c90e', 'chapter_id': 3, 'text': 'Co to jest emulsja fotograficzna i z ilu warstw się składa?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Emulsja fotograficzna to warstwa światłoczuła zawierająca żelatynę z zawieszonymi w niej kryształami halogenków srebra (bromku, jodku, czasem chlorku) oraz ewentualnie barwnikami spektralnymi (w materiałach kolorowych i ortochromatycznych). W filmie fotograficznym emulsja wraz z podłożem tworzy strukturę składającą się z: podłoża (poliester lub triacetyl celulozy), warstwy przylepnej łączącej podłoże z emulsją, samej emulsji światłoczułej (która w filmach kolorowych składa się z trzech warstw barwnych), warstwy ochronnej (overcoat) na wierzchu oraz warstwy antyhalacyjnej na spodniej stronie podłoża.'}, {'id': '0764e942-3465-482b-acc5-188a5ef678cb', 'chapter_id': 3, 'text': 'Czym się zakwasza triosiarczan sodu i w jakim celu?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': 'ca8ed118-e82d-42a4-91f0-08f8f899d402', 'question_id': '0764e942-3465-482b-acc5-188a5ef678cb', 'text': 'Wodą destylowaną; aby rozcieńczyć.', 'is_correct': 0, 'sort_order': 0}, {'id': 'd314be95-91cb-4507-8ba2-62068adea8f0', 'question_id': '0764e942-3465-482b-acc5-188a5ef678cb', 'text': 'Kwasem siarkawym, kwaśnym siarczynem sodu lub metabisulfitem sodu; aby zapobiec rozkładowi tiosiarczanu, wypłukaniu srebra i ustabilizować obraz.', 'is_correct': 1, 'sort_order': 1}, {'id': '7acc4d08-9833-4e9d-8568-322e2989c066', 'question_id': '0764e942-3465-482b-acc5-188a5ef678cb', 'text': 'Słodką wodą; aby zmienić smak.', 'is_correct': 0, 'sort_order': 2}, {'id': '9fb18220-bd2a-40e9-8d7b-384f8d08b00a', 'question_id': '0764e942-3465-482b-acc5-188a5ef678cb', 'text': 'Alkoholem; aby przyspieszyć suszenie.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1cc9242d-ba13-4634-ab72-9c39cb0ac505', 'chapter_id': 3, 'text': 'Czym się zakwasza triosiarczan sodu i w jakim celu?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Tiosiarczan sodu (siarczan sodu, „hipo") zakwasza się kwasem siarkawym (H2SO3), kwaśnym siarczynem sodu (NaHSO3) lub metabisulfitem sodu (Na2S2O5). Celem zakwaszenia jest: zapobiegnięcie rozkładowi tiosiarczanu w środowisku zasadowym (tiosiarczan w zasadowym pH ulega dekompozycji do siarczku i siarczanu); zapobiegnięcie wypłukaniu wywołanego obrazu srebra z emulsji (w środowisku zasadowym srebro mogłoby się rozpuścić); neutralizacja resztek zasadowego wywoływacza pozostałych na emulsji; utwardzenie żelatyny emulsji, zwiększenie jej odporności mechanicznej; oraz przygotowanie materiału do końcowego płukania.'}, {'id': '1fd49c21-2c30-4dff-b710-14d5ce6a71f9', 'chapter_id': 3, 'text': 'Jakie znasz substancje konserwujące w wywoływaczu czarno-białym?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '9def1363-0b45-4074-8f1b-6c2bd12002d8', 'question_id': '1fd49c21-2c30-4dff-b710-14d5ce6a71f9', 'text': 'Tylko woda.', 'is_correct': 0, 'sort_order': 0}, {'id': '49f7e16b-c9bf-4b4c-a271-b42dd3e9cb5d', 'question_id': '1fd49c21-2c30-4dff-b710-14d5ce6a71f9', 'text': 'Siarczyn sodu (Na2SO3), metabisulfit sodu (Na2S2O5), kwas siarkawy; zapobiegają utlenianiu się reduktorów przez powietrze.', 'is_correct': 1, 'sort_order': 1}, {'id': 'f373cc25-ca75-43ee-b003-a11392a1f075', 'question_id': '1fd49c21-2c30-4dff-b710-14d5ce6a71f9', 'text': 'Tylko sól kuchenna.', 'is_correct': 0, 'sort_order': 2}, {'id': '5de856a0-7374-4ef6-a404-0d1cf9ee422b', 'question_id': '1fd49c21-2c30-4dff-b710-14d5ce6a71f9', 'text': 'Tylko cukier.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '1524fc52-53d5-4d6a-a2ac-e95a73f9352c', 'chapter_id': 3, 'text': 'Jakie znasz substancje konserwujące w wywoływaczu czarno-białym?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Główne substancje konserwujące w wywoływaczach czarno-białych to: siarczyn sodu (Na2SO3) i metabisulfit sodu (Na2S2O5), które działają jako reduktory utleniające się pierwsze w kontakcie z tlenem z powietrza, zamiast reduktorów wywołujących (metolu, hydrochinonu). Dzięki temu zapobiegają utlenianiu i degradacji wywoływacza, wydłużając jego trwałość, utrzymując stałe właściwości chemiczne roztworu i zapobiegając powstawaniu zabarwienia oraz osadów. W niektórych formułach stosuje się też kwas siarkawy lub kwas benzoesowy.'}, {'id': '8e81ce0b-ba03-4053-b744-d614f14edbf5', 'chapter_id': 3, 'text': 'Czym charakteryzują się wywoływacze uniwersalne?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '673048e1-cfee-4da2-9ae7-15329d3ed520', 'question_id': '8e81ce0b-ba03-4053-b744-d614f14edbf5', 'text': 'Służą wyłącznie do wywoływania papieru.', 'is_correct': 0, 'sort_order': 0}, {'id': 'ff526928-6488-4f22-aff5-a6686dc24e03', 'question_id': '8e81ce0b-ba03-4053-b744-d614f14edbf5', 'text': 'Mogą być stosowane zarówno do filmów negatywowych, jak i papierów fotograficznych (czarno-białych), zazwyczaj przy różnym rozcieńczeniu i czasie; dają umiarkowany kontrast i są wygodne w użyciu.', 'is_correct': 1, 'sort_order': 1}, {'id': 'b6017090-f541-4292-b9c1-abe87b7b049d', 'question_id': '8e81ce0b-ba03-4053-b744-d614f14edbf5', 'text': 'Służą wyłącznie do czyszczenia obiektywu.', 'is_correct': 0, 'sort_order': 2}, {'id': 'dd26622c-943a-4dcb-8230-f0e85492f560', 'question_id': '8e81ce0b-ba03-4053-b744-d614f14edbf5', 'text': 'Służą wyłącznie do wywoływania filmów kolorowych.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'c885fa7d-ead7-4561-a547-77a32d291fc0', 'chapter_id': 3, 'text': 'Czym charakteryzują się wywoływacze uniwersalne?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Wywoływacze uniwersalne to preparaty chemiczne zaprojektowane do pracy z różnymi materiałami światłoczułymi – zarówno z filmami negatywowymi, jak i papierami fotograficznymi czarno-białymi. Charakteryzują się one kompromisowym składem, który przy odpowiednim rozcieńczeniu i czasie wywoływania daje zadowalające rezultaty z różnymi materiałami. Zazwyczaj przy mniejszym rozcieńczeniu i krótszym czasie służą do papieru, a przy większym rozcieńczeniu i dłuższym czasie – do filmów. Dają umiarkowany kontrast, są wygodne w użyciu dla amatorów, ale często nie dorównują specjalistycznym wywoływaczom dedykowanym pod konkretny materiał.'}, {'id': 'd94c05b4-3e1c-4807-bd2d-487b59286779', 'chapter_id': 3, 'text': 'Dlaczego stopień kontrastowości papieru jest jedną z najważniejszych cech papieru pozytywowego?', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '4b915208-6ad7-41d8-beaa-b6c4c6c10810', 'question_id': 'd94c05b4-3e1c-4807-bd2d-487b59286779', 'text': 'Ponieważ determinuje cenę papieru.', 'is_correct': 0, 'sort_order': 0}, {'id': '52d18598-1a4f-4f14-a5e3-1ab1ff357b55', 'question_id': 'd94c05b4-3e1c-4807-bd2d-487b59286779', 'text': 'Ponieważ pozwala skompensować kontrast negatywu i uzyskać odbitkę o odpowiednim zakresie tonalnym; niedopasowanie prowadzi do utraty szczegółów w cieniach lub światłach.', 'is_correct': 1, 'sort_order': 1}, {'id': '9bed3884-a24c-4f60-b2ea-a1f54273e2e0', 'question_id': 'd94c05b4-3e1c-4807-bd2d-487b59286779', 'text': 'Ponieważ zmienia kolor papieru.', 'is_correct': 0, 'sort_order': 2}, {'id': '6b90344d-6d8a-4e96-8236-9f76bade6025', 'question_id': 'd94c05b4-3e1c-4807-bd2d-487b59286779', 'text': 'Ponieważ wpływa na wagę odbitki.', 'is_correct': 0, 'sort_order': 3}]}, {'id': '0c9c38c8-470f-4006-9e33-976156ff4d75', 'chapter_id': 3, 'text': 'Dlaczego stopień kontrastowości papieru jest jedną z najważniejszych cech papieru pozytywowego?', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Stopień kontrastowości (gradacja) papieru pozytywowego jest kluczowa, ponieważ pozwala skompensować kontrast negatywu i uzyskać odbitkę o odpowiednim, zbalansowanym zakresie tonalnym. Negatyw kontrastowy wymaga papieru miękkiego (niskiego kontrastu), aby nie stracić szczegółów w cieniach i światłach. Negatyw płaski wymaga papieru twardego (wysokiego kontrastu), aby podbić różnice tonalne i uniknąć szarej, bez wyrazu odbitki. Niedopasowanie kontrastu prowadzi do utraty informacji tonalnej – zbyt twardy papier do kontrastowego negatywu da obraz z wypalonymi światłami i zasztywnionymi cieniami bez półtonów.'}, {'id': '3d16d832-37bc-486c-813c-ccefb1d29076', 'chapter_id': 3, 'text': 'Wymień jakiego rodzaju papieru należy użyć do negatywów kontrastowych, normalnych, miękkich.', 'type': 'closed', 'created_at': '2026-05-09 17:17:29', 'answers': [{'id': '7865b93a-d823-4cff-aba0-e865a65eb021', 'question_id': '3d16d832-37bc-486c-813c-ccefb1d29076', 'text': 'Do wszystkich negatywów papier twardy.', 'is_correct': 0, 'sort_order': 0}, {'id': '440f1742-e3fa-4107-8cb0-523d24df8cbc', 'question_id': '3d16d832-37bc-486c-813c-ccefb1d29076', 'text': 'Do negatywów kontrastowych – papier miękki (soft, niski kontrast); do negatywów normalnych – papier normalny (medium); do negatywów miękkich – papier twardy (hard, wysoki kontrast).', 'is_correct': 1, 'sort_order': 1}, {'id': '38ab19c1-3cb0-4fc1-b136-d286fff86e98', 'question_id': '3d16d832-37bc-486c-813c-ccefb1d29076', 'text': 'Do wszystkich negatywów papier miękki.', 'is_correct': 0, 'sort_order': 2}, {'id': '47ba666c-5156-48c0-9c2d-99babde1d4cb', 'question_id': '3d16d832-37bc-486c-813c-ccefb1d29076', 'text': 'Rodzaj papieru nie ma znaczenia.', 'is_correct': 0, 'sort_order': 3}]}, {'id': 'e8f69a42-559f-44b0-923b-e70f5dd9e6a8', 'chapter_id': 3, 'text': 'Wymień jakiego rodzaju papieru należy użyć do negatywów kontrastowych, normalnych, miękkich.', 'type': 'open', 'created_at': '2026-05-09 17:17:29', 'sample_answer': 'Dobór papieru do negatywu opiera się na zasadzie kompensacji kontrastu. Do negatywów kontrastowych (twardych, o wysokim kontraście, z wypalonymi światłami i głębokimi cieniami) należy używać papieru miękkiego (soft, niski kontrast, oznaczanego często numerem 1 lub 2), który rozciągnie zakres tonalny i odzyska szczegóły. Do negatywów normalnych stosuje się papier o normalnej gradacji (medium, numer 2 lub 3). Do negatywów miękkich (płaskich, o niskim kontraście, szarych i bez wyrazu) należy użyć papieru twardego (hard, wysoki kontrast, numer 3, 4 lub 5), który podbije różnice tonalne i nada obrazowi wyrazistości. Najwygodniejszym rozwiązaniem jest papier zmienno-kontrastowy (Multigrade), gdzie kontrast reguluje się za pomocą filtrów pod powiększalnikiem.'}]
